app.post('/api/admin/canal-url', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    if (req.user.role !== 'admin') {
      return res.status(403).json({ error: 'Solo el admin principal puede modificar la URL del canal.' });
    }
    const { url } = req.body;
    const safeUrl = (url || '').trim();
    if (safeUrl) {
      try {
        const parsed = new URL(safeUrl);
        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
          return res.status(400).json({ error: 'URL inválida. Debe comenzar con http:// o https://' });
        }
      } catch {
        return res.status(400).json({ error: 'URL inválida. Verificá que sea una URL completa y válida.' });
      }
    }
    await setConfig('canalInformativoUrl', safeUrl);
    res.json({ success: true, message: 'URL del Canal Informativo actualizada correctamente' });
  } catch (error) {
    console.error('Error guardando canal URL:', error);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

app.put('/api/admin/config/cbu', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    // Solo el admin principal puede cambiar el CBU. Un depositor/withdrawer comprometido
    // podria redirigir los depositos de los usuarios a su propia cuenta bancaria.
    if (req.user.role !== 'admin') {
      return res.status(403).json({ error: 'Solo el administrador principal puede modificar el CBU' });
    }

    const currentCbu = await getConfig('cbu') || {};
    // Whitelist de campos permitidos para evitar inyeccion de propiedades inesperadas.
    const allowed = {};
    if (typeof req.body.bank === 'string') allowed.bank = req.body.bank.trim();
    if (typeof req.body.titular === 'string') allowed.titular = req.body.titular.trim();
    if (typeof req.body.number === 'string') allowed.number = req.body.number.trim();
    if (typeof req.body.alias === 'string') allowed.alias = req.body.alias.trim();

    if (allowed.number !== undefined && allowed.number.length > 0 && allowed.number.length < 10) {
      return res.status(400).json({ error: 'CBU invalido (minimo 10 caracteres)' });
    }

    const newCbu = { ...currentCbu, ...allowed };
    await setConfig('cbu', newCbu);

    logger.info(`Admin ${req.user.username} updated CBU config`);
    res.json({ success: true, message: 'CBU actualizado', cbu: newCbu });
  } catch (error) {
    console.error('Error actualizando CBU:', error);
    res.status(500).json({ error: 'Error actualizando CBU' });
  }
});

// ============================================
// LÍNEAS POR USUARIO (mapeo prefijo → teléfono)
// Se muestran al usuario en la pantalla de reembolsos.
// 10 slots configurables + un teléfono default si ninguno matchea.
// ============================================
const USER_LINES_MAX_SLOTS = 30;

app.get('/api/admin/user-lines', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const config = (await getConfig('userLinesByPrefix')) || {};
    const slots = Array.isArray(config.slots) ? config.slots : [];
    // Devolvemos solo los slots con datos (no padding); el frontend agrega
    // un botón "+ Agregar línea" para sumar más, hasta USER_LINES_MAX_SLOTS.
    // teamName es opcional — se muestra arriba a la izquierda en el header
    // del usuario cuando el prefijo matchea (ej: 'ato' -> 'Atomic').
    const cleaned = slots
      .filter(s => s && (s.prefix || s.phone || s.teamName))
      .map(s => ({
        prefix: s.prefix || '',
        phone: s.phone || '',
        teamName: s.teamName || ''
      }));
    res.json({
      slots: cleaned,
      defaultPhone: config.defaultPhone || '',
      defaultTeamName: config.defaultTeamName || '',
      maxSlots: USER_LINES_MAX_SLOTS
    });
  } catch (error) {
    console.error('Error obteniendo user-lines:', error);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

app.put('/api/admin/user-lines', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    if (req.user.role !== 'admin') {
      return res.status(403).json({ error: 'Solo el admin principal puede modificar las líneas.' });
    }
    const { slots, defaultPhone, defaultTeamName } = req.body || {};
    if (!Array.isArray(slots)) {
      return res.status(400).json({ error: 'slots debe ser un array' });
    }
    if (slots.length > USER_LINES_MAX_SLOTS) {
      return res.status(400).json({ error: `Máximo ${USER_LINES_MAX_SLOTS} slots` });
    }
    const cleaned = [];
    for (const s of slots) {
      const prefix = (s && s.prefix ? String(s.prefix) : '').trim();
      const phone = (s && s.phone ? String(s.phone) : '').trim();
      const teamName = (s && s.teamName ? String(s.teamName) : '').trim();
      if (!prefix && !phone && !teamName) continue;
      if (prefix && !phone) {
        return res.status(400).json({ error: `El prefijo "${prefix}" no tiene número` });
      }
      // teamName es opcional (no es obligatorio aunque haya prefijo).
      // Cap visual razonable para que no rompa el layout del header del user.
      if (teamName.length > 24) {
        return res.status(400).json({ error: `El nombre de equipo "${teamName.slice(0,30)}…" es demasiado largo (máx 24)` });
      }
      cleaned.push({ prefix, phone, teamName });
    }
    const newDefaultPhone = (defaultPhone ? String(defaultPhone) : '').trim();
    const newDefaultTeamName = (defaultTeamName ? String(defaultTeamName) : '').trim();
    if (newDefaultTeamName.length > 24) {
      return res.status(400).json({ error: 'El nombre de equipo por defecto es demasiado largo (máx 24)' });
    }

    const value = {
      slots: cleaned,
      defaultPhone: newDefaultPhone,
      defaultTeamName: newDefaultTeamName
    };
    await setConfig('userLinesByPrefix', value);
    res.json({ success: true, message: 'Líneas actualizadas', value });
    // Auto-notificación al cambiar línea desactivada por requerimiento del cliente.
    // El usuario igualmente verá el banner rojo de "cambio de línea" cuando entre
    // a la app (la detección es del lado del frontend comparando el último número
    // visto en localStorage contra el actual).
  } catch (error) {
    console.error('Error actualizando user-lines:', error);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// ============================================
// IMPORT DE LÍNEAS DESDE DRIVE / .XLSX
// Permite asignar masivamente usuarios a líneas específicas subiendo un .xlsx
// exportado desde Google Sheets. Cada hoja del archivo representa una línea:
//   - Nombre de la hoja = teléfono de esa línea (ej: "+5491111...")
//   - Primera fila (header "name") se ignora
//   - Filas restantes = usernames que pertenecen a esa línea
// El parámetro `teamName` (query string) se aplica a todas las hojas del archivo.
// `dryRun=true` (default) no escribe nada — solo devuelve un reporte para preview.
// ============================================
const USER_LINES_IMPORT_LIMIT = '15mb'; // ~15 hojas × 3000 filas, holgado.

app.post(
  '/api/admin/user-lines/import',
  authMiddleware,
  adminMiddleware,
  express.raw({ limit: USER_LINES_IMPORT_LIMIT, type: '*/*' }),
  async (req, res) => {
    // Lazy require — si xlsx no está instalado, devolvemos error claro
    // (admin debe correr `npm install` después del deploy con este feature).
    let XLSX;
    try {
      XLSX = require('xlsx');
    } catch (e) {
      return res.status(503).json({
        error: 'Falta instalar la dependencia "xlsx" en el servidor. Ejecutá: npm install xlsx'
      });
    }

    try {
      const teamName = (req.query.teamName ? String(req.query.teamName) : '').trim();
      if (!teamName) {
        return res.status(400).json({ error: 'Falta el parámetro teamName (nombre del equipo)' });
      }
      if (teamName.length > 24) {
        return res.status(400).json({ error: 'El nombre del equipo es demasiado largo (máx 24)' });
      }

      // Prefijo de username del equipo (ej: "ato", "argen", "tiger"). El sistema
      // concatena prefix + valor de celda para reconstruir el username completo
      // antes de matchear contra la DB. Si la celda ya empieza con el prefix,
      // se usa la celda tal cual (modo tolerante).
      const prefix = (req.query.prefix ? String(req.query.prefix) : '').trim().toLowerCase();
      if (!prefix) {
        return res.status(400).json({ error: 'Falta el parámetro prefix (las "iniciales" del equipo, ej: ato, argen, tiger)' });
      }
      if (prefix.length > 20) {
        return res.status(400).json({ error: 'El prefijo es demasiado largo (máx 20)' });
      }

      // Línea explícita (modo "import per-slot"). Si viene, TODAS las hojas
      // del archivo se asignan a este teléfono — los nombres de las hojas se
      // ignoran. Esto permite que el admin suba un .xlsx desde el slot del
      // panel "Números vigentes" y la línea sea la del slot, no parseada de
      // la hoja. Si no viene, se usa el comportamiento legacy (parsear cada
      // sheet name como teléfono).
      const overrideLinePhone = (req.query.linePhone ? String(req.query.linePhone) : '').trim();

      // dryRun por default true. Solo `dryRun=false` ejecuta escrituras.
      const dryRun = String(req.query.dryRun || 'true').toLowerCase() !== 'false';

      const buf = req.body;
      if (!buf || !Buffer.isBuffer(buf) || buf.length < 100) {
        return res.status(400).json({ error: 'Archivo vacío o muy chico' });
      }

      let workbook;
      try {
        workbook = XLSX.read(buf, { type: 'buffer', cellDates: false });
      } catch (parseErr) {
        return res.status(400).json({ error: `No se pudo leer el .xlsx: ${parseErr.message}` });
      }

      if (!workbook.SheetNames || workbook.SheetNames.length === 0) {
        return res.status(400).json({ error: 'El archivo no tiene hojas' });
      }

      // Normaliza un string para matcheo fuzzy: quita tildes/diacríticos,
      // pasa a minúscula, y elimina todo lo que no sea letra/dígito.
      // Permite que "Argen.Pedro_98", "argenpedro98", "ARGEN PEDRO 98" y
      // "argén.Pedro 98" matcheen contra el mismo username "argenpedro98".
      const _normalizeUsername = (raw) => {
        if (!raw) return '';
        return String(raw)
          .normalize('NFD').replace(/[̀-ͯ]/g, '') // strip diacríticos
          .toLowerCase()
          .replace(/[^a-z0-9]/g, '');
      };

      // Extrae el teléfono del nombre de la hoja. El nombre puede venir como
      // un teléfono puro (ej: "+5491111...") o como "ETIQUETA + número" (ej:
      // "TIGER 1 39095913748", "Atomic 2 +5493853..."). Devolvemos siempre
      // un string que arranque con '+' y tenga solo dígitos (formato canónico
      // para WhatsApp links). Si no se puede extraer, devuelve el sheetName
      // sin cambios como fallback (legacy).
      const _extractPhoneFromSheetName = (raw) => {
        const trimmed = String(raw || '').trim();
        if (!trimmed) return '';
        // Buscar la última secuencia de 7+ dígitos (con + opcional al inicio)
        // al final del string. \d{7,} cubre cualquier teléfono internacional.
        const m = trimmed.match(/(\+?\d[\d\s\-]{6,})\s*$/);
        if (m) {
          // Limpiar todo lo que no sea dígito y reagregar el +
          const digits = m[1].replace(/[^\d]/g, '');
          if (digits.length >= 7) return '+' + digits;
        }
        return trimmed;
      };

      // -------- Pase 1: extraer (sheetName -> [usernames normalizados]) y detectar
      // conflictos dentro del mismo archivo (mismo username en dos hojas distintas).
      // Los usernames se normalizan AGRESIVAMENTE (sin tildes, sin puntuación)
      // para tolerar variaciones de formato entre el .xlsx y la DB.
      const prefixNorm = _normalizeUsername(prefix);
      const sheetData = []; // [{ sheetName, linePhone, usernamesNorm: [], originalByNorm: Map }]
      const seenNormToSheet = new Map(); // norm -> first sheetName que lo trajo
      const conflictsInFile = []; // [{ username, sheets: [a, b] }]
      const allUsernamesNorm = new Set();

      for (const sheetName of workbook.SheetNames) {
        const sheetTrimmed = String(sheetName || '').trim();
        if (!sheetTrimmed) continue;
        // Si vino linePhone explícito (modo per-slot), todas las hojas usan ese.
        // Si no, parseamos el nombre de la hoja (modo legacy multi-line file).
        const linePhone = overrideLinePhone || _extractPhoneFromSheetName(sheetTrimmed);
        if (!linePhone) continue;

        const ws = workbook.Sheets[sheetName];
        if (!ws) continue;

        // header:1 → array de arrays. blankrows:false → omite filas vacías.
        const rows = XLSX.utils.sheet_to_json(ws, { header: 1, blankrows: false, defval: '' });

        // Saltar la primera fila (header "name"). Si el sheet está vacío o solo
        // tiene header, queda como hoja sin matches (no error — se reporta).
        const dataRows = rows.length > 1 ? rows.slice(1) : [];

        const usernamesNorm = [];
        const originalByNorm = new Map(); // para mostrar el valor original en notFoundSample
        for (const row of dataRows) {
          if (!row) continue;
          const raw = row[0];
          if (raw === null || raw === undefined) continue;
          const cleaned = String(raw).trim();
          if (!cleaned) continue;
          const cellNorm = _normalizeUsername(cleaned);
          if (!cellNorm) continue; // la celda no tenía letras/dígitos

          // Reconstruir el username normalizado completo:
          //   - Si la celda normalizada ya empieza con el prefijo (norm), se usa tal cual.
          //   - Si no, le concatenamos el prefijo (la celda es solo el sufijo).
          // Ejemplo: prefix='ato', celda='joaquin398' → 'atojoaquin398'.
          //          prefix='ato', celda='Ato.Joaquín_398' → 'atojoaquin398'.
          const fullNorm = cellNorm.startsWith(prefixNorm) ? cellNorm : (prefixNorm + cellNorm);

          // Detectar conflicto entre hojas del mismo upload.
          // En modo per-slot (overrideLinePhone), todas las hojas asignan al mismo
          // teléfono — los duplicados no son conflictos, simplemente se deduplican.
          if (seenNormToSheet.has(fullNorm) && seenNormToSheet.get(fullNorm) !== sheetName) {
            if (!overrideLinePhone) {
              conflictsInFile.push({
                username: fullNorm,
                sheets: [seenNormToSheet.get(fullNorm), sheetName]
              });
              // El conflicto invalida ambas asignaciones (modo legacy multi-line).
              continue;
            }
            // En modo per-slot, simplemente saltear el duplicado (ya está asignado).
            continue;
          }
          seenNormToSheet.set(fullNorm, sheetName);
          usernamesNorm.push(fullNorm);
          if (!originalByNorm.has(fullNorm)) originalByNorm.set(fullNorm, cleaned);
          allUsernamesNorm.add(fullNorm);
        }

        sheetData.push({ sheetName, linePhone, usernamesNorm, originalByNorm });
      }

      // -------- Pase 2: lookup en DB con regex-prefijo y match en memoria.
      // Cargamos TODOS los users cuyo username arranca con `prefix` (case-insensitive)
      // y construimos un Map<normalizado, doc>. Esto permite que cosas como
      // "argen pedro 98", "Argen.Pedro_98" y "argén.Pedro98" en el .xlsx matcheen
      // contra el username "argenpedro98" de la DB. Es estrictamente más tolerante
      // que $in + collation porque la collation no normaliza puntuación ni tildes.
      const escapeRegexLocal = (s) => String(s).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      const prefixRegex = new RegExp('^' + escapeRegexLocal(prefix), 'i');

      // Safety: si el prefijo matchea > 50k users, abortar (algo está mal en config).
      const candidateCount = await User.countDocuments({ username: { $regex: prefixRegex } });
      if (candidateCount > 50000) {
        return res.status(400).json({
          error: `El prefijo "${prefix}" matchea ${candidateCount} usuarios (>50k). ¿Estás seguro? Achicalo más.`
        });
      }

      const candidateDocs = candidateCount > 0
        ? await User.find({ username: { $regex: prefixRegex } })
            .select('id username linePhone lineTeamName')
            .lean()
        : [];

      const docByNorm = new Map();
      for (const d of candidateDocs) {
        if (d && d.username) docByNorm.set(_normalizeUsername(d.username), d);
      }

      // -------- Pase 3: armar bulkOps y reporte por hoja.
      const bulkOps = [];
      const sheetReports = [];
      let totalMatched = 0;
      let totalNotFound = 0;
      const notFoundSample = []; // sólo guardamos los primeros 100 para no inflar la respuesta

      const now = new Date();
      const adminUsername = (req.user && req.user.username) || null;

      // Tracking global de las asignaciones para evitar duplicar bulkOps cuando
      // un mismo doc matchea varias celdas (en contains matching es común).
      const docAssignmentBySheet = new Map(); // docId → sheetName que lo reclamó

      for (const sd of sheetData) {
        let sheetMatched = 0;
        let sheetNotFound = 0;
        let sheetReassigned = 0; // ya tenían linePhone distinto → se sobreescribe

        for (const fullNorm of sd.usernamesNorm) {
          // CONTAINS matching bidireccional: matchea un User si:
          //   a) el username (normalizado) contiene la celda normalizada, O
          //   b) la celda normalizada contiene el username normalizado.
          // Esto permite que celdas con el username completo+anotaciones
          // ("argenpedro (líder)" → "argenpedrolider") matcheen contra
          // "argenpedro", y al revés que celdas con fragmentos cortos
          // ("pedro") matcheen contra "argenpedro".
          const matchedDocs = [];
          for (const [dbNorm, doc] of docByNorm) {
            if (!dbNorm) continue;
            if (dbNorm.includes(fullNorm) || fullNorm.includes(dbNorm)) {
              matchedDocs.push(doc);
            }
          }

          if (matchedDocs.length === 0) {
            sheetNotFound++;
            totalNotFound++;
            if (notFoundSample.length < 100) {
              const original = sd.originalByNorm.get(fullNorm) || fullNorm;
              notFoundSample.push({
                username: original,
                normalized: fullNorm,
                sheet: sd.sheetName
              });
            }
            continue;
          }

          sheetMatched++;
          totalMatched++;

          for (const doc of matchedDocs) {
            // En modo legacy multi-line: si este doc ya fue reclamado por otra
            // hoja, NO lo re-asignamos (preservamos el primero — comportamiento
            // determinista). En modo per-slot todas las hojas van al mismo
            // teléfono, no hay conflicto.
            if (!overrideLinePhone) {
              const prevSheet = docAssignmentBySheet.get(doc.id);
              if (prevSheet && prevSheet !== sd.sheetName) continue;
            }
            docAssignmentBySheet.set(doc.id, sd.sheetName);

            if (doc.linePhone && doc.linePhone !== sd.linePhone) {
              sheetReassigned++;
            }
            if (!dryRun) {
              bulkOps.push({
                updateOne: {
                  filter: { id: doc.id },
                  update: {
                    $set: {
                      linePhone: sd.linePhone,
                      lineTeamName: teamName,
                      lineAssignedAt: now,
                      lineAssignedBy: adminUsername
                    }
                  }
                }
              });
            }
          }
        }

        sheetReports.push({
          sheetName: sd.sheetName,
          linePhone: sd.linePhone,
          totalRows: sd.usernamesNorm.length,
          matched: sheetMatched,
          notFound: sheetNotFound,
          reassigned: sheetReassigned
        });
      }

      // -------- Escritura (solo si dryRun=false)
      // Dos bulkWrites en paralelo:
      //   1) User: asigna linePhone/lineTeamName a los usuarios YA existentes.
      //   2) UserLineLookup: persiste TODAS las celdas del .xlsx (matched o no)
      //      para que si después se crea un usuario nuevo (vía JUGAYGANA en
      //      su primer login) también se le asigne automáticamente la línea
      //      del archivo.
      let writeResult = null;
      let lookupResult = null;
      if (!dryRun) {
        const lookupOps = [];
        for (const sd of sheetData) {
          for (const fullNorm of sd.usernamesNorm) {
            lookupOps.push({
              updateOne: {
                filter: { usernameNorm: fullNorm },
                update: {
                  $set: {
                    usernameOriginal: sd.originalByNorm.get(fullNorm) || null,
                    linePhone: sd.linePhone,
                    lineTeamName: teamName,
                    prefix,
                    importedAt: now,
                    importedBy: adminUsername
                  },
                  $setOnInsert: { usernameNorm: fullNorm }
                },
                upsert: true
              }
            });
          }
        }

        const writePromises = [];
        if (bulkOps.length > 0) {
          writePromises.push(
            User.bulkWrite(bulkOps, { ordered: false }).then(r => {
              writeResult = { modifiedCount: r.modifiedCount || 0, matchedCount: r.matchedCount || 0 };
            })
          );
        }
        if (lookupOps.length > 0) {
          writePromises.push(
            UserLineLookup.bulkWrite(lookupOps, { ordered: false }).then(r => {
              lookupResult = {
                upsertedCount: r.upsertedCount || 0,
                modifiedCount: r.modifiedCount || 0
              };
            })
          );
        }
        try {
          await Promise.all(writePromises);
        } catch (bulkErr) {
          logger.error(`[user-lines/import] bulkWrite error: ${bulkErr.message}`);
          return res.status(500).json({ error: `Error escribiendo en la DB: ${bulkErr.message}` });
        }
      }

      logger.info(`[user-lines/import] team=${teamName} prefix=${prefix} dryRun=${dryRun} sheets=${sheetReports.length} matched=${totalMatched} notFound=${totalNotFound} conflicts=${conflictsInFile.length} by=${adminUsername}`);

      res.json({
        success: true,
        dryRun,
        teamName,
        prefix,
        summary: {
          totalSheets: sheetReports.length,
          totalRows: totalMatched + totalNotFound,
          matched: totalMatched,
          notFound: totalNotFound,
          conflicts: conflictsInFile.length
        },
        sheets: sheetReports,
        conflicts: conflictsInFile.slice(0, 100),
        notFoundSample,
        writeResult,
        lookupResult
      });
    } catch (error) {
      logger.error(`[user-lines/import] error: ${error.message}\n${error.stack}`);
      res.status(500).json({ error: `Error del servidor: ${error.message}` });
    }
  }
);

// =============================================================
// Import simple: 1 archivo = 1 línea, match EXACTO de username.
// =============================================================
// Pensado para listados que ya tienen el username completo en la primer
// columna (no fragmentos, no abreviaciones). Usa match exacto sobre el
// username normalizado (lowercase + sin acentos + sin puntuación). NO
// concatena prefijos ni hace contains-matching — eso evita los falsos
// positivos que tuvimos antes con archivos grandes.
//
// Inputs (query params):
//   teamName: nombre del equipo (label).
//   lineLabel: etiqueta amigable de la línea (opcional, ej "Principal", "Línea 2").
//   linePhone: teléfono WhatsApp en formato +5491... (canónico, con +).
//   dryRun: 'true' por default (solo cuenta), 'false' ejecuta.
// Body: archivo binario (.xlsx). Se lee la primera columna de la primera
// hoja con datos. Si la primera fila parece header (no contiene letras/dígitos
// pegados o es muy corta tipo "name"), se saltea.
//
// Comportamiento:
//   - Para cada nombre del archivo: busca User con username normalizado igual.
//     Si lo encuentra, le seta linePhone + lineTeamName.
//   - Siempre upsertea en UserLineLookup así si después de la importación
//     se crea un usuario nuevo con ese username (vía login a JUGAYGANA),
//     también recibe la línea automáticamente.
//   - Devuelve un reporte con matched / notFound + sample de los primeros 100
//     no-encontrados para que el admin pueda revisar typos.
app.post(
  '/api/admin/user-lines/import-exact',
  authMiddleware,
  adminMiddleware,
  express.raw({ limit: USER_LINES_IMPORT_LIMIT, type: '*/*' }),
  async (req, res) => {
    let XLSX;
    try {
      XLSX = require('xlsx');
    } catch (e) {
      return res.status(503).json({
        error: 'Falta instalar la dependencia "xlsx" en el servidor. Ejecutá: npm install xlsx'
      });
    }

    try {
      const teamName = (req.query.teamName ? String(req.query.teamName) : '').trim();
      if (!teamName) {
        return res.status(400).json({ error: 'Falta teamName' });
      }
      if (teamName.length > 32) {
        return res.status(400).json({ error: 'teamName demasiado largo (máx 32)' });
      }

      const lineLabel = (req.query.lineLabel ? String(req.query.lineLabel) : '').trim().slice(0, 32);
      // teamName + lineLabel se concatenan para mostrar al usuario "Equipo · Línea".
      const fullTeamLabel = lineLabel ? `${teamName} · ${lineLabel}` : teamName;

      const linePhoneRaw = (req.query.linePhone ? String(req.query.linePhone) : '').trim();
      if (!linePhoneRaw) {
        return res.status(400).json({ error: 'Falta linePhone (número de WhatsApp)' });
      }
      // Canonicalizar: solo dígitos, prefijar con + si no lo trae.
      const digits = linePhoneRaw.replace(/[^\d]/g, '');
      if (digits.length < 7 || digits.length > 18) {
        return res.status(400).json({ error: `linePhone inválido (${digits.length} dígitos)` });
      }
      const linePhone = '+' + digits;

      const dryRun = String(req.query.dryRun || 'true').toLowerCase() !== 'false';

      const buf = req.body;
      if (!buf || !Buffer.isBuffer(buf) || buf.length < 50) {
        return res.status(400).json({ error: 'Archivo vacío o muy chico' });
      }

      let workbook;
      try {
        workbook = XLSX.read(buf, { type: 'buffer', cellDates: false });
      } catch (parseErr) {
        return res.status(400).json({ error: `No se pudo leer el .xlsx: ${parseErr.message}` });
      }
      if (!workbook.SheetNames || workbook.SheetNames.length === 0) {
        return res.status(400).json({ error: 'El archivo no tiene hojas' });
      }

      // Dos normalizaciones distintas:
      //   - normLight: para matchear contra User.username. Solo trim + lowercase,
      //     sin tocar acentos ni puntuación. El username en el archivo tiene
      //     que coincidir EXACTO con el username de JUGAYGANA / login (como
      //     entra el jugador a la plataforma a jugar).
      //   - normHeavy: la misma que usa el login (normalizeUsernameForLookup)
      //     para guardar en UserLineLookup.usernameNorm. Así un usuario nuevo
      //     que se registra después de la importación encuentra su línea
      //     mediante el helper pickLineFromLookup.
      const normLight = (raw) => {
        if (!raw) return '';
        return String(raw).trim().toLowerCase();
      };
      const normHeavy = (raw) => {
        if (!raw) return '';
        return String(raw)
          .normalize('NFD').replace(/[̀-ͯ]/g, '')
          .toLowerCase()
          .replace(/[^a-z0-9]/g, '');
      };

      // Recolectar usernames del archivo (primera columna de la primera hoja
      // con datos). Saltea header si la primera fila parece una etiqueta
      // ("name", "username", "usuario", etc).
      // Estructura: Map<normLight, { original, normHeavy }> — guardamos ambas
      // normalizaciones para usar la light en el match con User (estricto) y
      // la heavy en el upsert a UserLineLookup (consistente con el login).
      const entries = new Map();
      let totalRowsRead = 0;

      for (const sheetName of workbook.SheetNames) {
        const ws = workbook.Sheets[sheetName];
        if (!ws) continue;
        const rows = XLSX.utils.sheet_to_json(ws, { header: 1, blankrows: false, defval: '' });
        if (rows.length === 0) continue;

        // Saltar primera fila si parece header.
        const firstCell = String((rows[0] && rows[0][0]) || '').trim().toLowerCase();
        const isHeader = ['name', 'username', 'usuario', 'nombre', 'user'].includes(firstCell);
        const dataRows = isHeader ? rows.slice(1) : rows;

        for (const row of dataRows) {
          if (!row) continue;
          const raw = row[0];
          if (raw === null || raw === undefined) continue;
          const cleaned = String(raw).trim();
          if (!cleaned) continue;
          totalRowsRead++;
          const lite = normLight(cleaned);
          if (!lite) continue;
          if (!entries.has(lite)) {
            entries.set(lite, { original: cleaned, normHeavy: normHeavy(cleaned) });
          }
        }
        // Solo leemos la primera hoja con datos — el contrato es 1 archivo = 1 línea.
        if (entries.size > 0) break;
      }

      if (entries.size === 0) {
        return res.status(400).json({ error: 'El archivo no tiene usernames legibles en la primera columna' });
      }

      // Lookup en DB: traemos todos los usernames y normalizamos en memoria
      // con la misma función light. Match es 1:1 con la versión lowercased
      // del username — exacto como entra el jugador a JUGAYGANA / login.
      const allUsernames = await User.find(
        { username: { $exists: true, $ne: null } },
        { id: 1, username: 1, linePhone: 1, lineTeamName: 1, _id: 0 }
      ).lean();

      const liteToDoc = new Map();
      for (const d of allUsernames) {
        if (!d || !d.username) continue;
        const lite = normLight(d.username);
        if (lite) liteToDoc.set(lite, d);
      }

      let matched = 0;
      let alreadyOnSameLine = 0;
      let reassignedFromOtherLine = 0;
      const notFoundSample = [];
      const bulkOps = [];
      const lookupOps = [];

      const now = new Date();
      const adminUsername = (req.user && req.user.username) || null;

      for (const [lite, info] of entries) {
        const doc = liteToDoc.get(lite);
        if (!doc) {
          if (notFoundSample.length < 100) {
            notFoundSample.push({
              username: info.original,
              normalized: lite
            });
          }
          continue;
        }
        matched++;
        if (doc.linePhone === linePhone) {
          alreadyOnSameLine++;
        } else if (doc.linePhone) {
          reassignedFromOtherLine++;
        }
        if (!dryRun) {
          bulkOps.push({
            updateOne: {
              filter: { id: doc.id },
              update: {
                $set: {
                  linePhone,
                  lineTeamName: fullTeamLabel,
                  lineAssignedAt: now,
                  lineAssignedBy: adminUsername
                }
              }
            }
          });
        }
      }

      // UserLineLookup: persistimos TODAS las entradas del archivo (matched o
      // no) para que un futuro registro con ese username reciba la línea sin
      // tener que re-importar. Acá usamos normHeavy porque el helper
      // pickLineFromLookup (login) busca con la misma normalización heavy.
      if (!dryRun) {
        for (const [lite, info] of entries) {
          if (!info.normHeavy) continue; // sin caracteres alfanuméricos: no se puede indexar
          lookupOps.push({
            updateOne: {
              filter: { usernameNorm: info.normHeavy },
              update: {
                $set: {
                  usernameOriginal: info.original,
                  linePhone,
                  lineTeamName: fullTeamLabel,
                  prefix: '',
                  importedAt: now,
                  importedBy: adminUsername
                },
                $setOnInsert: { usernameNorm: info.normHeavy }
              },
              upsert: true
            }
          });
        }
      }

      let writeResult = null;
      let lookupResult = null;
      if (!dryRun) {
        try {
          if (bulkOps.length > 0) {
            const r = await User.bulkWrite(bulkOps, { ordered: false });
            writeResult = { modifiedCount: r.modifiedCount || 0, matchedCount: r.matchedCount || 0 };
          }
          if (lookupOps.length > 0) {
            const r2 = await UserLineLookup.bulkWrite(lookupOps, { ordered: false });
            lookupResult = {
              upsertedCount: r2.upsertedCount || 0,
              modifiedCount: r2.modifiedCount || 0
            };
          }
        } catch (bulkErr) {
          logger.error(`[user-lines/import-exact] bulkWrite error: ${bulkErr.message}`);
          return res.status(500).json({ error: `Error escribiendo en la DB: ${bulkErr.message}` });
        }
      }

      logger.info(`[user-lines/import-exact] team="${fullTeamLabel}" phone=${linePhone} dryRun=${dryRun} rows=${totalRowsRead} unique=${entries.size} matched=${matched} notFound=${entries.size - matched} by=${adminUsername}`);

      res.json({
        success: true,
        dryRun,
        teamName: fullTeamLabel,
        linePhone,
        summary: {
          totalRowsRead,
          uniqueUsernames: entries.size,
          matched,
          notFound: entries.size - matched,
          alreadyOnSameLine,
          reassignedFromOtherLine
        },
        notFoundSample,
        writeResult,
        lookupResult
      });
    } catch (error) {
      logger.error(`[user-lines/import-exact] error: ${error.message}\n${error.stack}`);
      res.status(500).json({ error: `Error del servidor: ${error.message}` });
    }
  }
);

// Endpoint para limpiar la asignación de línea de TODOS los usuarios de un team
// (vuelve a usar el matcher por prefijo). Útil si se cargó un Drive equivocado.
// POST /api/admin/user-lines/reassign-orphans
// Backfill: para todos los users SIN linePhone, intenta asignar línea
// por matcheo de prefijo del username. Si el prefijo no matchea ningún
// slot del config 'userLinesByPrefix', cae a la línea general.
//
// dryRun=true (default) → no escribe, solo cuenta. Pasa dryRun=false
// en el body para ejecutar.
//
// Marca cada asignación con lineAssignmentSource='prefix-fallback' o
// 'general-default' según corresponda + lineAssignmentNote con la
// explicación humana ("argen → Argen 1 (+5491...)").
app.post('/api/admin/user-lines/reassign-orphans', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const dryRun = req.body && req.body.dryRun !== false; // default true
    // Modo destructivo (dryRun=false) → solo admin principal.
    if (!dryRun && req.user.role !== 'admin') {
      return res.status(403).json({ error: 'Solo el admin principal puede aplicar reasignación masiva. Para preview, sí podés.' });
    }
    const linesConfig = await getConfig('userLinesByPrefix');
    if (!linesConfig) {
      return res.status(400).json({ error: 'No hay config de líneas (userLinesByPrefix). Configurá primero "Números vigentes".' });
    }

    // Encontrar huérfanos: users con role='user' y sin linePhone.
    // Limit alto pero acotado para evitar OOM en bases enormes.
    const orphans = await User.find(
      {
        role: 'user',
        $or: [{ linePhone: null }, { linePhone: '' }, { linePhone: { $exists: false } }]
      },
      { id: 1, username: 1, _id: 0 }
    ).limit(50000).lean();

    const adminUsername = req.user.username || 'admin';
    const now = new Date();

    // Computar resoluciones primero (sin escribir).
    const plan = []; // [{userId, username, resolved}]
    const breakdown = {
      total: orphans.length,
      matchedPrefix: 0,
      fellToDefault: 0,
      noResolution: 0,
      byTeam: {}
    };
    for (const u of orphans) {
      const r = resolveLineByPrefixFallback(linesConfig, u.username);
      if (!r) {
        breakdown.noResolution++;
        continue;
      }
      if (r.source === 'prefix-fallback') breakdown.matchedPrefix++;
      else if (r.source === 'general-default') breakdown.fellToDefault++;
      const teamKey = r.lineTeamName || '— Sin equipo —';
      breakdown.byTeam[teamKey] = (breakdown.byTeam[teamKey] || 0) + 1;
      plan.push({ userId: u.id, username: u.username, resolved: r });
    }

    if (dryRun) {
      // Devolvemos solo el resumen para que el admin confirme.
      return res.json({
        success: true,
        dryRun: true,
        summary: breakdown,
        sampleAssignments: plan.slice(0, 20).map(p => ({
          username: p.username,
          linePhone: p.resolved.linePhone,
          lineTeamName: p.resolved.lineTeamName,
          source: p.resolved.source,
          note: p.resolved.note
        }))
      });
    }

    // Ejecutar bulkWrite.
    if (plan.length === 0) {
      return res.json({ success: true, dryRun: false, summary: breakdown, applied: 0 });
    }

    const ops = plan.map(p => ({
      updateOne: {
        filter: { id: p.userId },
        update: {
          $set: {
            linePhone: p.resolved.linePhone,
            lineTeamName: p.resolved.lineTeamName,
            lineAssignedAt: now,
            lineAssignedBy: adminUsername + ':reassign-orphans',
            lineAssignmentSource: p.resolved.source,
            lineAssignmentNote: p.resolved.note
          }
        }
      }
    }));

    // bulkWrite en chunks para no estresar Mongo.
    let applied = 0;
    const CHUNK = 500;
    for (let i = 0; i < ops.length; i += CHUNK) {
      const slice = ops.slice(i, i + CHUNK);
      const r = await User.bulkWrite(slice, { ordered: false });
      applied += r.modifiedCount || 0;
    }

    logger.info(`[reassign-orphans] aplicado: ${applied}/${plan.length} (matched=${breakdown.matchedPrefix}, default=${breakdown.fellToDefault}, sin-resolución=${breakdown.noResolution})`);
    res.json({
      success: true,
      dryRun: false,
      summary: breakdown,
      applied
    });
  } catch (err) {
    logger.error(`POST reassign-orphans: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

app.post('/api/admin/user-lines/clear-team', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const { teamName } = req.body || {};
    if (!teamName || typeof teamName !== 'string' || !teamName.trim()) {
      return res.status(400).json({ error: 'Falta teamName' });
    }
    const cleanTeam = teamName.trim();
    const r = await User.updateMany(
      { lineTeamName: cleanTeam },
      { $set: { linePhone: null, lineTeamName: null, lineAssignedAt: null, lineAssignedBy: null } }
    );
    res.json({
      success: true,
      teamName: cleanTeam,
      cleared: r.modifiedCount || 0
    });
  } catch (error) {
    logger.error(`[user-lines/clear-team] error: ${error.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// Stats de asignaciones de línea (para mostrar resumen en el panel admin).
// =============================================================
// Stats por equipo: agrupa lineTeamName por la parte antes del " · "
// y devuelve, para cada equipo, total de usuarios + canal abierto +
// activos en la semana + desglose por línea dentro del equipo.
// =============================================================
app.get('/api/admin/teams/stats', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    // Una sola query trae todo lo necesario para construir el agregado.
    // role='user' para excluir admins. Solo campos requeridos para no
    // saturar memoria en bases grandes.
    const users = await User.find(
      { role: 'user' },
      {
        username: 1,
        lineTeamName: 1,
        linePhone: 1,
        lastLogin: 1,
        fcmTokens: 1,
        fcmTokenContext: 1,
        notifPermission: 1,
        _id: 0
      }
    ).lean();

    const oneWeekAgo = Date.now() - 7 * 24 * 3600 * 1000;
    const teams = new Map(); // teamPrefix -> { totalUsers, withChannel, activeThisWeek, lines: Map }

    let totalWithTeam = 0;
    let totalWithoutTeam = 0;

    for (const u of users) {
      // Calcular si tiene canal abierto. AMBAS condiciones tienen que
      // estar en el MISMO token (igual que APP_NOTIFS_FILTER con $elemMatch).
      const tokens = Array.isArray(u.fcmTokens) ? u.fcmTokens : [];
      const hasApp = u.fcmTokenContext === 'standalone'
        || tokens.some(t => t && t.context === 'standalone');
      const hasNotifs = u.notifPermission === 'granted'
        || tokens.some(t => t && t.notifPermission === 'granted');
      const legacyMatch = u.fcmTokenContext === 'standalone' && u.notifPermission === 'granted';
      const arrayMatch = tokens.some(t => t && t.context === 'standalone' && t.notifPermission === 'granted');
      const hasChannel = legacyMatch || arrayMatch;
      const isActiveThisWeek = u.lastLogin
        && new Date(u.lastLogin).getTime() >= oneWeekAgo;

      const fullLabel = (u.lineTeamName || '').trim();
      if (!fullLabel) {
        totalWithoutTeam++;
        continue;
      }
      totalWithTeam++;

      // Equipo = parte antes del primer " · " (si existe). Si no hay " · ",
      // el label completo ES el equipo (sin sub-línea).
      const sepIdx = fullLabel.indexOf(' · ');
      const teamPrefix = sepIdx >= 0 ? fullLabel.slice(0, sepIdx) : fullLabel;

      let team = teams.get(teamPrefix);
      if (!team) {
        team = {
          teamName: teamPrefix,
          totalUsers: 0,
          withChannel: 0,
          activeThisWeek: 0,
          lines: new Map() // fullLabel -> { fullLabel, linePhone, count, withChannel, activeThisWeek }
        };
        teams.set(teamPrefix, team);
      }
      team.totalUsers++;
      if (hasChannel) team.withChannel++;
      if (isActiveThisWeek) team.activeThisWeek++;

      // Sub-grupo por línea exacta (incluye la etiqueta opcional).
      let line = team.lines.get(fullLabel);
      if (!line) {
        line = {
          fullLabel,
          linePhone: u.linePhone || null,
          count: 0,
          withChannel: 0,
          activeThisWeek: 0
        };
        team.lines.set(fullLabel, line);
      }
      line.count++;
      if (hasChannel) line.withChannel++;
      if (isActiveThisWeek) line.activeThisWeek++;
    }

    // Pre-asignaciones pendientes (UserLineLookup): cuenta por equipo de los
    // usuarios que están en el archivo pero todavía NO se registraron.
    let pendingByTeam = new Map();
    try {
      const pendings = await UserLineLookup.aggregate([
        { $match: { lineTeamName: { $ne: null } } },
        { $group: { _id: '$lineTeamName', count: { $sum: 1 } } }
      ]);
      for (const p of pendings) {
        const fullLabel = String(p._id || '').trim();
        if (!fullLabel) continue;
        const sepIdx = fullLabel.indexOf(' · ');
        const teamPrefix = sepIdx >= 0 ? fullLabel.slice(0, sepIdx) : fullLabel;
        pendingByTeam.set(teamPrefix, (pendingByTeam.get(teamPrefix) || 0) + (p.count || 0));
      }
    } catch (lookupErr) {
      logger.warn(`[teams/stats] lookup agg falló: ${lookupErr.message}`);
    }

    // Convertir Maps a array y sortear.
    const teamsArr = Array.from(teams.values()).map(t => ({
      teamName: t.teamName,
      totalUsers: t.totalUsers,
      withChannel: t.withChannel,
      channelPct: t.totalUsers > 0 ? Math.round((t.withChannel / t.totalUsers) * 100) : 0,
      activeThisWeek: t.activeThisWeek,
      activePct: t.totalUsers > 0 ? Math.round((t.activeThisWeek / t.totalUsers) * 100) : 0,
      pendingPreAssigned: pendingByTeam.get(t.teamName) || 0,
      lines: Array.from(t.lines.values()).sort((a, b) => b.count - a.count)
    })).sort((a, b) => b.totalUsers - a.totalUsers);

    // Equipos que SOLO tienen pre-asignados (nadie registrado todavía):
    // mostrarlos también para que el admin vea que la lista está cargada.
    for (const [teamPrefix, count] of pendingByTeam) {
      if (!teams.has(teamPrefix)) {
        teamsArr.push({
          teamName: teamPrefix,
          totalUsers: 0,
          withChannel: 0,
          channelPct: 0,
          activeThisWeek: 0,
          activePct: 0,
          pendingPreAssigned: count,
          lines: []
        });
      }
    }

    res.json({
      success: true,
      totalUsers: users.length,
      totalWithTeam,
      totalWithoutTeam,
      teams: teamsArr
    });
  } catch (error) {
    logger.error(`/api/admin/teams/stats error: ${error.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

app.get('/api/admin/user-lines/stats', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const pipeline = [
      { $match: { linePhone: { $ne: null, $exists: true } } },
      {
        $group: {
          _id: { teamName: '$lineTeamName', linePhone: '$linePhone' },
          count: { $sum: 1 }
        }
      },
      { $sort: { '_id.teamName': 1, '_id.linePhone': 1 } }
    ];
    const groups = await User.aggregate(pipeline);
    const totalAssigned = groups.reduce((acc, g) => acc + (g.count || 0), 0);
    const totalUsers = await User.countDocuments({});
    res.json({
      totalUsers,
      totalAssigned,
      totalUnassigned: totalUsers - totalAssigned,
      lines: groups.map(g => ({
        teamName: g._id.teamName || '(sin team)',
        linePhone: g._id.linePhone,
        count: g.count
      }))
    });
  } catch (error) {
    logger.error(`[user-lines/stats] error: ${error.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// ============================================
// LINKS DE COMUNIDAD POR USUARIO (mapeo prefijo -> link)
// Mismo patron que user-lines pero para links de WhatsApp/comunidades.
// ============================================
const USER_COMMUNITIES_MAX_SLOTS = 30;

app.get('/api/admin/user-communities', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const config = (await getConfig('userCommunitiesByPrefix')) || {};
    const slots = Array.isArray(config.slots) ? config.slots : [];
    const cleaned = slots
      .filter(s => s && (s.prefix || s.link))
      .map(s => ({ prefix: s.prefix || '', link: s.link || '' }));
    res.json({
      slots: cleaned,
      defaultLink: config.defaultLink || '',
      maxSlots: USER_COMMUNITIES_MAX_SLOTS
    });
  } catch (error) {
    console.error('Error obteniendo user-communities:', error);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

app.put('/api/admin/user-communities', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const { slots, defaultLink } = req.body || {};
    if (!Array.isArray(slots)) {
      return res.status(400).json({ error: 'slots debe ser un array' });
    }
    if (slots.length > USER_COMMUNITIES_MAX_SLOTS) {
      return res.status(400).json({ error: `Máximo ${USER_COMMUNITIES_MAX_SLOTS} slots` });
    }
    const cleaned = [];
    for (const s of slots) {
      const prefix = (s && s.prefix ? String(s.prefix) : '').trim();
      const link = (s && s.link ? String(s.link) : '').trim();
      if (!prefix && !link) continue;
      if (prefix && !link) {
        return res.status(400).json({ error: `El prefijo "${prefix}" no tiene link` });
      }
      // Validacion minima: que sea http(s) o wa.me/chat link
      if (link && !/^https?:\/\//i.test(link)) {
        return res.status(400).json({ error: `El link "${link}" debe empezar con http:// o https://` });
      }
      cleaned.push({ prefix, link });
    }
    const newDefaultLink = (defaultLink ? String(defaultLink) : '').trim();
    if (newDefaultLink && !/^https?:\/\//i.test(newDefaultLink)) {
      return res.status(400).json({ error: 'El link por defecto debe empezar con http:// o https://' });
    }

    const value = {
      slots: cleaned,
      defaultLink: newDefaultLink
    };
    await setConfig('userCommunitiesByPrefix', value);
    res.json({ success: true, message: 'Links de comunidad actualizados', value });
  } catch (error) {
    console.error('Error actualizando user-communities:', error);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// ============================================
// BONO DE BIENVENIDA — $5.000 one-time por usuario (req: 5 cargas en 30d)
// Requisitos client-side: PWA instalada + notificaciones activas. El backend
// NO los puede verificar (son flags del navegador), confia en que el flujo
// del cliente solo dispara la request cuando ambos estan OK. La proteccion
// real contra doble cobro es el indice unique de RefundClaim.
// ============================================
const WELCOME_BONUS_AMOUNT = 5000;

// Caps de seguridad para el money giveaway. Si el admin (o un atacante con
// la cookie) crea un giveaway con cifras absurdas (typo de un 0 de mas, o
// drain malicioso) estos topes lo frenan en el endpoint POST. Si el negocio
// realmente necesita superar estos limites hay que tocar el codigo a
// proposito — un click accidental no puede vaciar JUGAYGANA.
const GIVEAWAY_MAX_AMOUNT_PER_USER = 50000;     // 5x el welcome bonus
const GIVEAWAY_MAX_TOTAL_BUDGET    = 5000000;   // $5M por giveaway
const GIVEAWAY_MAX_CLAIMS          = 1000;      // 1000 personas por giveaway

// Requisito de actividad: para reclamar el welcome bonus el usuario debe
// tener al menos N cargas en los ultimos M dias. Esto reemplaza al chequeo
// por antiguedad de cuenta. Configurable por env.
// Default 0 = sin requisito de cargas (basta con tener cuenta + app
// instalada para reclamar). El owner pidio sacar la friction al regalo
// de instalacion. Si en el futuro se quiere reactivar el anti-fraude
// (ej: pedir 5 cargas en 30 dias antes de poder reclamar), se setea la
// env var WELCOME_BONUS_MIN_DEPOSITS al numero deseado y el codigo de
// _welcomeDepositCheck lo respeta automaticamente.
const WELCOME_BONUS_MIN_DEPOSITS = Math.max(0, parseInt(process.env.WELCOME_BONUS_MIN_DEPOSITS, 10) || 0);
const WELCOME_BONUS_DEPOSIT_WINDOW_DAYS = Math.max(1, parseInt(process.env.WELCOME_BONUS_DEPOSIT_WINDOW_DAYS, 10) || 30);

async function _welcomeDepositCheck(username) {
  // Devuelve { eligible, depositCount, requiredDeposits, windowDays, source }.
  // Cuenta cargas (deposits) reales del usuario en JUGAYGANA durante la
  // ventana, excluyendo bonos que acreditamos nosotros (welcome / refunds /
  // giveaways) — esos llegan como "deposit" en JUGAYGANA por usar
  // creditUserBalance, pero no son cargas del usuario.
  const required = WELCOME_BONUS_MIN_DEPOSITS;
  const windowDays = WELCOME_BONUS_DEPOSIT_WINDOW_DAYS;
  if (required <= 0) {
    return { eligible: true, depositCount: 0, requiredDeposits: 0, windowDays, source: 'disabled' };
  }
  if (!username) {
    return { eligible: false, depositCount: 0, requiredDeposits: required, windowDays, source: 'no_username' };
  }
  try {
    const now = Date.now();
    const startMs = now - windowDays * 24 * 3600 * 1000;
    const startDate = new Date(startMs).toISOString().split('T')[0];
    const endDate = new Date(now + 24 * 3600 * 1000).toISOString().split('T')[0];

    // tx ids de bonos acreditados a este usuario (refunds + giveaways) para
    // descontar del conteo: aparecen como "deposit" en JUGAYGANA.
    const [refundDocs, giveawayDocs] = await Promise.all([
      RefundClaim.find(
        { username, transactionId: { $ne: null } },
        { transactionId: 1, _id: 0 }
      ).lean().catch(() => []),
      MoneyGiveawayClaim.find(
        { username, transactionId: { $ne: null } },
        { transactionId: 1, _id: 0 }
      ).lean().catch(() => [])
    ]);
    const bonusTxIds = new Set();
    for (const d of refundDocs) if (d.transactionId) bonusTxIds.add(String(d.transactionId));
    for (const d of giveawayDocs) if (d.transactionId) bonusTxIds.add(String(d.transactionId));

    const result = await jugayganaMovements.getUserMovements(username, {
      startDate,
      endDate,
      operationType: 'deposit',
      pageSize: 500
    });
    if (!result || !result.success) {
      logger.warn(`[BONUS] welcome — getUserMovements fallo para ${username} err=${result && result.error}`);
      return { eligible: false, depositCount: 0, requiredDeposits: required, windowDays, source: 'movements_failed' };
    }

    let count = 0;
    for (const m of (result.movements || [])) {
      const mid = String(
        m.id || m.Id || m._id ||
        m.transfer_id || m.transferId ||
        m.transactionId || m.TransactionId || ''
      );
      if (mid && bonusTxIds.has(mid)) continue;

      const type = (m.type || m.operation || m.OperationType || m.Type || m.Operation || '').toString().toLowerCase();
      let amt = 0;
      if (m.amount !== undefined) amt = parseFloat(m.amount);
      else if (m.Amount !== undefined) amt = parseFloat(m.Amount);
      else if (m.value !== undefined) amt = parseFloat(m.value);
      else if (m.Value !== undefined) amt = parseFloat(m.Value);
      else if (m.monto !== undefined) amt = parseFloat(m.monto);
      else if (m.Monto !== undefined) amt = parseFloat(m.Monto);

      // Allowlist estricta: SOLO contamos cargas reales del usuario. Tipos
      // como "withdrawal_reversed", "bonus", "promo", "adjustment" tambien
      // tienen amt>0 pero no son cargas — antes los contabamos como tales,
      // permitiendo que ajustes manuales del admin habiliten el bono.
      const isDep = (
        (type.includes('deposit') || type.includes('credit') ||
         type.includes('carga')   || type.includes('recarga')) &&
        amt > 0
      );
      if (!isDep) continue;

      // Sin timestamp parseable -> descartar. Antes se contaban best-effort
      // pero eso permitia que cargas viejas sin fecha se sumen a la ventana.
      const tsRaw = m.created_at || m.createdAt || m.date || m.Date ||
                    m.datetime || m.timestamp || m.time || m.created || null;
      let ts = 0;
      if (tsRaw) {
        const d = new Date(tsRaw);
        ts = isNaN(d.getTime()) ? 0 : d.getTime();
      }
      if (!ts) continue;
      if (ts < startMs) continue;
      count++;
    }

    return {
      eligible: count >= required,
      depositCount: count,
      requiredDeposits: required,
      windowDays,
      source: 'movements'
    };
  } catch (err) {
    logger.error(`[BONUS] welcome — _welcomeDepositCheck error para ${username}: ${err.message}`);
    return { eligible: false, depositCount: 0, requiredDeposits: required, windowDays, source: 'exception' };
  }
}

// =====================================================================
// ENCUESTA DE PREFERENCIA DE NOTIFICACIONES (Fase 1)
// =====================================================================
// El user elige una vez al primer login post-survey. Se persiste en
