app.post('/api/admin/notif-strategy', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const body = req.body || {};
    const prefs = body.preferences || {};
    const monthlyCap = Math.max(0, Number(body.monthlyCap) || 0);
    const monthlyTotalToDistribute = Math.max(0, Number(body.monthlyTotalToDistribute) || 0);
    const bonusType = String(body.bonusType || 'cash').slice(0, 64);
    // Ventana horaria de envío. Default 18-21. Validamos que start < end y
    // ambos en rango [0, 24].
    let windowStartHour = Math.max(0, Math.min(23, parseInt(body.windowStartHour, 10)));
    let windowEndHour   = Math.max(1, Math.min(24, parseInt(body.windowEndHour, 10)));
    if (!Number.isFinite(windowStartHour)) windowStartHour = 18;
    if (!Number.isFinite(windowEndHour))   windowEndHour   = 21;
    if (windowEndHour <= windowStartHour) {
      return res.status(400).json({ error: 'La hora de fin debe ser mayor que la de inicio.' });
    }
    const sanitize = (v, allowFlags) => ({
      bonos: Math.max(0, Number(v && v.bonos) || 0),
      juegos: Math.max(0, Number(v && v.juegos) || 0),
      regalos: Math.max(0, Number(v && v.regalos) || 0),
      budget: Math.max(0, Number(v && v.budget) || 0),
      refundsOnly: allowFlags ? !!(v && v.refundsOnly) : false
    });
    const update = {
      preferences: {
        suave: sanitize(prefs.suave, false),
        normal: sanitize(prefs.normal, false),
        activo: sanitize(prefs.activo, false),
        solo_reembolsos: { ...sanitize(prefs.solo_reembolsos, true), refundsOnly: true }
      },
      monthlyCap,
      monthlyTotalToDistribute,
      bonusType,
      windowStartHour,
      windowEndHour,
      updatedAt: new Date(),
      updatedBy: (req.user && req.user.username) || 'admin'
    };

    const existing = await NotifStrategyConfig.findOne({ key: 'monthly-default' });
    if (!existing) {
      const created = await NotifStrategyConfig.create({
        key: 'monthly-default',
        ...update,
        revisions: [{ at: new Date(), by: update.updatedBy, prefs: update.preferences, monthlyCap: update.monthlyCap }]
      });
      return res.json(created.toObject());
    }

    // Append revision (cap a las ultimas 50 para no inflar el doc).
    existing.preferences = update.preferences;
    existing.monthlyCap = update.monthlyCap;
    existing.monthlyTotalToDistribute = update.monthlyTotalToDistribute;
    existing.bonusType = update.bonusType;
    existing.windowStartHour = update.windowStartHour;
    existing.windowEndHour = update.windowEndHour;
    existing.updatedAt = update.updatedAt;
    existing.updatedBy = update.updatedBy;
    existing.revisions.push({ at: new Date(), by: update.updatedBy, prefs: update.preferences, monthlyCap: update.monthlyCap });
    if (existing.revisions.length > 50) existing.revisions = existing.revisions.slice(-50);
    await existing.save();
    res.json(existing.toObject());
  } catch (err) {
    logger.error(`POST /api/admin/notif-strategy: ${err.message}\n${err.stack}`);
    res.status(500).json({ error: err.message });
  }
});

// Genera una previa NO-PERSISTIDA de como quedaria la distribucion de
// la estrategia con el config actual + lista real de users que
// contestaron la encuesta. NO guarda nada — el admin la mira y despues
// decide si guarda + activa.
//
// Logica de reparto:
//   - El pozo se reparte por tier segun shares fijas (10/40/50/0).
//   - Dentro de cada tier, los users ACTIVOS reciben proporcional a
//     sumLossToHouse (cuanto le dejaron a la casa en 30d).
//   - Los INACTIVOS reciben monto simbolico pero quedan marcados
//     unavailable=true ("no disponible: cliente inactivo").
app.get('/api/admin/notif-strategy/preview', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    let cfg = await NotifStrategyConfig.findOne({ key: 'monthly-default' }).lean();
    if (!cfg) {
      cfg = (await NotifStrategyConfig.create({ key: 'monthly-default' })).toObject();
    }
    const total = Math.max(0, Number(cfg.monthlyTotalToDistribute) || 0);
    const tierShares = { suave: 0.10, normal: 0.40, activo: 0.50, solo_reembolsos: 0 };

    // Traer users que respondieron la encuesta + su PlayerStats para tier
    // y actividad.
    const respondents = await User.find(
      { notifPreference: { $in: ['suave', 'normal', 'activo', 'solo_reembolsos', 'opt_out'] } },
      { username: 1, notifPreference: 1, _id: 0 }
    ).lean();

    const usernamesLc = respondents.map(u => String(u.username || '').toLowerCase());
    const psRows = await PlayerStats.find(
      { username: { $in: usernamesLc } },
      { username: 1, netToHouse30d: 1, realDeposits30d: 1, realChargesCount30d: 1, activityStatus: 1, lastRealDepositDate: 1, _id: 0 }
    ).lean();
    const psByUser = {};
    for (const p of psRows) psByUser[String(p.username || '').toLowerCase()] = p;

    // Agrupar por tier.
    const byTier = { suave: [], normal: [], activo: [], solo_reembolsos: [], opt_out: [] };
    for (const u of respondents) {
      const tier = u.notifPreference;
      if (!byTier[tier]) continue;
      const ps = psByUser[String(u.username || '').toLowerCase()] || {};
      byTier[tier].push({
        username: u.username,
        netToHouse30d: ps.netToHouse30d || 0,
        realDeposits30d: ps.realDeposits30d || 0,
        chargesCount30d: ps.realChargesCount30d || 0,
        activityStatus: ps.activityStatus || 'NUEVO',
        lastRealDepositDate: ps.lastRealDepositDate || null
      });
    }

    // Calcular plan por tier.
    const tierPlans = {};
    for (const tier of ['suave', 'normal', 'activo', 'solo_reembolsos']) {
      const list = byTier[tier] || [];
      const tierBudget = Math.round(total * (tierShares[tier] || 0));
      const active = list.filter(u => ['ACTIVO', 'EN_RIESGO'].includes(u.activityStatus));
      const inactive = list.filter(u => !['ACTIVO', 'EN_RIESGO'].includes(u.activityStatus));

      // Reparto del tierBudget: 80% a activos por proporcion de netToHouse,
      // 20% repartido entre inactivos como monto simbolico (NO DISPONIBLE).
      const activeBudget = Math.round(tierBudget * 0.80);
      const inactiveBudget = tierBudget - activeBudget;

      // Distribucion con multiplicador "top player = 3x" pedido por owner:
      //   - Cada user activo arranca con baseline 1.
      //   - Suma hasta +2 segun su netToHouse normalizado contra el max
      //     del tier (top player = +2 = total 3x; user con 0 perdida = 1x).
      // Esto premia mas plata a quien mas le dejo a la casa, sin dejar
      // a nadie sin recibir nada.
      const maxNet = active.reduce((m, u) => Math.max(m, Math.max(0, u.netToHouse30d || 0)), 0);
      const weights = active.map(u => 1 + (maxNet > 0 ? 2 * (Math.max(0, u.netToHouse30d || 0) / maxNet) : 0));
      const sumWeights = weights.reduce((s, w) => s + w, 0) || 1;
      const activeAlloc = active.map((u, i) => ({
        username: u.username,
        tier,
        activityStatus: u.activityStatus,
        netToHouse30d: u.netToHouse30d,
        chargesCount30d: u.chargesCount30d,
        assignedARS: Math.round(activeBudget * (weights[i] / sumWeights)),
        multiplier: weights[i],
        available: true,
        reason: weights[i] >= 2.5 ? 'Top player · 3× el resto' : 'Cliente activo · proporcional a actividad'
      })).sort((a, b) => b.assignedARS - a.assignedARS);

      const inactivePerUser = inactive.length > 0 ? Math.round(inactiveBudget / inactive.length) : 0;
      const inactiveAlloc = inactive.map(u => ({
        username: u.username,
        tier,
        activityStatus: u.activityStatus,
        netToHouse30d: u.netToHouse30d,
        chargesCount30d: u.chargesCount30d,
        assignedARS: inactivePerUser,
        available: false,
        reason: 'No disponible: cliente inactivo'
      }));

      tierPlans[tier] = {
        userCount: list.length,
        activeCount: active.length,
        inactiveCount: inactive.length,
        tierBudget,
        activeBudget,
        inactiveBudget,
        activeAlloc,
        inactiveAlloc
      };
    }

    // Top 10 globales (los que mas reciben) + inactivos top 5.
    const allActive = [];
    const allInactive = [];
    for (const tier of ['suave', 'normal', 'activo']) {
      allActive.push(...tierPlans[tier].activeAlloc);
      allInactive.push(...tierPlans[tier].inactiveAlloc);
    }
    allActive.sort((a, b) => b.assignedARS - a.assignedARS);
    allInactive.sort((a, b) => b.netToHouse30d - a.netToHouse30d);

    res.json({
      generatedAt: new Date(),
      monthlyTotalToDistribute: total,
      bonusDefaults: {
        bonus50pct: !!cfg.bonus50pctEnabled,
        bonus100pctTimed: {
          enabled: !!cfg.bonus100pctTimedEnabled,
          startHour: cfg.bonus100pctStartHour,
          durationHours: cfg.bonus100pctDurationHours
        },
        bonusType: cfg.bonusType || 'cash'
      },
      tierShares,
      tierPlans,
      topReceivers: allActive.slice(0, 10),
      topInactives: allInactive.slice(0, 10),
      respondedTotal: respondents.length
    });
  } catch (err) {
    logger.error(`/api/admin/notif-strategy/preview: ${err.message}\n${err.stack}`);
    res.status(500).json({ error: err.message });
  }
});

// =====================================================================
// TEST FIRE — dispara todas las notifs a un user cada 1 min para QA
// =====================================================================
// El admin pone un username y un N (default 5) y el server le manda
// 5 pushes seguidas (bono, juga con nosotros, regalo, recordatorio
// reembolso, motivacional) con 1 min de gap entre cada una. Sirve para
// validar que la app las recibe y que el copy/icono renderean bien.
//
// LIMITES:
//  - Maximo 10 notifs por test (10 min total).
//  - 1 test concurrente por user (evita pisarse).
const _TEST_FIRE_RUNNING = new Set();
const _TEST_FIRE_BLUEPRINTS = [
  { kind: 'bono',     title: '🎁 Tenés un bono',         body: 'TEST: Bono 50% al próximo depósito. ¡Aprovechá!' },
  { kind: 'juga',     title: '🎰 Jugá con nosotros',      body: 'TEST: La racha está caliente, vení a tirar unos giros.' },
  { kind: 'regalo',   title: '💸 Regalo activo',          body: 'TEST: Tenemos un regalo de plata para vos. Pasá por la app.' },
  { kind: 'reembolso',title: '💰 Tu reembolso te espera', body: 'TEST: No te olvides — tenés un reembolso disponible.' },
  { kind: 'motivado', title: '⚡ Bonus 100% × 2hs',       body: 'TEST: Solo hoy 19:00–21:00, te duplicamos la carga.' },
  { kind: 'extra',    title: '🏆 Top jugador',            body: 'TEST: Sos top de la semana, premio extra al cargar hoy.' },
  { kind: 'sorteo',   title: '🎫 Sorteo gratis',          body: 'TEST: Tenés un número en el sorteo del lunes. ¡Suerte!' }
];

app.post('/api/admin/notif-strategy/test-fire', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const username = String((req.body && req.body.username) || '').trim();
    if (!username) return res.status(400).json({ error: 'username requerido' });
    const count = Math.min(10, Math.max(1, Number(req.body && req.body.count) || 5));

    if (_TEST_FIRE_RUNNING.has(username.toLowerCase())) {
      return res.status(409).json({ error: 'Ya hay un test corriendo para este user. Esperá ' + count + ' min.' });
    }

    const user = await User.findOne(
      { username: { $regex: new RegExp('^' + username.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '$', 'i') } },
      { username: 1, fcmToken: 1, fcmTokens: 1, _id: 0 }
    ).lean();
    if (!user) return res.status(404).json({ error: 'Usuario no encontrado: ' + username });
    const tokens = [];
    if (user.fcmToken) tokens.push(user.fcmToken);
    if (Array.isArray(user.fcmTokens)) tokens.push(...user.fcmTokens.filter(t => t && !tokens.includes(t)));
    if (tokens.length === 0) {
      return res.status(400).json({ error: 'El usuario no tiene FCM tokens registrados (no instaló la app o no aceptó notifs).' });
    }

    _TEST_FIRE_RUNNING.add(username.toLowerCase());
    const blueprints = _TEST_FIRE_BLUEPRINTS.slice(0, count);
    const startedAt = new Date();
    logger.info(`[TEST-FIRE] iniciado para ${user.username} · ${count} notifs · cada 1 min · token(s)=${tokens.length}`);

    // Disparar cada blueprint a 1 min, 2 min, 3 min... usando setTimeout.
    // Si el server reinicia entre medio, el test se aborta — no hace falta
    // persistir nada porque es solo QA.
    blueprints.forEach((bp, i) => {
      setTimeout(async () => {
        try {
          for (const tok of tokens) {
            await _sendPushToUser(tok, bp.title, bp.body, { test: '1', kind: bp.kind, idx: String(i + 1) });
          }
          logger.info(`[TEST-FIRE] ${user.username} #${i+1}/${count} · ${bp.kind} · "${bp.title}"`);
        } catch (e) {
          logger.warn(`[TEST-FIRE] ${user.username} #${i+1} fallo: ${e.message}`);
        } finally {
          if (i === blueprints.length - 1) _TEST_FIRE_RUNNING.delete(username.toLowerCase());
        }
      }, (i + 1) * 60 * 1000); // 60s, 120s, 180s, ...
    });

    res.json({
      success: true,
      message: 'Test programado: ' + count + ' notifs a ' + user.username + ' cada 1 minuto.',
      username: user.username,
      count,
      startedAt,
      blueprints: blueprints.map((b, i) => ({ idx: i + 1, fireInMin: i + 1, ...b }))
    });
  } catch (err) {
    logger.error(`/api/admin/notif-strategy/test-fire: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// Detalle del calendario de envíos: ventana configurada + lista de
// ScheduledNotifications pendientes generadas por la estrategia + agregado
// por tier, categoría (bonos/juegos/regalos) y por día. El admin lo abre
// cuando activa para ver el detalle.
app.get('/api/admin/notif-strategy/schedule', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const cfg = await NotifStrategyConfig.findOne({ key: 'monthly-default' }).lean();
    const startHour = (cfg && Number.isFinite(cfg.windowStartHour)) ? cfg.windowStartHour : 18;
    const endHour   = (cfg && Number.isFinite(cfg.windowEndHour))   ? cfg.windowEndHour   : 21;

    // Aceptamos AMBOS prefijos: el viejo strategy-wave (auto +100) y el nuevo
    // strategy-month (calendario completo del mes). Así el admin ve todo.
    const pending = await ScheduledNotification.find({
      status: 'pending',
      $or: [
        { createdBy: { $regex: /^strategy-month:/ } },
        { createdBy: { $regex: /^strategy-wave:/ } }
      ]
    })
      .sort({ scheduledFor: 1 })
      .lean();

    const tierCounts = { suave: 0, normal: 0, activo: 0, solo_reembolsos: 0 };
    const categoryCounts = { bonos: 0, juegos: 0, regalos: 0, otros: 0 };
    const byDay = {}; // 'YYYY-MM-DD' → count
    const uniqueUsers = new Set();
    let earliest = null, latest = null;

    const parseTag = (createdBy) => {
      // strategy-month:YYYY-MM:tier:cat:reason   (nuevo)
      // strategy-wave:tier:reason                 (legacy)
      const cb = String(createdBy || '');
      let m = cb.match(/^strategy-month:[^:]+:(\w+):(\w+):(.*)$/);
      if (m) return { tier: m[1], category: m[2], reason: m[3], scope: 'month' };
      m = cb.match(/^strategy-wave:(\w+):(.*)$/);
      if (m) return { tier: m[1], category: 'otros', reason: m[2], scope: 'wave' };
      return { tier: null, category: 'otros', reason: null, scope: null };
    };

    for (const p of pending) {
      const tag = parseTag(p.createdBy);
      if (tag.tier && tierCounts[tag.tier] != null) tierCounts[tag.tier]++;
      if (categoryCounts[tag.category] != null) categoryCounts[tag.category]++;
      else categoryCounts.otros++;
      if (p.targetUsername) uniqueUsers.add(p.targetUsername);
      if (p.scheduledFor) {
        const dt = new Date(p.scheduledFor);
        const ts = dt.getTime();
        if (earliest === null || ts < earliest) earliest = ts;
        if (latest   === null || ts > latest)   latest   = ts;
        const dayKey = dt.getFullYear() + '-' + String(dt.getMonth() + 1).padStart(2, '0') + '-' + String(dt.getDate()).padStart(2, '0');
        byDay[dayKey] = (byDay[dayKey] || 0) + 1;
      }
    }

    const dailyDistribution = Object.keys(byDay).sort().map(d => ({ day: d, count: byDay[d] }));

    const items = pending.slice(0, 200).map(p => {
      const tag = parseTag(p.createdBy);
      return {
        id: p.id,
        scheduledFor: p.scheduledFor,
        targetUsername: p.targetUsername,
        tier: tag.tier,
        category: tag.category,
        scope: tag.scope,
        title: p.title
      };
    });

    res.json({
      window: {
        startHour,
        endHour,
        label: `${String(startHour).padStart(2, '0')}:00 a ${String(endHour).padStart(2, '0')}:00`
      },
      pendingTotal: pending.length,
      uniqueUsers: uniqueUsers.size,
      tierCounts,
      categoryCounts,
      dailyDistribution,
      earliestAt: earliest ? new Date(earliest) : null,
      latestAt:   latest   ? new Date(latest)   : null,
      monthKey: _currentMonthKey(),
      items
    });
  } catch (err) {
    logger.error(`/api/admin/notif-strategy/schedule: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// Cronograma semanal: para los próximos N días (default 7), devuelve día
// por día cuántos pushes salen y a qué público (por tier y por categoría).
// Pensado para que el admin vea "esta semana, lunes mando X bonos a Y users
// del tier normal", "martes Z regalos a W del tier activo", etc.
app.get('/api/admin/notif-strategy/weekly-schedule', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const days = Math.max(1, Math.min(30, parseInt(req.query.days, 10) || 7));
    const cfg = await NotifStrategyConfig.findOne({ key: 'monthly-default' }).lean();
    const startHour = (cfg && Number.isFinite(cfg.windowStartHour)) ? cfg.windowStartHour : 18;
    const endHour   = (cfg && Number.isFinite(cfg.windowEndHour))   ? cfg.windowEndHour   : 21;

    // Día actual (ART) a 00:00.
    const ART_OFFSET_MS = 3 * 60 * 60 * 1000;
    const localNow = new Date(Date.now() - ART_OFFSET_MS);
    const startART = new Date(localNow.getFullYear(), localNow.getMonth(), localNow.getDate(), 0, 0, 0, 0);
    // Reconvertir a UTC sumando el offset.
    const startUTC = new Date(startART.getTime() + ART_OFFSET_MS);
    const endUTC = new Date(startUTC.getTime() + days * 24 * 60 * 60 * 1000);

    const pending = await ScheduledNotification.find({
      status: 'pending',
      scheduledFor: { $gte: startUTC, $lt: endUTC },
      $or: [
        { createdBy: { $regex: /^strategy-month:/ } },
        { createdBy: { $regex: /^strategy-wave:/ } }
      ]
    })
      .sort({ scheduledFor: 1 })
      .lean();

    const parseTag = (createdBy) => {
      const cb = String(createdBy || '');
      let m = cb.match(/^strategy-month:[^:]+:(\w+):(\w+):.*$/);
      if (m) return { tier: m[1], category: m[2] };
      m = cb.match(/^strategy-wave:(\w+):.*$/);
      if (m) return { tier: m[1], category: 'otros' };
      return { tier: null, category: 'otros' };
    };

    // Inicializar buckets por día.
    const buckets = [];
    const dayNames = ['Domingo', 'Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado'];
    for (let i = 0; i < days; i++) {
      const dayDate = new Date(startART.getTime() + i * 24 * 60 * 60 * 1000);
      const key = dayDate.getFullYear() + '-' + String(dayDate.getMonth() + 1).padStart(2, '0') + '-' + String(dayDate.getDate()).padStart(2, '0');
      buckets.push({
        day: key,
        dayName: dayNames[dayDate.getDay()],
        total: 0,
        byTier: { suave: 0, normal: 0, activo: 0, solo_reembolsos: 0 },
        byCategory: { bonos: 0, juegos: 0, regalos: 0, otros: 0 },
        users: new Set(),
        firstAt: null,
        lastAt: null
      });
    }

    // Asignar pushes a su bucket por día (ART).
    for (const p of pending) {
      if (!p.scheduledFor) continue;
      const dt = new Date(p.scheduledFor);
      const localMs = dt.getTime() - ART_OFFSET_MS;
      const ld = new Date(localMs);
      const key = ld.getFullYear() + '-' + String(ld.getMonth() + 1).padStart(2, '0') + '-' + String(ld.getDate()).padStart(2, '0');
      const b = buckets.find(x => x.day === key);
      if (!b) continue;
      const tag = parseTag(p.createdBy);
      b.total++;
      if (tag.tier && b.byTier[tag.tier] != null) b.byTier[tag.tier]++;
      if (b.byCategory[tag.category] != null) b.byCategory[tag.category]++;
      else b.byCategory.otros++;
      if (p.targetUsername) b.users.add(p.targetUsername);
      const ts = dt.getTime();
      if (b.firstAt === null || ts < b.firstAt) b.firstAt = ts;
      if (b.lastAt  === null || ts > b.lastAt)  b.lastAt  = ts;
    }

    // Materializar Sets como counts.
    const result = buckets.map(b => ({
      day: b.day,
      dayName: b.dayName,
      total: b.total,
      uniqueUsers: b.users.size,
      byTier: b.byTier,
      byCategory: b.byCategory,
      firstAt: b.firstAt ? new Date(b.firstAt) : null,
      lastAt:  b.lastAt  ? new Date(b.lastAt)  : null
    }));

    res.json({
      window: {
        startHour,
        endHour,
        label: `${String(startHour).padStart(2, '0')}:00 a ${String(endHour).padStart(2, '0')}:00`
      },
      days: result,
      totalPushes: result.reduce((s, b) => s + b.total, 0),
      totalUniqueUsers: new Set(pending.map(p => p.targetUsername).filter(Boolean)).size
    });
  } catch (err) {
    logger.error(`/api/admin/notif-strategy/weekly-schedule: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// Activa o desactiva la estrategia. Cuando isActive=true:
//   1) Cancela cualquier push programado anterior de la estrategia (idempotencia).
//   2) Genera el calendario mensual COMPLETO para todos los respondentes con
//      tier suave/normal/activo y FCM token: bonos + juegos + regalos
//      repartidos en días distintos del resto del mes, cada uno a hora
//      random dentro de la ventana configurada (default 18-21).
// Cuando isActive=false: cancela todos los pendientes y limpia el flag.
app.post('/api/admin/notif-strategy/activate', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const activate = req.body && req.body.activate !== false; // default true
    const cfg = await NotifStrategyConfig.findOne({ key: 'monthly-default' });
    if (!cfg) return res.status(404).json({ error: 'Estrategia no configurada todavía. Guardá primero.' });
    cfg.isActive = !!activate;
    cfg.activatedAt = activate ? new Date() : null;
    cfg.activatedBy = activate ? ((req.user && req.user.username) || 'admin') : null;
    await cfg.save();

    let cancelled = 0;
    let scheduled = { totalUsers: 0, totalPushes: 0, totalFailed: 0, perTier: {}, perCategory: { bonos: 0, juegos: 0, regalos: 0 } };

    if (activate) {
      // Cancelar pendientes anteriores (re-activate idempotente).
      cancelled = await _cancelPendingStrategyNotifications();

      // Pre-programar el mes completo para todos los respondentes válidos.
      const monthKey = _currentMonthKey();
      const respondents = await User.find(
        { notifPreference: { $in: ['suave', 'normal', 'activo'] } },
        { username: 1, notifPreference: 1, fcmToken: 1, fcmTokens: 1, _id: 0 }
      ).lean();

      const cfgPlain = cfg.toObject();
      for (const u of respondents) {
        const hasToken = !!(u.fcmToken || (Array.isArray(u.fcmTokens) && u.fcmTokens.length > 0));
        if (!hasToken) continue;
        const r = await _scheduleMonthlyStrategyForUser({
          user: u,
          tier: u.notifPreference,
          cfg: cfgPlain,
          monthKey,
          reason: 'activate'
        });
        scheduled.totalUsers++;
        scheduled.totalPushes += r.scheduled;
        scheduled.totalFailed += r.failed;
        scheduled.perCategory.bonos   += r.perCategory.bonos;
        scheduled.perCategory.juegos  += r.perCategory.juegos;
        scheduled.perCategory.regalos += r.perCategory.regalos;
        const tk = u.notifPreference;
        if (!scheduled.perTier[tk]) scheduled.perTier[tk] = { users: 0, pushes: 0 };
        scheduled.perTier[tk].users++;
        scheduled.perTier[tk].pushes += r.scheduled;
      }

      logger.info(`[NOTIF-STRATEGY] ACTIVATED by ${req.user && req.user.username} · cancelled=${cancelled} usersScheduled=${scheduled.totalUsers} pushes=${scheduled.totalPushes} (bonos=${scheduled.perCategory.bonos}, juegos=${scheduled.perCategory.juegos}, regalos=${scheduled.perCategory.regalos})`);
    } else {
      cancelled = await _cancelPendingStrategyNotifications();
      logger.info(`[NOTIF-STRATEGY] DEACTIVATED by ${req.user && req.user.username} · cancelled=${cancelled}`);
    }

    res.json({
      ...cfg.toObject(),
      _activation: {
        activated: !!activate,
        cancelledPending: cancelled,
        scheduled
      }
    });
  } catch (err) {
    logger.error(`POST /api/admin/notif-strategy/activate: ${err.message}\n${err.stack}`);
    res.status(500).json({ error: err.message });
  }
});

// Reporte de reaccion: cruza NotificationHistory contra User.notifPreference
// para ver, por tier, cuantas pushes mandamos en los ultimos 30d, cuantas
// se entregaron y cual fue el engagement (open/click si existe en el doc).
app.get('/api/admin/notif-strategy/reactions', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const days = Math.max(1, Math.min(90, Number(req.query.days) || 30));
    const since = new Date(Date.now() - days * 24 * 3600 * 1000);

    // 1) Map username → notifPreference.
    const users = await User.find({ notifPreference: { $ne: null } }, { username: 1, notifPreference: 1, _id: 0 }).lean();
    const prefByUser = {};
    for (const u of users) prefByUser[String(u.username || '').toLowerCase()] = u.notifPreference;

    // 2) Pushes en la ventana.
    const NotificationHistory = require('./src/models').NotificationHistory;
    const histories = await NotificationHistory.find(
      { createdAt: { $gte: since } },
      { username: 1, status: 1, createdAt: 1, _id: 0 }
    ).lean();

    // 3) Aggregate por tier.
    const buckets = { suave: { sent: 0, delivered: 0, failed: 0 },
                       normal: { sent: 0, delivered: 0, failed: 0 },
                       activo: { sent: 0, delivered: 0, failed: 0 },
                       solo_reembolsos: { sent: 0, delivered: 0, failed: 0 },
                       opt_out: { sent: 0, delivered: 0, failed: 0 },
                       sin_responder: { sent: 0, delivered: 0, failed: 0 } };
    for (const h of histories) {
      const u = String(h.username || '').toLowerCase();
      const tier = prefByUser[u] || 'sin_responder';
      const b = buckets[tier];
      if (!b) continue;
      b.sent++;
      const st = String(h.status || '').toLowerCase();
      if (st.includes('deliver') || st.includes('sent') || st === 'success') b.delivered++;
      else if (st.includes('fail') || st === 'error') b.failed++;
    }

    // 4) Conversiones rough: cargas reales POST-push por tier.
    // Aproximacion: contamos users que tuvieron al menos 1 deposito en el
    // periodo en DailyPlayerStats.
    const usernames = users.map(u => String(u.username || '').toLowerCase());
    const sinceDay = new Date(since); sinceDay.setUTCHours(0, 0, 0, 0);
    const depAgg = await DailyPlayerStats.aggregate([
      { $match: { username: { $in: usernames }, dateUtc: { $gte: sinceDay }, depositCount: { $gt: 0 } } },
      { $group: { _id: '$username', count: { $sum: '$depositCount' }, sum: { $sum: '$depositSum' } } }
    ]);
    const depByUser = {};
    for (const d of depAgg) depByUser[d._id] = d;
    const conversions = { suave: { users: 0, deposits: 0, sum: 0 },
                           normal: { users: 0, deposits: 0, sum: 0 },
                           activo: { users: 0, deposits: 0, sum: 0 },
                           solo_reembolsos: { users: 0, deposits: 0, sum: 0 },
                           opt_out: { users: 0, deposits: 0, sum: 0 } };
    for (const u of users) {
      const pr = u.notifPreference;
      if (!conversions[pr]) continue;
      const d = depByUser[String(u.username || '').toLowerCase()];
      if (d) {
        conversions[pr].users++;
        conversions[pr].deposits += d.count || 0;
        conversions[pr].sum += d.sum || 0;
      }
    }

    res.json({ days, since, buckets, conversions, totalUsers: users.length });
  } catch (err) {
    logger.error(`/api/admin/notif-strategy/reactions: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// =====================================================================
// REGALAR BONO DESDE ENCUESTA (per-user grant)
// =====================================================================
// El admin, mirando la lista de respuestas de la encuesta, le regala a un
// usuario un bono individual. Tres tipos:
//   - 'cod50'  → promo-alert per-user con código COD50  (50% en cargas)
//   - 'cod100' → promo-alert per-user con código COD100 (100% en cargas)
//   - 'cash'   → MoneyGiveaway con audienceWhitelist=[user] y monto fijo
// La PWA ya sabe pintar ambos:
//   - applyPromoAlertIfActive() reemplaza el botón QUIERO CARGAR por la
//     CTA del promo (con el código y el wa.link pre-cargado).
//   - renderGiveawayCard() pinta la card RECLAMAR con el monto cash.
// =====================================================================
app.post('/api/admin/encuesta/grant-bonus', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    if (req.user.role !== 'admin') {
      return res.status(403).json({ error: 'Solo el admin principal puede regalar bonos.' });
    }
    const { username, type, amount, durationHours } = req.body || {};
    const u = String(username || '').trim().toLowerCase();
    const t = String(type || '').trim().toLowerCase();
    const amt = Number(amount);
    const hrs = Number(durationHours) > 0 ? Math.min(168, Number(durationHours)) : 24;
    if (!u) return res.status(400).json({ error: 'Username requerido' });
    if (!['cod50', 'cod100', 'cash'].includes(t)) {
      return res.status(400).json({ error: 'Tipo inválido (cod50, cod100, cash)' });
    }
    if (!isFinite(amt) || amt <= 0) {
      return res.status(400).json({ error: 'Monto inválido' });
    }

    // Confirmar que el usuario existe.
    const target = await User.findOne({ username: u }, { id: 1, username: 1, fcmToken: 1, fcmTokens: 1 }).lean();
    if (!target) return res.status(404).json({ error: 'Usuario no encontrado' });

    if (t === 'cash') {
      // Cap de seguridad por user.
      if (amt > GIVEAWAY_MAX_AMOUNT_PER_USER) {
        return res.status(400).json({ error: `Monto excede el tope de seguridad ($${GIVEAWAY_MAX_AMOUNT_PER_USER.toLocaleString('es-AR')})` });
      }
      // Cerrar otros giveaways individuales activos del MISMO user para no
      // acumular varios al mismo tiempo (sería confuso para el user).
      await MoneyGiveaway.updateMany(
        { status: 'active', strategySource: 'individual_grant', audienceWhitelist: u },
        { $set: { status: 'cancelled' } }
      );

      const g = await MoneyGiveaway.create({
        id: uuidv4(),
        amount: amt,
        totalBudget: amt,
        maxClaims: 1,
        expiresAt: new Date(Date.now() + hrs * 3600 * 1000),
        createdBy: req.user.username || null,
        prefix: null,
        notificationHistoryId: null,
        requireZeroBalance: false,
        strategySource: 'individual_grant',
        audienceWhitelist: [u],
        status: 'active'
      });

      // Push para que se entere ya.
      const tokens = [];
      if (target.fcmToken) tokens.push(target.fcmToken);
      if (Array.isArray(target.fcmTokens)) {
        for (const tk of target.fcmTokens) if (tk && !tokens.includes(tk)) tokens.push(tk);
      }
      if (tokens.length > 0) {
        const title = `🎁 Te regalamos $${amt.toLocaleString('es-AR')}`;
        const body = 'Tocá la app para reclamarlo antes de que se venza.';
        Promise.all(tokens.map(tk =>
          _sendPushToUser(tk, title, body, { kind: 'individual_grant_cash', giveawayId: g.id })
            .catch(e => logger.warn(`[GRANT/cash] push fail ${u}: ${e.message}`))
        )).catch(() => {});
      }

      logger.info(`[GRANT] cash $${amt} → ${u} por ${req.user.username} · ${hrs}h`);
      return res.json({ success: true, type: 'cash', amount: amt, giveawayId: g.id, expiresAt: g.expiresAt });
    }

    // Promo-alert per-user (cod50 / cod100). Guardamos en TIER_PROMOS_KEY
    // como una entrada más con audienceWhitelist=[u]. _resolveActivePromoForUser
    // ya itera ese array y devuelve la primera entrada que matchee.
    const codeNorm = t === 'cod50' ? 'COD50' : 'COD100';
    const pct = t === 'cod50' ? 50 : 100;
    const message = `🎁 Cargás $${amt.toLocaleString('es-AR')} y te damos un ${pct}% extra. Pedí el código ${codeNorm}.`;
    const now = new Date();
    const expires = new Date(now.getTime() + hrs * 3600 * 1000);
    const promo = {
      id: uuidv4(),
      message,
      code: codeNorm,
      expiresAt: expires.toISOString(),
      createdAt: now.toISOString(),
      createdBy: req.user.username || null,
      prefix: null,
      audienceWhitelist: [u],
      kind: 'individual_grant',
      grantAmount: amt,
      grantPct: pct,
      notificationHistoryId: null
    };
    const arr = (await getConfig(TIER_PROMOS_KEY, [])) || [];
    // Limpiar expirados y otros grants individuales del mismo user antes
    // de pushear el nuevo (un user solo tiene un bono individual activo
    // a la vez — pisamos el anterior).
    const nowMs = Date.now();
    const cleaned = arr.filter(p => {
      if (!p || !p.expiresAt) return false;
      const exp = new Date(p.expiresAt).getTime();
      if (!isFinite(exp) || exp <= nowMs) return false;
      const isSameUserGrant = p.kind === 'individual_grant'
        && Array.isArray(p.audienceWhitelist)
        && p.audienceWhitelist.some(x => String(x).toLowerCase() === u);
      return !isSameUserGrant;
    });
    cleaned.push(promo);
    await setConfig(TIER_PROMOS_KEY, cleaned);

    // Push para que el user vuelva ya.
    const tokens = [];
    if (target.fcmToken) tokens.push(target.fcmToken);
    if (Array.isArray(target.fcmTokens)) {
      for (const tk of target.fcmTokens) if (tk && !tokens.includes(tk)) tokens.push(tk);
    }
    if (tokens.length > 0) {
      const title = `🎁 Bono ${pct}% activo`;
      const body = `Cargá $${amt.toLocaleString('es-AR')} y te damos ${pct}% más. Tocá para usarlo.`;
      Promise.all(tokens.map(tk =>
        _sendPushToUser(tk, title, body, { kind: 'individual_grant_promo', code: codeNorm })
          .catch(e => logger.warn(`[GRANT/promo] push fail ${u}: ${e.message}`))
      )).catch(() => {});
    }

    logger.info(`[GRANT] ${codeNorm} $${amt} → ${u} por ${req.user.username} · ${hrs}h`);
    res.json({ success: true, type: t, amount: amt, code: codeNorm, expiresAt: promo.expiresAt });
  } catch (err) {
    logger.error(`/api/admin/encuesta/grant-bonus: ${err.message}\n${err.stack}`);
    res.status(500).json({ error: err.message || 'Error del servidor' });
  }
});

// =====================================================================
// TIMELINE — gente que se va uniendo a la encuesta (orden desc).
// =====================================================================
app.get('/api/admin/encuesta/timeline', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const limit = Math.max(1, Math.min(500, parseInt(req.query.limit, 10) || 500));
    const respondents = await User.find(
      { notifPreference: { $exists: true, $ne: null } },
      { username: 1, notifPreference: 1, notifPreferenceAt: 1, team: 1, fcmToken: 1, fcmTokens: 1, _id: 0 }
    )
      .sort({ notifPreferenceAt: -1 })
      .limit(limit)
      .lean();

    // Enrich con PlayerStats (lookup batch por username) — así la tabla
    // muestra $ neto 30d para los que tienen stats sin tener que pedir un
    // segundo endpoint. Los users que NUNCA cargaron quedan con netToHouse30d=0.
    const usernames = respondents.map(u => (u.username || '').toLowerCase());
    const stats = usernames.length > 0
      ? await PlayerStats.find(
          { username: { $in: usernames } },
          { username: 1, netToHouse30d: 1, realDeposits30d: 1, realChargesCount30d: 1, activityStatus: 1, _id: 0 }
        ).lean()
      : [];
    const statsByUser = new Map(stats.map(s => [s.username.toLowerCase(), s]));

    const items = respondents.map(u => {
      const s = statsByUser.get((u.username || '').toLowerCase()) || {};
      return {
        username: u.username,
        preference: u.notifPreference,
        notifPreference: u.notifPreference,
        answeredAt: u.notifPreferenceAt,
        notifPreferenceAt: u.notifPreferenceAt,
        team: u.team || null,
        hasApp: !!(u.fcmToken || (Array.isArray(u.fcmTokens) && u.fcmTokens.length > 0)),
        netToHouse30d: s.netToHouse30d || 0,
        realDeposits30d: s.realDeposits30d || 0,
        activityStatus: s.activityStatus || null
      };
    });

    const totalRespCount = await User.countDocuments({ notifPreference: { $exists: true, $ne: null } });
    const cfg = await NotifStrategyConfig.findOne({ key: 'monthly-default' }).lean();
    const threshold = (cfg && cfg.autoRepeatThreshold) || 100;
    const lastFired = (cfg && cfg.lastAutoFiredAtRespCount) || 0;
    const nextThreshold = (Math.floor(totalRespCount / threshold) + 1) * threshold;
    const remainingToNextWave = Math.max(0, nextThreshold - totalRespCount);
    const isActive = !!(cfg && cfg.isActive);
    const unlockedFirstStrategy = totalRespCount >= threshold;

    res.json({
      total: totalRespCount,
      items,
      threshold,
      lastFiredAtRespCount: lastFired,
      autoFireCount: (cfg && cfg.autoFireCount) || 0,
      lastAutoFiredAt: (cfg && cfg.lastAutoFiredAt) || null,
      nextThreshold,
      remainingToNextWave,
      isActive,
      unlockedFirstStrategy
    });
  } catch (err) {
    logger.error(`/api/admin/encuesta/timeline: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// =====================================================================
// HISTORIAL SEMANAL — agrega por semana ISO los KPI clave de la encuesta:
//   - respuestas nuevas (User.notifPreferenceAt en la semana)
//   - pushes enviadas (NotificationHistory.sentAt en la semana)
//   - cargas (RefundClaim type=daily/weekly/monthly o money-giveaway claims)
//   - $ depositado a la casa vs $ regalado
//   - ROI estimado: ($ neto a la casa) / ($ regalado)
// =====================================================================
app.get('/api/admin/encuesta/weekly-history', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const weeks = Math.max(1, Math.min(52, parseInt(req.query.weeks, 10) || 12));
    const now = new Date();
    // Inicio de semana (lunes 00:00 ARG/UTC simple — usamos UTC para no
    // pelear con timezones; el admin lo ve en su huso pero la agregación
    // queda consistente).
    const weekStart = (d) => {
      const x = new Date(d);
      const dow = x.getUTCDay() || 7;
      x.setUTCHours(0, 0, 0, 0);
      x.setUTCDate(x.getUTCDate() - (dow - 1));
      return x;
    };
    const thisWeek = weekStart(now);
    const ranges = [];
    for (let i = 0; i < weeks; i++) {
      const start = new Date(thisWeek);
      start.setUTCDate(start.getUTCDate() - i * 7);
      const end = new Date(start);
      end.setUTCDate(end.getUTCDate() + 7);
      ranges.push({ start, end, label: start.toISOString().slice(0, 10) });
    }
    const oldest = ranges[ranges.length - 1].start;

    const [respondents, pushes, refunds, giveawayClaims] = await Promise.all([
      User.find(
        { notifPreferenceAt: { $gte: oldest } },
        { notifPreference: 1, notifPreferenceAt: 1, _id: 0 }
      ).lean(),
      NotificationHistory.find(
        { sentAt: { $gte: oldest } },
        { sentAt: 1, successCount: 1, failureCount: 1, totalUsers: 1, type: 1, waClicks: 1, _id: 0 }
      ).lean(),
      RefundClaim.find(
        { claimedAt: { $gte: oldest }, status: { $ne: 'pending_credit_failed' } },
        { claimedAt: 1, type: 1, amount: 1, _id: 0 }
      ).lean(),
      MoneyGiveawayClaim.find(
        { claimedAt: { $gte: oldest }, status: 'completed' },
        { claimedAt: 1, amount: 1, _id: 0 }
      ).lean()
    ]);

    const inRange = (d, r) => d && d >= r.start && d < r.end;

    const buckets = ranges.map(r => {
      const newRespByPref = { suave: 0, normal: 0, activo: 0, solo_reembolsos: 0, opt_out: 0 };
      let newResp = 0;
      for (const u of respondents) {
        if (inRange(new Date(u.notifPreferenceAt), r)) {
          newResp++;
          const k = u.notifPreference;
          if (newRespByPref[k] != null) newRespByPref[k]++;
        }
      }
      let pushSent = 0, pushDelivered = 0, waClicks = 0;
      for (const p of pushes) {
        if (inRange(new Date(p.sentAt), r)) {
          pushSent += (p.totalUsers || 0);
          pushDelivered += (p.successCount || 0);
          waClicks += (p.waClicks || 0);
        }
      }
      let refundsGiven = 0, refundsAmount = 0;
      for (const rf of refunds) {
        if (inRange(new Date(rf.claimedAt), r)) {
          refundsGiven++;
          refundsAmount += (rf.amount || 0);
        }
      }
      let giveawayCount = 0, giveawayAmount = 0;
      for (const g of giveawayClaims) {
        if (inRange(new Date(g.claimedAt), r)) {
          giveawayCount++;
          giveawayAmount += (g.amount || 0);
        }
      }
      const totalRegalado = refundsAmount + giveawayAmount;
      return {
        weekStart: r.start.toISOString(),
        weekLabel: r.label,
        newRespondents: newResp,
        newRespByPref,
        pushSent,
        pushDelivered,
        waClicks,
        refundsGiven,
        refundsAmount,
        giveawayCount,
        giveawayAmount,
        totalRegalado
      };
    });

    res.json({ weeks: weeks, buckets });
  } catch (err) {
    logger.error(`/api/admin/encuesta/weekly-history: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// =====================================================================
// REVIEWS — opiniones de usuarios (1 por user, 1-5★, comentario ≤ 100ch).
// Categorización: 1-2★ malo · 3★ regular · 4-5★ bueno.
// =====================================================================
function _maskUsername(u) {
  const s = String(u || '');
  if (!s) return '***';
  // Mostrar el último 20% (mínimo 1, máximo 6 chars), el resto con *.
  const visibleChars = Math.max(1, Math.min(6, Math.ceil(s.length * 0.20)));
  const hiddenChars = s.length - visibleChars;
  return '*'.repeat(hiddenChars) + s.slice(hiddenChars);
}
function _bucketOf(stars) {
  const n = Number(stars) || 0;
  if (n >= 4) return 'bueno';
  if (n === 3) return 'regular';
  return 'malo';
}

// POST /api/reviews — el user crea su review (1 sola vez, no se puede editar).
app.post('/api/reviews', authMiddleware, async (req, res) => {
  try {
    const userId = req.user.userId;
    const username = req.user.username;
    const stars = Math.round(Number((req.body && req.body.stars) || 0));
    const comment = String((req.body && req.body.comment) || '').trim().slice(0, 100);
    // Teléfono opcional — solo dígitos, +, espacios y guiones. Truncado a 25.
    const contactPhone = String((req.body && req.body.contactPhone) || '')
      .trim().replace(/[^\d+\-\s()]/g, '').slice(0, 25);
    if (!isFinite(stars) || stars < 1 || stars > 5) {
      return res.status(400).json({ error: 'Estrellas inválidas (1-5)' });
    }
    // 1 review por user — si ya votó, no permitir más.
    const existing = await Review.findOne({ userId }).lean();
    if (existing) {
      return res.status(409).json({ error: 'Ya enviaste tu opinión. Solo se permite una por usuario.', alreadyReviewed: true });
    }
    const now = new Date();
    let saved;
    try {
      saved = await Review.create({
        id: uuidv4(),
        userId,
        username,
        stars,
        comment,
        contactPhone,
        createdAt: now,
        updatedAt: now
      });
      saved = saved.toObject ? saved.toObject() : saved;
    } catch (e) {
      // Race: otro POST simultáneo creó la review primero (unique index).
      if (e && e.code === 11000) {
        return res.status(409).json({ error: 'Ya enviaste tu opinión.', alreadyReviewed: true });
      }
      throw e;
    }
    res.json({
      success: true,
      review: {
        stars: saved.stars,
        comment: saved.comment || '',
        updatedAt: saved.updatedAt
      }
    });
  } catch (err) {
    logger.error(`POST /api/reviews: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// GET /api/reviews/mine — devuelve la review propia (si existe).
app.get('/api/reviews/mine', authMiddleware, async (req, res) => {
  try {
    const r = await Review.findOne({ userId: req.user.userId }).lean();
    if (!r) return res.json({ review: null });
    res.json({
      review: {
        stars: r.stars,
        comment: r.comment || '',
        updatedAt: r.updatedAt
      }
    });
  } catch (err) {
    logger.error(`GET /api/reviews/mine: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// GET /api/reviews/feed — feed público (los usernames vienen enmascarados).
// Devuelve también el promedio + cantidad por bucket.
app.get('/api/reviews/feed', authMiddleware, async (req, res) => {
  try {
    const limit = Math.max(1, Math.min(100, parseInt(req.query.limit, 10) || 30));
    const all = await Review.find({}, { stars: 1, comment: 1, username: 1, updatedAt: 1, _id: 0 })
      .sort({ updatedAt: -1 })
      .limit(500)
      .lean();
    const total = all.length;
    const sumStars = all.reduce((acc, r) => acc + (r.stars || 0), 0);
    const avgStars = total > 0 ? (sumStars / total) : 0;
    const counts = { bueno: 0, regular: 0, malo: 0 };
    for (const r of all) counts[_bucketOf(r.stars)]++;
    const list = all.slice(0, limit).map(r => ({
      stars: r.stars,
      comment: r.comment || '',
      maskedUsername: _maskUsername(r.username),
      updatedAt: r.updatedAt
    }));
    res.json({ total, avgStars, counts, items: list });
  } catch (err) {
    logger.error(`GET /api/reviews/feed: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// GET /api/admin/reviews — lista admin con username completo + filtro.
app.get('/api/admin/reviews', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const bucket = String(req.query.bucket || 'all').toLowerCase();
    const limit = Math.max(1, Math.min(500, parseInt(req.query.limit, 10) || 200));
    const filter = {};
    if (bucket === 'bueno')         filter.stars = { $gte: 4 };
    else if (bucket === 'regular')  filter.stars = 3;
    else if (bucket === 'malo')     filter.stars = { $lte: 2 };

    const all = await Review.find({}, { stars: 1, _id: 0 }).lean();
    const total = all.length;
    const sumStars = all.reduce((acc, r) => acc + (r.stars || 0), 0);
    const avgStars = total > 0 ? (sumStars / total) : 0;
    const counts = { bueno: 0, regular: 0, malo: 0 };
    for (const r of all) counts[_bucketOf(r.stars)]++;

    const items = await Review.find(filter)
      .sort({ updatedAt: -1 })
      .limit(limit)
      .lean();

    res.json({
      total,
      avgStars,
      counts,
      items: items.map(r => ({
        id: r.id,
        username: r.username,
        stars: r.stars,
        comment: r.comment || '',
        contactPhone: r.contactPhone || '',
        bucket: _bucketOf(r.stars),
        createdAt: r.createdAt,
        updatedAt: r.updatedAt
      }))
    });
  } catch (err) {
    logger.error(`GET /api/admin/reviews: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// DELETE /api/admin/reviews/:id — borra una opinión (admin only). El user
// dueño queda libre para volver a opinar (no recreamos el constraint).
app.delete('/api/admin/reviews/:id', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const id = String(req.params.id || '').trim();
    if (!id) return res.status(400).json({ error: 'id requerido' });
    const removed = await Review.findOneAndDelete({ id }).lean();
    if (!removed) return res.status(404).json({ error: 'Opinión no encontrada' });
    logger.info(`[REVIEW-DELETE] ${removed.username} (${removed.stars}★) borrada por ${req.user.username}`);
    res.json({ success: true });
  } catch (err) {
    logger.error(`DELETE /api/admin/reviews: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// =====================================================================
// WIN-BACK AUTOMÁTICO (estrategia de recuperación)
// Cron horario: si isActive, escanea PlayerStats.lastRealDepositDate y
// dispara push escalonado en 3 tiers según días sin cargar.
// Cada wave reutiliza la infra existente:
//   - Tier 1: solo push (FCM directo)
//   - Tier 2: MoneyGiveaway con audienceWhitelist=[user]
//   - Tier 3: promo-alert per-user con código COD<pct>
// Se graba 1 fila en RecoveryPush por cada send (sentBy='cron-winback').
// El outcome resolver existente (en _refreshPendingRecoveryOutcomes) ya
// se encarga de marcar recovered/opportunist/no_response sin tocar nada.
// =====================================================================
let _WINBACK_TICK_RUNNING = false;

function _winbackTierForDays(days, cfg) {
  if (days >= cfg.tier4Days) return 4;        // cooldown
  if (days >= cfg.tier3Days) return 3;
  if (days >= cfg.tier2Days) return 2;
  if (days >= cfg.tier1Days) return 1;
  return 0;
}

async function _fireWinbackForUser(user, tier, cfg, opts = {}) {
  const username = (user.username || '').toLowerCase();
  const userId = user.id || user.userId;
  if (!username || !userId) return { fired: false, reason: 'no-user-id' };

  const tokens = [];
  if (user.fcmToken) tokens.push(user.fcmToken);
  if (Array.isArray(user.fcmTokens)) {
    for (const t of user.fcmTokens) if (t && !tokens.includes(t)) tokens.push(t);
  }
  if (tokens.length === 0) return { fired: false, reason: 'no-tokens' };

  const msg = tier === 1 ? cfg.tier1Message
            : tier === 2 ? cfg.tier2Message
            : tier === 3 ? cfg.tier3Message
            : null;
  if (!msg || !msg.title) return { fired: false, reason: 'no-msg' };

  // Setup bono según tier (antes del push para que cuando el user toque
  // ya tenga lo que necesita listo).
  let bonusType = 'none', bonusAmount = 0;
  let promoCode = null, giveawayId = null;
  const now = new Date();
  try {
    if (tier === 2 && cfg.tier2BonusAmount > 0) {
      // Cerrar otros giveaways individuales activos del mismo user.
      await MoneyGiveaway.updateMany(
        { status: 'active', strategySource: 'individual_grant', audienceWhitelist: username },
        { $set: { status: 'cancelled' } }
      );
      const g = await MoneyGiveaway.create({
        id: uuidv4(),
        amount: cfg.tier2BonusAmount,
        totalBudget: cfg.tier2BonusAmount,
        maxClaims: 1,
        expiresAt: new Date(now.getTime() + cfg.tier2DurationHours * 3600 * 1000),
        createdBy: 'cron-winback',
        prefix: null,
        notificationHistoryId: null,
        requireZeroBalance: false,
        strategySource: 'individual_grant',
        audienceWhitelist: [username],
        status: 'active'
      });
      bonusType = 'giveaway';
      bonusAmount = cfg.tier2BonusAmount;
      giveawayId = g.id;
    } else if (tier === 3 && cfg.tier3BonusPct > 0) {
      promoCode = 'COD' + Math.round(cfg.tier3BonusPct);
      const promoMessage = `🎁 Cargás $${cfg.tier3SuggestedAmount.toLocaleString('es-AR')} y te damos un ${cfg.tier3BonusPct}% extra. Pedí el código ${promoCode}.`;
      const promo = {
        id: uuidv4(),
        message: promoMessage,
        code: promoCode,
        expiresAt: new Date(now.getTime() + cfg.tier3DurationHours * 3600 * 1000).toISOString(),
        createdAt: now.toISOString(),
        createdBy: 'cron-winback',
        prefix: null,
        audienceWhitelist: [username],
        kind: 'winback_grant',
        grantAmount: cfg.tier3SuggestedAmount,
        grantPct: cfg.tier3BonusPct,
        notificationHistoryId: null
      };
      const arr = (await getConfig(TIER_PROMOS_KEY, [])) || [];
      const nowMs = Date.now();
      const cleaned = arr.filter(p => {
        if (!p || !p.expiresAt) return false;
        const exp = new Date(p.expiresAt).getTime();
        if (!isFinite(exp) || exp <= nowMs) return false;
        const sameUser = Array.isArray(p.audienceWhitelist)
          && p.audienceWhitelist.some(x => String(x).toLowerCase() === username)
          && (p.kind === 'individual_grant' || p.kind === 'winback_grant');
        return !sameUser;
      });
      cleaned.push(promo);
      await setConfig(TIER_PROMOS_KEY, cleaned);
      bonusType = 'promo';
      bonusAmount = cfg.tier3SuggestedAmount;
    }

    // Push.
    let pushOk = false;
    for (const tok of tokens) {
      try {
        await _sendPushToUser(tok, msg.title, msg.body, {
          kind: 'winback_auto',
          tier: String(tier),
          promoCode: promoCode || '',
          giveawayId: giveawayId || ''
        });
        pushOk = true;
      } catch (e) {
        logger.warn(`[WINBACK] push fail ${username} t${tier}: ${e.message}`);
      }
    }
    if (!pushOk && !opts.dryRun) {
      logger.warn(`[WINBACK] ${username} t${tier} sin push exitoso`);
    }

    // Audit row en RecoveryPush para que el outcome resolver lo levante.
    try {
      await RecoveryPush.create({
        username,
        segmentAtSend: null,
        tierAtSend: null,
        activityStatusAtSend: null,
        bonusAmount,
        bonusType,
        notificationHistoryId: null,
        campaignBatchId: 'winback-auto-' + new Date().toISOString().slice(0, 10),
        sentAt: now,
        sentBy: 'cron-winback'
      });
    } catch (e) {
      logger.warn(`[WINBACK] no se pudo grabar RecoveryPush: ${e.message}`);
    }

    return { fired: true, bonusType, bonusAmount, promoCode, giveawayId };
  } catch (e) {
    logger.warn(`[WINBACK] _fireWinbackForUser ${username} t${tier} error: ${e.message}`);
    return { fired: false, reason: 'error', error: e.message };
  }
}

// Tick del cron — si ya hay uno corriendo, sale. Default OFF.
async function winbackCronTick(opts = {}) {
  if (_WINBACK_TICK_RUNNING) return { skipped: true, reason: 'already-running' };
  _WINBACK_TICK_RUNNING = true;
  const startedAt = new Date();
  try {
    const cfg = await WinbackStrategyConfig.findOne({ key: 'winback-default' });
    if (!cfg) {
      // Crear singleton con defaults la primera vez.
      await WinbackStrategyConfig.create({ key: 'winback-default' });
      return { skipped: true, reason: 'no-config-created' };
    }
    if (!cfg.isActive && !opts.force) {
      return { skipped: true, reason: 'disabled' };
    }

    const now = Date.now();
    const cutoffMin = now - cfg.tier1Days * 86400000;
    const cutoffMax = now - 0;

    // Pull users con stats donde lastRealDepositDate < cutoffMin (≥ tier1).
    // Limit alto pero ordenado por días-más-viejos primero (tier3 antes que tier1).
    const stats = await PlayerStats.find({
      lastRealDepositDate: { $exists: true, $ne: null, $lt: new Date(cutoffMin) }
    }, { username: 1, lastRealDepositDate: 1, isOpportunist: 1, _id: 0 })
      .sort({ lastRealDepositDate: 1 })
      .limit(2000)
      .lean();

    // Pull users matching para conseguir fcm + winbackTier.
    const usernames = stats.map(s => s.username);
    if (usernames.length === 0) {
      cfg.lastCronRunAt = startedAt;
      cfg.lastCronOutcome = { skipped: 'no-users-matched', startedAt };
      await cfg.save();
      return { skipped: true, reason: 'no-users-matched' };
    }
    const users = await User.find(
      { username: { $in: usernames } },
      { id: 1, username: 1, fcmToken: 1, fcmTokens: 1, winbackTier: 1, winbackLastSentAt: 1, notifPreference: 1, _id: 0 }
    ).lean();
    const userByName = new Map(users.map(u => [u.username.toLowerCase(), u]));

    // Caps diarios.
    const todayStart = new Date(); todayStart.setHours(0,0,0,0);
    const sentTodayByTier = await RecoveryPush.aggregate([
      { $match: { sentBy: 'cron-winback', sentAt: { $gte: todayStart } } },
      { $group: { _id: '$bonusType', count: { $sum: 1 } } }
    ]);
    let tier2SentToday = 0, tier3SentToday = 0;
    for (const row of sentTodayByTier) {
      if (row._id === 'giveaway') tier2SentToday = row.count;
      else if (row._id === 'promo') tier3SentToday = row.count;
    }

    const result = { tier1: 0, tier2: 0, tier3: 0, skipped_cap: 0, skipped_recent: 0, skipped_no_user: 0, skipped_no_tokens: 0, skipped_filter: 0, errors: 0 };

    for (const s of stats) {
      const days = Math.floor((now - new Date(s.lastRealDepositDate).getTime()) / 86400000);
      const targetTier = _winbackTierForDays(days, cfg);
      if (targetTier === 0 || targetTier === 4) {
        // 0 = no aplicable, 4 = cooldown (no mandar más).
        if (targetTier === 4) {
          // Marcar tier 4 sin mandar nada para que no escale más.
          await User.updateOne(
            { username: s.username, winbackTier: { $lt: 4 } },
            { $set: { winbackTier: 4, winbackLastSentAt: new Date() } }
          );
        }
        continue;
      }
      const u = userByName.get(s.username.toLowerCase());
      if (!u) { result.skipped_no_user++; continue; }
      // Filtros.
      if (cfg.onlySurveyResponders && !u.notifPreference) { result.skipped_filter++; continue; }
      if (cfg.excludeOpportunists && s.isOpportunist) { result.skipped_filter++; continue; }
      // Idempotencia: solo si tier nuevo > tier actual.
      if ((u.winbackTier || 0) >= targetTier) continue;
      // Anti-spam: 24h mínimo entre mandadas.
      if (u.winbackLastSentAt && (now - new Date(u.winbackLastSentAt).getTime()) < 24 * 3600 * 1000) {
        result.skipped_recent++;
        continue;
      }
      // Daily caps.
      if (targetTier === 2 && tier2SentToday >= cfg.dailyCapTier2) { result.skipped_cap++; continue; }
      if (targetTier === 3 && tier3SentToday >= cfg.dailyCapTier3) { result.skipped_cap++; continue; }

      // Claim atómico: solo escala si seguimos en el tier viejo.
      const claimed = await User.findOneAndUpdate(
        {
          username: s.username,
          $or: [{ winbackTier: { $lt: targetTier } }, { winbackTier: { $exists: false } }]
        },
        { $set: { winbackTier: targetTier, winbackLastSentAt: new Date() } },
        { new: true }
      );
      if (!claimed) continue;

      // Fire.
      const r = await _fireWinbackForUser(u, targetTier, cfg, opts);
      if (r.fired) {
        result['tier' + targetTier]++;
        if (targetTier === 2) tier2SentToday++;
        if (targetTier === 3) tier3SentToday++;
      } else {
        if (r.reason === 'no-tokens') result.skipped_no_tokens++;
        else result.errors++;
      }
    }

    // Stats agregadas.
    cfg.totalSentByTier.tier1 = (cfg.totalSentByTier.tier1 || 0) + result.tier1;
    cfg.totalSentByTier.tier2 = (cfg.totalSentByTier.tier2 || 0) + result.tier2;
    cfg.totalSentByTier.tier3 = (cfg.totalSentByTier.tier3 || 0) + result.tier3;
    cfg.lastCronRunAt = startedAt;
    cfg.lastCronOutcome = { ...result, startedAt, durationMs: Date.now() - startedAt.getTime() };
    await cfg.save();

    logger.info(`[WINBACK] tick · t1=${result.tier1} t2=${result.tier2} t3=${result.tier3} skipped(cap=${result.skipped_cap},recent=${result.skipped_recent},filter=${result.skipped_filter},notok=${result.skipped_no_tokens})`);
    return result;
  } catch (err) {
    logger.error(`[WINBACK] tick error: ${err.message}\n${err.stack}`);
    return { error: err.message };
  } finally {
    _WINBACK_TICK_RUNNING = false;
  }
}

// Cron: cada 60 min (no-op si isActive=false). El primer tick ocurre 5 min
// después del boot del server para no chocar con otros crons del start.
setTimeout(() => {
  winbackCronTick().catch(err => logger.warn(`[WINBACK] first tick: ${err.message}`));
  setInterval(() => {
    winbackCronTick().catch(err => logger.warn(`[WINBACK] tick interval: ${err.message}`));
  }, 60 * 60 * 1000).unref();
}, 5 * 60 * 1000);

// Reset winback tier cuando el user vuelve a cargar — hook en el outcome
// resolver no es necesario porque _refreshPendingRecoveryOutcomes ya lo
// hace por su cuenta. Pero igual vamos a resetear cada 6h como red de
// seguridad: cualquier user con realDepositMade reciente y winbackTier>0
// lo bajamos a 0.
async function _resetWinbackTierForReturners() {
  try {
    const since = new Date(Date.now() - 7 * 86400000);
    const recent = await PlayerStats.find(
      { lastRealDepositDate: { $gte: since } },
      { username: 1, _id: 0 }
    ).lean();
    if (recent.length === 0) return;
    const usernames = recent.map(s => s.username);
    const r = await User.updateMany(
      { username: { $in: usernames }, winbackTier: { $gt: 0 } },
      { $set: { winbackTier: 0, winbackLastSentAt: null } }
    );
    if (r.modifiedCount > 0) {
      logger.info(`[WINBACK] reset tier para ${r.modifiedCount} returners`);
    }
  } catch (e) {
    logger.warn(`[WINBACK] reset returners falló: ${e.message}`);
  }
}
setTimeout(() => {
  _resetWinbackTierForReturners().catch(() => {});
  setInterval(() => _resetWinbackTierForReturners().catch(() => {}), 6 * 3600 * 1000).unref();
}, 8 * 60 * 1000);

// ===== ADMIN ENDPOINTS WIN-BACK =====
app.get('/api/admin/winback', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    let cfg = await WinbackStrategyConfig.findOne({ key: 'winback-default' }).lean();
    if (!cfg) cfg = (await WinbackStrategyConfig.create({ key: 'winback-default' })).toObject();
    res.json(cfg);
  } catch (err) {
    logger.error(`GET /api/admin/winback: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

app.post('/api/admin/winback', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    if (req.user.role !== 'admin') return res.status(403).json({ error: 'Solo el admin principal' });
    const body = req.body || {};
    const $set = { updatedAt: new Date(), updatedBy: req.user.username || 'admin' };
    const allowed = [
      'tier1Days','tier2Days','tier3Days','tier4Days',
      'tier1Message','tier2Message','tier3Message',
      'tier2BonusAmount','tier2DurationHours',
      'tier3BonusPct','tier3SuggestedAmount','tier3DurationHours',
      'onlySurveyResponders','excludeOpportunists',
      'dailyCapTier2','dailyCapTier3'
    ];
    for (const k of allowed) {
      if (body[k] !== undefined) $set[k] = body[k];
    }
    const cfg = await WinbackStrategyConfig.findOneAndUpdate(
      { key: 'winback-default' },
      { $set, $setOnInsert: { key: 'winback-default' } },
      { new: true, upsert: true }
    );
    res.json(cfg.toObject ? cfg.toObject() : cfg);
  } catch (err) {
    logger.error(`POST /api/admin/winback: ${err.message}\n${err.stack}`);
    res.status(500).json({ error: err.message });
  }
});

app.post('/api/admin/winback/activate', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    if (req.user.role !== 'admin') return res.status(403).json({ error: 'Solo el admin principal' });
    const activate = req.body && req.body.activate !== false;
    const cfg = await WinbackStrategyConfig.findOne({ key: 'winback-default' });
    if (!cfg) return res.status(404).json({ error: 'Configurá primero la estrategia' });
    cfg.isActive = !!activate;
    cfg.activatedAt = activate ? new Date() : null;
    cfg.activatedBy = activate ? (req.user.username || 'admin') : null;
    await cfg.save();
    logger.info(`[WINBACK] ${activate ? 'ACTIVATED' : 'DEACTIVATED'} by ${req.user.username}`);
    res.json(cfg.toObject());
  } catch (err) {
    logger.error(`POST /api/admin/winback/activate: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

app.get('/api/admin/winback/preview', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    let cfg = await WinbackStrategyConfig.findOne({ key: 'winback-default' }).lean();
    if (!cfg) cfg = (await WinbackStrategyConfig.create({ key: 'winback-default' })).toObject();

    const now = Date.now();
    const cutoff = new Date(now - cfg.tier1Days * 86400000);
    const stats = await PlayerStats.find({
      lastRealDepositDate: { $exists: true, $ne: null, $lt: cutoff }
    }, { username: 1, lastRealDepositDate: 1, isOpportunist: 1, _id: 0 }).lean();

    const usernames = stats.map(s => s.username);
    const users = usernames.length > 0 ? await User.find(
      { username: { $in: usernames } },
      { username: 1, winbackTier: 1, fcmToken: 1, fcmTokens: 1, notifPreference: 1, _id: 0 }
    ).lean() : [];
    const uMap = new Map(users.map(u => [u.username.toLowerCase(), u]));

    const buckets = { tier1: [], tier2: [], tier3: [], tier4: [], skipped_filter: 0, skipped_already: 0, skipped_no_token: 0 };
    for (const s of stats) {
      const days = Math.floor((now - new Date(s.lastRealDepositDate).getTime()) / 86400000);
      const target = _winbackTierForDays(days, cfg);
      if (target === 0) continue;
      const u = uMap.get(s.username.toLowerCase());
      const hasTokens = u && (u.fcmToken || (Array.isArray(u.fcmTokens) && u.fcmTokens.length > 0));
      if (cfg.onlySurveyResponders && (!u || !u.notifPreference)) { buckets.skipped_filter++; continue; }
      if (cfg.excludeOpportunists && s.isOpportunist) { buckets.skipped_filter++; continue; }
      if (u && (u.winbackTier || 0) >= target) { buckets.skipped_already++; continue; }
      if (target !== 4 && !hasTokens) { buckets.skipped_no_token++; continue; }
      const row = { username: s.username, days, hasTokens: !!hasTokens };
      buckets['tier' + target].push(row);
    }

    res.json({
      cfg,
      counts: {
        tier1: buckets.tier1.length,
        tier2: buckets.tier2.length,
        tier3: buckets.tier3.length,
        tier4: buckets.tier4.length,
        skipped_filter: buckets.skipped_filter,
        skipped_already: buckets.skipped_already,
        skipped_no_token: buckets.skipped_no_token
      },
      // Sample para el panel admin (máx 15 por tier).
      samples: {
        tier1: buckets.tier1.slice(0, 15),
        tier2: buckets.tier2.slice(0, 15),
        tier3: buckets.tier3.slice(0, 15)
      }
    });
  } catch (err) {
    logger.error(`/api/admin/winback/preview: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

app.post('/api/admin/winback/test-fire-once', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    if (req.user.role !== 'admin') return res.status(403).json({ error: 'Solo el admin principal' });
    const r = await winbackCronTick({ force: true });
    res.json({ success: true, result: r });
  } catch (err) {
    logger.error(`/api/admin/winback/test-fire-once: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

app.get('/api/admin/winback/history', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const days = Math.max(1, Math.min(180, parseInt(req.query.days, 10) || 30));
    const since = new Date(Date.now() - days * 86400000);
    const items = await RecoveryPush.find({ sentBy: 'cron-winback', sentAt: { $gte: since } })
      .sort({ sentAt: -1 })
      .limit(500)
      .lean();

    // Por tier (lo deducimos del bonusType + bonusAmount).
    // tier1 = bonusType 'none', tier2 = 'giveaway', tier3 = 'promo'.
    const byTier = { tier1: { sent: 0, recovered: 0, opportunist: 0, no_response: 0, pending: 0, deposited: 0 },
                     tier2: { sent: 0, recovered: 0, opportunist: 0, no_response: 0, pending: 0, deposited: 0 },
                     tier3: { sent: 0, recovered: 0, opportunist: 0, no_response: 0, pending: 0, deposited: 0 } };
    for (const it of items) {
      const tier = it.bonusType === 'none' ? 'tier1'
                : it.bonusType === 'giveaway' ? 'tier2'
                : it.bonusType === 'promo' ? 'tier3'
                : null;
      if (!tier) continue;
      byTier[tier].sent++;
      const oc = it.outcome || 'pending';
      if (byTier[tier][oc] != null) byTier[tier][oc]++;
      if (it.realDepositMade) byTier[tier].deposited += (it.realDepositAmount || 0);
    }

    res.json({
      days,
      total: items.length,
      byTier,
      items: items.slice(0, 100).map(it => ({
        username: it.username,
        sentAt: it.sentAt,
        bonusType: it.bonusType,
        bonusAmount: it.bonusAmount,
        outcome: it.outcome,
        bonusClaimed: !!it.bonusClaimed,
        realDepositMade: !!it.realDepositMade,
        realDepositAmount: it.realDepositAmount || 0
      }))
    });
  } catch (err) {
    logger.error(`/api/admin/winback/history: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// Anti-fraude: extrae la IP del cliente normalizada. Express ya tiene
// 'trust proxy' = 1, así que req.ip viene de X-Forwarded-For.
// Normalizamos IPv6-mapped-IPv4 (::ffff:1.2.3.4 → 1.2.3.4).
function _getClientIp(req) {
  let ip = req.ip || (req.socket && req.socket.remoteAddress) || '';
  if (typeof ip !== 'string') return '';
  ip = ip.trim();
  if (ip.startsWith('::ffff:')) ip = ip.slice(7);
  return ip.slice(0, 60);
}

// Si esta IP ya cobró el welcome bonus desde otra cuenta, bloquear.
async function _isWelcomeBlockedByIp(userId, username, req) {
  try {
    const ip = _getClientIp(req);
    if (!ip) return { blocked: false };
    const prior = await RefundClaim.findOne({
      type: 'welcome_install',
      clientIp: ip,
      userId: { $ne: userId },
      username: { $ne: username }
    }).lean();
    if (!prior) return { blocked: false };
    logger.warn(`[BONUS] welcome bloqueado por IP duplicada. ${username} (${ip}) — ya cobró ${prior.username}`);
    return { blocked: true, otherUsername: prior.username, claimedAt: prior.claimedAt, ip };
  } catch (e) {
    logger.warn(`[BONUS] _isWelcomeBlockedByIp error: ${e.message}`);
    return { blocked: false };
  }
}

app.get('/api/refunds/welcome/status', authMiddleware, async (req, res) => {
  try {
    const userId = req.user.userId;
    const username = req.user.username;
    const claim = await RefundClaim.findOne({
      type: 'welcome_install',
      $or: [{ userId }, { username }]
    }).lean();

    // Si ya reclamó, no necesitamos llamar a JUGAYGANA para chequear cargas.
    if (claim) {
      return res.json({
        amount: WELCOME_BONUS_AMOUNT,
        claimed: true,
        claimedAt: claim.claimedAt || null,
        status: claim.status || null,
        eligible: false,
        notEnoughDeposits: false,
        depositCount: 0,
        requiredDeposits: WELCOME_BONUS_MIN_DEPOSITS,
        windowDays: WELCOME_BONUS_DEPOSIT_WINDOW_DAYS
      });
    }

    // Bloqueo por IP duplicada — cuenta JUGAYGANA nueva pero mismo router.
    const ipBlock = await _isWelcomeBlockedByIp(userId, username, req);
    if (ipBlock.blocked) {
      return res.json({
        amount: WELCOME_BONUS_AMOUNT,
        claimed: true,
        claimedAt: ipBlock.claimedAt || null,
        status: 'blocked_duplicate_ip',
        blockedReason: 'duplicate_ip',
        eligible: false,
        notEnoughDeposits: false,
        depositCount: 0,
        requiredDeposits: WELCOME_BONUS_MIN_DEPOSITS,
        windowDays: WELCOME_BONUS_DEPOSIT_WINDOW_DAYS
      });
    }

    const depCheck = await _welcomeDepositCheck(username);
    res.json({
      amount: WELCOME_BONUS_AMOUNT,
      claimed: false,
      claimedAt: null,
      status: null,
      eligible: depCheck.eligible,
      notEnoughDeposits: !depCheck.eligible,
      depositCount: depCheck.depositCount,
      requiredDeposits: depCheck.requiredDeposits,
      windowDays: depCheck.windowDays
    });
  } catch (error) {
    logger.error(`/api/refunds/welcome/status error: ${error.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

app.post('/api/refunds/claim/welcome', authMiddleware, async (req, res) => {
  try {
    const userId = req.user.userId;
    const username = req.user.username;

    if (!await acquireRefundLock(userId, 'welcome_install')) {
      return res.json({
        success: false,
        message: '⏳ Ya estás procesando el bono. Por favor espera...',
        processing: true
      });
    }

    try {
      // Requisito: minimo N cargas en los ultimos M dias para reclamar.
      // El finally global libera el lock — no hace falta liberarlo manualmente.
      const depCheck = await _welcomeDepositCheck(username);
      if (!depCheck.eligible) {
        logger.warn(`[BONUS] welcome — bloqueado por cargas insuficientes (${depCheck.depositCount}/${depCheck.requiredDeposits} en ${depCheck.windowDays}d, source=${depCheck.source}) — ${username}`);
        return res.json({
          success: false,
          message: `Necesitás al menos ${depCheck.requiredDeposits} cargas en los últimos ${depCheck.windowDays} días para reclamar el bono.`,
          canClaim: false,
          notEnoughDeposits: true,
          depositCount: depCheck.depositCount,
          requiredDeposits: depCheck.requiredDeposits,
          windowDays: depCheck.windowDays
        });
      }

      const periodKey = computePeriodKey('welcome_install');

      // Pre-check rapido por userId O username. Sin filtrar por periodKey:
      // el bono es one-time absoluto, cualquier claim previo del tipo
      // 'welcome_install' bloquea para siempre, sin importar que en algun
      // momento se haya cambiado la convencion de periodKey.
      const existing = await RefundClaim.findOne({
        type: 'welcome_install',
        $or: [{ userId }, { username }]
      }).lean();
      if (existing) {
        logger.warn(`[BONUS] welcome — pre-check rechazo por claim existente para ${username}`);
        return res.json({
          success: false,
          message: 'Ya reclamaste tu bono de bienvenida.',
          canClaim: false,
          claimed: true
        });
      }

      // Anti-fraude por IP: si otra cuenta ya cobró desde la misma IP,
      // FLAGGEAR la cuenta como fraud_blocked y rechazar. El próximo login
      // de este user queda rechazado con el motivo, y cualquier claim
      // futuro también. El acto de intentar reclamar desde una IP donde
      // ya cobraron es la evidencia del intento de estafa.
      const ipBlock = await _isWelcomeBlockedByIp(userId, username, req);
      if (ipBlock.blocked) {
        const fraudReason = 'Intento de reclamo de bono desde IP duplicada (cobrado previamente por ' + (ipBlock.otherUsername || '?') + ').';
        try {
          await User.updateOne(
            { id: userId },
            { $set: {
                fraudBlocked: true,
                fraudReason,
                fraudBlockedAt: new Date(),
                fraudBlockedIp: ipBlock.ip || _getClientIp(req)
              } }
          );
          logger.warn(`[FRAUD-BLOCK] ${username} bloqueado por intento de reclamo duplicado de welcome bonus desde ${ipBlock.ip} (otro user previo: ${ipBlock.otherUsername})`);
        } catch (e) {
          logger.warn(`[FRAUD-BLOCK] no se pudo flaggear ${username}: ${e.message}`);
        }
        return res.status(403).json({
          success: false,
          message: 'Usuario bloqueado por intento de estafa de bono.',
          canClaim: false,
          claimed: true,
          blockedReason: 'fraud_block',
          fraudBlocked: true,
          // code triggerea el overlay global #fraudBlockOverlay en la PWA
          code: 'FRAUD_BLOCKED'
        });
      }

      // Crear el claim con status='pending' explicito. Si el proceso muere
      // entre el create y el credit, queda como 'pending' y el admin lo
      // detecta facilmente filtrando RefundClaim {type:'welcome_install',
      // status:'pending', transactionId:null} para reconciliacion.
      let claim;
      try {
        claim = await RefundClaim.create({
          id: uuidv4(),
          userId,
          username,
          type: 'welcome_install',
          amount: WELCOME_BONUS_AMOUNT,
          netAmount: 0,
          percentage: 0,
          period: 'Bono de bienvenida',
          periodKey,
          status: 'pending',
          claimedAt: new Date(),
          clientIp: _getClientIp(req)
        });
      } catch (e) {
        if (e && e.code === 11000) {
          logger.warn(`[BONUS] welcome — duplicado bloqueado por indice unique para ${username} (key: ${JSON.stringify(e.keyValue || e.keyPattern || {})})`);
          return res.json({
            success: false,
            message: 'Ya reclamaste tu bono de bienvenida.',
            canClaim: false,
            claimed: true
          });
        }
        throw e;
      }

      const depositResult = await jugaygana.creditUserBalance(username, WELCOME_BONUS_AMOUNT);

      if (!depositResult.success) {
        // NO eliminar, marcar pending_credit_failed para que el admin lo revise.
        try {
          claim.status = 'pending_credit_failed';
          claim.creditError = String(depositResult.error || 'Error desconocido').slice(0, 500);
          await claim.save();
        } catch (e) {
          logger.error(`[BONUS] no se pudo persistir pending_credit_failed para claim ${claim._id}: ${e.message}`);
        }
        logger.error(`[BONUS] welcome credit fallo para ${username}: ${depositResult.error} - claim ${claim._id} marcado pending_credit_failed`);
        return res.json({
          success: false,
          message: 'Hubo un problema al acreditar tu bono. El administrador lo está revisando — no reintentes, podés contactarte por WhatsApp.',
          canClaim: false,
          pendingReview: true
        });
      }

      try {
        claim.transactionId = depositResult.data?.transfer_id || depositResult.data?.transferId || null;
        claim.status = 'completed';
        await claim.save();
      } catch (_) { /* best-effort */ }

      await Transaction.create({
        id: uuidv4(),
        type: 'refund',
        amount: WELCOME_BONUS_AMOUNT,
        username,
        description: 'Bono de bienvenida (PWA + notificaciones)',
        transactionId: depositResult.data?.transfer_id || depositResult.data?.transferId,
        timestamp: new Date()
      });

      // Invalidar cache del total regalado.
      _totalGiveawayCache.ts = 0;

      // Programar notif a 10 min para informar el código de retiro RETIRO10.
      // Filtra a la gente que reclama el bono y desinstala antes de cargar:
      // si la app fue desinstalada en esos 10min, la push no llega y no
      // gastamos atención del agente. Si sigue instalada, le dejamos un
      // recordatorio claro y conciso de cómo retirar (vía WA con código).
      // Best-effort: no bloqueamos la respuesta del claim si esto falla.
      try {
        const scheduledFor = new Date(Date.now() + 10 * 60 * 1000);
        await ScheduledNotification.create({
          id: uuidv4(),
          scheduledFor,
          status: 'pending',
          title: '🙌 ¡Gracias!',
          body: 'Gracias por confiar en nuestro servicio!',
          targetUsername: String(username).toLowerCase().trim(),
          audiencePrefix: null,
          extraType: 'none',
          createdBy: 'auto-welcome-bonus'
        });
        logger.info(`[BONUS] welcome — notif RETIRO10 programada para ${username} a ${scheduledFor.toISOString()}`);
      } catch (schedErr) {
        // No es crítico — el bono ya fue acreditado. Si falla la programación,
        // simplemente no llega el recordatorio (peor caso pierde efectividad).
        logger.warn(`[BONUS] welcome — no se pudo programar notif RETIRO10 para ${username}: ${schedErr.message}`);
      }

      res.json({
        success: true,
        message: `¡Reclamaste tu bono de bienvenida de $${WELCOME_BONUS_AMOUNT.toLocaleString('es-AR')}!`,
        amount: WELCOME_BONUS_AMOUNT
      });
    } finally {
      releaseRefundLock(userId, 'welcome_install');
    }
  } catch (error) {
    // Antes devolvia solo { error: 'Error del servidor' } y el frontend
    // mostraba "No se pudo reclamar" generico (sin diagnostico). Ahora
    // logueamos el stack completo y devolvemos un message concreto para
    // que el toast del user lo muestre y podamos debuggear.
    logger.error(`[BONUS] welcome claim crash para ${req.user && req.user.username}: ${error.message}\n${error.stack}`);
    console.error('Error reclamando bono de bienvenida:', error);
    res.status(500).json({
      success: false,
      message: 'Error del servidor: ' + (error.message || 'desconocido') + '. Avisanos por WhatsApp.',
      error: error.message || 'Error del servidor'
    });
  }
});

// ============================================
// REPORTES - REEMBOLSOS RECLAMADOS POR TIPO + FECHA
// GET /api/admin/reports/refunds?type=daily|weekly|monthly&from=YYYY-MM-DD&to=YYYY-MM-DD
// Devuelve: lista de reclamos en el rango, totales y serie por día.
// ============================================
app.get('/api/admin/reports/refunds', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const { type, from, to } = req.query;
    const validTypes = ['daily', 'weekly', 'monthly'];
    if (type && !validTypes.includes(type)) {
      return res.status(400).json({ error: `type debe ser uno de: ${validTypes.join(', ')}` });
    }

    // Parse fechas. Si no vienen, default = últimos 30 días en ART.
    // ART = UTC-3, día empieza a las 03:00 UTC.
    const ART_DAY_START_OFFSET_MS = 3 * 60 * 60 * 1000;
    const DAY_MS = 24 * 60 * 60 * 1000;

    let startUTC, endUTC;
    if (from && to) {
      const [fy, fm, fd] = String(from).split('-').map(Number);
      const [ty, tm, td] = String(to).split('-').map(Number);
      if (!fy || !fm || !fd || !ty || !tm || !td) {
        return res.status(400).json({ error: 'Formato de fecha inválido. Use YYYY-MM-DD.' });
      }
      startUTC = new Date(Date.UTC(fy, fm - 1, fd, 3, 0, 0, 0));
      endUTC = new Date(Date.UTC(ty, tm - 1, td, 3, 0, 0, 0) + DAY_MS - 1);
    } else {
      endUTC = new Date();
      startUTC = new Date(endUTC.getTime() - 30 * DAY_MS);
    }

    const filter = { claimedAt: { $gte: startUTC, $lte: endUTC } };
    if (type) filter.type = type;

    const refunds = await RefundClaim.find(filter).sort({ claimedAt: -1 }).lean();

    // Agregaciones
    const summary = {
      totalCount: refunds.length,
      totalAmount: 0,
      uniqueUsers: 0,
      byType: { daily: 0, weekly: 0, monthly: 0 },
      amountByType: { daily: 0, weekly: 0, monthly: 0 }
    };
    const usernamesSet = new Set();
    const perDay = {}; // { 'YYYY-MM-DD': { count, amount } }

    for (const r of refunds) {
      const amt = Number(r.amount) || 0;
      summary.totalAmount += amt;
      if (r.username) usernamesSet.add(r.username);
      if (r.type && summary.byType[r.type] != null) {
        summary.byType[r.type]++;
        summary.amountByType[r.type] += amt;
      }
      // Día en ART (restar 3h y tomar YYYY-MM-DD)
      const localMs = new Date(r.claimedAt).getTime() - ART_DAY_START_OFFSET_MS;
      const dayKey = new Date(localMs).toISOString().slice(0, 10);
      if (!perDay[dayKey]) perDay[dayKey] = { count: 0, amount: 0 };
      perDay[dayKey].count++;
      perDay[dayKey].amount += amt;
    }
    summary.uniqueUsers = usernamesSet.size;

    const series = Object.keys(perDay)
      .sort()
      .map((day) => ({ day, count: perDay[day].count, amount: perDay[day].amount }));

    res.json({
      type: type || 'all',
      from: startUTC.toISOString(),
      to: endUTC.toISOString(),
      summary,
      series,
      refunds: refunds.map((r) => ({
        id: r.id,
        username: r.username,
        type: r.type,
        amount: r.amount,
        netAmount: r.netAmount,
        period: r.period,
        periodKey: r.periodKey || null,
        status: r.status || 'completed',
        creditError: r.creditError || null,
        claimedAt: r.claimedAt
      }))
    });
  } catch (error) {
    logger.error(`/api/admin/reports/refunds error: ${error.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// ============================================
// REPORTES - INGRESOS DE USUARIOS POR DÍA
// GET /api/admin/reports/logins?days=30
// Devuelve: usuarios nuevos por día (createdAt), activos en últimas 24h y total.
// ============================================
app.get('/api/admin/reports/logins', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const ART_DAY_START_OFFSET_MS = 3 * 60 * 60 * 1000;
    const DAY_MS = 24 * 60 * 60 * 1000;
    const days = Math.max(1, Math.min(180, parseInt(req.query.days, 10) || 30));

    const endUTC = new Date();
    const startUTC = new Date(endUTC.getTime() - days * DAY_MS);

    // Usuarios creados en el rango
    const newUsers = await User.find(
      { createdAt: { $gte: startUTC, $lte: endUTC } },
      { username: 1, createdAt: 1, lastLogin: 1, _id: 0 }
    ).lean();

    // Agrupar por día (ART)
    const perDayNew = {};
    const perDayActive = {};
    for (const u of newUsers) {
      const localMs = new Date(u.createdAt).getTime() - ART_DAY_START_OFFSET_MS;
      const dayKey = new Date(localMs).toISOString().slice(0, 10);
      perDayNew[dayKey] = (perDayNew[dayKey] || 0) + 1;
    }

    // Usuarios con lastLogin reciente, agrupados por día (último ingreso de cada uno)
    const recentlyActive = await User.find(
      { lastLogin: { $gte: startUTC, $lte: endUTC } },
      { username: 1, lastLogin: 1, _id: 0 }
    ).lean();
    for (const u of recentlyActive) {
      const localMs = new Date(u.lastLogin).getTime() - ART_DAY_START_OFFSET_MS;
      const dayKey = new Date(localMs).toISOString().slice(0, 10);
      perDayActive[dayKey] = (perDayActive[dayKey] || 0) + 1;
    }

    // Construir serie con todos los días del rango (relleno cero)
    const series = [];
    for (let i = 0; i < days; i++) {
      const dt = new Date(endUTC.getTime() - (days - 1 - i) * DAY_MS);
      const localMs = dt.getTime() - ART_DAY_START_OFFSET_MS;
      const dayKey = new Date(localMs).toISOString().slice(0, 10);
      series.push({
        day: dayKey,
        newUsers: perDayNew[dayKey] || 0,
        activeUsers: perDayActive[dayKey] || 0
      });
    }

    // Totales
    const totalUsers = await User.countDocuments();
    const last24hWindow = new Date(Date.now() - DAY_MS);
    const activeLast24h = await User.countDocuments({ lastLogin: { $gte: last24hWindow } });
    const newLast24h = await User.countDocuments({ createdAt: { $gte: last24hWindow } });

    res.json({
      from: startUTC.toISOString(),
      to: endUTC.toISOString(),
      totals: {
        totalUsers,
        activeLast24h,
        newLast24h,
        newInRange: newUsers.length
      },
      series
    });
  } catch (error) {
    logger.error(`/api/admin/reports/logins error: ${error.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// ============================================
// REPORTES - EQUIPAMIENTO POR USUARIO
// GET /api/admin/reports/equipment
// Devuelve quien tiene la PWA instalada y quien tiene notificaciones activas,
// derivado de fcmTokens[].context === 'standalone' y notifPermission === 'granted'.
// ============================================
app.get('/api/admin/reports/equipment', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const users = await User.find(
      { role: 'user' },
      { username: 1, lastLogin: 1, createdAt: 1, fcmToken: 1, fcmTokenContext: 1, notifPermission: 1, fcmTokens: 1, lineTeamName: 1, linePhone: 1, lineAssignmentSource: 1, lineAssignmentNote: 1, _id: 0 }
    ).lean();

    let withApp = 0;
    let withNotifs = 0;
    let withBoth = 0;
    const list = [];

    for (const u of users) {
      const tokens = Array.isArray(u.fcmTokens) ? u.fcmTokens : [];
      // Solo tokens con context='standalone' (PWA real instalada).
      const standaloneTokens = tokens.filter(t => t && t.context === 'standalone');
      // ultima vez que el cliente refresco el token desde la PWA. Cuando el
      // user desinstala, no puede abrir la PWA, asi que updatedAt nunca mas
      // se actualiza. Es la mejor senal de "app realmente activa".
      const appLastSeen = standaloneTokens
        .map(t => t.updatedAt ? new Date(t.updatedAt).getTime() : 0)
        .reduce((a, b) => Math.max(a, b), 0);

      // Plataforma: tomamos la del token standalone mas reciente. Si no hay
      // standalone token, caemos al token mas reciente de cualquier tipo
      // (browser) para al menos saber con que dispositivo se loguea.
      let platform = null;
      const sourceTokens = standaloneTokens.length > 0 ? standaloneTokens : tokens;
      const sortedByUpdated = sourceTokens.slice().sort((a, b) => {
        const ta = a && a.updatedAt ? new Date(a.updatedAt).getTime() : 0;
        const tb = b && b.updatedAt ? new Date(b.updatedAt).getTime() : 0;
        return tb - ta;
      });
      const newest = sortedByUpdated.find(t => t && t.platform);
      if (newest) platform = newest.platform;

      const hasApp = (
        u.fcmTokenContext === 'standalone' ||
        standaloneTokens.length > 0
      );
      const hasNotifs = (
        u.notifPermission === 'granted' ||
        tokens.some(t => t && t.notifPermission === 'granted')
      );
      if (hasApp) withApp++;
      if (hasNotifs) withNotifs++;
      if (hasApp && hasNotifs) withBoth++;
      list.push({
        username: u.username || '',
        lastLogin: u.lastLogin || null,
        createdAt: u.createdAt || null,
        hasApp,
        hasNotifs,
        appLastSeen: appLastSeen > 0 ? new Date(appLastSeen).toISOString() : null,
        platform: platform,
        lineTeamName: u.lineTeamName || null,
        linePhone: u.linePhone || null,
        lineAssignmentSource: u.lineAssignmentSource || null,
        lineAssignmentNote: u.lineAssignmentNote || null
      });
    }

    // Orden: ultimos en loguearse primero, luego por username.
    list.sort((a, b) => {
      const ta = a.lastLogin ? new Date(a.lastLogin).getTime() : 0;
      const tb = b.lastLogin ? new Date(b.lastLogin).getTime() : 0;
      if (tb !== ta) return tb - ta;
      return (a.username || '').localeCompare(b.username || '');
    });

    res.json({
      totals: {
        totalUsers: list.length,
        withApp,
        withNotifs,
        withBoth
      },
      users: list
    });
  } catch (error) {
    logger.error(`/api/admin/reports/equipment error: ${error.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// ============================================
// LANDING TRACKING — contador de visitas a paginas /landing/<code>
// ============================================
//
// Para que el admin pueda medir el impacto de campañas de marketing sin
// depender de Google Analytics o herramientas externas. Cada landing tiene
// un slug (ej: 'promo2k') y cada visita queda registrada en LandingVisit.
//
// Endpoints:
//   POST /api/landings/:code/visit   - Public, rate-limited. La landing lo llama al cargarse.
//   GET  /api/admin/landings/:code/stats - Admin. KPIs y breakdown por dia.
//   GET  /api/admin/landings         - Admin. Lista todas las landings con totales.
//
// Privacidad: la IP se hashea con LANDING_IP_SALT (env var, fallback a un
// constante). NUNCA se persiste la IP en plano.

const LANDING_IP_SALT = process.env.LANDING_IP_SALT || 'jugaygana-landing-salt-2026-prod';
function _hashIpForLanding(ip) {
  if (!ip) return null;
  return crypto.createHash('sha256').update(String(ip) + '|' + LANDING_IP_SALT).digest('hex');
}

// POST /api/landings/:code/visit — registra una visita. Public, rate-limited.
// El body puede traer { referer } pero confiamos mas en el header. El user
// puede o no estar logueado: si lo esta, leemos su username del JWT
// opcionalmente (no obligatorio).
app.post('/api/landings/:code/visit', landingVisitLimiter, async (req, res) => {
  try {
    const code = String(req.params.code || '').toLowerCase().trim();
    if (!code || !/^[a-z0-9_-]{2,60}$/.test(code)) {
      return res.status(400).json({ error: 'Codigo invalido' });
    }
    const ip = req.ip || req.socket?.remoteAddress || null;
    const ipHash = _hashIpForLanding(ip);
    const userAgent = String(req.headers['user-agent'] || '').slice(0, 200) || null;
    const referer = String(req.headers.referer || req.headers.referrer || req.body?.referer || '').slice(0, 200) || null;

    // Opcional: si el visitante esta logueado y manda el token, lo guardamos.
    // No fallamos si no lo manda. El front es libre de no enviar token.
    let username = null;
    try {
      const auth = req.headers.authorization;
      if (auth && auth.startsWith('Bearer ')) {
        const token = auth.slice(7);
        const decoded = jwt.verify(token, JWT_SECRET);
        if (decoded && decoded.username) username = String(decoded.username).toLowerCase();
      }
    } catch (_) { /* ignore */ }

    await LandingVisit.create({ code, ipHash, userAgent, referer, username });
    res.json({ success: true });
  } catch (err) {
    logger.error(`/api/landings/visit error: ${err.message}`);
    // Devolvemos 200 igual: si falla el log, NO queremos romper la landing
    // que esta sirviendo el browser. El conteo de la app es secundario.
    res.json({ success: false });
  }
});

// GET /api/admin/landings — lista todos los codes vistos con conteos basicos.
app.get('/api/admin/landings', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const since30d = new Date(Date.now() - 30 * 86400000);
    const agg = await LandingVisit.aggregate([
      { $group: {
        _id: '$code',
        totalVisits: { $sum: 1 },
        uniqueIps: { $addToSet: '$ipHash' },
        last24h: { $sum: { $cond: [{ $gte: ['$at', new Date(Date.now() - 86400000)] }, 1, 0] } },
        last7d: { $sum: { $cond: [{ $gte: ['$at', new Date(Date.now() - 7 * 86400000)] }, 1, 0] } },
        first: { $min: '$at' },
        last: { $max: '$at' }
      } },
      { $project: {
        _id: 0,
        code: '$_id',
        totalVisits: 1,
        uniqueIps: { $size: '$uniqueIps' },
        last24h: 1,
        last7d: 1,
        first: 1,
        last: 1
      } },
      { $sort: { totalVisits: -1 } }
    ]);
    res.json({ since30d, landings: agg });
  } catch (err) {
    logger.error(`/api/admin/landings error: ${err.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// GET /api/admin/landings/:code/stats — KPIs detallados de una landing.
// Devuelve totales, unicos, por-dia (ultimos 30 dias) y ultimas N visitas.
app.get('/api/admin/landings/:code/stats', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const code = String(req.params.code || '').toLowerCase().trim();
    if (!code) return res.status(400).json({ error: 'Codigo invalido' });

    const now = new Date();
    const _24h = new Date(now.getTime() - 86400000);
    const _7d  = new Date(now.getTime() - 7 * 86400000);
    const _30d = new Date(now.getTime() - 30 * 86400000);

    const [totalVisits, uniqueIpsAgg, visits24h, visits7d, byDay, recent, attributedUsers] = await Promise.all([
      LandingVisit.countDocuments({ code }),
      LandingVisit.aggregate([
        { $match: { code } },
        { $group: { _id: '$ipHash' } },
        { $count: 'count' }
      ]),
      LandingVisit.countDocuments({ code, at: { $gte: _24h } }),
      LandingVisit.countDocuments({ code, at: { $gte: _7d } }),
      // Breakdown por dia (Argentina UTC-3) en los ultimos 30 dias.
      LandingVisit.aggregate([
        { $match: { code, at: { $gte: _30d } } },
        { $project: {
          dayKey: {
            $dateToString: {
              format: '%Y-%m-%d',
              date: '$at',
              timezone: '-03:00'
            }
          },
          ipHash: 1
        } },
        { $group: {
          _id: '$dayKey',
          visits: { $sum: 1 },
          uniqueIps: { $addToSet: '$ipHash' }
        } },
        { $project: { _id: 0, day: '$_id', visits: 1, uniqueIps: { $size: '$uniqueIps' } } },
        { $sort: { day: 1 } }
      ]),
      // Todas las visitas (sin limit). El admin pidio listado completo en
      // vez de "ultimas 50". Si la campaña explota a millones, ahi mirar
      // de paginar; mientras tanto el sort en memoria + render scroll-only
      // alcanza para volumenes razonables.
      LandingVisit.find({ code }, { ipHash: 1, userAgent: 1, referer: 1, username: 1, at: 1 })
        .sort({ at: -1 }).lean(),
      // Funnel: traemos el set de users atribuidos a esta campaña con los
      // campos que necesitamos para distinguir registrados vs instalados.
      // hasApp = el user tiene un fcmToken con context='standalone' (PWA).
      // El reclamo del bono se computa abajo via RefundClaim.
      User.find(
        { campaignCode: code },
        { id: 1, username: 1, createdAt: 1, fcmTokenContext: 1, fcmTokens: 1 }
      ).lean()
    ]);

    const uniqueIps = (uniqueIpsAgg[0] && uniqueIpsAgg[0].count) || 0;

    // Funnel — calcular cuantos de los users atribuidos:
    //   1) se registraron (signups = attributedUsers.length)
    //   2) instalaron la app (hasApp por fcmTokenContext='standalone')
    //   3) reclamaron el bono $10k/$5k/$2k de bienvenida (welcome_install).
    const signups = attributedUsers.length;
    const installedUsernames = [];
    for (const u of attributedUsers) {
      const tokens = Array.isArray(u.fcmTokens) ? u.fcmTokens : [];
      const hasApp = u.fcmTokenContext === 'standalone'
        || tokens.some(t => t && t.context === 'standalone');
      if (hasApp) installedUsernames.push(String(u.username || '').toLowerCase());
    }
    const installed = installedUsernames.length;

    let claimed = 0, claimedAmountTotal = 0;
    if (signups > 0) {
      const usernames = attributedUsers.map(u => String(u.username || '').toLowerCase()).filter(Boolean);
      // Lookup case-insensitive sobre RefundClaim. Match por username exact-lowercase
      // funciona porque tanto User.username como RefundClaim.username se guardan
      // en el mismo casing en este sistema (ver welcome bonus claim handler).
      const claims = await RefundClaim.find(
        {
          type: 'welcome_install',
          status: 'completed',
          username: { $in: usernames }
        },
        { username: 1, amount: 1, claimedAt: 1 }
      ).lean();
      claimed = claims.length;
      claimedAmountTotal = claims.reduce((s, c) => s + (c.amount || 0), 0);
    }

    // Tabla detallada de los users atribuidos: util para que el admin pueda
    // ver fila por fila quien entro, se registro, instalo y reclamo.
    const usernamesLc = attributedUsers.map(u => String(u.username || '').toLowerCase());
    const claimsByUser = {};
    if (usernamesLc.length > 0) {
      const allClaims = await RefundClaim.find(
        {
          type: 'welcome_install',
          status: 'completed',
          username: { $in: usernamesLc }
        },
        { username: 1, amount: 1, claimedAt: 1 }
      ).lean();
      for (const c of allClaims) {
        const k = String(c.username || '').toLowerCase();
        claimsByUser[k] = c;
      }
    }
    const installedSet = new Set(installedUsernames);
    const attributed = attributedUsers.map(u => {
      const lc = String(u.username || '').toLowerCase();
      const claim = claimsByUser[lc];
      return {
        username: u.username,
        signedUpAt: u.createdAt,
        installed: installedSet.has(lc),
        claimedBonus: !!claim,
        bonusAmount: claim ? (claim.amount || 0) : 0,
        bonusClaimedAt: claim ? claim.claimedAt : null
      };
    }).sort((a, b) => new Date(b.signedUpAt || 0) - new Date(a.signedUpAt || 0));

    // Para enriquecer cada visita con "instalo la app", batch-lookup de los
    // users que aparecieron logueados al visitar. Hacemos 1 sola query por
    // todos los usernames distintos en las visitas (en vez de N+1).
    const visitUsernamesLc = Array.from(new Set(
      recent.map(r => r.username ? String(r.username).toLowerCase() : null).filter(Boolean)
    ));
    const visitUserMap = {};
    if (visitUsernamesLc.length > 0) {
      // Usamos los users ya traidos en attributedUsers para evitar otra query
      // si todos coinciden, pero la mayoria de visitas pueden ser de users
      // que NO se atribuyeron (ej: un user existente que clickeo el link).
      const usersFromVisits = await User.find(
        { username: { $in: visitUsernamesLc } },
        { username: 1, fcmTokenContext: 1, fcmTokens: 1 }
      ).lean();
      for (const u of usersFromVisits) {
        const tokens = Array.isArray(u.fcmTokens) ? u.fcmTokens : [];
        const hasApp = u.fcmTokenContext === 'standalone'
          || tokens.some(t => t && t.context === 'standalone');
        visitUserMap[String(u.username || '').toLowerCase()] = { hasApp };
      }
    }

    res.json({
      code,
      totalVisits,
      uniqueIps,
      last24h: visits24h,
      last7d: visits7d,
      byDay,
      recent: recent.map(r => {
        const lc = r.username ? String(r.username).toLowerCase() : null;
        const u = lc ? visitUserMap[lc] : null;
        return {
          // No devolvemos el ipHash completo, solo los primeros 8 chars para
          // que el admin pueda agrupar visualmente sin exponer el hash entero.
          ipHashShort: r.ipHash ? String(r.ipHash).slice(0, 8) : null,
          userAgent: r.userAgent,
          referer: r.referer,
          username: r.username,
          // installed: true/false si el user existe; null si la visita es
          // anonima (no podemos saber si esa persona despues instalo).
          installed: u ? !!u.hasApp : null,
          // El link/code por el que entro. En este endpoint siempre es el
          // mismo (el filtro), pero lo devolvemos explicito para que el front
          // pueda mostrar la columna sin ambiguedad.
          code,
          at: r.at
        };
      }),
      // Funnel: visitas -> registros -> instalaron -> reclamaron bono.
      funnel: {
        signups,
        installed,
        claimed,
        claimedAmountTotal
      },
      attributed
    });
  } catch (err) {
    logger.error(`/api/admin/landings/${req.params.code}/stats error: ${err.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// ============================================
// GET /api/admin/reports/welcome-bonus
// Lista de users que reclamaron el bono de bienvenida (cualquier monto histórico) + su estado actual
// de app instalada y notificaciones. Permite ver quien todavia tiene la
// app + notifs y quien las desactivo o desinstalo despues de cobrar.
// ============================================
app.get('/api/admin/reports/welcome-bonus', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    // 1) Todos los claims del bono.
    const claims = await RefundClaim.find(
      { type: 'welcome_install' },
      {
        username: 1, userId: 1, claimedAt: 1, status: 1, transactionId: 1,
        amount: 1,
        chargesAfterClaim: 1, chargesAfterClaimAmount: 1,
        lastChargeAfterClaimAt: 1, chargesAfterClaimCheckedAt: 1,
        _id: 0
      }
    ).sort({ claimedAt: -1 }).lean();

    if (claims.length === 0) {
      return res.json({
        totals: { totalClaimed: 0, stillHasApp: 0, stillHasNotifs: 0, stillBoth: 0, lostApp: 0, lostNotifs: 0 },
        claims: []
      });
    }

    // 2) Pull de los users involucrados, una sola query.
    const usernames = [...new Set(claims.map(c => c.username).filter(Boolean))];
    const users = await User.find(
      { username: { $in: usernames } },
      { username: 1, fcmTokenContext: 1, notifPermission: 1, fcmTokens: 1, lastLogin: 1, _id: 0 }
    ).lean();
    const byUsername = new Map(users.map(u => [(u.username || '').toLowerCase(), u]));

    // 2.b) PlayerStats con realDeposits30d/realChargesCount30d como contexto
    // adicional ("¿qué actividad tuvo en los últimos 30d?"). El flag de
    // "cargó después del bono" YA NO se calcula desde lastRealDepositDate
    // (que solo guarda una aproximación mid-period y no responde la pregunta).
    // Ahora vive en RefundClaim.chargesAfterClaim (snapshot poblado por
    // /api/admin/reports/welcome-bonus/refresh-charges contra los movimientos
    // reales de JUGAYGANA, excluyendo las acreditaciones de bonos).
    const lowerUsernames = usernames.map(u => (u || '').toLowerCase());
    const playerStats = await PlayerStats.find(
      { username: { $in: lowerUsernames } },
      { username: 1, realDeposits30d: 1, realChargesCount30d: 1, _id: 0 }
    ).lean();
    const psByUsername = new Map(playerStats.map(p => [(p.username || '').toLowerCase(), p]));

    let stillHasApp = 0, stillHasNotifs = 0, stillBoth = 0, lostApp = 0, lostNotifs = 0;
    let chargedAfterClaim = 0;
    let chargesNeverChecked = 0;
    // Breakdown por monto reclamado (10000 historicos vs 2000 nuevos vs otros).
    const claimsByAmount = {}; // amount -> count
    let totalAmountGivenARS = 0;
    const enriched = claims.map(c => {
      const u = byUsername.get((c.username || '').toLowerCase()) || {};
      const ps = psByUsername.get((c.username || '').toLowerCase()) || {};
      const tokens = Array.isArray(u.fcmTokens) ? u.fcmTokens : [];
      const standaloneTokens = tokens.filter(t => t && t.context === 'standalone');
      const appLastSeen = standaloneTokens
        .map(t => t.updatedAt ? new Date(t.updatedAt).getTime() : 0)
        .reduce((a, b) => Math.max(a, b), 0);

      let platform = null;
      const sourceTokens = standaloneTokens.length > 0 ? standaloneTokens : tokens;
      const sortedByUpdated = sourceTokens.slice().sort((a, b) => {
        const ta = a && a.updatedAt ? new Date(a.updatedAt).getTime() : 0;
        const tb = b && b.updatedAt ? new Date(b.updatedAt).getTime() : 0;
        return tb - ta;
      });
      const newest = sortedByUpdated.find(t => t && t.platform);
      if (newest) platform = newest.platform;

      const hasApp = (
        u.fcmTokenContext === 'standalone' ||
        standaloneTokens.length > 0
      );
      const hasNotifs = (
        u.notifPermission === 'granted' ||
        tokens.some(t => t && t.notifPermission === 'granted')
      );
      if (hasApp) stillHasApp++; else lostApp++;
      if (hasNotifs) stillHasNotifs++; else lostNotifs++;
      if (hasApp && hasNotifs) stillBoth++;

      // ¿Cargó después del reclamo del bono?
      // Fuente de verdad: snapshot por-claim poblado desde los movimientos
      // de JUGAYGANA (excluyendo las acreditaciones de bonos por transactionId).
      // Cuenta DEPÓSITOS, no monto: alguien puede haber cargado y retirado
      // todo, lo que daría saldo $0 pero igual responde "sí, cargaron".
      // Si chargesAfterClaimCheckedAt es null, el claim todavía no fue
      // refrescado contra JUGAYGANA — el admin debe tocar "Refrescar cargas".
      const chargesCount = Number(c.chargesAfterClaim || 0);
      const chargesAmount = Number(c.chargesAfterClaimAmount || 0);
      const didChargeAfter = chargesCount > 0;
      const checkedAt = c.chargesAfterClaimCheckedAt || null;
      if (didChargeAfter) chargedAfterClaim++;
      if (!checkedAt) chargesNeverChecked++;

      const claimedAmount = Number(c.amount || 0);
      claimsByAmount[claimedAmount] = (claimsByAmount[claimedAmount] || 0) + 1;
      totalAmountGivenARS += claimedAmount;

      return {
        username: c.username || '',
        claimedAt: c.claimedAt || null,
        status: c.status || 'completed',
        transactionId: c.transactionId || null,
        amount: claimedAmount,
        hasApp,
        hasNotifs,
        lastLogin: u.lastLogin || null,
        appLastSeen: appLastSeen > 0 ? new Date(appLastSeen).toISOString() : null,
        platform: platform,
        // Datos de carga post-bono (desde snapshot por-claim)
        chargedAfterClaim: didChargeAfter,
        chargesAfterClaim: chargesCount,
        chargesAfterClaimAmount: chargesAmount,
        lastDepositAt: c.lastChargeAfterClaimAt || null,
        chargesCheckedAt: checkedAt,
        // Contexto agregado de PlayerStats (últimos 30d, no atado al claim)
        realDeposits30d: ps.realDeposits30d || 0,
        realChargesCount30d: ps.realChargesCount30d || 0
      };
    });

    // Convertir claimsByAmount a array ordenado por monto desc para que
    // el UI los muestre en orden ($10.000 primero, $2.000 después, etc.).
    const byAmountArr = Object.keys(claimsByAmount)
      .map(k => ({ amount: Number(k), count: claimsByAmount[k] }))
      .sort((a, b) => b.amount - a.amount);

    res.json({
      totals: {
        totalClaimed: claims.length,
        stillHasApp,
        stillHasNotifs,
        stillBoth,
        lostApp,
        lostNotifs,
        chargedAfterClaim,
        chargesNeverChecked,
        totalAmountGivenARS,
        byAmount: byAmountArr
      },
      claims: enriched
    });
  } catch (error) {
    logger.error(`/api/admin/reports/welcome-bonus error: ${error.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// ============================================
// POST /api/admin/reports/welcome-bonus/refresh-charges
// Para cada claim de welcome_install, consulta los movimientos reales en
// JUGAYGANA (ShowUserMovements) desde claimedAt, cuenta los DEPÓSITOS
// (excluyendo las acreditaciones de bonos por transactionId match) y
// guarda el snapshot en RefundClaim.chargesAfterClaim/Amount/lastAt.
//
// Por qué no usamos lastRealDepositDate de PlayerStats: ese campo guarda
// solo una aproximación mid-period (15d atrás), entonces para claims
// recientes el flag salía siempre falso. Y por qué contamos cargas y no
// monto: alguien puede haber cargado y retirado todo, dejando $0 de
// saldo o $0 de delta — pero la pregunta de negocio es "¿volvieron a
// jugar después del regalo?", no "¿les quedó plata?".
//
// El admin polea GET /api/admin/reports/welcome-bonus/refresh-charges
// para ver progreso. Anti-overlap: si ya está corriendo, devolvemos
// el state actual sin disparar otro pase.
// ============================================
let _welcomeBonusChargesRefreshState = {
  running: false, total: 0, done: 0, errors: 0,
  startedAt: null, finishedAt: null
};

async function _refreshChargesAfterClaimFor(claim) {
  const username = claim.username;
  const claimedAt = claim.claimedAt ? new Date(claim.claimedAt) : null;
  if (!username || !claimedAt) return { ok: false, reason: 'missing_data' };

  // TransactionIds de TODOS los bonos que le acreditamos a este user
  // (welcome + daily/weekly/monthly + giveaways). Estos van a aparecer
  // como "deposits" en JUGAYGANA porque creditUserBalance pasa por su
  // endpoint de depósito — los excluimos para no contarlos como cargas
  // del usuario.
  const [refundDocs, giveawayDocs] = await Promise.all([
    RefundClaim.find(
      { username, transactionId: { $ne: null } },
      { transactionId: 1, _id: 0 }
    ).lean(),
    MoneyGiveawayClaim.find(
      { username, transactionId: { $ne: null } },
      { transactionId: 1, _id: 0 }
    ).lean().catch(() => [])
  ]);
  const bonusTxIds = new Set();
  for (const d of refundDocs) if (d.transactionId) bonusTxIds.add(String(d.transactionId));
  for (const d of giveawayDocs) if (d.transactionId) bonusTxIds.add(String(d.transactionId));

  // JUGAYGANA filtra por YYYY-MM-DD. Pedimos desde un día antes del claim
  // (tolerancia de timezone) y filtramos al timestamp después.
  const startDate = new Date(claimedAt.getTime() - 24*3600*1000).toISOString().split('T')[0];
  const endDate = new Date(Date.now() + 24*3600*1000).toISOString().split('T')[0];

  const result = await jugayganaMovements.getUserMovements(username, {
    startDate,
    endDate,
    operationType: 'deposit',
    pageSize: 500
  });

  if (!result || !result.success) {
    return { ok: false, reason: result?.error || 'movements_failed' };
  }

  const claimedMs = claimedAt.getTime();
  let count = 0;
  let amount = 0;
  let lastAt = 0;

  for (const m of (result.movements || [])) {
    // Posibles nombres de campo para el id del movimiento.
    const mid = String(
      m.id || m.Id || m._id ||
      m.transfer_id || m.transferId ||
      m.transactionId || m.TransactionId || ''
    );
    if (mid && bonusTxIds.has(mid)) continue;

    // Defensa en profundidad: confirmamos que es depósito aunque ya
    // pedimos operationType='deposit' arriba.
    const type = (m.type || m.operation || m.OperationType || m.Type || m.Operation || '').toString().toLowerCase();
    let amt = 0;
    if (m.amount !== undefined) amt = parseFloat(m.amount);
    else if (m.Amount !== undefined) amt = parseFloat(m.Amount);
    else if (m.value !== undefined) amt = parseFloat(m.value);
    else if (m.Value !== undefined) amt = parseFloat(m.Value);
    else if (m.monto !== undefined) amt = parseFloat(m.monto);
    else if (m.Monto !== undefined) amt = parseFloat(m.Monto);

    const isDep = type.includes('deposit') || type.includes('credit') ||
                  type.includes('carga') || type.includes('recarga') || amt > 0;
    if (!isDep) continue;

    // Timestamp del movimiento. Si lo tenemos, exigimos > claimedAt para
    // descartar depósitos del mismo día previos al reclamo. Si no lo
    // tenemos, contamos best-effort (el bono ya quedó excluido por id).
    const tsRaw = m.created_at || m.createdAt || m.date || m.Date ||
                  m.datetime || m.timestamp || m.time || m.created || null;
    let mTs = 0;
    if (tsRaw) {
      const d = new Date(tsRaw);
      if (!isNaN(d.getTime())) mTs = d.getTime();
    }
    if (mTs > 0 && mTs <= claimedMs) continue;

    count++;
    amount += Math.abs(Number.isFinite(amt) ? amt : 0);
    if (mTs > lastAt) lastAt = mTs;
  }

  await RefundClaim.updateOne(
    { id: claim.id },
    {
      $set: {
        chargesAfterClaim: count,
        chargesAfterClaimAmount: amount,
        lastChargeAfterClaimAt: lastAt > 0 ? new Date(lastAt) : null,
        chargesAfterClaimCheckedAt: new Date()
      }
    }
  );

  return { ok: true, count, amount };
}

app.post('/api/admin/reports/welcome-bonus/refresh-charges', authMiddleware, adminMiddleware, async (req, res) => {
  if (_welcomeBonusChargesRefreshState.running) {
    return res.json({
      success: false,
      message: 'Ya hay un refresh corriendo',
      state: _welcomeBonusChargesRefreshState
    });
  }

  _welcomeBonusChargesRefreshState = {
    running: true, total: 0, done: 0, errors: 0,
    startedAt: new Date().toISOString(), finishedAt: null
  };
  res.json({ success: true, state: _welcomeBonusChargesRefreshState });

  (async () => {
    try {
      const claims = await RefundClaim.find(
        { type: 'welcome_install' },
        { id: 1, username: 1, claimedAt: 1, _id: 0 }
      ).sort({ claimedAt: -1 }).lean();
      _welcomeBonusChargesRefreshState.total = claims.length;

      for (const c of claims) {
        try {
          const r = await _refreshChargesAfterClaimFor(c);
          if (!r.ok) _welcomeBonusChargesRefreshState.errors++;
        } catch (e) {
          _welcomeBonusChargesRefreshState.errors++;
          logger.warn(`[welcome-charges] ${c.username}: ${e.message}`);
        }
        _welcomeBonusChargesRefreshState.done++;
        await new Promise(r => setTimeout(r, 250));
      }
    } catch (e) {
      logger.error(`[welcome-charges] fatal: ${e.message}`);
    } finally {
      _welcomeBonusChargesRefreshState.running = false;
      _welcomeBonusChargesRefreshState.finishedAt = new Date().toISOString();
    }
  })();
});

app.get('/api/admin/reports/welcome-bonus/refresh-charges', authMiddleware, adminMiddleware, async (req, res) => {
  res.json({ state: _welcomeBonusChargesRefreshState });
});

// ============================================
// POST /api/admin/reports/revalidate-tokens
// Dispara la validacion on-demand de todos los tokens FCM via dry-run.
// FCM responde "not-found"/"unregistered" para tokens cuya app fue
// desinstalada → los borramos del array fcmTokens. Resultado: el
// reporte siguiente refleja el estado real (no el cacheado de hace 24h).
//
// Anti-overlap: si el cron ya esta corriendo, devolvemos 409 para que
// el admin sepa que esperar y no se dispare doble.
// ============================================
let _adminRevalidateRunning = false;
app.post('/api/admin/reports/revalidate-tokens', authMiddleware, adminMiddleware, async (req, res) => {
  if (_adminRevalidateRunning) {
    return res.status(409).json({
      success: false,
      error: 'Ya hay una revalidación en curso. Esperá unos minutos y volvé a intentar.'
    });
  }
  _adminRevalidateRunning = true;
  const startedAt = Date.now();
  try {
    const result = await pruneInvalidFcmTokens(User);
    const elapsedMs = Date.now() - startedAt;
    if (!result || !result.success) {
      logger.warn(`[admin/revalidate] sin resultado: ${result && result.error}`);
      return res.json({ success: false, error: (result && result.error) || 'Error desconocido' });
    }
    logger.info(`[admin/revalidate] manual: total=${result.total} valid=${result.valid} cleaned=${result.cleaned} errors=${result.errors} (${Math.round(elapsedMs/1000)}s)`);
    res.json({
      success: true,
      total: result.total,
      valid: result.valid,
      invalid: result.invalid,
      cleaned: result.cleaned,
      errors: result.errors,
      elapsedMs
    });
  } catch (e) {
    logger.error(`[admin/revalidate] excepción: ${e.message}`);
    res.status(500).json({ success: false, error: e.message });
  } finally {
    _adminRevalidateRunning = false;
  }
});

// ============================================
// PROMO ALERT TEMPORAL en boton "QUIERO CARGAR" del home.
// El admin lo configura junto con la notificacion masiva: titulo,
// codigo y duracion. Mientras este vigente, el card de WhatsApp del
// home muestra "🎁 RECLAMÁ <mensaje> · Código: <CODE>" en vez del
// "QUIERO CARGAR" normal.
//
// Storage: usamos getConfig/setConfig (key='activePromoAlert') para
// no agregar otra coleccion Mongoose. El formato es:
//   { id, message, code, expiresAt (ISO), createdAt (ISO),
//     createdBy, prefix (opcional para targetear por prefijo) }
// Si expiresAt < ahora, el endpoint GET responde null (no esta activo).
// ============================================
const PROMO_ALERT_KEY = 'activePromoAlert';
// Array paralelo de promos por tier (estrategia jueves). Cada elemento
// tiene el mismo shape que la singleton + audienceWhitelist obligatorio.
// Soporta hasta N tiers activos en paralelo (oro/plata/bronce). Cada user
// ve UNA promo: la primera del array donde su username está en el whitelist.
// Si no matchea ningún tier, fallback al singleton PROMO_ALERT_KEY.
const TIER_PROMOS_KEY = 'activeTierPromos';

function _normalizePromoCode(raw) {
  return String(raw || '').trim().toUpperCase().replace(/[^A-Z0-9_-]/g, '').slice(0, 20);
}

// Helper: dado un username, encuentra la promo activa que le corresponde
// chequeando primero TIER_PROMOS (whitelist exacto) y luego el singleton
// PROMO_ALERT (singleton manual / line-down). Devuelve null si nada matchea.
async function _resolveActivePromoForUser(username) {
  const usernameLower = String(username || '').toLowerCase();
  const now = Date.now();

  // 1) Buscar en tier promos (whitelist exacto).
  const tierPromos = await getConfig(TIER_PROMOS_KEY, null);
  if (Array.isArray(tierPromos) && tierPromos.length > 0) {
    for (const p of tierPromos) {
      if (!p || !p.expiresAt) continue;
      const exp = new Date(p.expiresAt).getTime();
      if (!isFinite(exp) || exp <= now) continue;
      if (Array.isArray(p.audienceWhitelist) && p.audienceWhitelist.some(u => String(u).toLowerCase() === usernameLower)) {
        return p;
      }
    }
  }

  // 2) Singleton (manual / line-down).
  const promo = await getConfig(PROMO_ALERT_KEY, null);
  if (!promo || !promo.expiresAt) return null;
  const exp = new Date(promo.expiresAt).getTime();
  if (!isFinite(exp) || exp <= now) return null;

  if (Array.isArray(promo.audienceWhitelist) && promo.audienceWhitelist.length > 0) {
    const wl = new Set(promo.audienceWhitelist.map(u => String(u).toLowerCase()));
    if (!wl.has(usernameLower)) return null;
  } else if (promo.prefix && typeof promo.prefix === 'string') {
    if (!usernameLower.startsWith(promo.prefix.toLowerCase())) return null;
  }
  return promo;
}

// GET publico (autenticado): devuelve la promo activa para este user.
app.get('/api/promo-alert/active', authMiddleware, async (req, res) => {
  try {
    const username = (req.user && req.user.username) || '';
    const promo = await _resolveActivePromoForUser(username);
    if (!promo) return res.json({ active: false });
    res.json({
      active: true,
      id: promo.id,
      message: promo.message,
      code: promo.code,
      expiresAt: promo.expiresAt,
      createdAt: promo.createdAt,
      notificationHistoryId: promo.notificationHistoryId || null,
      lineDown: !!promo.lineDown,
      strategyTier: promo.strategyTier || null,
      strategyBonusPct: promo.strategyBonusPct || null
    });
  } catch (error) {
    logger.error(`/api/promo-alert/active error: ${error.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// POST /api/promo-alert/track-click — incrementa contador waClicks del
// row de historial asociado a LA promo del user (singleton o tier).
app.post('/api/promo-alert/track-click', authMiddleware, async (req, res) => {
  try {
    const promo = await _resolveActivePromoForUser(req.user.username);
    if (!promo) return res.json({ ok: true, tracked: false });

    // 1) Log por-usuario.
    try {
      await WaClickLog.create({
        id: uuidv4(),
        userId: req.user.userId,
        username: req.user.username,
        promoId: promo.id || null,
        notificationHistoryId: promo.notificationHistoryId || null,
        clickedAt: new Date()
      });
    } catch (e) {
      logger.warn(`/track-click WaClickLog falló: ${e.message}`);
    }

    // 2) Contador agregado en NotificationHistory.
    if (promo.notificationHistoryId) {
      await NotificationHistory.updateOne(
        { id: promo.notificationHistoryId },
        { $inc: { waClicks: 1 } }
      );
    }
    res.json({ ok: true, tracked: true });
  } catch (error) {
    logger.warn(`/api/promo-alert/track-click error: ${error.message}`);
    res.json({ ok: true, tracked: false });
  }
});

// ============================================
// MONEY GIVEAWAY (regalo de plata por difusion).
// El admin crea un regalo con monto-por-persona, tope de plata total,
// tope de cantidad de personas, y duracion en minutos. Mientras este
// abierto, los users pueden tocar un boton en la home y se les acredita
// la plata directo en JUGAYGANA.
//
// Cierres automaticos (status):
//   - closed_expired: paso la duracion
//   - closed_budget:  totalGiven >= totalBudget
//   - closed_max:     claimedCount >= maxClaims
//   - cancelled:      el admin lo cancelo manualmente
// ============================================

// Helper: dado un giveaway "in memory", chequea si deberia cerrarse y lo
// updateOnece a la BD si corresponde. Devuelve el doc actualizado o el
// mismo input si sigue activo.
async function _maybeCloseGiveaway(g) {
  if (!g || g.status !== 'active') return g;
  let newStatus = null;
  if (new Date(g.expiresAt).getTime() <= Date.now()) newStatus = 'closed_expired';
  else if ((g.totalGiven || 0) >= g.totalBudget) newStatus = 'closed_budget';
  else if ((g.claimedCount || 0) >= g.maxClaims) newStatus = 'closed_max';
  if (!newStatus) return g;
  try {
    await MoneyGiveaway.updateOne({ id: g.id, status: 'active' }, { $set: { status: newStatus } });
    g.status = newStatus;
  } catch (_) { /* ignore */ }
  return g;
}

// GET publico (auth): regalo activo para este user.
//
// Devuelve el regalo MIENTRAS esté dentro de la ventana original de tiempo,
// incluso si se agotó el cupo o el presupuesto antes — en esos casos
// soldOut=true para que el frontend lo muestre como "llegaste tarde".
// Solo se oculta cuando expiresAt vence (closed_expired) o si el admin lo
// canceló manualmente.
app.get('/api/money-giveaway/active', authMiddleware, async (req, res) => {
  try {
    const username = req.user.username || '';
    const userId = req.user.userId;

    // Buscar EL regalo más reciente que aún esté vigente y para el cual
    // ESTE user es elegible. Importante: la estrategia automática puede
    // tener varios giveaways activos en paralelo (uno por tier de pérdida),
    // cada uno con su propio audienceWhitelist. Si solo agarráramos el
    // último creado, los users de tiers anteriores verían "no hay regalo"
    // aunque haya uno destinado a ellos.
    //
    // Estrategia de matching (en orden de prioridad):
    //   1) Giveaway donde el user está EXPLÍCITAMENTE en audienceWhitelist
    //   2) Giveaway sin whitelist (público) cuyo prefix matchee el username
    //   3) Giveaway sin whitelist y sin prefix (open a todos)
    const now = new Date();
    const usernameLower = username.toLowerCase();
    const baseFilter = {
      status: { $in: ['active', 'closed_max', 'closed_budget'] },
      expiresAt: { $gt: now }
    };

    // Prioridad 1: whitelist explícito (estrategia / rule suggestions)
    let g = await MoneyGiveaway.findOne({
      ...baseFilter,
      audienceWhitelist: usernameLower
    }).sort({ createdAt: -1 }).lean();

    // Prioridad 2-3: giveaway público (sin whitelist) — buscamos varios
    // candidatos y elegimos el más nuevo cuyo prefix matchee (o sin prefix).
    if (!g) {
      const candidates = await MoneyGiveaway.find({
        ...baseFilter,
        $or: [
          { audienceWhitelist: null },
          { audienceWhitelist: { $size: 0 } },
          { audienceWhitelist: { $exists: false } }
        ]
      }).sort({ createdAt: -1 }).limit(10).lean();
      for (const c of candidates) {
        if (!c.prefix || usernameLower.startsWith(String(c.prefix).toLowerCase())) {
          g = c;
          break;
        }
      }
    }

    if (!g) return res.json({ active: false });

    // Auto-cierre lazy SOLO por expiración o por reservas (cupo/budget).
    // Si está en closed_max/closed_budget pero todavía no venció, no lo cerramos a closed_expired.
    if (g.status === 'active') {
      const fresh = await _maybeCloseGiveaway({ ...g });
      if (fresh.status === 'closed_expired' || fresh.status === 'cancelled') {
        return res.json({ active: false });
      }
      // Si se cerró por cupo/budget acá, sigue siendo soldOut (continuamos abajo).
      g.status = fresh.status;
      g.claimedCount = fresh.claimedCount;
      g.totalGiven = fresh.totalGiven;
    }

    // Detectar sold-out.
    const soldOut = g.status === 'closed_max' || g.status === 'closed_budget';
    const soldOutReason = g.status === 'closed_max' ? 'max'
                       : g.status === 'closed_budget' ? 'budget'
                       : null;

    // Chequear si este user ya reclamo.
    const existing = await MoneyGiveawayClaim.findOne({
      giveawayId: g.id,
      $or: [{ username }, { userId }]
    }).lean();

    // Si el regalo exige saldo cero, pre-chequeamos para que el frontend
    // pueda mostrar "no disponible" en vez del botón. No tira error si el
    // lookup falla (el rechazo final está en el endpoint de claim).
    // Si ya está soldOut o el user ya reclamó, no hace falta el lookup.
    let notEligibleReason = null;
    if (g.requireZeroBalance && !soldOut && !existing) {
      try {
        const jgUser = await Promise.race([
          jugaygana.getUserInfoByName(username),
          new Promise((_, reject) => setTimeout(() => reject(new Error('lookup-timeout')), 4000))
        ]);
        const userBalance = (jgUser && Number.isFinite(Number(jgUser.balance))) ? Number(jgUser.balance) : null;
        if (userBalance != null && userBalance > 0) {
          notEligibleReason = 'has_balance';
        }
      } catch (_) {
        // Si falla el lookup acá, NO marcamos no-elegible (no queremos
        // ocultar un regalo válido por un blip). El claim hará el check
        // hard al momento de reclamar.
      }
    }

    res.json({
      active: true,
      id: g.id,
      amount: g.amount,
      totalBudget: g.totalBudget,
      maxClaims: g.maxClaims,
      claimedCount: g.claimedCount || 0,
      totalGiven: g.totalGiven || 0,
      expiresAt: g.expiresAt,
      alreadyClaimed: !!existing,
      claimedAmount: existing ? existing.amount : null,
      claimedAt: existing ? existing.claimedAt : null,
      notificationHistoryId: g.notificationHistoryId || null,
      requireZeroBalance: !!g.requireZeroBalance,
      notEligibleReason,
      soldOut,
      soldOutReason
    });
  } catch (error) {
    logger.error(`/api/money-giveaway/active error: ${error.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// POST claim: el user reclama el regalo activo.
app.post('/api/money-giveaway/claim', authMiddleware, async (req, res) => {
  try {
    const userId = req.user.userId;
    const username = req.user.username;

    // Buscar EL giveaway destinado a ESTE user (mismo criterio que /active):
    // 1) whitelist explícito → 2) público con prefix match → 3) público sin prefix.
    // Sin esto, si la estrategia automática creó varios giveaways en
    // paralelo (uno por tier), users de tiers anteriores quedaban
    // afuera por el .sort createdAt:-1 y no podían reclamar.
    const usernameLower = username.toLowerCase();
    const baseFilter = { status: 'active' };
    let g = await MoneyGiveaway.findOne({
      ...baseFilter,
      audienceWhitelist: usernameLower
    }).sort({ createdAt: -1 });

    if (!g) {
      const candidates = await MoneyGiveaway.find({
        ...baseFilter,
        $or: [
          { audienceWhitelist: null },
          { audienceWhitelist: { $size: 0 } },
          { audienceWhitelist: { $exists: false } }
        ]
      }).sort({ createdAt: -1 }).limit(10);
      for (const c of candidates) {
        if (!c.prefix || usernameLower.startsWith(String(c.prefix).toLowerCase())) {
          g = c;
          break;
        }
      }
    }

    if (!g) {
      return res.json({ success: false, message: 'No hay regalo activo en este momento.', closed: true });
    }
    // Como ya filtramos por whitelist en la query, no hace falta re-checkear acá.

    // Filtro por saldo cero (regalo exclusivo para clientes sin plata).
    // Hard-fail si JUGAYGANA no responde — preferimos no dar el regalo a
    // dejarlo entrar sin verificar. Lookup con timeout corto para no colgar.
    if (g.requireZeroBalance) {
      let jgUser = null;
      try {
        jgUser = await Promise.race([
          jugaygana.getUserInfoByName(username),
          new Promise((_, reject) => setTimeout(() => reject(new Error('balance-lookup-timeout')), 6000))
        ]);
      } catch (lookupErr) {
        logger.warn(`[giveaway/claim] no se pudo verificar saldo de ${username}: ${lookupErr.message}`);
        return res.status(503).json({
          success: false,
          message: 'No pudimos verificar tu saldo en este momento. Intentá en unos minutos.',
          retry: true
        });
      }
      const userBalance = (jgUser && Number.isFinite(Number(jgUser.balance))) ? Number(jgUser.balance) : null;
      if (userBalance == null) {
        // No pudimos resolver el balance (user no encontrado en JUGAYGANA, etc).
        // Fail-safe: rechazar.
        logger.warn(`[giveaway/claim] balance no resolvable para ${username} — rechazo`);
        return res.status(403).json({
          success: false,
          message: 'No pudimos verificar tu cuenta. Contactanos por WhatsApp.',
          notEligible: true
        });
      }
      if (userBalance > 0) {
        return res.status(403).json({
          success: false,
          message: 'No disponible. Tenés saldo en tu cuenta. Regalo exclusivo para clientes sin saldo.',
          notEligible: true,
          reason: 'has_balance'
        });
      }
    }

    // Auto-cierre lazy.
    if (new Date(g.expiresAt).getTime() <= Date.now()) {
      g.status = 'closed_expired';
      await g.save().catch(() => {});
      return res.json({ success: false, message: 'El tiempo del regalo terminó.', closed: true });
    }
    if ((g.totalGiven || 0) >= g.totalBudget) {
      g.status = 'closed_budget';
      await g.save().catch(() => {});
      return res.json({ success: false, message: 'Se acabó la plata del regalo.', closed: true });
    }
    if ((g.claimedCount || 0) >= g.maxClaims) {
      g.status = 'closed_max';
      await g.save().catch(() => {});
      return res.json({ success: false, message: 'Se llegó al máximo de personas.', closed: true });
    }

    // Lock distribuido por user para serializar reintentos.
    if (!await acquireRefundLock(userId, 'money_giveaway_' + g.id)) {
      return res.json({ success: false, message: '⏳ Ya estás procesando el reclamo. Esperá unos segundos…', processing: true });
    }

    try {
      // Pre-check: ya reclamo? (busca por userId O username, mismo patron
      // que welcome bonus).
      const existing = await MoneyGiveawayClaim.findOne({
        giveawayId: g.id,
        $or: [{ userId }, { username }]
      }).lean();
      if (existing) {
        return res.json({ success: false, message: 'Ya reclamaste este regalo.', alreadyClaimed: true });
      }

      // 1) RESERVA ATOMICA del slot ANTES de cualquier escritura. Si el
      //    cap (claimedCount/totalBudget) ya esta agotado, el update
      //    condicional no matchea y devuelve null → no creditamos ni
      //    insertamos, asi nunca podemos pasarnos. Esto cubre el caso
      //    de N usuarios tocando simultaneamente cuando quedan M<N slots.
      const reserved = await MoneyGiveaway.findOneAndUpdate(
        {
          id: g.id,
          status: 'active',
          $expr: {
            $and: [
              { $lt: ['$claimedCount', '$maxClaims'] },
              { $lte: [{ $add: ['$totalGiven', g.amount] }, '$totalBudget'] }
            ]
          }
        },
        { $inc: { claimedCount: 1, totalGiven: g.amount } },
        { new: true }
      ).lean();
      if (!reserved) {
        // Algun cap se cumplio en el momento. Disparar cierre lazy y
        // avisar al user con mensaje correcto.
        const fresh = await MoneyGiveaway.findOne({ id: g.id }).lean();
        if (fresh) await _maybeCloseGiveaway({ ...fresh });
        return res.json({ success: false, message: 'Se acabaron los cupos del regalo.', closed: true });
      }

      // 2) INSERT del claim. Si choca con el unique index → este user ya
      //    reclamo en otra request paralela; tenemos que devolver el slot
      //    reservado (decrement) y avisar.
      let claim;
      try {
        claim = await MoneyGiveawayClaim.create({
          id: uuidv4(),
          giveawayId: g.id,
          userId,
          username,
          amount: g.amount,
          claimedAt: new Date()
        });
      } catch (e) {
        if (e && e.code === 11000) {
          // Devolver el slot que reservamos.
          await MoneyGiveaway.updateOne(
            { id: g.id },
            { $inc: { claimedCount: -1, totalGiven: -g.amount } }
          ).catch(() => {});
          return res.json({ success: false, message: 'Ya reclamaste este regalo.', alreadyClaimed: true });
        }
        // Otro error: tambien revertir slot.
        await MoneyGiveaway.updateOne(
          { id: g.id },
          { $inc: { claimedCount: -1, totalGiven: -g.amount } }
        ).catch(() => {});
        throw e;
      }

      // 3) Acreditar en JUGAYGANA.
      const depositResult = await jugaygana.creditUserBalance(username, g.amount);
      if (!depositResult.success) {
        try {
          claim.status = 'pending_credit_failed';
          claim.creditError = String(depositResult.error || 'Error desconocido').slice(0, 500);
          await claim.save();
        } catch (_) {}
        // El row de claim queda 'pending_credit_failed' (bloquea reclamo
        // duplicado de este user). Pero el slot del giveaway SI se devuelve
        // — sino los caps se contaminan con plata no acreditada y el
        // giveaway cierra antes de tiempo. _totalGiveawayCache se basa
        // en MoneyGiveawayClaim status='completed' asi que estos rows ya
        // estan excluidos del agregado.
        await MoneyGiveaway.updateOne(
          { id: g.id },
          { $inc: { claimedCount: -1, totalGiven: -g.amount } }
        ).catch(() => {});
        logger.error(`[GIVEAWAY] credit fallo para ${username} (giveaway ${g.id}): ${depositResult.error} - claim ${claim._id} marcado pending_credit_failed, slot devuelto`);
        return res.json({
          success: false,
          message: 'Hubo un problema al acreditar. El admin lo está revisando — no reintentes.',
          pendingReview: true
        });
      }

      // 4) Persistir transactionId.
      try {
        claim.transactionId = depositResult.data?.transfer_id || depositResult.data?.transferId || null;
        await claim.save();
      } catch (_) {}

      // 5) Chequear si tras este claim se cerro el giveaway por cap.
      await _maybeCloseGiveaway({ ...reserved });

      // Invalidar el cache del total (lo lee /api/giveaway-stats/total)
      // para que el home muestre el numero actualizado sin esperar 5min.
      _totalGiveawayCache.ts = 0;

      // Tambien sumar al contador del row de NotificationHistory si la
      // giveaway esta vinculada.
      if (g.notificationHistoryId) {
        try {
          await NotificationHistory.updateOne(
            { id: g.notificationHistoryId },
            { $inc: { giveawayClaims: 1 } }
          );
          // Si la difusión es de estrategia automática, marcar
          // strategyDetails.<este_user>.claimed = true. Sirve para
          // ver en ROI por difusión quién reclamó y quién no.
          await NotificationHistory.updateOne(
            { id: g.notificationHistoryId, 'strategyDetails.username': username },
            {
              $set: {
                'strategyDetails.$.claimed': true,
                'strategyDetails.$.claimedAt': new Date(),
                'strategyDetails.$.claimedAmount': g.amount
              }
            }
          ).catch(() => {});
        } catch (_) {}
      }

      // Tambien crear un Transaction para que aparezca en reportes.
      try {
        await Transaction.create({
          id: uuidv4(),
          type: 'refund',
          amount: g.amount,
          username,
          description: 'Regalo de difusión',
          transactionId: depositResult.data?.transfer_id || depositResult.data?.transferId,
          timestamp: new Date()
        });
      } catch (_) {}

      res.json({
        success: true,
        message: `¡Reclamaste $${Number(g.amount).toLocaleString('es-AR')}!`,
        amount: g.amount
      });
    } finally {
      releaseRefundLock(userId, 'money_giveaway_' + g.id);
    }
  } catch (error) {
    console.error('Error reclamando giveaway:', error);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// POST admin: crear/reemplazar el giveaway. Marca cualquier activo como
// 'cancelled' y crea uno nuevo. Body: { amount, totalBudget, maxClaims,
// durationMinutes, prefix?, notificationHistoryId? }.
app.post('/api/admin/money-giveaway', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    if (req.user.role !== 'admin') {
      return res.status(403).json({ error: 'Solo el admin principal puede crear regalos de plata.' });
    }
    const { amount, totalBudget, maxClaims, durationMinutes, prefix, notificationHistoryId, requireZeroBalance } = req.body || {};
    const a = Number(amount), b = Number(totalBudget), m = Number(maxClaims), d = Number(durationMinutes);
    if (!isFinite(a) || a <= 0) return res.status(400).json({ error: 'Monto por persona inválido' });
    if (!isFinite(b) || b < a) return res.status(400).json({ error: 'Presupuesto total inválido (debe ser >= monto por persona)' });
    if (!isFinite(m) || m < 1) return res.status(400).json({ error: 'Cantidad máxima inválida' });
    if (!isFinite(d) || d < 10 || d > 60 || d % 10 !== 0) {
      return res.status(400).json({ error: 'Duración inválida (10-60 minutos en bloques de 10)' });
    }
    // Caps anti-fat-finger / anti-cookie-robada. Si el admin necesita superarlos
    // hay que tocar el server a proposito — un typo o un atacante con la cookie
    // no puede drenar JUGAYGANA con un giveaway de $999.999.999 sin pasar por aca.
    if (a > GIVEAWAY_MAX_AMOUNT_PER_USER) {
      return res.status(400).json({ error: `Monto por persona excede el tope de seguridad ($${GIVEAWAY_MAX_AMOUNT_PER_USER.toLocaleString('es-AR')})` });
    }
    if (b > GIVEAWAY_MAX_TOTAL_BUDGET) {
      return res.status(400).json({ error: `Presupuesto total excede el tope de seguridad ($${GIVEAWAY_MAX_TOTAL_BUDGET.toLocaleString('es-AR')})` });
    }
    if (m > GIVEAWAY_MAX_CLAIMS) {
      return res.status(400).json({ error: `Cantidad máxima excede el tope de seguridad (${GIVEAWAY_MAX_CLAIMS})` });
    }

    // Cerrar SOLO giveaways manuales activos previos. Los de estrategia
    // automática y de reglas aprobadas son intocables — corren en su
    // propio carril con audienceWhitelist y strategySource distinto.
    await MoneyGiveaway.updateMany(
      { status: 'active', $or: [{ strategySource: 'manual' }, { strategySource: null }, { strategySource: { $exists: false } }] },
      { $set: { status: 'cancelled' } }
    );

    const g = await MoneyGiveaway.create({
      id: uuidv4(),
      amount: a,
      totalBudget: b,
      maxClaims: m,
      expiresAt: new Date(Date.now() + d * 60 * 1000),
      createdBy: req.user.username || null,
      prefix: prefix && typeof prefix === 'string' && prefix.trim() ? prefix.trim() : null,
      notificationHistoryId: notificationHistoryId || null,
      requireZeroBalance: !!requireZeroBalance,
      strategySource: 'manual',
      status: 'active'
    });
    res.json({ success: true, giveaway: g.toObject() });
  } catch (error) {
    logger.error(`POST /api/admin/money-giveaway error: ${error.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// GET admin: ver el giveaway activo + sus claims.
app.get('/api/admin/money-giveaway', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const g = await MoneyGiveaway.findOne({ status: 'active' }).sort({ createdAt: -1 }).lean();
    if (!g) return res.json({ giveaway: null, claims: [] });
    const claims = await MoneyGiveawayClaim.find({ giveawayId: g.id })
      .sort({ claimedAt: -1 }).lean();

    // Hidratar con la audiencia alcanzada por la notif vinculada (si existe).
    // Útil para que el admin sepa "cuánta gente compite por el regalo".
    let audience = null;
    if (g.notificationHistoryId) {
      try {
        const hist = await NotificationHistory.findOne({ id: g.notificationHistoryId })
          .select('totalUsers successCount failureCount audienceType audiencePrefix')
          .lean();
        if (hist) {
          audience = {
            totalUsers: hist.totalUsers || 0,        // a cuántos se intentó
            delivered: hist.successCount || 0,       // a cuántos llegó push real
            failed: hist.failureCount || 0,          // tokens muertos / errores
            audienceType: hist.audienceType || 'all',
            audiencePrefix: hist.audiencePrefix || null
          };
        }
      } catch (auxErr) {
        logger.warn(`[admin/money-giveaway] no se pudo hidratar audiencia: ${auxErr.message}`);
      }
    }

    res.json({ giveaway: g, claims, audience });
  } catch (error) {
    logger.error(`GET /api/admin/money-giveaway error: ${error.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// GET publico (auth): suma TOTAL de plata regalada via money giveaways
// (todo el historico, sin filtro de fecha). Lo usa el home para
// mostrar "Total plata regalada a usuarios con app + notifs: $X".
// Cache simple in-memory de 5 min para no recalcular en cada hit.
let _totalGiveawayCache = { ts: 0, amount: 0, count: 0, breakdown: null };
app.get('/api/giveaway-stats/total', authMiddleware, async (req, res) => {
  try {
    const NOW = Date.now();
    // 60s TTL: balance entre carga (no recalcular en cada hit) y frescura
    // (que el numero del home se vea actualizado pronto despues de que
    // alguien reclame). Cada claim exitoso ademas invalida el cache.
    const TTL = 60 * 1000;
    if (NOW - _totalGiveawayCache.ts < TTL && _totalGiveawayCache.breakdown) {
      return res.json({
        amount: _totalGiveawayCache.amount,
        count: _totalGiveawayCache.count,
        breakdown: _totalGiveawayCache.breakdown,
        cached: true
      });
    }

    // Sumamos TODA la plata que la casa regaló a usuarios desde la app:
    //   1) Money giveaways (campañas de difusión) — MoneyGiveawayClaim status=completed
    //   2) Bono de bienvenida ($5.000 actual; $2.000/$10.000 históricos) — RefundClaim type=welcome_install (claims completados)
    //   3) Reembolsos daily/weekly/monthly — RefundClaim type ∈ {daily,weekly,monthly}
    //
    // Solo cuentan claims acreditados (status='completed' / status default
    // en RefundClaim) — los pending_credit_failed NO suman porque la plata
    // nunca se acreditó realmente al usuario.
    const [giveawayAgg, refundAgg] = await Promise.all([
      MoneyGiveawayClaim.aggregate([
        { $match: { status: 'completed' } },
        { $group: { _id: null, total: { $sum: '$amount' }, count: { $sum: 1 } } }
      ]),
      RefundClaim.aggregate([
        { $match: { status: { $ne: 'pending_credit_failed' } } },
        {
          $group: {
            _id: '$type',
            total: { $sum: '$amount' },
            count: { $sum: 1 }
          }
        }
      ])
    ]);

    const giveawayAmount = giveawayAgg.length > 0 ? Number(giveawayAgg[0].total || 0) : 0;
    const giveawayCount = giveawayAgg.length > 0 ? Number(giveawayAgg[0].count || 0) : 0;

    const breakdown = {
      giveaway: { amount: giveawayAmount, count: giveawayCount },
      welcome:  { amount: 0, count: 0 },
      daily:    { amount: 0, count: 0 },
      weekly:   { amount: 0, count: 0 },
      monthly:  { amount: 0, count: 0 }
    };
    for (const r of refundAgg) {
      const key = r._id; // 'welcome_install' | 'daily' | 'weekly' | 'monthly'
      const bucket = key === 'welcome_install' ? 'welcome' : key;
      if (breakdown[bucket]) {
        breakdown[bucket].amount = Number(r.total || 0);
        breakdown[bucket].count = Number(r.count || 0);
      }
    }

    const amount = giveawayAmount + breakdown.welcome.amount + breakdown.daily.amount + breakdown.weekly.amount + breakdown.monthly.amount;
    const count = giveawayCount + breakdown.welcome.count + breakdown.daily.count + breakdown.weekly.count + breakdown.monthly.count;

    _totalGiveawayCache = { ts: NOW, amount, count, breakdown };
    res.json({ amount, count, breakdown, cached: false });
  } catch (error) {
    logger.error(`/api/giveaway-stats/total error: ${error.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// ============================================
// ANALÍTICA DE GIVEAWAYS — endpoints para el panel de Top estadísticas → 🎁 Regalos
// ============================================

// GET /api/admin/giveaways/history
// Lista TODOS los giveaways (active + closed) con métricas computadas.
// Query params:
//   - limit (default 100)
//   - from / to: rango ISO de createdAt
//   - status: filtro de estado
//   - prefix: filtro por prefijo de targeting
app.get('/api/admin/giveaways/history', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const limit = Math.min(parseInt(req.query.limit, 10) || 100, 500);
    const filter = {};
    if (req.query.status) filter.status = String(req.query.status);
    if (req.query.prefix) filter.prefix = String(req.query.prefix).trim();
    if (req.query.from || req.query.to) {
      filter.createdAt = {};
      if (req.query.from) filter.createdAt.$gte = new Date(String(req.query.from));
      if (req.query.to) filter.createdAt.$lte = new Date(String(req.query.to));
    }

    const giveaways = await MoneyGiveaway.find(filter)
      .sort({ createdAt: -1 })
      .limit(limit)
      .lean();

    // Computar métricas adicionales por giveaway:
    //   - claimedPct: % de maxClaims consumido
    //   - budgetPct: % de totalBudget consumido
    //   - durationToCloseMinutes: tiempo desde createdAt hasta el cierre (updatedAt
    //     si status != 'active', null si sigue activo). Como no tenemos un campo
    //     `closedAt` dedicado, usamos updatedAt — Mongoose lo refresca cada vez
    //     que el doc cambia, y el cierre es el último cambio típico.
    //   - notification: data básica de la notif vinculada (si existe)
    const enriched = giveaways.map(g => {
      const claimedPct = g.maxClaims > 0 ? Math.round((g.claimedCount / g.maxClaims) * 100) : 0;
      const budgetPct = g.totalBudget > 0 ? Math.round((g.totalGiven / g.totalBudget) * 100) : 0;
      const isClosed = g.status !== 'active';
      const closedAt = isClosed ? (g.updatedAt || null) : null;
      const durationToCloseMinutes = (isClosed && closedAt && g.createdAt)
        ? Math.round((new Date(closedAt) - new Date(g.createdAt)) / 60000)
        : null;
      const remainingBudget = Math.max(0, (g.totalBudget || 0) - (g.totalGiven || 0));
      const remainingClaims = Math.max(0, (g.maxClaims || 0) - (g.claimedCount || 0));
      return {
        ...g,
        claimedPct,
        budgetPct,
        closedAt,
        durationToCloseMinutes,
        remainingBudget,
        remainingClaims
      };
    });

    // Stats generales del rango filtrado
    const totalAgg = giveaways.reduce((acc, g) => {
      acc.totalGiveaways += 1;
      acc.totalGiven += g.totalGiven || 0;
      acc.totalClaims += g.claimedCount || 0;
      acc.totalBudgetSet += g.totalBudget || 0;
      return acc;
    }, { totalGiveaways: 0, totalGiven: 0, totalClaims: 0, totalBudgetSet: 0 });

    // Total usuarios únicos que reclamaron en CUALQUIERA de estos giveaways.
    const giveawayIds = giveaways.map(g => g.id);
    let uniqueClaimers = 0;
    if (giveawayIds.length > 0) {
      const distinctAgg = await MoneyGiveawayClaim.aggregate([
        { $match: { giveawayId: { $in: giveawayIds }, status: 'completed' } },
        { $group: { _id: '$username' } },
        { $count: 'count' }
      ]);
      uniqueClaimers = distinctAgg.length > 0 ? distinctAgg[0].count : 0;
    }

    res.json({
      giveaways: enriched,
      totals: { ...totalAgg, uniqueClaimers }
    });
  } catch (error) {
    logger.error(`/api/admin/giveaways/history: ${error.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// GET /api/admin/giveaways/:id/claims — drill-down de un giveaway específico
app.get('/api/admin/giveaways/:id/claims', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const giveaway = await MoneyGiveaway.findOne({ id: req.params.id }).lean();
    if (!giveaway) return res.status(404).json({ error: 'Giveaway no encontrado' });

    const claims = await MoneyGiveawayClaim.find({ giveawayId: giveaway.id })
      .sort({ claimedAt: 1 }) // orden cronológico para ver curva de reclamos
      .lean();

    // Si el giveaway está cerrado, calculamos cuánto tardó cada decil de claims.
    // Útil para ver "se agotó en los primeros X minutos" vs "vino lento".
    let claimVelocity = null;
    if (claims.length > 0 && giveaway.createdAt) {
      const startMs = new Date(giveaway.createdAt).getTime();
      const lastClaim = claims[claims.length - 1];
      const lastMs = new Date(lastClaim.claimedAt).getTime();
      claimVelocity = {
        firstClaimMinutes: Math.round((new Date(claims[0].claimedAt).getTime() - startMs) / 60000),
        lastClaimMinutes: Math.round((lastMs - startMs) / 60000),
        avgPerMinute: ((lastMs - startMs) / 60000) > 0
          ? Number((claims.length / ((lastMs - startMs) / 60000)).toFixed(2))
          : 0
      };
    }

    res.json({
      giveaway,
      claims,
      claimVelocity
    });
  } catch (error) {
    logger.error(`/api/admin/giveaways/:id/claims: ${error.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// GET /api/admin/giveaways/user/:username — todos los reclamos de un usuario
app.get('/api/admin/giveaways/user/:username', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const username = String(req.params.username || '').trim().toLowerCase();
    if (!username) return res.status(400).json({ error: 'Falta username' });

    const claims = await MoneyGiveawayClaim.find({
      username: { $regex: new RegExp('^' + escapeRegex(username) + '$', 'i') },
      status: 'completed'
    }).sort({ claimedAt: -1 }).lean();

    if (claims.length === 0) {
      return res.json({ username, totalClaimed: 0, claimsCount: 0, claims: [] });
    }

    // Hidratar cada claim con info del giveaway correspondiente
    const giveawayIds = [...new Set(claims.map(c => c.giveawayId))];
    const giveaways = await MoneyGiveaway.find({ id: { $in: giveawayIds } })
      .select('id amount totalBudget maxClaims expiresAt createdAt prefix status')
      .lean();
    const giveawayById = new Map(giveaways.map(g => [g.id, g]));

    const enrichedClaims = claims.map(c => ({
      ...c,
      giveaway: giveawayById.get(c.giveawayId) || null
    }));

    const totalClaimed = claims.reduce((sum, c) => sum + (c.amount || 0), 0);

    res.json({
      username,
      totalClaimed,
      claimsCount: claims.length,
      claims: enrichedClaims
    });
  } catch (error) {
    logger.error(`/api/admin/giveaways/user: ${error.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// DELETE admin: cancelar el giveaway activo.
