// ===== Worker que dispara las notificaciones programadas =====
// Cada 60s busca pending vencidas y las ejecuta. Marca status='sent' o
// 'failed' segun resultado. Anti-overlap con flag in-memory para no
// disparar 2 veces si la corrida anterior aun no termino.
let _schedulerRunning = false;
async function _runScheduledNotifications() {
  if (_schedulerRunning) return;
  _schedulerRunning = true;
  try {
    // Recuperar rows que quedaron 'processing' por mas de 5 min — significa
    // que el server crasheo a mitad de ejecutar. Las volvemos a 'pending'
    // para que un proximo ciclo las reintente.
    const stuck = new Date(Date.now() - 5 * 60 * 1000);
    const recovered = await ScheduledNotification.updateMany(
      { status: 'processing', processingStartedAt: { $lt: stuck } },
      { $set: { status: 'pending' }, $unset: { processingStartedAt: 1 } }
    );
    if (recovered.modifiedCount > 0) {
      logger.warn(`[scheduler] ${recovered.modifiedCount} notif(s) atascadas en 'processing' devueltas a 'pending' para reintento`);
    }

    const due = await ScheduledNotification.find({
      status: 'pending',
      scheduledFor: { $lte: new Date() }
    }).limit(20).lean();
    for (const sched of due) {
      // Atomic claim: marcamos 'processing' (no 'sent'). Solo flipeamos a
      // 'sent' DESPUES de que _executeScheduledNotification retorne con
      // exito. Si crasheamos antes, queda 'processing' con timestamp y el
      // recovery del proximo ciclo lo vuelve a tomar.
      const now = new Date();
      const claimed = await ScheduledNotification.findOneAndUpdate(
        { id: sched.id, status: 'pending' },
        { $set: { status: 'processing', processingStartedAt: now } },
        { new: true }
      );
      if (!claimed) continue;

      try {
        await _executeScheduledNotification(sched);
        await ScheduledNotification.updateOne(
          { id: sched.id },
          { $set: { status: 'sent', executedAt: new Date() }, $unset: { processingStartedAt: 1 } }
        ).catch(() => {});
        logger.info(`[scheduler] notif ${sched.id} ejecutada (${sched.title.slice(0, 40)})`);
      } catch (e) {
        logger.error(`[scheduler] error ejecutando ${sched.id}: ${e.message}`);
        await ScheduledNotification.updateOne(
          { id: sched.id },
          { $set: { status: 'failed', errorMsg: e.message.slice(0, 500) }, $unset: { processingStartedAt: 1 } }
        ).catch(() => {});
      }
    }
  } catch (e) {
    logger.error(`[scheduler] error global: ${e.message}`);
  } finally {
    _schedulerRunning = false;
  }
}
// Helper que replica el flujo del admin: send-all + crear promo o giveaway.
async function _executeScheduledNotification(sched) {
  const { sendNotificationToAllUsers } = require('./src/services/notificationService');

  // 1) Construir filter por target (single user) o prefix.
  // targetUsername gana sobre audiencePrefix — match EXACTO (no prefix).
  const filter = {};
  if (sched.targetUsername) {
    const safe = sched.targetUsername.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    filter.username = { $regex: '^' + safe + '$', $options: 'i' };
  } else if (sched.audiencePrefix) {
    const safe = sched.audiencePrefix.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    filter.username = { $regex: '^' + safe, $options: 'i' };
  }

  // 2) Construir body: si es giveaway, append automatico del monto.
  let body = sched.body;
  if (sched.extraType === 'giveaway' && sched.giveawayAmount) {
    body = body + ` · 🎁 Te regalamos $${Number(sched.giveawayAmount).toLocaleString('es-AR')} — abrí la app y reclamalo`;
  }

  // 3) Enviar push.
  const data = { source: 'admin-scheduled', tag: 'admin-broadcast' };
  if (sched.extraType === 'promo') {
    data.promoCode = sched.promoCode;
    data.promoMessage = sched.promoMessage;
    data.promoExpiresIn = String(sched.promoDurationHours);
  } else if (sched.extraType === 'giveaway') {
    data.giveawayAmount = String(sched.giveawayAmount);
    data.giveawayDurationMinutes = String(sched.giveawayDurationMinutes);
  }
  const sendResult = await sendNotificationToAllUsers(User, sched.title, body, data, filter);

  // 4) Crear row en NotificationHistory.
  let historyId = null;
  try {
    const histType = sched.extraType === 'promo' ? 'whatsapp_promo'
                   : sched.extraType === 'giveaway' ? 'money_giveaway'
                   : 'plain';
    const promoExpiresAt = sched.extraType === 'promo'
      ? new Date(Date.now() + sched.promoDurationHours * 3600 * 1000)
      : null;
    const giveawayExpiresAt = sched.extraType === 'giveaway'
      ? new Date(Date.now() + sched.giveawayDurationMinutes * 60 * 1000)
      : null;
    const hist = await NotificationHistory.create({
      id: uuidv4(),
      sentAt: new Date(),
      scheduledFor: sched.scheduledFor,
      audienceType: sched.targetUsername ? 'single' : (sched.audiencePrefix ? 'prefix' : 'all'),
      audiencePrefix: sched.audiencePrefix,
      title: sched.title,
      body,
      type: histType,
      promoMessage: sched.promoMessage,
      promoCode: sched.promoCode,
      promoExpiresAt,
      giveawayAmount: sched.giveawayAmount,
      giveawayDurationMins: sched.giveawayDurationMinutes,
      giveawayExpiresAt,
      totalUsers: sendResult?.totalUsers || 0,
      successCount: sendResult?.successCount || 0,
      failureCount: sendResult?.failureCount || 0,
      cleanedTokens: sendResult?.cleanedTokens || 0,
      sentBy: sched.createdBy || null
    });
    historyId = hist.id;
    await ScheduledNotification.updateOne({ id: sched.id }, { $set: { notificationHistoryId: historyId } });
  } catch (e) {
    logger.warn(`[scheduler] no se pudo crear historial para ${sched.id}: ${e.message}`);
  }

  // 5) Crear promo o giveaway si aplica, vinculados al historyId.
  if (sched.extraType === 'promo') {
    const promo = {
      id: uuidv4(),
      message: sched.promoMessage,
      code: sched.promoCode,
      expiresAt: new Date(Date.now() + sched.promoDurationHours * 3600 * 1000).toISOString(),
      createdAt: new Date().toISOString(),
      createdBy: sched.createdBy || null,
      prefix: sched.audiencePrefix,
      notificationHistoryId: historyId
    };
    await setConfig(PROMO_ALERT_KEY, promo);
  } else if (sched.extraType === 'giveaway') {
    // Cancelar SOLO los giveaways manuales activos (no los de estrategia
    // automática ni los aprobados de reglas). Sin este filtro, un push
    // programado del admin cancelaba la campaña netwin/tier-bonus en curso.
    await MoneyGiveaway.updateMany(
      { status: 'active', $or: [{ strategySource: 'manual' }, { strategySource: null }, { strategySource: { $exists: false } }] },
      { $set: { status: 'cancelled' } }
    );
    await MoneyGiveaway.create({
      id: uuidv4(),
      amount: sched.giveawayAmount,
      totalBudget: sched.giveawayBudget,
      maxClaims: sched.giveawayMaxClaims,
      expiresAt: new Date(Date.now() + sched.giveawayDurationMinutes * 60 * 1000),
      createdBy: sched.createdBy || null,
      prefix: sched.audiencePrefix,
      notificationHistoryId: historyId,
      requireZeroBalance: !!sched.giveawayRequireZeroBalance,
      strategySource: 'manual',
      status: 'active'
    });
  }
}
// Limpieza one-shot al boot: cancelar notifs pendientes del sistema viejo
// (strategy-wave:*) que ya no se usa. Si quedan en cola desde antes del
// switch al calendario mensual, el worker las dispararía con copys viejos.
setTimeout(async () => {
  try {
    const r = await ScheduledNotification.updateMany(
      { status: 'pending', createdBy: { $regex: /^strategy-wave:/ } },
      { $set: { status: 'cancelled' } }
    );
    if (r.modifiedCount > 0) {
      logger.info(`[BOOT] Canceladas ${r.modifiedCount} notifs pendientes del sistema viejo (strategy-wave:*).`);
    }
  } catch (e) {
    logger.warn(`[BOOT] No se pudo limpiar pendientes legacy: ${e.message}`);
  }
}, 5 * 1000);

// Arrancar el scheduler 30s despues del boot y correr cada 60s.
setTimeout(() => { _runScheduledNotifications(); }, 30 * 1000);
setInterval(() => { _runScheduledNotifications(); }, 60 * 1000);

// ============================================================
// SNAPSHOT DIARIO DE SALUD DEL CANAL DE PUSH
// ============================================================
// Cada día a las 00:05 ART contamos cuántos usuarios tienen PWA instalada
// (algún fcmToken con context='standalone') y notificaciones concedidas
// (algún fcmToken con notifPermission='granted'). Es la métrica que importa
// para saber si el canal de re-engagement crece o se erosiona.
//
// Bootstrap: al primer arranque después del deploy, si no hay snapshots,
// reconstruimos los últimos 30 días aproximadamente desde fcmToken.updatedAt.
// La aproximación NO resta desinstalaciones del pasado, así que la curva
// histórica es un piso, no un valor exacto. Desde el primer cron real, los
// snapshots son exactos.
// ============================================================
function _appNotifTodayKey() {
  const { year, month, day } = _getArgentinaParts();
  return `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
}

function _appNotifKeyFromMs(ms) {
  const { year, month, day } = _getArgentinaParts(new Date(ms));
  return `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
}

// Cuenta los 4 totales con la misma lógica que /api/admin/reports/equipment
// para que las cifras sean consistentes entre paneles.
async function _computeAppNotifTotalsNow() {
  const users = await User.find(
    { role: 'user' },
    { fcmTokenContext: 1, notifPermission: 1, fcmTokens: 1, _id: 0 }
  ).lean();

  let withApp = 0, withNotifs = 0, withBoth = 0;
  for (const u of users) {
    const tokens = Array.isArray(u.fcmTokens) ? u.fcmTokens : [];
    const standaloneTokens = tokens.filter(t => t && t.context === 'standalone');
    const hasApp = (u.fcmTokenContext === 'standalone' || standaloneTokens.length > 0);
    const hasNotifs = (
      u.notifPermission === 'granted' ||
      tokens.some(t => t && t.notifPermission === 'granted')
    );
    if (hasApp) withApp++;
    if (hasNotifs) withNotifs++;
    if (hasApp && hasNotifs) withBoth++;
  }
  return { totalUsers: users.length, withApp, withNotifs, withBoth };
}

async function _writeAppNotifSnapshot(dateKey, source = 'cron') {
  try {
    const totals = await _computeAppNotifTotalsNow();
    await AppNotifSnapshot.findOneAndUpdate(
      { dateKey },
      { $set: { ...totals, source } },
      { upsert: true, new: true }
    );
    logger.info(`[app-notif-snapshot] ${dateKey} (${source}): app=${totals.withApp} notif=${totals.withNotifs} both=${totals.withBoth} / ${totals.totalUsers}`);
  } catch (err) {
    logger.error(`[app-notif-snapshot] error: ${err.message}`);
  }
}

// Reconstrucción aproximada de los últimos 30 días leyendo fcmToken.updatedAt.
// Para cada día D del rango, contamos usuarios donde:
//  - createdAt <= fin del día D, Y
//  - tienen al menos un fcmToken con context='standalone' Y updatedAt <= fin
//    del día D, Y notifPermission='granted' (o el campo legacy).
// Limitación: usuarios que se instalaron Y desinstalaron antes del rango
// no figuran; usuarios que se instalaron en el rango y luego desinstalaron
// figurarán como instalados (sobrestima). Es un piso aproximado.
async function _bootstrapAppNotifSnapshots() {
  try {
    const existingCount = await AppNotifSnapshot.countDocuments({});
    if (existingCount > 0) return; // ya hay datos, no rehacemos

    const todayKey = _appNotifTodayKey();
    const ART_OFFSET_MS = 3 * 60 * 60 * 1000; // ART es UTC-3
    const todayStartArtMs = new Date(todayKey + 'T00:00:00Z').getTime() + ART_OFFSET_MS;

    // Traemos la base completa una sola vez (heavy pero one-shot).
    const users = await User.find(
      { role: 'user' },
      { createdAt: 1, fcmTokenContext: 1, notifPermission: 1, fcmTokens: 1, _id: 0 }
    ).lean();

    const ops = [];
    for (let d = 30; d >= 1; d--) {
      const dayEndMs = todayStartArtMs - (d - 1) * 24 * 60 * 60 * 1000 - 1; // fin del día D
      const dayKeyMs = todayStartArtMs - d * 24 * 60 * 60 * 1000;
      const dateKey = _appNotifKeyFromMs(dayKeyMs);

      let totalUsers = 0, withApp = 0, withNotifs = 0, withBoth = 0;
      for (const u of users) {
        const createdMs = u.createdAt ? new Date(u.createdAt).getTime() : 0;
        if (!createdMs || createdMs > dayEndMs) continue;
        totalUsers++;

        const tokens = Array.isArray(u.fcmTokens) ? u.fcmTokens : [];
        const standaloneTokens = tokens.filter(t =>
          t && t.context === 'standalone' &&
          t.updatedAt && new Date(t.updatedAt).getTime() <= dayEndMs
        );
        const grantedTokens = tokens.filter(t =>
          t && t.notifPermission === 'granted' &&
          t.updatedAt && new Date(t.updatedAt).getTime() <= dayEndMs
        );
        const hasApp = standaloneTokens.length > 0;
        const hasNotifs = grantedTokens.length > 0 || u.notifPermission === 'granted';
        if (hasApp) withApp++;
        if (hasNotifs) withNotifs++;
        if (hasApp && hasNotifs) withBoth++;
      }

      ops.push({
        updateOne: {
          filter: { dateKey },
          update: { $set: { dateKey, totalUsers, withApp, withNotifs, withBoth, source: 'bootstrap-approx' } },
          upsert: true
        }
      });
    }

    if (ops.length > 0) {
      await AppNotifSnapshot.bulkWrite(ops, { ordered: false });
      logger.info(`[app-notif-snapshot] bootstrap aproximado: ${ops.length} días reconstruidos`);
    }
  } catch (err) {
    logger.error(`[app-notif-snapshot] bootstrap error: ${err.message}`);
  }
}

// Cron: corre cada hora y dispara el snapshot del día solo si la hora ART
// es 00 (00:00-00:59). Idempotente vía upsert por dateKey, así si el server
// se reinicia justo a esa hora no perdemos el snapshot.
function _maybeRunAppNotifSnapshotHourly() {
  try {
    const { year, month, day } = _getArgentinaParts();
    const nowArtParts = new Intl.DateTimeFormat('en-US', {
      timeZone: 'America/Argentina/Buenos_Aires',
      hour: '2-digit', hour12: false
    }).formatToParts(new Date());
    const hour = parseInt(nowArtParts.find(p => p.type === 'hour').value, 10);
    if (hour !== 0) return; // solo al cambio de día ART

    const dateKey = `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    _writeAppNotifSnapshot(dateKey, 'cron');
  } catch (err) {
    logger.error(`[app-notif-snapshot] hourly check error: ${err.message}`);
  }
}

// Bootstrap al boot (con delay para no chocar con la conexión a Mongo) +
// cron cada hora.
setTimeout(() => { _bootstrapAppNotifSnapshots(); }, 90 * 1000);
// Snapshot adicional al boot (best-effort, si todavía no existe el del día)
setTimeout(() => { _writeAppNotifSnapshot(_appNotifTodayKey(), 'cron'); }, 120 * 1000);
setInterval(() => { _maybeRunAppNotifSnapshotHourly(); }, 60 * 60 * 1000);

// ============================================================
// MOTOR DE REGLAS DE NOTIFICACIÓN AUTOMÁTICAS
// ============================================================
// Carga las reglas pre-definidas (B1-B6, A3-A4) en el primer arranque
// del feature, y corre el evaluador cada 5 min. Cada regla decide si
// le toca disparar AHORA (matching su trigger cron) y resuelve su
// audiencia desde User/PlayerStats/DailyPlayerStats/RefundClaim.
const notificationRulesService = require('./src/services/notificationRulesService');
const _notifRulesModels = {
  User,
  RefundClaim,
  PlayerStats,
  NotificationRule,
  NotificationRuleSuggestion,
  NotificationHistory,
  MoneyGiveaway
};
// DailyPlayerStats es required acá lazy porque no está en la lista de top.
try {
  _notifRulesModels.DailyPlayerStats = require('./src/models').DailyPlayerStats;
} catch (_) {}

const _notifRulesSendFn = require('./src/services/notificationService').sendNotificationToAllUsers;

// Seed al boot (idempotente — solo crea las que no existen).
setTimeout(async () => {
  try {
    await notificationRulesService.seedDefaultRulesIfMissing(NotificationRule);
    logger.info('[notif-rules] seed inicial completado');
  } catch (err) {
    logger.error(`[notif-rules] seed error: ${err.message}`);
  }
}, 60 * 1000);

// Evaluar cada 5 min.
async function _runNotifRulesEvaluator() {
  try {
    const result = await notificationRulesService.evaluateAllRules({
      models: _notifRulesModels,
      sendPushFn: _notifRulesSendFn,
      logger
    });
    if (result.firedCount > 0 || result.suggestedCount > 0) {
      logger.info(`[notif-rules] eval done: fired=${result.firedCount} suggested=${result.suggestedCount}`);
    }
  } catch (err) {
    logger.error(`[notif-rules] evaluator error: ${err.message}`);
  }
}
setTimeout(() => { _runNotifRulesEvaluator(); }, 3 * 60 * 1000);
setInterval(() => { _runNotifRulesEvaluator(); }, 5 * 60 * 1000);

// ============================================================
// MOTOR DE ESTRATEGIA SEMANAL (lunes/jueves/miércoles)
// ============================================================
// Ver src/services/weeklyStrategyService.js para detalle.
//
// Cron 1 (cada 5 min): chequea si toca disparar netwin (lun) /
//   tier-bonus (jue) / reporte (mié) según hora ART configurada.
// Cron 2 (cada 30 min): tracker de ROI — busca pushes de estrategia
//   con sentAt > 48h y mide carga pre/post para llenar el reporte.
const weeklyStrategyService = require('./src/services/weeklyStrategyService');
const adhocStrategyService = require('./src/services/adhocStrategyService');
const automationStrategyService = require('./src/services/automationStrategyService');
const refundReminderService = require('./src/services/refundReminderService');
