// GET /api/admin/strategy/roi/:historyId/details — detalle completo
// de una difusión: forecast per-user (qué le iba a tocar a cada uno)
// + estado de claim (local) + clasificación (si ya se computó).
app.get('/api/admin/strategy/roi/:historyId/details', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const h = await NotificationHistory.findOne({ id: req.params.historyId }).lean();
    if (!h) return res.status(404).json({ error: 'Difusión no encontrada' });
    if (!h.strategyType) return res.status(400).json({ error: 'No es una difusión de estrategia automática' });

    const details = h.strategyDetails || [];

    // Aggregates rapidos.
    const claimed = details.filter(d => d.claimed).length;
    const notClaimed = details.length - claimed;
    const totalGiftedARS = details.reduce((s, d) => s + (Number(d.claimedAmount) || 0), 0);

    // Computar agregado de cargas pre/post (ya está en el doc).
    const tgtPre = Number(h.chargesBefore48hARS) || 0;
    const tgtPost = Number(h.chargesAfter48hARS) || 0;
    const ctlPre = Number(h.controlChargesBefore48hARS) || 0;
    const ctlPost = Number(h.controlChargesAfter48hARS) || 0;
    const tgtSize = Number(h.audienceCount) || 1;
    const ctlSize = Number(h.controlGroupCount) || 1;
    const tgtDeltaPerUser = (tgtPost - tgtPre) / tgtSize;
    const ctlDeltaPerUser = ctlSize > 0 ? (ctlPost - ctlPre) / ctlSize : 0;
    const attributableDeltaPerUser = tgtDeltaPerUser - ctlDeltaPerUser;
    const attributableDeltaTotal = attributableDeltaPerUser * tgtSize;
    const roi = totalGiftedARS > 0 ? (attributableDeltaTotal - totalGiftedARS) / totalGiftedARS : null;

    // Detección de "efectos negativos" automáticos.
    const alerts = [];
    if (h.roiTrackedAt && tgtPost < tgtPre * 0.5 && tgtPre > 1000) {
      alerts.push('🔴 La carga del segmento BAJÓ más del 50% post-push. Posible efecto negativo: revisá si el copy o el monto desincentivó.');
    }
    if (h.roiTrackedAt && ctlSize >= 5 && ctlDeltaPerUser > tgtDeltaPerUser) {
      alerts.push('🔴 El grupo control cargó MÁS por usuario que el segmento que recibió el push. La difusión puede haber sido contraproducente.');
    }
    if (totalGiftedARS > 0 && roi !== null && roi < -0.5) {
      alerts.push(`🔴 ROI muy negativo (${(roi*100).toFixed(0)}%): por cada peso regalado, recuperás menos de la mitad. Considerá pausar esta campaña.`);
    }
    if (h.roiTrackedAt && claimed === 0 && details.length > 0) {
      alerts.push('🟡 NADIE reclamó el regalo. El push pudo no haber llegado o el copy no convenció. Revisá el copy y la entrega FCM.');
    }
    if (details.length > 0 && claimed / details.length < 0.10 && (h.successCount || 0) > 5) {
      alerts.push(`🟡 Tasa de claim muy baja: solo ${claimed}/${details.length} (${Math.round(100*claimed/details.length)}%). El push llegó pero no convirtió.`);
    }

    res.json({
      success: true,
      history: {
        id: h.id,
        sentAt: h.sentAt,
        strategyType: h.strategyType,
        strategyWeekKey: h.strategyWeekKey,
        title: h.title,
        body: h.body,
        audienceCount: h.audienceCount,
        controlGroupCount: h.controlGroupCount,
        successCount: h.successCount,
        failureCount: h.failureCount,
        waClicks: h.waClicks,
        giveawayClaims: h.giveawayClaims,
        roiTrackedAt: h.roiTrackedAt,
        chargesBefore48hARS: tgtPre,
        chargesAfter48hARS: tgtPost,
        controlChargesBefore48hARS: ctlPre,
        controlChargesAfter48hARS: ctlPost,
        classificationCounts: h.classificationCounts || null
      },
      summary: {
        totalUsers: details.length,
        claimed,
        notClaimed,
        totalGiftedARS,
        deliveryRate: h.audienceCount > 0 ? (h.successCount / h.audienceCount) : null,
        claimRate: details.length > 0 ? (claimed / details.length) : null,
        attributableDeltaTotal,
        attributableDeltaPerUser,
        roi
      },
      alerts,
      details
    });
  } catch (err) {
    logger.error(`GET strategy/roi/details: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// POST /api/admin/strategy/roi/:historyId/recompute-perf
// Calcula CARGA PER-USER consumiendo JUGAYGANA API (~1 request por
// user del audience + control), clasifica cada uno como
// converter/passive/no_response/regressive y guarda los resultados
// en strategyDetails de cada user + classificationCounts agregado.
//
// Async: arranca el cómputo y devuelve job inmediatamente. El
// cliente polea GET .../details para ver cuando terminó.
app.post('/api/admin/strategy/roi/:historyId/recompute-perf', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const h = await NotificationHistory.findOne({ id: req.params.historyId }).lean();
    if (!h) return res.status(404).json({ error: 'No encontrada' });
    if (!h.strategyType) return res.status(400).json({ error: 'No es difusión de estrategia' });
    if (!h.sentAt) return res.status(400).json({ error: 'sentAt vacío' });

    const sentAtMs = new Date(h.sentAt).getTime();
    const ageHours = (Date.now() - sentAtMs) / 3600000;
    if (ageHours < 48) {
      return res.status(409).json({ error: `Pasaron solo ${ageHours.toFixed(1)}h del envío. Esperá 48h para tener data confiable.` });
    }

    res.json({ success: true, queued: true, message: 'Recompute iniciado en background. Refrescá en ~30s.' });

    // Async — reusa la función compartida que también usa el cron.
    setImmediate(async () => {
      try {
        await weeklyStrategyService.classifyHistoryPerUser({
          historyId: h.id,
          models: _strategyModels,
          jugayganaMovements,
          logger
        });
      } catch (err) {
        logger.error(`[strategy] perf recompute error ${h.id}: ${err.message}`);
      }
    });
  } catch (err) {
    logger.error(`POST recompute-perf: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// GET /api/admin/strategy/budget-status — cuánto se gastó esta semana
// + conteo de la audiencia base elegible (app + notifs).
app.get('/api/admin/strategy/budget-status', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const cfg = await weeklyStrategyService.getOrCreateConfig(WeeklyStrategyConfig);
    const wk = weeklyStrategyService._weekKey();
    // Suma claims de giveaways de esta weekKey.
    const claimsAgg = await MoneyGiveawayClaim.aggregate([
      {
        $lookup: {
          from: 'notificationhistories',
          localField: 'notificationHistoryId',
          foreignField: 'id',
          as: 'h'
        }
      },
      { $unwind: { path: '$h', preserveNullAndEmptyArrays: false } },
      { $match: { 'h.strategyWeekKey': wk } },
      { $group: { _id: null, total: { $sum: '$amount' }, count: { $sum: 1 } } }
    ]);
    const spent = claimsAgg[0] ? Number(claimsAgg[0].total) || 0 : 0;
    const claimsCount = claimsAgg[0] ? Number(claimsAgg[0].count) || 0 : 0;

    // Audiencia base elegible: la regla HARD del producto.
    const eligibleUsersCount = await weeklyStrategyService.countAppNotifsCandidates(User);
    const totalRealUsers = await weeklyStrategyService.countTotalRealUsers(User);

    res.json({
      success: true,
      weekKey: wk,
      spentARS: spent,
      capARS: cfg.weeklyBudgetCapARS,
      remainingARS: Math.max(0, cfg.weeklyBudgetCapARS - spent),
      pctUsed: cfg.weeklyBudgetCapARS > 0 ? Math.round(100 * spent / cfg.weeklyBudgetCapARS) : 0,
      claimsCount,
      lastNetwinFireWeek: cfg.lastNetwinFireWeek,
      lastTierBonusFireWeek: cfg.lastTierBonusFireWeek,
      lastReportWeek: cfg.lastReportWeek,
      // Audiencia base — quiénes son elegibles para CUALQUIER campaña
      // de la estrategia automática.
      eligibleUsersCount,
      totalRealUsers,
      excludedNoChannel: totalRealUsers - eligibleUsersCount,
      eligiblePct: totalRealUsers > 0 ? Math.round(100 * eligibleUsersCount / totalRealUsers) : 0
    });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ============================================================
// SORTEOS PAID 🎁
// ============================================================
// Sorteos pagados con saldo JUGAYGANA. 4 niveles de premio paralelos:
//   $1.000.000 (100 numeros x $15.000)
//   $2.000.000 (100 numeros x $30.000)
//   $500.000   (100 numeros x $7.500)
//   $100.000   (100 numeros x $2.000)
//
// Lifecycle: el sistema mantiene 1 instancia 'active' por cada tipo. Los
// users compran numeros con su saldo (jugaygana.withdrawFromUser). Cuando
// se llena el cupo, el sorteo pasa a 'closed' y se respawnea otra
// instancia activa con los mismos parametros (instanceNumber + 1). Todos
// los lunes en la Loteria Nacional Nocturna se sortea contra el 1er
// premio. Admin carga el numero ganador desde el panel → ganador queda
// con prizeClaimable=true y puede acreditar su premio al saldo desde la
// app. Cleanup archiva los 'drawn' para mantener el panel limpio.
//
// Endpoints:
//   GET  /api/raffles/active                      — usuario: lista activos + balance
//   POST /api/raffles/:id/buy                     — usuario: comprar numero(s)
//   POST /api/raffles/:id/claim-prize             — usuario: ganador acredita premio
//   GET  /api/admin/raffles                       — admin: lista para panel
//   GET  /api/admin/raffles/:id/participants      — admin: detalle de participantes
//   POST /api/admin/raffles/:id/draw              — admin: cargar numero ganador
//   POST /api/admin/raffles/:id/cancel            — admin: cancelar y reembolsar
//   POST /api/admin/raffles/cleanup               — admin: archiva drawn + reseed
// ============================================================

const RAFFLE_TYPES = [
  { type: 'p2m',  prize: 2000000, totalTickets: 100, entryCost: 30000, emoji: '👑',
    name: 'Sorteo $2.000.000', prizeName: '$2.000.000 en saldo' },
  { type: 'p1m',  prize: 1000000, totalTickets: 100, entryCost: 15000, emoji: '💎',
    name: 'Sorteo $1.000.000', prizeName: '$1.000.000 en saldo' },
  { type: 'p500', prize: 500000,  totalTickets: 100, entryCost: 7500,  emoji: '💰',
    name: 'Sorteo $500.000',   prizeName: '$500.000 en saldo' },
  { type: 'p100', prize: 100000,  totalTickets: 100, entryCost: 2000,  emoji: '🎯',
    name: 'Sorteo $100.000',   prizeName: '$100.000 en saldo' }
];

// Sorteo RELAMPAGO: hero del sistema, gratis, una sola vez. Cuando se sortea
// NO auto-respawna — el admin decide si crear otro despues. Por eso vive
// fuera de RAFFLE_TYPES (auto-rotation) y FREE_RAFFLE_TYPES (auto-enroll
// recurrente). Se seedea manualmente desde el panel admin.
const LIGHTNING_RAFFLE_CONFIG = {
  type: 'relampago',
  prize: 200000,
  totalTickets: 100,
  entryCost: 0, // gratis
  // Sin minCargasARS: cualquiera puede inscribirse (no necesita tener cargas).
  // Si la owner quiere subir la barra despues, lo cambia aca.
  minCargasARS: 0,
  emoji: '⚡',
  name: '⚡ RELÁMPAGO · $200.000',
  prizeName: '$200.000 en saldo'
};

// Sorteos GRATIS para clientes activos. La auto-participacion ocurre cuando
// el user abre el modal: si tuvo >= minCargasARS de cargas en los ultimos
// 30 dias y todavia hay cupo (1 numero por persona, 100 personas tope),
// se le asigna automaticamente un numero secuencial. Mismo draw que paid.
const FREE_RAFFLE_TYPES = [
  { type: 'free_p2m',  prize: 2000000, totalTickets: 100, minCargasARS: 200000, emoji: '👑',
    name: 'Sorteo Gratis $2.000.000', prizeName: '$2.000.000 en saldo' },
  { type: 'free_p1m',  prize: 1000000, totalTickets: 100, minCargasARS: 100000, emoji: '💎',
    name: 'Sorteo Gratis $1.000.000', prizeName: '$1.000.000 en saldo' },
  { type: 'free_p500', prize: 500000,  totalTickets: 100, minCargasARS: 100000, emoji: '💰',
    name: 'Sorteo Gratis $500.000',   prizeName: '$500.000 en saldo' },
  { type: 'free_p100', prize: 100000,  totalTickets: 100, minCargasARS: 50000,  emoji: '🎯',
    name: 'Sorteo Gratis $100.000',   prizeName: '$100.000 en saldo' }
];

const FREE_RAFFLE_TYPE_SET = new Set(FREE_RAFFLE_TYPES.map(t => t.type));

const RAFFLE_LOTTERY_RULE = '1° premio de la Lotería Nacional Nocturna del lunes próximo. Resultado oficial publicado por Lotería Nacional — verificable. Si el número sale fuera del rango vendido, se cicla al rango vendido por módulo.';

// Devuelve un Date corrido a TZ Argentina (UTC-3, sin DST) para hacer
// calculos de dia/semana en hora local sin librerias externas.
function _argZonedNow() {
  return new Date(Date.now() - 3 * 3600 * 1000);
}

// Clave de dia (YYYY-MM-DD) en TZ ARG. La usamos para agrupar spend diario.
function _argDayKey(date) {
  const d = new Date((date ? date.getTime() : Date.now()) - 3 * 3600 * 1000);
  const y = d.getUTCFullYear();
  const m = String(d.getUTCMonth() + 1).padStart(2, '0');
  const day = String(d.getUTCDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
}

// Resuelve si un user esta dentro de la audiencia de un sorteo (segun el
// audienceMode + audienceTeams). El equipo se deriva del prefijo del username
// usando la config global 'userLinesByPrefix'. Si linesConfig es null o el
// modo es 'all', devuelve true sin chequear nada.
//
// El parametro linesConfig se pasa para no leer de DB en cada llamada
// (caller hace 1 sola lectura y la reutiliza para todos los raffles).
function _userInRaffleAudience(raffle, username, linesConfig) {
  const mode = raffle && raffle.audienceMode;
  if (!mode || mode === 'all') return true;
  const u = String(username || '').toLowerCase().trim();
  // Modo testing: solo los usernames listados pasan. No depende de equipos.
  if (mode === 'user') {
    const allowed = (raffle.audienceUsernames || [])
      .map(x => String(x || '').toLowerCase().trim())
      .filter(Boolean);
    if (allowed.length === 0) return true; // lista vacia = no restringe
    return allowed.includes(u);
  }
  const teams = (raffle.audienceTeams || []).map(t => String(t).toLowerCase().trim()).filter(Boolean);
  if (teams.length === 0) return true; // mode con lista vacia = todos pasan
  const userTeam = String(pickTeamNameForUsername(linesConfig, username) || '').toLowerCase().trim();
  if (mode === 'except') {
    return !teams.includes(userTeam);
  }
  if (mode === 'only') {
    return teams.includes(userTeam);
  }
  return true;
}

function _isoWeekKey(date) {
  const d = new Date(Date.UTC(date.getUTCFullYear(), date.getUTCMonth(), date.getUTCDate()));
  const dayNum = d.getUTCDay() || 7;
  d.setUTCDate(d.getUTCDate() + 4 - dayNum);
  const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
  const weekNum = Math.ceil((((d - yearStart) / 86400000) + 1) / 7);
  return `${d.getUTCFullYear()}-W${String(weekNum).padStart(2, '0')}`;
}

// Proximo lunes 21:00 ARG (= 00:00 UTC del martes). Si hoy es lunes en ARG
// pero todavia no son las 21:00, apunta a HOY 21:00. Si hoy es lunes y ya
// pasaron las 21:00, apunta al lunes que viene.
function _nextMondayDraw() {
  const argNow = _argZonedNow();
  let daysToMon = (1 - argNow.getUTCDay() + 7) % 7;
  if (daysToMon === 0 && argNow.getUTCHours() >= 21) daysToMon = 7;
  const target = new Date(argNow);
  target.setUTCDate(argNow.getUTCDate() + daysToMon);
  target.setUTCHours(21, 0, 0, 0);
  // De ARG-zoned a UTC real.
  return new Date(target.getTime() + 3 * 3600 * 1000);
}

// Devuelve { mode, teams } leyendo Config 'raffle_audience_paid' o
// 'raffle_audience_free'. Si no esta seteado, devuelve { mode:'all', teams:[] }.
// Cuenta cuantas cargas REALES tuvo un user en los ultimos 7 dias. "Real"
// significa Transaction.type === 'deposit' — los bonus, refunds, fire_rewards
// y referral commissions van con type distinto y NO se cuentan. Asi medimos
// actividad real del jugador sin que las bonificaciones inflen el numero.
//
// Lookup case-insensitive para matchear como Transaction guarda el username.
async function _getRealChargeCountLastWeek(username) {
  if (!username) return 0;
  const since = new Date(Date.now() - 7 * 24 * 3600 * 1000);
  const safe = String(username).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  try {
    return await Transaction.countDocuments({
      username: { $regex: '^' + safe + '$', $options: 'i' },
      type: 'deposit',
      timestamp: { $gte: since }
    });
  } catch (e) {
    logger.warn(`[raffles] _getRealChargeCountLastWeek ${username}: ${e.message}`);
    return 0;
  }
}

async function _readRaffleAudienceConfig(kind) {
  const key = kind === 'free' ? 'raffle_audience_free' : 'raffle_audience_paid';
  try {
    const raw = await getConfig(key);
    if (!raw || typeof raw !== 'object') return { mode: 'all', teams: [] };
    const mode = ['all', 'except', 'only'].includes(raw.mode) ? raw.mode : 'all';
    const teams = Array.isArray(raw.teams)
      ? Array.from(new Set(raw.teams.map(t => String(t || '').trim()).filter(Boolean))).slice(0, 50)
      : [];
    // Sanity: si el modo no es 'all' pero la lista esta vacia, degrada a 'all'
    // (no tiene sentido except [] = nadie excluido = lo mismo que all).
    if (mode !== 'all' && teams.length === 0) return { mode: 'all', teams: [] };
    return { mode, teams };
  } catch (_) {
    return { mode: 'all', teams: [] };
  }
}

// Cuenta cargas REALES de un user via jugayganaMovements.getUserMovements
// (misma fuente que el panel de cargas del admin — Reembolsos diarios/semanales/
// mensuales). NO usa la colection Transaction local porque ahi solo se registran
// algunos eventos: muchos users con cargas reales en JUGAYGANA figuran con 0
// en Transaction (bug que rompia el conteo del relampago).
//
// Args:
//   username: el username del user
//   beforeMs: opcional, si se pasa, solo cuenta cargas con timestamp < beforeMs.
//             Para el sorteo: drawnAt. Para el live display al user: null
//             (cuenta hasta ahora).
//   lookbackDays: cuanto atras buscar (default 365). pageSize 500 cubre la
//                 mayoria. Si un user tiene mas de 500 cargas en 1 año, ya
//                 califica con creces.
async function _getLightningCargasCount(username, beforeMs, lookbackDays) {
  const days = Number.isFinite(lookbackDays) ? lookbackDays : 365;
  const endMs = beforeMs ? Number(beforeMs) : Date.now();
  const startMs = endMs - days * 24 * 3600 * 1000;
  const fmt = (d) => {
    const x = new Date(d);
    const y = x.getFullYear();
    const m = String(x.getMonth() + 1).padStart(2, '0');
    const dd = String(x.getDate()).padStart(2, '0');
    return `${y}-${m}-${dd}`;
  };
  try {
    const r = await jugayganaMovements.getUserMovements(username, {
      startDate: fmt(startMs),
      endDate: fmt(endMs),
      pageSize: 500
    });
    if (!r || !r.success) return 0;
    let count = 0;
    for (const m of (r.movements || [])) {
      // Filtro por timestamp del movement si esta disponible.
      const candidates = [m.timestamp, m.Timestamp, m.date, m.Date, m.datetime, m.fecha, m.Fecha, m.createdAt];
      let ts = null;
      for (const c of candidates) {
        if (!c) continue;
        const t = new Date(c).getTime();
        if (isFinite(t) && t > 0) { ts = t; break; }
      }
      if (beforeMs && ts && ts >= Number(beforeMs)) continue;
      const type = String(m.type || m.operation || m.OperationType || m.Type || m.Operation || '').toLowerCase();
      let amount = 0;
      if (m.amount !== undefined) amount = parseFloat(m.amount);
      else if (m.Amount !== undefined) amount = parseFloat(m.Amount);
      else if (m.value !== undefined) amount = parseFloat(m.value);
      else if (m.Value !== undefined) amount = parseFloat(m.Value);
      else if (m.monto !== undefined) amount = parseFloat(m.monto);
      else if (m.Monto !== undefined) amount = parseFloat(m.Monto);
      const isDep = type.includes('deposit') || type.includes('credit') ||
                    type.includes('carga') || type.includes('recarga') || amount > 0;
      if (isDep) count++;
    }
    return count;
  } catch (e) {
    logger.warn(`[raffles] _getLightningCargasCount ${username}: ${e.message}`);
    return 0;
  }
}

// Clona un relampago cerrado (status='closed') en uno nuevo activo. Mantiene
// premio, cupos, isFree/entryCost, audiencia y todos los gates de elegibilidad
// (requiresPaidTicket, requiresMinChargesLastWeek). instanceNumber se renumera
// segun los relampagos creados. Usado por el auto-respawn cuando el N°1 (que
// armo el admin) se llena -> arrancamos N°2; cuando N°2 se llena -> N°3; tope 3.
async function _spawnLightningClone(srcRaffle) {
  const prevCount = await Raffle.countDocuments({ raffleType: 'relampago' });
  const drawArg = _nextMondayDraw();
  const weekKey = _isoWeekKey(drawArg);
  const id = uuidv4();
  return await Raffle.create({
    id,
    raffleType: 'relampago',
    instanceNumber: prevCount + 1,
    name: srcRaffle.name,
    prizeName: srcRaffle.prizeName,
    description: srcRaffle.description,
    emoji: srcRaffle.emoji || '⚡',
    entryCost: srcRaffle.entryCost || 0,
    totalTickets: srcRaffle.totalTickets,
    prizeValueARS: srcRaffle.prizeValueARS,
    _ticketCounter: 0,
    claimedNumbers: [],
    drawDate: drawArg,
    weekKey,
    status: 'active',
    isFree: !!srcRaffle.isFree,
    minCargasARS: srcRaffle.minCargasARS || 0,
    requiresPaidTicket: !!srcRaffle.requiresPaidTicket,
    audienceMode: srcRaffle.audienceMode || 'all',
    audienceTeams: srcRaffle.audienceTeams || [],
    audienceUsernames: srcRaffle.audienceUsernames || [],
    requiresMinChargesLastWeek: srcRaffle.requiresMinChargesLastWeek || 0,
    lotteryRule: srcRaffle.lotteryRule,
    createdAt: new Date()
  });
}

// Push a todos los participantes del relampago cerrado avisando que el cupo
// se lleno y recordando los requisitos para reclamar el premio si ganan
// (5 cargas + juego con nosotros). Es el momento de mas atencion: el user
// acaba de saber que su numero esta en juego.
async function _notifyLightningClosed(raffle) {
  const parts = await RaffleParticipation.find({ raffleId: raffle.id }, { username: 1 }).lean();
  if (!parts || parts.length === 0) return;
  const seen = new Set();
  const names = [];
  for (const p of parts) {
    const u = String(p.username || '').trim();
    if (!u) continue;
    const key = u.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    names.push(u);
  }
  if (names.length === 0) return;
  const title = '⚡ ' + (raffle.name || 'RELÁMPAGO') + ' · ¡cupo lleno!';
  const body = 'Tu número está en juego. RECORDÁ: para reclamar el premio si ganás, necesitás MÍNIMO 5 cargas y haber jugado con nosotros. Es exclusivo para clientes activos.';
  await sendNotificationToAllUsers(
    User,
    title,
    body,
    {
      source: 'raffle-lightning-closed',
      raffleId: raffle.id,
      raffleType: 'relampago'
    },
    { username: { $in: names } }
  );
  logger.info(`[raffles] LIGHTNING closed notify enviado a ${names.length} users (${raffle.id})`);
}

async function _spawnRaffleInstance(typeCfg, instanceNumber) {
  // Spawn altera el set de active raffles -> invalidar cache para que el
  // proximo /api/raffles/active vea el sorteo nuevo en seguida.
  if (typeof _invalidateSeedCache === 'function') _invalidateSeedCache();
  const draw = _nextMondayDraw();
  // weekKey corresponde a la SEMANA del sorteo (no del momento de creacion).
  const drawArg = new Date(draw.getTime() - 3 * 3600 * 1000);
  const weekKey = _isoWeekKey(drawArg);
  const id = uuidv4();
  const isFree = !!FREE_RAFFLE_TYPE_SET.has(typeCfg.type);
  const description = isFree
    ? `Sorteo GRATIS. Necesitás $${(typeCfg.minCargasARS||0).toLocaleString('es-AR')} de cargas en los últimos 30 días para entrar. ${typeCfg.totalTickets} cupos, 1 número por persona.`
    : `Premio ${typeCfg.prizeName}. ${typeCfg.totalTickets} números a $${(typeCfg.entryCost||0).toLocaleString('es-AR')}.`;
  // Audiencia heredada del config global por kind (paid o free). Asi el
  // admin define una sola vez "los pagos no van a crazy" y se aplica a
  // todas las instancias futuras al respawnear.
  const aud = await _readRaffleAudienceConfig(isFree ? 'free' : 'paid');
  await Raffle.create({
    id,
    name: typeCfg.name + ' #' + instanceNumber,
    prizeName: typeCfg.prizeName,
    description,
    emoji: typeCfg.emoji,
    raffleType: typeCfg.type,
    instanceNumber,
    weekKey,
    entryCost: isFree ? 0 : (typeCfg.entryCost || 0),
    totalTickets: typeCfg.totalTickets,
    prizeValueARS: typeCfg.prize,
    drawDate: draw,
    lotteryRule: RAFFLE_LOTTERY_RULE,
    status: 'active',
    isFree,
    minCargasARS: isFree ? (typeCfg.minCargasARS || 0) : 0,
    audienceMode: aud.mode,
    audienceTeams: aud.teams
  });
  return id;
}

async function _ensureActiveRafflesSeeded() {
  // POLITICA: solo se seedean sorteos GRATIS. Los pagos activos se dejan
  // correr hasta sortearse; cuando se llenan, no se respawnean (ver el
  // bloque de cupo lleno en /buy). Los proximos sorteos van a ser todos
  // gratis (luego: por netwin).
  const allTypes = [...FREE_RAFFLE_TYPES];
  for (const cfg of allTypes) {
    try {
      const existing = await Raffle.findOne(
        { raffleType: cfg.type, status: 'active' },
        { id: 1, drawDate: 1, name: 1 }
      ).lean();

      // Auto-fix: si el sorteo activo tiene drawDate en el pasado (cron del
      // martes no corrio o boot tardio), lo cerramos y dejamos que se cree
      // uno nuevo abajo. Sin esto el cutoff de 3hs pre-draw bloquea las
      // compras y el usuario ve "Este sorteo cerro las ventas".
      if (existing) {
        if (existing.drawDate && new Date(existing.drawDate).getTime() < Date.now()) {
          await Raffle.updateOne(
            { id: existing.id, status: 'active' },
            { $set: { status: 'closed' } }
          );
          logger.warn(`[raffles] auto-rotate stale ${cfg.type} (drawDate paso): ${existing.name}`);
        } else {
          continue;
        }
      }

      const last = await Raffle.findOne(
        { raffleType: cfg.type },
        { instanceNumber: 1 }
      ).sort({ instanceNumber: -1 }).lean();
      const next = ((last && last.instanceNumber) || 0) + 1;
      await _spawnRaffleInstance(cfg, next);
      logger.info(`[raffles] seed ${cfg.type} #${next}`);
    } catch (e) {
      logger.warn(`[raffles] seed ${cfg.type}: ${e.message}`);
    }
  }
}

// Boot: 5s después arranca el seed para tener los 4 sorteos activos.
setTimeout(() => { _ensureActiveRafflesSeeded().catch(() => {}); }, 5000);

// =============================
// AUTO-ENROLLMENT EN FREE RAFFLES (DESHABILITADO)
// =============================
// HISTORICO: este helper auto-asignaba un numero al user si superaba el
// threshold de cargas semanales. El owner cambio la UX: ahora la gente
// que llega al threshold tiene que ELEGIR su numero del grid (mismo flow
// que paid/relampago), por interaccion + FOMO. Dejamos la funcion como
// no-op para no romper los call-sites; el pick se maneja desde /buy con
// entryCost=0 y validacion de threshold antes de reservar.
async function _autoEnrollFreeRaffles(_username) {
  return [];
}

// Dead code preservado abajo por si necesitamos revertir. NUNCA se ejecuta.
async function _autoEnrollFreeRaffles_LEGACY_DISABLED(username) {
  const enrolled = []; // { raffleId, ticketNumber, raffleName, prizeValueARS, raffleType }
  try {
    // Solo los free clasicos (free_p100/p500/p1m/p2m) auto-enrolean. RELAMPAGO
    // queda afuera: el dueno quiere que la gente entre, ELIJA su numero del
    // grid 1-100 y vea como se llena el cupo en tiempo real (interaccion +
    // FOMO). El relampago se maneja por el endpoint /buy con entryCost=0.
    const freeRaffles = await Raffle.find(
      { raffleType: { $in: Array.from(FREE_RAFFLE_TYPE_SET) }, status: 'active' }
    ).lean();
    if (freeRaffles.length === 0) return enrolled;

    // Cargas del user esta semana (lun-dom corriente). Antes era 'monthly'
    // (30 dias rolling) pero el dueno aclaro que el sorteo es semanal y el
    // umbral debe medirse de lunes a domingo, no en una ventana de 30 dias.
    let weeklyDeposits = 0;
    try {
      const m = await getRealMovementsTotals(username, 'weekly');
      weeklyDeposits = Number(m && m.deposits) || 0;
    } catch (e) {
      logger.warn(`[free-raffles] cargas check fail ${username}: ${e.message}`);
      // No abortamos: para 'relampago' (minCargasARS=0) seguimos el flujo.
      // Solo los que requieran umbral van a saltar mas abajo.
    }

    // Lines config para filtro de audiencia (best-effort; null no bloquea).
    let linesCfg = null;
    try { linesCfg = await getConfig('userLinesByPrefix'); } catch (_) {}
    const safe = String(username).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    for (const r of freeRaffles) {
      if (weeklyDeposits < (r.minCargasARS || 0)) continue;
      // Si el sorteo tiene audienceMode restringido y este user no entra,
      // skip (no se le asigna numero ni le aparece como "anotado").
      if (!_userInRaffleAudience(r, username, linesCfg)) continue;

      // Ya enrolado en este sorteo? Skip.
      const alreadyIn = await RaffleParticipation.findOne({
        raffleId: r.id,
        username: { $regex: '^' + safe + '$', $options: 'i' }
      }, { _id: 1 }).lean();
      if (alreadyIn) continue;

      // Tomar el siguiente numero disponible (1..totalTickets).
      const claimedSet = new Set((r.claimedNumbers || []).map(n => Number(n)));
      let nextNum = 0;
      for (let n = 1; n <= (r.totalTickets || 0); n++) {
        if (!claimedSet.has(n)) { nextNum = n; break; }
      }
      if (nextNum === 0) continue; // cupo lleno

      // Reservar atomicamente el numero.
      const reserved = await Raffle.findOneAndUpdate(
        {
          id: r.id,
          status: 'active',
          claimedNumbers: { $nin: [nextNum] },
          $expr: { $lt: [{ $size: { $ifNull: ['$claimedNumbers', []] } }, '$totalTickets'] }
        },
        {
          $push: { claimedNumbers: nextNum },
          $inc: { _ticketCounter: 1 }
        },
        { new: true }
      );
      if (!reserved) continue; // race lost; siguiente sorteo

      // Crear participation gratuita.
      try {
        await RaffleParticipation.create({
          id: uuidv4(),
          raffleId: r.id,
          username,
          joinedAt: new Date(),
          lastBoughtAt: new Date(),
          cuposCount: 1,
          ticketNumbers: [nextNum],
          entryCostPaid: 0
        });
        enrolled.push({
          raffleId: r.id,
          ticketNumber: nextNum,
          raffleName: r.name,
          prizeValueARS: r.prizeValueARS,
          raffleType: r.raffleType,
          emoji: r.emoji
        });
        logger.info(`[free-raffles] auto-enroll ${username} #${nextNum} in ${r.name} (cargas=$${monthlyDeposits}, threshold=$${r.minCargasARS})`);

        // Si llenamos el cupo con este enroll, cerrar y respawnear.
        // 'relampago' es one-shot: cierra al llenarse, pero NO respawnea
        // (la owner decide cuando crear otro desde el panel admin).
        if ((reserved._ticketCounter || 0) >= (r.totalTickets || 0)) {
          const closeRes = await Raffle.updateOne(
            { id: r.id, status: 'active' },
            { $set: { status: 'closed' } }
          );
          if (closeRes.modifiedCount === 1 && r.raffleType !== 'relampago') {
            const cfg = FREE_RAFFLE_TYPES.find(t => t.type === r.raffleType);
            if (cfg) {
              try { await _spawnRaffleInstance(cfg, (r.instanceNumber || 1) + 1); }
              catch (e) { logger.warn(`[free-raffles] respawn ${cfg.type}: ${e.message}`); }
            }
          }
        }
      } catch (e) {
        // Rollback de la reserva del numero si falla la creacion de participation.
        await Raffle.updateOne(
          { id: r.id },
          { $pull: { claimedNumbers: nextNum }, $inc: { _ticketCounter: -1 } }
        ).catch(() => {});
        logger.warn(`[free-raffles] enroll exc ${username} ${r.name}: ${e.message}`);
      }
    }
  } catch (e) {
    logger.error(`[free-raffles] _autoEnrollFreeRaffles ${username}: ${e.message}`);
  }
  return enrolled;
}

// =============================
// AUTO-ROTACION SEMANAL DE SORTEOS
// =============================
// Cada martes 06:00 ARG (= 09:00 UTC) hacemos:
//   - Archivar todos los sorteos 'drawn' (cleanup automatico).
//   - Cancelar sorteos 'active' cuya drawDate ya paso (no se llenaron y el
//     admin no sorteo). Se reembolsa a los participantes que pagaron.
//   - Reseed: asegurar que haya 1 instancia 'active' por cada tipo.
// El cron corre cada hora; solo dispara cuando es Tuesday entre 06:00-07:00
// ARG y no se ejecuto ya en este martes (lock por timestamp).
let _lastWeeklyRotationKey = null;

async function _runWeeklyRaffleRotation(triggeredBy = 'cron') {
  try {
    const argNow = _argZonedNow();
    const argDay = argNow.getUTCDay();    // 2 = martes en ARG-shifted
    const argHour = argNow.getUTCHours();
    const todayKey = `${argNow.getUTCFullYear()}-${argNow.getUTCMonth()}-${argNow.getUTCDate()}`;

    // Si el trigger es manual (admin endpoint), corremos sin chequear.
    if (triggeredBy === 'cron') {
      // Solo Tuesday 06:00-06:59 ARG.
      if (argDay !== 2 || argHour !== 6) return;
      // No correr dos veces el mismo martes.
      if (_lastWeeklyRotationKey === todayKey) return;
    }

    logger.info(`[raffles] weekly rotation start (trigger=${triggeredBy}, day=${todayKey})`);

    // 1) Archivar drawn — pero solo los que ya pasaron 24h del draw para
    // que el banner de "Felicitaciones" del ganador siga visible un dia
    // entero antes de desaparecer. Si drawnAt es null por algun motivo,
    // archivamos igual (compat con sorteos viejos).
    const FELICITACIONES_TTL_MS = 24 * 3600 * 1000;
    const drawnUpd = await Raffle.updateMany(
      {
        status: 'drawn',
        $or: [
          { drawnAt: { $lt: new Date(Date.now() - FELICITACIONES_TTL_MS) } },
          { drawnAt: null },
          { drawnAt: { $exists: false } }
        ]
      },
      { $set: { status: 'archived' } }
    );

    // 2) Cancelar active no-llenos cuya drawDate ya paso. Reembolsar.
    // Aplica para paid Y free (los free no reembolsan plata pero sí se cierran).
    const allTypes = [...RAFFLE_TYPES.map(t => t.type), ...FREE_RAFFLE_TYPES.map(t => t.type)];
    const stale = await Raffle.find({
      raffleType: { $in: allTypes },
      status: 'active',
      drawDate: { $lt: new Date() }
    }).lean();
    let cancelled = 0, refundedCount = 0, refundedAmount = 0;
    for (const r of stale) {
      try {
        await Raffle.updateOne({ id: r.id }, { $set: { status: 'cancelled' } });
        cancelled++;
        const parts = await RaffleParticipation.find({ raffleId: r.id, refundedAt: null }).lean();
        for (const p of parts) {
          if (!p.entryCostPaid || p.entryCostPaid <= 0) continue;
          const reserved = await RaffleParticipation.findOneAndUpdate(
            { id: p.id, refundedAt: null },
            { $set: { refundedAt: new Date(), refundedAmount: p.entryCostPaid } }
          );
          if (!reserved) continue;
          try {
            const cr = await jugaygana.creditUserBalance(p.username, p.entryCostPaid);
            if (cr && cr.success) {
              refundedCount++;
              refundedAmount += p.entryCostPaid;
              await RaffleParticipation.updateOne(
                { id: p.id },
                { $set: { refundedTxId: (cr.transactionId || cr.transferId) || null } }
              ).catch(() => {});
            } else {
              await RaffleParticipation.updateOne(
                { id: p.id },
                { $set: { refundedAt: null, refundedAmount: 0 } }
              ).catch(() => {});
              logger.warn(`[raffles weekly-rotation] refund fail ${p.username} ${r.name}: ${cr && cr.error}`);
            }
          } catch (e) {
            await RaffleParticipation.updateOne(
              { id: p.id },
              { $set: { refundedAt: null, refundedAmount: 0 } }
            ).catch(() => {});
            logger.error(`[raffles weekly-rotation] refund exc ${p.username} ${r.name}: ${e.message}`);
          }
        }
      } catch (e) {
        logger.error(`[raffles weekly-rotation] cancel ${r.name}: ${e.message}`);
      }
    }

    // 3) Reseed.
    await _ensureActiveRafflesSeeded();

    if (triggeredBy === 'cron') _lastWeeklyRotationKey = todayKey;
    logger.info(`[raffles] weekly rotation done: archived=${drawnUpd.modifiedCount||0} cancelled=${cancelled} refunded=${refundedCount}/$${refundedAmount}`);
    return {
      archived: drawnUpd.modifiedCount || 0,
      cancelled,
      refundedCount,
      refundedAmount
    };
  } catch (e) {
    logger.error(`[raffles weekly-rotation] global: ${e.message}`);
    return null;
  }
}

// Boot: arranca el cron 60s después; corre cada hora.
setTimeout(() => { _runWeeklyRaffleRotation('cron').catch(() => {}); }, 60 * 1000);
setInterval(() => { _runWeeklyRaffleRotation('cron').catch(() => {}); }, 60 * 60 * 1000);

// Cache del seed check: corremos _ensureActiveRafflesSeeded como mucho 1 vez
// cada 60s. La primera request paga el costo; las demas hits dentro del
// proximo minuto saltean los 8 findOne. Combinado con la auto-rotacion al
// crear un sorteo cuando se llena, el TTL de 60s no afecta UX.
let _seedLastRunTs = 0;
const _SEED_TTL_MS = 60 * 1000;
async function _ensureActiveRafflesSeededCached() {
  if (Date.now() - _seedLastRunTs < _SEED_TTL_MS) return;
  await _ensureActiveRafflesSeeded();
  _seedLastRunTs = Date.now();
}
function _invalidateSeedCache() { _seedLastRunTs = 0; }

// =============================
// USER ENDPOINTS
// =============================

app.get('/api/raffles/active', authMiddleware, async (req, res) => {
  try {
    const username = req.user.username;

    // Seed check con TTL 60s para no pagar 8 findOne en cada apertura.
    await _ensureActiveRafflesSeededCached();

    // Auto-enroll free raffles. Por defecto va EN BACKGROUND (no bloquea la
    // response del modal — el user lo ve en el siguiente refresh). El cliente
    // puede pasar ?waitEnroll=1 cuando quiera bloquear (ej. PR primer load
    // tras cargar plata).
    const waitEnroll = String(req.query.waitEnroll || '') === '1';
    // 'relampago' va aparte (no esta en RAFFLE_TYPES ni FREE_RAFFLE_TYPES por
    // ser one-shot). Sin esto, el filter de raffleType en la query lo descarta
    // y el user no ve el sorteo ni en el modal ni en el hero.
    const allTypes = [...RAFFLE_TYPES.map(t => t.type), ...FREE_RAFFLE_TYPES.map(t => t.type), 'relampago'];
    const safe = String(username).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

    // Paralelizamos las 3 fuentes pesadas: saldo en JUGAYGANA, lista de
    // raffles en mongo, y participaciones del user en mongo. Antes era
    // secuencial: balance (red) -> raffles (db) -> myParts (db).
    let autoEnrollPromise = null;
    if (waitEnroll) {
      autoEnrollPromise = _autoEnrollFreeRaffles(username).catch(() => []);
    } else {
      // Background: si falla, perfectly fine, se intenta de nuevo proximo refresh
      _autoEnrollFreeRaffles(username).catch(() => {});
    }

    const [balanceRes, rafflesRes, myPartsRes, autoEnrolled] = await Promise.all([
      jugaygana.getUserInfoByName(username).catch(() => null),
      Raffle.find(
        { status: { $in: ['active', 'closed', 'drawn'] }, raffleType: { $in: allTypes } }
      ).sort({ isFree: 1, prizeValueARS: -1, instanceNumber: 1 }).lean(),
      RaffleParticipation.find(
        { username: { $regex: '^' + safe + '$', $options: 'i' } },
        { raffleId: 1, ticketNumbers: 1, cuposCount: 1, isWinner: 1, _id: 0 }
      ).lean(),
      autoEnrollPromise || Promise.resolve([])
    ]);

    const balance = balanceRes && balanceRes.balance ? Number(balanceRes.balance) : 0;
    // Cargamos la config de prefijos UNA vez para filtrar audiencia. Si
    // falla, dejamos pasar todos (defensa: no bloquear UX por una config
    // suelta — es solo un filtro de marketing, no de seguridad critica).
    let linesConfig = null;
    try { linesConfig = await getConfig('userLinesByPrefix'); } catch (_) {}
    // Filtro de audiencia: si un sorteo tiene audienceMode != 'all' y este
    // user no entra, lo sacamos de la lista (no lo ve siquiera).
    const raffles = rafflesRes.filter(r => _userInRaffleAudience(r, username, linesConfig));

    // Cargas semanales del user — solo las consultamos si hay al menos un
    // free raffle visible. Para que el front sepa si el user llego al
    // threshold de cada sorteo gratis (y muestre picker o "te faltan $X").
    let weeklyDeposits = 0;
    const hasFreeWeekly = raffles.some(r =>
      r.raffleType !== 'relampago'
      && (r.isFree || FREE_RAFFLE_TYPE_SET.has(r.raffleType))
      && r.status === 'active'
    );
    if (hasFreeWeekly) {
      try {
        const m = await getRealMovementsTotals(username, 'weekly');
        weeklyDeposits = Number(m && m.deposits) || 0;
      } catch (_) {
        weeklyDeposits = 0;
      }
    }
    // Cargas REALES del user (misma fuente que el panel de cargas del admin
    // — JUGAYGANA via jugayganaMovements.getUserMovements). Antes contabamos
    // Transaction local pero ahi muchas cargas reales no quedan registradas
    // -> users con 1+ carga real figuraban con 0.
    let lightningCargasCount = null;
    const hasLightningVisible = raffles.some(r => r.raffleType === 'relampago');
    if (hasLightningVisible) {
      lightningCargasCount = await _getLightningCargasCount(username, null);
    }
    const myByRaffle = {};
    for (const p of myPartsRes) myByRaffle[p.raffleId] = p;

    // Pendientes de reclamar (auto-credit fallo o todavia no se acredito).
    const claimable = raffles
      .filter(r => r.prizeClaimable && r.winnerUsername &&
        r.winnerUsername.toLowerCase() === username.toLowerCase() && !r.prizeClaimedAt)
      .map(r => ({
        id: r.id, name: r.name, prizeName: r.prizeName, emoji: r.emoji,
        prizeValueARS: r.prizeValueARS || 0,
        winningTicketNumber: r.winningTicketNumber
      }));

    // Ventana de "Felicitaciones":
    //   - Pre-cobro: hasta 24h desde el draw (para que el ganador alcance
    //     a verlo aunque entre dias despues si auto-credit fallo).
    //   - Post-cobro: 30 min con countdown desde prizeClaimedAt. Una vez
    //     que cobro la queremos sacar pronto para no enturbiar el home,
    //     pero le damos 30 min para que disfrute la victoria.
    const FELICITACIONES_TTL_MS = 24 * 3600 * 1000;
    const POSTCLAIM_TTL_MS = 30 * 60 * 1000;
    const recentWins = raffles
      .filter(r => {
        if (r.status !== 'drawn') return false;
        if (!r.winnerUsername || r.winnerUsername.toLowerCase() !== username.toLowerCase()) return false;
        if (!r.drawnAt) return false;
        if (r.prizeClaimedAt) {
          return (Date.now() - new Date(r.prizeClaimedAt).getTime()) < POSTCLAIM_TTL_MS;
        }
        return (Date.now() - new Date(r.drawnAt).getTime()) < FELICITACIONES_TTL_MS;
      })
      .map(r => {
        const claimed = !!r.prizeClaimedAt;
        const expiresAt = claimed
          ? new Date(new Date(r.prizeClaimedAt).getTime() + POSTCLAIM_TTL_MS)
          : new Date(new Date(r.drawnAt).getTime() + FELICITACIONES_TTL_MS);
        const secondsRemaining = Math.max(0, Math.floor((expiresAt.getTime() - Date.now()) / 1000));
        return {
          id: r.id,
          name: r.name,
          prizeName: r.prizeName,
          emoji: r.emoji,
          prizeValueARS: r.prizeValueARS || 0,
          winningTicketNumber: r.winningTicketNumber,
          drawnAt: r.drawnAt,
          prizeClaimedAt: r.prizeClaimedAt || null,
          prizeClaimable: !!r.prizeClaimable,
          expiresAt: expiresAt.toISOString(),
          secondsRemaining,
          // Para compat con el render viejo: si ya cobro, mostramos minutos.
          // Si no cobro todavia, horas como antes.
          hoursRemaining: claimed
            ? 0
            : Math.max(0, Math.ceil((FELICITACIONES_TTL_MS - (Date.now() - new Date(r.drawnAt).getTime())) / 3600000)),
          minutesRemaining: claimed
            ? Math.max(0, Math.ceil(secondsRemaining / 60))
            : null
        };
      });

    res.json({
      balance,
      lotteryRule: RAFFLE_LOTTERY_RULE,
      autoEnrolled,
      weeklyDeposits,
      lightningCargasCount,
      lightningCargasRequired: 5,
      raffles: raffles.map(r => ({
        id: r.id,
        name: r.name,
        prizeName: r.prizeName,
        description: r.description,
        emoji: r.emoji,
        raffleType: r.raffleType,
        instanceNumber: r.instanceNumber,
        entryCost: r.entryCost,
        totalTickets: r.totalTickets,
        prizeValueARS: r.prizeValueARS,
        isFree: !!r.isFree,
        minCargasARS: r.minCargasARS || 0,
        cuposSold: r._ticketCounter || 0,
        cuposRemaining: Math.max(0, (r.totalTickets || 0) - (r._ticketCounter || 0)),
        claimedNumbers: r.claimedNumbers || [],
        drawDate: r.drawDate,
        drawnAt: r.drawnAt || null,
        lotteryRule: r.lotteryRule,
        status: r.status,
        winnerUsername: r.winnerUsername,
        winningTicketNumber: r.winningTicketNumber,
        prizeClaimable: !!r.prizeClaimable,
        prizeClaimedAt: r.prizeClaimedAt || null,
        myTicketNumbers: (myByRaffle[r.id] && myByRaffle[r.id].ticketNumbers) || [],
        myCuposCount: (myByRaffle[r.id] && myByRaffle[r.id].cuposCount) || 0,
        iAmWinner: (myByRaffle[r.id] && myByRaffle[r.id].isWinner) || false,
        requiresPaidTicket: !!r.requiresPaidTicket,
        requiresMinChargesLastWeek: r.requiresMinChargesLastWeek || 0
      })),
      claimable,
      recentWins
    });
  } catch (err) {
    logger.error(`/api/raffles/active: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// GET /api/raffles/recent-winners — ganadores recientes para el banner del home.
// Ventana 6h por default. Sirve para social proof: cualquier user que abre la
// app ve "alguien acaba de ganar" en el menu, sin tener que abrir el modal.
// Si el caller es el ganador, devuelve isMe=true y el front muestra el banner
// personalizado de "FELICITACIONES" en vez del generico.
app.get('/api/raffles/recent-winners', authMiddleware, async (req, res) => {
  try {
    const hours = Math.max(1, Math.min(48, parseInt(req.query.hours, 10) || 6));
    const cutoff = new Date(Date.now() - hours * 3600 * 1000);
    const recent = await Raffle.find({
      status: 'drawn',
      winnerUsername: { $ne: null },
      drawnAt: { $gte: cutoff }
    })
      .sort({ drawnAt: -1 })
      .limit(5)
      .select('id name prizeName prizeValueARS emoji winnerUsername winningTicketNumber drawnAt prizeClaimedAt prizeClaimable raffleType')
      .lean();
    const me = String((req.user && req.user.username) || '').toLowerCase();
    const POSTCLAIM_TTL_MS = 30 * 60 * 1000;
    // Filtramos: si soy el ganador y ya cobre hace mas de 30 min, no muestro.
    // Si no soy el ganador, sigue la ventana de "hours" del filtro.
    const winners = [];
    for (const r of recent) {
      const isMe = String(r.winnerUsername || '').toLowerCase() === me;
      // Si soy yo y ya cobre, recortamos a 30 min post-cobro
      if (isMe && r.prizeClaimedAt) {
        const sinceClaim = Date.now() - new Date(r.prizeClaimedAt).getTime();
        if (sinceClaim >= POSTCLAIM_TTL_MS) continue;
      }
      const ageMs = Date.now() - new Date(r.drawnAt).getTime();
      const hoursAgo = Math.max(0, Math.floor(ageMs / 3600000));
      const minutesAgo = Math.max(0, Math.floor(ageMs / 60000));
      let secondsRemaining = null;
      if (isMe && r.prizeClaimedAt) {
        secondsRemaining = Math.max(0, Math.floor((POSTCLAIM_TTL_MS - (Date.now() - new Date(r.prizeClaimedAt).getTime())) / 1000));
      }
      winners.push({
        id: r.id,
        name: r.name,
        prizeName: r.prizeName,
        prizeValueARS: r.prizeValueARS || 0,
        emoji: r.emoji || '🏆',
        winnerUsername: r.winnerUsername,
        winningTicketNumber: r.winningTicketNumber,
        drawnAt: r.drawnAt,
        prizeClaimedAt: r.prizeClaimedAt || null,
        prizeClaimable: !!r.prizeClaimable,
        isMe,
        hoursAgo,
        minutesAgo,
        secondsRemaining,
        raffleType: r.raffleType
      });
    }
    // Incluimos info del sorteo RELAMPAGO si hay uno activo o cerrado-en-espera.
    // El home usa esto para renderizar el hero electrico arriba del card
    // generico de "SORTEOS SEMANALES".
    let lightning = null;
    let homeBalance = null;
    try {
      // Cuando hay multiples relampagos abiertos (auto-respawn), priorizamos
      // el ACTIVO (status='active') sobre el cerrado (status='closed'). Asi
      // si el N°1 ya se lleno y largo el N°2, el hero del home muestra el
      // N°2 (donde la gente puede anotarse) y no el N°1 cerrado. Sort:
      // active primero, despues por createdAt desc (mas reciente).
      const lights = await Raffle.find(
        { raffleType: 'relampago', status: { $in: ['active', 'closed'] } },
        { id: 1, name: 1, prizeValueARS: 1, totalTickets: 1, _ticketCounter: 1, status: 1, drawDate: 1, emoji: 1, entryCost: 1, isFree: 1, createdAt: 1, instanceNumber: 1 }
      ).sort({ status: 1, createdAt: -1 }).limit(3).lean();
      // Sort {status:1} pone 'active' antes que 'closed' alfabeticamente
      // ('a' < 'c'). Tomamos el primero (preferentemente active mas reciente).
      const light = lights[0];
      if (light) {
        const myUsername = (req.user && req.user.username) || '';
        const safeUser = String(myUsername).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        const myPart = await RaffleParticipation.findOne(
          { raffleId: light.id, username: { $regex: '^' + safeUser + '$', $options: 'i' } },
          { ticketNumbers: 1 }
        ).lean();
        // Si el user esta anotado en OTRO relampago (no este), lo informamos
        // para que el front muestre "NO DISPONIBLE — ya estas anotado en N°X
        // con #Y" en lugar del boton "ELEGIR MI NUMERO". Regla 1 cupo por
        // persona en TODOS los relampagos abiertos.
        const otherIds = lights.map(l => l.id).filter(id => id !== light.id);
        let myEnrolledOther = null;
        if (otherIds.length > 0) {
          const other = await RaffleParticipation.findOne(
            { raffleId: { $in: otherIds }, username: { $regex: '^' + safeUser + '$', $options: 'i' } },
            { ticketNumbers: 1, raffleId: 1 }
          ).lean();
          if (other) {
            const otherRaffle = lights.find(l => l.id === other.raffleId);
            myEnrolledOther = {
              raffleId: other.raffleId,
              raffleName: (otherRaffle && otherRaffle.name) || 'otro RELÁMPAGO',
              status: (otherRaffle && otherRaffle.status) || 'active',
              ticketNumber: (other.ticketNumbers && other.ticketNumbers[0]) || null
            };
          }
        }
        // Si el relampago es PAGO, traemos balance para que el front decida
        // mostrar "QUIERO CARGAR" vs "ELEGIR MI NÚMERO ($X)" sin un round trip
        // extra. Si es gratis, no necesitamos balance.
        if (!light.isFree && (light.entryCost || 0) > 0) {
          try {
            const info = await jugaygana.getUserInfoByName(myUsername);
            homeBalance = info && info.balance != null ? Number(info.balance) : 0;
          } catch (_) { homeBalance = null; }
        }
        lightning = {
          id: light.id,
          name: light.name,
          prizeValueARS: light.prizeValueARS || 0,
          totalTickets: light.totalTickets || 0,
          cuposSold: light._ticketCounter || 0,
          status: light.status,
          drawDate: light.drawDate,
          emoji: light.emoji || '⚡',
          entryCost: light.entryCost || 0,
          isFree: !!light.isFree,
          myTicket: (myPart && myPart.ticketNumbers && myPart.ticketNumbers[0]) || null,
          myEnrolledOther
        };
      }
    } catch (e) {
      logger.warn(`[raffles] recent-winners lightning fetch fail: ${e.message}`);
    }
    res.json({ winners, windowHours: hours, lightning, balance: homeBalance });
  } catch (err) {
    logger.error(`/api/raffles/recent-winners: ${err.message}`);
    res.status(500).json({ error: 'Error obteniendo ganadores recientes' });
  }
});

// POST /api/raffles/:id/buy — comprar N numeros con saldo de JUGAYGANA.
// El user PUEDE elegir sus numeros (pickedNumbers[]) o dejar que el sistema
// los asigne aleatoriamente entre los disponibles.
//
// Flujo: (1) chequea balance — (2) reserva atomicamente los numeros via
// findOneAndUpdate con $nin (ningun numero pedido puede estar tomado) +
// $push + $inc — si falla, otro caller los tomo — (3) descuenta saldo en
// JUGAYGANA — si falla, libera los numeros — (4) crea/actualiza
// participation — (5) si se lleno el cupo, marca closed y respawnea.
app.post('/api/raffles/:id/buy', authMiddleware, async (req, res) => {
  const username = req.user.username;
  const raffleId = req.params.id;
  const body = req.body || {};
  const rawPicked = Array.isArray(body.pickedNumbers) ? body.pickedNumbers : null;
  const quantity = Math.max(1, Math.min(50, parseInt(body.quantity, 10) || (rawPicked ? rawPicked.length : 1)));
  let reservedNumbers = [];
  let withdrew = false;
  logger.info(`[raffles] BUY ATTEMPT ${username} raffle=${raffleId} qty=${quantity} picked=[${(rawPicked || []).join(',')}]`);
  try {
    const raffle = await Raffle.findOne({ id: raffleId }).lean();
    if (!raffle) {
      logger.warn(`[raffles] BUY REJ ${username}: raffle ${raffleId} not found`);
      return res.status(404).json({ error: 'Sorteo no encontrado.' });
    }
    if (raffle.status !== 'active') {
      logger.warn(`[raffles] BUY REJ ${username}: raffle ${raffle.name} status=${raffle.status}`);
      return res.status(400).json({ error: `Este sorteo ya no acepta compras (estado: ${raffle.status}).` });
    }
    // Audience gate: si tiene mode != 'all', validamos que el user este
    // dentro del segmento permitido por equipo.
    if (raffle.audienceMode && raffle.audienceMode !== 'all') {
      let linesCfg = null;
      try { linesCfg = await getConfig('userLinesByPrefix'); } catch (_) {}
      if (!_userInRaffleAudience(raffle, username, linesCfg)) {
        return res.status(403).json({ error: 'Este sorteo no está disponible para tu equipo.' });
      }
    }
    // Free clasicos (free_p100/p500/p1m/p2m): el user llega cuando supera
    // el threshold de cargas semanales y desde la app elige su numero del
    // grid (mismo UX que paid/relampago). Validamos:
    //   1) entryCost = 0 (sino seria un sorteo pago)
    //   2) cargas semanales >= minCargasARS
    //   3) 1 cupo max por persona
    //   4) tiene que mandar pickedNumbers (no aleatorio)
    const isFreeWeekly = raffle.raffleType !== 'relampago'
      && (raffle.isFree || FREE_RAFFLE_TYPE_SET.has(raffle.raffleType));
    if (isFreeWeekly) {
      // Threshold check
      if ((raffle.minCargasARS || 0) > 0) {
        let weeklyDeposits = 0;
        try {
          const m = await getRealMovementsTotals(username, 'weekly');
          weeklyDeposits = Number(m && m.deposits) || 0;
        } catch (e) {
          logger.warn(`[raffles] FREE buy threshold check fail ${username}: ${e.message}`);
          return res.status(503).json({ error: 'No pudimos verificar tus cargas. Probá en un minuto.' });
        }
        if (weeklyDeposits < raffle.minCargasARS) {
          const falta = raffle.minCargasARS - weeklyDeposits;
          return res.status(403).json({
            error: `Te faltan $${falta.toLocaleString('es-AR')} de cargas esta semana para entrar a este sorteo gratis.`,
            notEnoughDeposits: true,
            weeklyDeposits,
            requiredDeposits: raffle.minCargasARS,
            shortfall: falta
          });
        }
      }
      // 1 cupo max
      const safeBuy = String(username).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      const already = await RaffleParticipation.findOne({
        raffleId: raffle.id,
        username: { $regex: '^' + safeBuy + '$', $options: 'i' }
      }, { ticketNumbers: 1 }).lean();
      if (already) {
        return res.status(400).json({
          error: `Ya estás anotado en este sorteo gratis con el número #${already.ticketNumbers && already.ticketNumbers[0]}. Es 1 cupo por persona.`,
          alreadyEnrolledNumber: already.ticketNumbers && already.ticketNumbers[0]
        });
      }
      if (quantity > 1) {
        return res.status(400).json({ error: 'En los sorteos gratis solo se permite 1 número por persona.' });
      }
      if (!rawPicked || rawPicked.length === 0) {
        return res.status(400).json({ error: 'En los sorteos gratis tenés que ELEGIR vos tu número del grid.' });
      }
    }
    // Relampago: 1 cupo por persona max. Validar antes de reservar para que
    // el error sea claro (el unique index lo atajaria igual pero con error feo).
    if (raffle.raffleType === 'relampago') {
      const safeBuy = String(username).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      // 1 cupo por persona en TODOS los relampagos abiertos (active+closed).
      // Asi cuando el N°1 se llena y respawnea N°2, los que ya entraron al N°1
      // no pueden entrar al N°2. Una vez que su relampago se sortea (drawn),
      // pueden entrar al proximo.
      const openLightnings = await Raffle.find(
        { raffleType: 'relampago', status: { $in: ['active', 'closed'] } },
        { id: 1, name: 1 }
      ).lean();
      const openLightningIds = openLightnings.map(r => r.id);
      const already = await RaffleParticipation.findOne({
        raffleId: { $in: openLightningIds },
        username: { $regex: '^' + safeBuy + '$', $options: 'i' }
      }, { ticketNumbers: 1, raffleId: 1 }).lean();
      if (already) {
        const otherRaffle = openLightnings.find(r => r.id === already.raffleId);
        const otherName = (otherRaffle && otherRaffle.name) || 'otro RELÁMPAGO';
        const sameRaffle = already.raffleId === raffle.id;
        return res.status(400).json({
          error: sameRaffle
            ? `Ya estás anotado en este RELÁMPAGO con el número #${already.ticketNumbers && already.ticketNumbers[0]}. Es 1 cupo por persona.`
            : `Ya estás anotado en ${otherName} con el número #${already.ticketNumbers && already.ticketNumbers[0]}. Solo se permite 1 cupo por persona en sorteos RELÁMPAGO.`,
          alreadyEnrolledNumber: already.ticketNumbers && already.ticketNumbers[0],
          alreadyEnrolledRaffleId: already.raffleId
        });
      }
      if (quantity > 1) {
        return res.status(400).json({ error: 'En el RELÁMPAGO solo se permite 1 número por persona.' });
      }
      // Defense in depth: el owner pidio explicitamente que el user ELIJA
      // su numero (no aleatorio). El front siempre manda pickedNumbers porque
      // el boton se habilita despues de tap, pero por si llega un buy sin
      // pickedNumbers (bug o cliente custom) lo rechazamos.
      if (!rawPicked || rawPicked.length === 0) {
        return res.status(400).json({ error: 'En el RELÁMPAGO tenés que ELEGIR vos tu número (no es aleatorio).' });
      }
      // Gate: si este relampago lo requiere, exigir al menos 1 participation
      // en algun sorteo PAGO. Asi convertimos el primer relampago (libre)
      // en gancho hacia los pagos -> el segundo en adelante recompensa a
      // los que ya jugaron pagos.
      if (raffle.requiresPaidTicket) {
        const paidPart = await RaffleParticipation.findOne({
          username: { $regex: '^' + safeBuy + '$', $options: 'i' },
          entryCostPaid: { $gt: 0 }
        }, { _id: 1 }).lean();
        if (!paidPart) {
          return res.status(403).json({
            error: 'Este RELÁMPAGO es exclusivo para clientes que ya tienen al menos 1 número en sorteos pagos. ¡Comprá uno y volvé al próximo gratis!',
            requiresPaidTicket: true
          });
        }
      }
      // Gate: si requiere N cargas REALES en los ultimos 7 dias. Las
      // bonificaciones no cuentan — solo cargas con plata propia. Util para
      // sorteos de "recompensa por actividad" (jugadores constantes) sin
      // mirar el monto, solo la frecuencia.
      const minCharges = Number(raffle.requiresMinChargesLastWeek) || 0;
      if (minCharges > 0) {
        const userCharges = await _getRealChargeCountLastWeek(username);
        if (userCharges < minCharges) {
          return res.status(403).json({
            error: `Este RELÁMPAGO es solo para usuarios con al menos ${minCharges} cargas en la última semana. Vos tenés ${userCharges}. ¡Cargá unas más y vení al próximo!`,
            requiresMinChargesLastWeek: minCharges,
            userChargesLastWeek: userCharges
          });
        }
      }
    }

    // Cutoff: no vender cupos en las 3 horas previas al draw para evitar que
    // alguien compre mientras el admin ya está cargando el ganador.
    if (raffle.drawDate) {
      const drawTs = new Date(raffle.drawDate).getTime();
      const minutesToDraw = Math.round((drawTs - Date.now()) / 60000);
      if (Date.now() > drawTs - 3 * 3600 * 1000) {
        logger.warn(`[raffles] BUY REJ ${username}: raffle ${raffle.name} drawDate=${raffle.drawDate} cutoff=3hs minutesToDraw=${minutesToDraw}`);
        return res.status(400).json({
          error: `Este sorteo cerró las ventas (faltan menos de 3 horas para el draw — quedan ${minutesToDraw} min).`,
          minutesToDraw,
          drawDate: raffle.drawDate
        });
      }
    }

    const totalTickets = raffle.totalTickets || 0;
    const claimedSet = new Set((raffle.claimedNumbers || []).map(n => Number(n)));
    const remaining = Math.max(0, totalTickets - claimedSet.size);
    if (remaining <= 0) return res.status(400).json({ error: 'No quedan cupos en este sorteo.' });

    // Determinar los numeros a reservar.
    let pickedNumbers;
    if (rawPicked) {
      // Validar lo que pidio el user.
      if (rawPicked.length === 0) return res.status(400).json({ error: 'No elegiste ningún número.' });
      if (rawPicked.length !== quantity) return res.status(400).json({ error: 'Inconsistencia entre cantidad y números elegidos.' });
      const cleaned = rawPicked.map(n => parseInt(n, 10)).filter(n => Number.isFinite(n));
      if (cleaned.length !== rawPicked.length) return res.status(400).json({ error: 'Hay números inválidos en la selección.' });
      const dedup = Array.from(new Set(cleaned));
      if (dedup.length !== cleaned.length) return res.status(400).json({ error: 'No podés elegir el mismo número dos veces.' });
      for (const n of dedup) {
        if (n < 1 || n > totalTickets) return res.status(400).json({ error: `El número ${n} está fuera del rango (1 a ${totalTickets}).` });
        if (claimedSet.has(n)) return res.status(400).json({ error: `El número ${n} ya está tomado por otro jugador. Elegí otro.`, takenNumber: n });
      }
      pickedNumbers = dedup;
    } else {
      // Aleatorio: tomamos `quantity` numeros disponibles del pool.
      const buyQty = Math.min(quantity, remaining);
      const available = [];
      for (let n = 1; n <= totalTickets && available.length < buyQty * 3; n++) {
        if (!claimedSet.has(n)) available.push(n);
      }
      // Mezclar y tomar buyQty
      for (let i = available.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [available[i], available[j]] = [available[j], available[i]];
      }
      pickedNumbers = available.slice(0, buyQty);
    }

    const buyQty = pickedNumbers.length;
    const totalCost = buyQty * (raffle.entryCost || 0);
    const isFreeRaffleBuy = (raffle.entryCost || 0) === 0;
    // Para free (relampago) saltamos toda la verificacion de saldo y el
    // withdraw — la inscripcion es gratis. Solo los pagos pasan por aca.
    if (!isFreeRaffleBuy && totalCost <= 0) {
      logger.error(`[raffles] BUY REJ ${username}: totalCost=${totalCost} (entryCost=${raffle.entryCost} buyQty=${buyQty}) — config rota`);
      return res.status(500).json({ error: 'Configuración del sorteo inválida (entryCost = 0). Avisá al admin.' });
    }

    // Balance check con retry — solo para sorteos pagos.
    let balance = 0;
    if (!isFreeRaffleBuy) {
      let userFetchOk = false;
      let userInfo = null;
      for (let attempt = 1; attempt <= 2; attempt++) {
        try {
          userInfo = await jugaygana.getUserInfoByName(username);
          if (userInfo) {
            userFetchOk = true;
            balance = Number(userInfo.balance) || 0;
            break;
          }
        } catch (e) {
          logger.warn(`[raffles] BUY balance fetch exc ${username} attempt=${attempt}: ${e.message}`);
        }
        if (attempt === 1) await new Promise(r => setTimeout(r, 500));
      }

      if (!userFetchOk) {
        logger.error(`[raffles] BUY REJ ${username}: no se pudo obtener user info de JUGAYGANA tras 2 intentos`);
        return res.status(503).json({
          error: 'No pudimos verificar tu saldo en JUGAYGANA en este momento. Probá de nuevo en unos segundos.',
          retry: true
        });
      }

      if (balance < totalCost) {
        logger.warn(`[raffles] BUY REJ ${username}: saldo insuficiente balance=$${balance} needed=$${totalCost} (qty=${buyQty} x $${raffle.entryCost})`);
        return res.status(400).json({
          error: `Saldo insuficiente. Necesitás $${totalCost.toLocaleString('es-AR')} y tenés $${balance.toLocaleString('es-AR')} en JUGAYGANA.`,
          needed: totalCost,
          balance,
          entryCost: raffle.entryCost,
          cuposIntended: buyQty
        });
      }
    }

    // Reserva atomica: el update solo prospera si NINGUN pickedNumber esta en
    // claimedNumbers Y el cupo final no excede totalTickets. Si dos compras
    // pelean por el mismo numero, una gana y la otra recibe null aqui.
    const reserved = await Raffle.findOneAndUpdate(
      {
        id: raffleId,
        status: 'active',
        claimedNumbers: { $nin: pickedNumbers },
        $expr: { $lte: [{ $add: [{ $size: { $ifNull: ['$claimedNumbers', []] } }, buyQty] }, '$totalTickets'] }
      },
      {
        $push: { claimedNumbers: { $each: pickedNumbers } },
        $inc: { _ticketCounter: buyQty }
      },
      { new: true }
    );
    if (!reserved) {
      // Refetch para reportar bien al user
      const fresh = await Raffle.findOne({ id: raffleId }, { claimedNumbers: 1, totalTickets: 1, status: 1 }).lean();
      const freshSet = new Set((fresh && fresh.claimedNumbers || []).map(n => Number(n)));
      const conflict = pickedNumbers.find(n => freshSet.has(n));
      if (conflict) {
        return res.status(409).json({
          error: `Otro jugador tomó el número ${conflict} antes que vos. Elegí otro.`,
          takenNumber: conflict
        });
      }
      const r2 = fresh ? Math.max(0, (fresh.totalTickets || 0) - freshSet.size) : 0;
      return res.status(400).json({ error: `No se pudo reservar (quedan ${r2} cupos).`, cuposRemaining: r2 });
    }
    reservedNumbers = pickedNumbers;
    const counterAfter = reserved._ticketCounter;
    const assignedNumbers = [...pickedNumbers].sort((a, b) => a - b);
    const numStr = assignedNumbers.length === 1
      ? `#${assignedNumbers[0]}`
      : `#${assignedNumbers.join(', #')}`;

    // Withdraw solo para sorteos pagos. Relampago/free saltea esto.
    let txId = null;
    if (!isFreeRaffleBuy) {
      const wRes = await jugaygana.withdrawFromUser(username, totalCost, `Sorteo ${raffle.name} ${numStr}`);
      if (!wRes || !wRes.success) {
        await Raffle.updateOne(
          { id: raffleId },
          { $pull: { claimedNumbers: { $in: reservedNumbers } }, $inc: { _ticketCounter: -buyQty } }
        ).catch(() => {});
        reservedNumbers = [];
        const errMsg = (wRes && wRes.error) || 'Error desconocido al descontar saldo';
        logger.error(`[raffles] withdraw failed ${username} ${raffle.name}: ${errMsg}`);
        return res.status(503).json({ error: `No se pudo procesar el pago: ${errMsg}.` });
      }
      withdrew = true;
      txId = (wRes && wRes.data && (wRes.data.transfer_id || wRes.data.transferId || wRes.data.transaction_id || wRes.data.transactionId)) || null;
    } else {
      // Inscripcion gratis: marcamos withdrew=true por compatibilidad con la
      // logica de cleanup mas abajo (asi no intenta refund si algo falla).
      withdrew = true;
    }
    logger.info(`[raffles] BUY OK ${username} +${buyQty} numeros [${assignedNumbers.join(',')}] ${raffle.name} = $${totalCost} ${isFreeRaffleBuy ? '(gratis)' : '(txid: ' + (txId || 'n/a') + ')'}`);

    // Log inmutable de gasto: alimenta el cierre diario. Best-effort: si
    // falla, el cobro ya esta hecho y no debemos tirar la compra (queda
    // logueado en winston con [raffles-spend] para reconciliar a mano).
    try {
      await RaffleSpend.create({
        id: uuidv4(),
        username,
        raffleId,
        raffleType: raffle.raffleType,
        raffleName: raffle.name,
        cuposCount: buyQty,
        ticketNumbers: assignedNumbers,
        amountARS: totalCost,
        jugayganaTxId: txId ? String(txId) : null,
        createdAt: new Date(),
        dayKeyArg: _argDayKey()
      });
    } catch (logErr) {
      logger.error(`[raffles-spend] insert fail ${username} ${raffle.name} $${totalCost} txid=${txId || 'n/a'}: ${logErr.message}`);
    }

    // Persistencia de la participation. Si esto falla DESPUES del withdraw,
    // tenemos un riesgo: el user pago pero no quedo registrado. Para
    // mitigarlo: 3 reintentos con backoff. Si todos fallan, hacemos
    // refund automatico via creditUserBalance + log de incidente.
    const safe = String(username).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    let participationOk = false;
    let participationLastErr = null;
    for (let attempt = 1; attempt <= 3; attempt++) {
      try {
        const existing = await RaffleParticipation.findOne({ raffleId, username: { $regex: '^' + safe + '$', $options: 'i' } });
        if (existing) {
          existing.cuposCount = (existing.cuposCount || 1) + buyQty;
          existing.entryCostPaid = (existing.entryCostPaid || 0) + totalCost;
          existing.lastBoughtAt = new Date();
          existing.ticketNumbers = (existing.ticketNumbers || []).concat(assignedNumbers);
          await existing.save();
        } else {
          await RaffleParticipation.create({
            id: uuidv4(),
            raffleId,
            username,
            joinedAt: new Date(),
            lastBoughtAt: new Date(),
            cuposCount: buyQty,
            ticketNumbers: assignedNumbers,
            entryCostPaid: totalCost
          });
        }
        participationOk = true;
        break;
      } catch (partErr) {
        participationLastErr = partErr;
        logger.warn(`[raffles] participation save fail ${username} ${raffle.name} attempt=${attempt}: ${partErr.message}`);
        if (attempt < 3) await new Promise(r => setTimeout(r, 200 * attempt));
      }
    }
    if (!participationOk) {
      // Plata cobrada pero no podemos registrar. Refund + log incident.
      logger.error(`[raffles] CRITICAL participation save FAIL after retries ${username} ${raffle.name} $${totalCost} txid=${txId || 'n/a'} err=${participationLastErr && participationLastErr.message} — emitiendo refund automatico`);
      try {
        await jugaygana.creditUserBalance(username, totalCost, `REFUND ${raffle.name} (error registro participation)`);
        // Liberar los numeros reservados.
        await Raffle.updateOne(
          { id: raffleId },
          { $pull: { claimedNumbers: { $in: reservedNumbers } }, $inc: { _ticketCounter: -buyQty } }
        ).catch(() => {});
      } catch (refundErr) {
        logger.error(`[raffles] CRITICAL refund failed ${username} ${raffle.name} $${totalCost}: ${refundErr.message} — INCIDENT: revisar a mano`);
      }
      return res.status(500).json({ error: 'Hubo un error guardando tu compra. Te devolvimos el dinero. Probá de nuevo.' });
    }

    let cupoFilled = false;
    if (counterAfter >= raffle.totalTickets) {
      cupoFilled = true;
      // Cerrar atomicamente: solo el primer caller que vea el cupo lleno
      // pasa de 'active' a 'closed'. Los demas no respawnean (evita doble
      // instancia activa cuando dos compras llegan simultaneas).
      const closeRes = await Raffle.updateOne(
        { id: raffleId, status: 'active' },
        { $set: { status: 'closed' } }
      );
      if (closeRes.modifiedCount === 1) {
        // POLITICA: solo respawneamos GRATIS. Los pagos cierran y listo —
        // cuando se sortea, no se crea otra instancia. Cuando todos los
        // pagos terminen, esa lista queda vacia para siempre (hasta que
        // se reactive la politica desde codigo).
        const cfg = FREE_RAFFLE_TYPES.find(t => t.type === raffle.raffleType);
        if (cfg) {
          try {
            await _spawnRaffleInstance(cfg, (raffle.instanceNumber || 1) + 1);
            logger.info(`[raffles] respawn ${cfg.type} #${(raffle.instanceNumber || 1) + 1}`);
          } catch (e) {
            logger.warn(`[raffles] respawn ${cfg.type}: ${e.message}`);
          }
        } else if (raffle.raffleType !== 'relampago') {
          logger.info(`[raffles] paid ${raffle.raffleType} llenó — NO respawn (politica: solo gratis).`);
        }
        if (raffle.raffleType === 'relampago') {
          // Auto-respawn del relampago hasta tope 3. El admin arma el N°1, el
          // N°2 y N°3 los abre el sistema clonando la config (premio, cupos,
          // gratis/pago, audiencia). Los que ya estan anotados en el cerrado
          // NO pueden entrar al nuevo (regla de 1 cupo por persona en todos
          // los relampagos abiertos — chequeada en el /buy).
          try {
            const openCount = await Raffle.countDocuments({
              raffleType: 'relampago',
              status: { $in: ['active', 'closed'] }
            });
            if (openCount < 3) {
              await _spawnLightningClone(raffle);
              logger.info(`[raffles] LIGHTNING auto-respawn (count=${openCount} -> ${openCount + 1})`);
            } else {
              logger.info(`[raffles] LIGHTNING no respawn — ya hay ${openCount} (tope 3)`);
            }
          } catch (e) {
            logger.warn(`[raffles] LIGHTNING auto-respawn fail: ${e.message}`);
          }
          // Push a todos los participantes del que se acaba de llenar:
          // recordatorio de que para reclamar el premio necesitan 5 cargas +
          // juego con nosotros. Es la mecanica de "exclusivo para clientes".
          try {
            await _notifyLightningClosed(raffle);
          } catch (e) {
            logger.warn(`[raffles] LIGHTNING notify closed fail: ${e.message}`);
          }
        }
      }
    }

    res.json({
      success: true,
      ticketNumbers: assignedNumbers,
      cuposBought: buyQty,
      totalCost,
      raffleId,
      cuposSold: counterAfter,
      cuposRemaining: Math.max(0, raffle.totalTickets - counterAfter),
      cupoFilled
    });
  } catch (err) {
    logger.error(`/api/raffles/buy: ${err.message}`);
    // Si reservamos numeros pero NO se cobro (excepcion entre reservar y
    // withdraw, o entre withdraw y participation), liberamos los numeros
    // para que otros puedan comprarlos. Si ya se cobro, los numeros quedan
    // marcados como reservados (es lo correcto: el user pago).
    if (reservedNumbers && reservedNumbers.length > 0 && !withdrew) {
      await Raffle.updateOne(
        { id: raffleId },
        { $pull: { claimedNumbers: { $in: reservedNumbers } }, $inc: { _ticketCounter: -reservedNumbers.length } }
      ).catch(() => {});
    }
    res.status(500).json({ error: err.message || 'Error procesando la compra' });
  }
});

// POST /api/raffles/:id/claim-prize — el ganador acredita el premio a su saldo.
// Defensa contra doble-claim: marcamos prizeClaimedAt atomicamente ANTES de
// pegarle a JUGAYGANA. Si dos requests llegan simultaneas, solo una pasa el
// findOneAndUpdate. Si el credit falla, hacemos rollback explicito del marker.
app.post('/api/raffles/:id/claim-prize', authMiddleware, async (req, res) => {
  const username = req.user.username;
  const raffleId = req.params.id;
  let claimReserved = false;
  try {
    const raffleRead = await Raffle.findOne({ id: raffleId }, {
      status: 1, winnerUsername: 1, prizeClaimedAt: 1, prizeValueARS: 1, name: 1, _id: 0
    }).lean();
    if (!raffleRead) return res.status(404).json({ error: 'Sorteo no encontrado.' });
    if (raffleRead.status !== 'drawn') return res.status(400).json({ error: 'Este sorteo todavía no fue sorteado.' });
    if (!raffleRead.winnerUsername || raffleRead.winnerUsername.toLowerCase() !== username.toLowerCase()) {
      return res.status(403).json({ error: 'No sos el ganador de este sorteo.' });
    }
    if (raffleRead.prizeClaimedAt) {
      return res.status(400).json({ error: 'Ya reclamaste este premio.' });
    }
    const prize = Number(raffleRead.prizeValueARS) || 0;
    if (prize <= 0) return res.status(400).json({ error: 'Este sorteo no tiene premio configurado.' });

    // Reserva atomica: solo un request gana esta carrera.
    const reservedClaim = await Raffle.findOneAndUpdate(
      { id: raffleId, status: 'drawn', prizeClaimedAt: null, prizeClaimable: true },
      { $set: { prizeClaimedAt: new Date(), prizeClaimable: false } },
      { new: true }
    );
    if (!reservedClaim) {
      return res.status(400).json({ error: 'Ya reclamaste este premio.' });
    }
    claimReserved = true;

    const credit = await jugaygana.creditUserBalance(username, prize);
    if (!credit || !credit.success) {
      // Rollback: liberar el marker para que el user pueda reintentar.
      await Raffle.updateOne(
        { id: raffleId },
        { $set: { prizeClaimedAt: null, prizeClaimable: true } }
      ).catch(() => {});
      claimReserved = false;
      const msg = (credit && credit.error) || 'Error al acreditar premio';
      logger.error(`[raffles] claim-prize fail ${username} ${reservedClaim.name}: ${msg}`);
      return res.status(503).json({ error: `No se pudo acreditar el premio: ${msg}. Reintentá en unos segundos.` });
    }

    // Persistir el txId del credit para auditoria.
    await Raffle.updateOne(
      { id: raffleId },
      { $set: { prizeClaimTxId: (credit.transactionId || credit.transferId) || null } }
    ).catch(() => {});
    logger.info(`[raffles] PREMIO ACREDITADO: ${username} +$${prize} (${reservedClaim.name})`);

    res.json({
      success: true,
      amount: prize,
      message: `¡Premio de $${prize.toLocaleString('es-AR')} acreditado a tu saldo!`
    });
  } catch (err) {
    // Si reservamos el claim pero algo explotó después, liberamos para que
    // pueda reintentar (best-effort).
    if (claimReserved) {
      await Raffle.updateOne(
        { id: raffleId },
        { $set: { prizeClaimedAt: null, prizeClaimable: true } }
      ).catch(() => {});
    }
    logger.error(`/api/raffles/claim-prize: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// =============================
// ADMIN ENDPOINTS
// =============================

app.get('/api/admin/raffles', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const newTypes = RAFFLE_TYPES.map(t => t.type);
    const raffles = await Raffle.find(
      { status: { $in: ['active', 'closed', 'drawn'] }, raffleType: { $in: newTypes } }
    ).sort({ status: 1, raffleType: 1, instanceNumber: 1 }).lean();
    const ids = raffles.map(r => r.id);
    const partsAgg = await RaffleParticipation.aggregate([
      { $match: { raffleId: { $in: ids } } },
      { $group: { _id: '$raffleId', cuposSold: { $sum: '$cuposCount' }, participants: { $sum: 1 }, revenue: { $sum: '$entryCostPaid' } } }
    ]);
    const byId = {};
    for (const p of partsAgg) byId[p._id] = p;

    res.json({
      raffles: raffles.map(r => ({
        id: r.id,
        name: r.name,
        prizeName: r.prizeName,
        emoji: r.emoji,
        raffleType: r.raffleType,
        instanceNumber: r.instanceNumber,
        entryCost: r.entryCost,
        totalTickets: r.totalTickets,
        prizeValueARS: r.prizeValueARS,
        cuposSold: (byId[r.id] && byId[r.id].cuposSold) || 0,
        participants: (byId[r.id] && byId[r.id].participants) || 0,
        revenue: (byId[r.id] && byId[r.id].revenue) || 0,
        drawDate: r.drawDate,
        weekKey: r.weekKey,
        status: r.status,
        winnerUsername: r.winnerUsername,
        winningTicketNumber: r.winningTicketNumber,
        lotteryDrawNumber: r.lotteryDrawNumber,
        lotteryDrawSource: r.lotteryDrawSource,
        prizeClaimable: r.prizeClaimable || false,
        prizeClaimedAt: r.prizeClaimedAt,
        drawnAt: r.drawnAt
      }))
    });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

app.get('/api/admin/raffles/:id/participants', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const raffle = await Raffle.findOne({ id: req.params.id }).lean();
    if (!raffle) return res.status(404).json({ error: 'Sorteo no encontrado.' });
    const parts = await RaffleParticipation.find({ raffleId: raffle.id })
      .sort({ entryCostPaid: -1, lastBoughtAt: -1 })
      .lean();

    // Para los pagos, traemos cada COMPRA individual desde RaffleSpend para
    // poder mostrar el historial completo del user en este sorteo (no solo
    // el acumulado). Si es free, RaffleSpend va a estar vacio.
    const spends = await RaffleSpend.find({ raffleId: raffle.id })
      .sort({ createdAt: 1 })
      .lean();
    const spendsByUser = {};
    for (const s of spends) {
      const k = String(s.username).toLowerCase();
      if (!spendsByUser[k]) spendsByUser[k] = [];
      spendsByUser[k].push({
        amountARS: s.amountARS,
        cuposCount: s.cuposCount,
        ticketNumbers: s.ticketNumbers || [],
        jugayganaTxId: s.jugayganaTxId,
        createdAt: s.createdAt
      });
    }

    // RELAMPAGO: enriquecemos cada participant con count de cargas. Hay 2
    // fuentes posibles, controladas por ?source:
    //   - source=master (con ?from/?to opcional): lee las cargas del
    //     segmento Master cargado desde Drive/CSV. Mucho mas rapido y
    //     consistente con lo que el admin esta analizando en Segmentos.
    //   - source=live (default): cuenta cargas reales en JUGAYGANA (lento
    //     pero siempre actualizado).
    const isLightning = raffle.raffleType === 'relampago';
    const LIGHTNING_MIN_CARGAS = 5;
    const cargasByUser = {};
    const cargasAmountByUser = {};
    let cutoffMs = null;
    let cutoffSource = 'live';
    let masterUsedInfo = null;
    if (isLightning) {
      const queryCutoff = req.query && req.query.cutoff ? new Date(req.query.cutoff) : null;
      if (queryCutoff && !isNaN(queryCutoff.getTime())) {
        cutoffMs = queryCutoff.getTime();
        cutoffSource = 'query';
      } else if (raffle.drawnAt) {
        cutoffMs = new Date(raffle.drawnAt).getTime();
        cutoffSource = 'drawnAt';
      }
      const sourceMode = String((req.query && req.query.source) || 'daily').toLowerCase();
      if (sourceMode === 'daily') {
        // Leer cargas del CSV importado (DailyPlayerStats). El admin elige
        // el rango from/to manualmente segun el sorteo. Si no manda from,
        // arrancamos del createdAt del raffle. Si no manda to, usamos
        // cutoffMs (drawnAt o ahora).
        const fromQ = req.query.from ? new Date(req.query.from) : null;
        const toQ = req.query.to ? new Date(req.query.to) : null;
        const fromMs = fromQ && !isNaN(fromQ.getTime())
          ? fromQ.getTime()
          : (raffle.createdAt ? new Date(raffle.createdAt).getTime() : null);
        const toMs = toQ && !isNaN(toQ.getTime())
          ? toQ.getTime()
          : (cutoffMs || Date.now());

        const usernamesLc = parts
          .map(p => String(p.username || '').toLowerCase().trim())
          .filter(Boolean);

        for (const u of usernamesLc) {
          cargasByUser[u] = 0;
          cargasAmountByUser[u] = 0;
        }

        if (usernamesLc.length > 0) {
          // DailyPlayerStats indexa por dia UTC, asi que redondeamos los
          // bordes a inicio/fin de dia para no perder filas que cubran el
          // rango pedido.
          const dayStart = new Date(fromMs);
          dayStart.setUTCHours(0, 0, 0, 0);
          const dayEnd = new Date(toMs);
          dayEnd.setUTCHours(23, 59, 59, 999);

          const agg = await DailyPlayerStats.aggregate([
            {
              $match: {
                username: { $in: usernamesLc },
                dateUtc: { $gte: dayStart, $lte: dayEnd }
              }
            },
            {
              $group: {
                _id: '$username',
                count: { $sum: '$depositCount' },
                sum: { $sum: '$depositSum' }
              }
            }
          ]);
          for (const row of agg) {
            cargasByUser[row._id] = row.count || 0;
            cargasAmountByUser[row._id] = row.sum || 0;
          }
        }

        masterUsedInfo = {
          source: 'daily',
          fromMs,
          toMs,
          rowsCount: null
        };
      } else if (sourceMode === 'master') {
        // Leer del segmento maestro. Range opcional from/to (over-rides cutoff).
        const master = await Segment.findOne({ isMaster: true }).lean();
        if (!master) {
          return res.status(400).json({ error: 'No hay segmento marcado como Maestro. Ir a Segmentos y marcar uno.' });
        }
        const fromQ = req.query.from ? new Date(req.query.from) : null;
        const toQ = req.query.to ? new Date(req.query.to) : null;
        const fromMs = fromQ && !isNaN(fromQ.getTime()) ? fromQ.getTime() : null;
        const toMs = toQ && !isNaN(toQ.getTime()) ? toQ.getTime() : (cutoffMs || null);
        masterUsedInfo = {
          slug: master.slug,
          name: master.name,
          fromMs, toMs,
          rowsCount: (master.rows || []).length
        };
        // Optimizacion: 1 pasada sobre master.rows en vez de N×R (donde
        // N=participants y R=rows). Pre-construimos set de usernames
        // participantes, despues recorremos rows UNA vez.
        const partSet = new Set();
        for (const p of parts) {
          const ul = String(p.username || '').toLowerCase().trim();
          if (ul) { partSet.add(ul); cargasByUser[ul] = 0; cargasAmountByUser[ul] = 0; }
        }
        const rows = (master && master.rows) || [];
        for (const r of rows) {
          if (!r.u || r.kind !== 'deposit') continue;
          if (!partSet.has(r.u)) continue;
          if (fromMs != null && r.t != null && r.t < fromMs) continue;
          if (toMs != null && r.t != null && r.t > toMs) continue;
          cargasByUser[r.u] = (cargasByUser[r.u] || 0) + 1;
          cargasAmountByUser[r.u] = (cargasAmountByUser[r.u] || 0) + (r.amount || 0);
        }
      } else {
        // Live (JUGAYGANA). Concurrency 5 para no saturar.
        const concurrency = 5;
        for (let i = 0; i < parts.length; i += concurrency) {
          const slice = parts.slice(i, i + concurrency);
          const results = await Promise.all(slice.map(p => _getLightningCargasCount(p.username, cutoffMs)));
          for (let j = 0; j < slice.length; j++) {
            cargasByUser[String(slice[j].username).toLowerCase()] = results[j];
          }
        }
      }
    }

    const participants = parts.map(p => {
      const lower = String(p.username).toLowerCase();
      const cargasCount = isLightning
        ? (cargasByUser[lower] || 0)
        : null;
      const cargasAmount = isLightning ? (cargasAmountByUser[lower] || null) : null;
      return {
        username: p.username,
        cuposCount: p.cuposCount,
        ticketNumbers: (p.ticketNumbers || []).slice().sort((a, b) => a - b),
        entryCostPaid: p.entryCostPaid,
        joinedAt: p.joinedAt,
        lastBoughtAt: p.lastBoughtAt,
        isWinner: p.isWinner,
        cargasCount,
        cargasAmount,
        cargasRequired: isLightning ? LIGHTNING_MIN_CARGAS : null,
        qualifies: isLightning ? cargasCount >= LIGHTNING_MIN_CARGAS : null,
        purchases: spendsByUser[lower] || []
      };
    });

    const totalQualifying = isLightning ? participants.filter(p => p.qualifies).length : null;

    res.json({
      raffle: {
        id: raffle.id, name: raffle.name, prizeName: raffle.prizeName,
        emoji: raffle.emoji, totalTickets: raffle.totalTickets,
        cuposSold: raffle._ticketCounter || 0,
        entryCost: raffle.entryCost, prizeValueARS: raffle.prizeValueARS,
        status: raffle.status, winnerUsername: raffle.winnerUsername,
        winningTicketNumber: raffle.winningTicketNumber,
        drawDate: raffle.drawDate, lotteryRule: raffle.lotteryRule,
        isFree: !!raffle.isFree, minCargasARS: raffle.minCargasARS || 0,
        raffleType: raffle.raffleType, instanceNumber: raffle.instanceNumber,
        weekKey: raffle.weekKey,
        prizeClaimedAt: raffle.prizeClaimedAt,
        drawnAt: raffle.drawnAt
      },
      participants,
      lightning: isLightning ? (function () {
        const effSourceMode = (masterUsedInfo && masterUsedInfo.source === 'daily')
          ? 'daily'
          : (masterUsedInfo ? 'master' : 'live');
        let note;
        if (effSourceMode === 'daily') {
          const fromTxt = masterUsedInfo.fromMs ? new Date(masterUsedInfo.fromMs).toLocaleString('es-AR') : '—';
          const toTxt = masterUsedInfo.toMs ? new Date(masterUsedInfo.toMs).toLocaleString('es-AR') : '—';
          note = '📄 Cargas leídas del archivo CSV importado · desde ' + fromTxt + ' hasta ' + toTxt;
        } else if (effSourceMode === 'master') {
          note = 'Cargas leídas del archivo Maestro "' + (masterUsedInfo.name || masterUsedInfo.slug) + '"' +
                 (masterUsedInfo.fromMs ? ' · desde ' + new Date(masterUsedInfo.fromMs).toLocaleString('es-AR') : '') +
                 (masterUsedInfo.toMs ? ' · hasta ' + new Date(masterUsedInfo.toMs).toLocaleString('es-AR') : '');
        } else if (cutoffSource === 'query') {
          note = 'Cargas con timestamp anterior a la fecha que elegiste';
        } else if (cutoffSource === 'drawnAt') {
          note = 'Cargas con timestamp anterior al draw';
        } else {
          note = 'Cargas hasta ahora (sorteo aún pendiente)';
        }
        return {
          minCargas: LIGHTNING_MIN_CARGAS,
          totalQualifying,
          cutoff: cutoffMs ? new Date(cutoffMs).toISOString() : null,
          cutoffSource,
          sourceMode: effSourceMode,
          masterUsed: masterUsedInfo,
          rangeFrom: masterUsedInfo && masterUsedInfo.fromMs ? new Date(masterUsedInfo.fromMs).toISOString() : null,
          rangeTo: masterUsedInfo && masterUsedInfo.toMs ? new Date(masterUsedInfo.toMs).toISOString() : null,
          cutoffNote: note
        };
      })() : null
    });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// POST /api/admin/raffles/:id/analyze-csv
// Recibe un CSV crudo (text/plain o application/octet-stream), lo parsea
// EN MEMORIA, cruza contra los participantes del relampago y devuelve los
// conteos de cargas por usuario con precision horaria (filtrando por
// timestamp del deposito, no por dia). Nada se persiste — es ad-hoc.
// Util para sorteos cortos donde el CSV global de DailyPlayerStats no
// tiene la granularidad suficiente.
//
// Query params:
//   ?from=<ISO>  → solo cuenta deposits con timestamp >= from (default: createdAt del raffle)
//   ?to=<ISO>    → solo cuenta deposits con timestamp <= to (default: drawnAt o ahora)
app.post(
  '/api/admin/raffles/:id/analyze-csv',
  authMiddleware,
  adminMiddleware,
  // csvImportLimitMb se declara mas abajo en el archivo (linea ~19599); usamos
  // el string literal aca para evitar TDZ ReferenceError al boot.
  express.text({ limit: '100mb', type: '*/*' }),
  async (req, res) => {
    try {
      const raffle = await Raffle.findOne({ id: req.params.id }).lean();
      if (!raffle) return res.status(404).json({ error: 'Sorteo no encontrado.' });
      if (raffle.raffleType !== 'relampago') {
        return res.status(400).json({ error: 'Este endpoint solo aplica a sorteos relámpago.' });
      }

      const raw = req.body;
      if (!raw || typeof raw !== 'string' || raw.length < 100) {
        return res.status(400).json({ error: 'Archivo vacío o muy chico.' });
      }

      const parsed = _parseJugayganaCsv(raw);
      if (!parsed.rows || parsed.rows.length === 0) {
        return res.status(400).json({
          error: 'El archivo no tiene filas válidas. Skipped: ' + parsed.skipped + '.'
        });
      }

      const fromQ = req.query.from ? new Date(req.query.from) : null;
      const toQ = req.query.to ? new Date(req.query.to) : null;
      const fromMs = fromQ && !isNaN(fromQ.getTime())
        ? fromQ.getTime()
        : (raffle.createdAt ? new Date(raffle.createdAt).getTime() : 0);
      const toMs = toQ && !isNaN(toQ.getTime())
        ? toQ.getTime()
        : (raffle.drawnAt ? new Date(raffle.drawnAt).getTime() : Date.now());

      const parts = await RaffleParticipation.find({ raffleId: raffle.id })
        .sort({ entryCostPaid: -1, lastBoughtAt: -1 })
        .lean();

      const spends = await RaffleSpend.find({ raffleId: raffle.id })
        .sort({ createdAt: 1 })
        .lean();
      const spendsByUser = {};
      for (const s of spends) {
        const k = String(s.username || '').toLowerCase();
        if (!spendsByUser[k]) spendsByUser[k] = [];
        spendsByUser[k].push({
          ticketNumber: s.ticketNumber,
          amount: s.entryCost,
          at: s.createdAt
        });
      }

      const partSet = new Set();
      const cargasByUser = {};
      const cargasAmountByUser = {};
      for (const p of parts) {
        const ul = String(p.username || '').toLowerCase().trim();
        if (ul) {
          partSet.add(ul);
          cargasByUser[ul] = 0;
          cargasAmountByUser[ul] = 0;
        }
      }

      // Filtramos por timestamp con precision a milisegundos (la columna
      // es 'deposit'/'withdraw'/'bonus' del parser, ya normalizada).
      let countedRows = 0;
      for (const r of parsed.rows) {
        if (r.type !== 'deposit') continue;
        if (!partSet.has(r.username)) continue;
        if (r.dateMs < fromMs || r.dateMs > toMs) continue;
        cargasByUser[r.username]++;
        cargasAmountByUser[r.username] += (r.amount || 0);
        countedRows++;
      }

      const LIGHTNING_MIN_CARGAS = 5;
      const participants = parts.map(p => {
        const lower = String(p.username).toLowerCase();
        const cargasCount = cargasByUser[lower] || 0;
        const cargasAmount = cargasAmountByUser[lower] || 0;
        return {
          username: p.username,
          cuposCount: p.cuposCount,
          ticketNumbers: (p.ticketNumbers || []).slice().sort((a, b) => a - b),
          entryCostPaid: p.entryCostPaid,
          joinedAt: p.joinedAt,
          lastBoughtAt: p.lastBoughtAt,
          isWinner: p.isWinner,
          cargasCount,
          cargasAmount,
          cargasRequired: LIGHTNING_MIN_CARGAS,
          qualifies: cargasCount >= LIGHTNING_MIN_CARGAS,
          purchases: spendsByUser[lower] || []
        };
      });

      const totalQualifying = participants.filter(p => p.qualifies).length;

      res.json({
        raffle: {
          id: raffle.id, name: raffle.name, prizeName: raffle.prizeName,
          emoji: raffle.emoji, totalTickets: raffle.totalTickets,
          cuposSold: raffle._ticketCounter || 0,
          entryCost: raffle.entryCost, prizeValueARS: raffle.prizeValueARS,
          status: raffle.status, winnerUsername: raffle.winnerUsername,
          winningTicketNumber: raffle.winningTicketNumber,
          drawDate: raffle.drawDate, lotteryRule: raffle.lotteryRule,
          isFree: !!raffle.isFree, minCargasARS: raffle.minCargasARS || 0,
          raffleType: raffle.raffleType, instanceNumber: raffle.instanceNumber,
          weekKey: raffle.weekKey,
          prizeClaimedAt: raffle.prizeClaimedAt,
          drawnAt: raffle.drawnAt
        },
        participants,
        lightning: {
          minCargas: LIGHTNING_MIN_CARGAS,
          totalQualifying,
          cutoff: new Date(toMs).toISOString(),
          cutoffSource: 'file',
          sourceMode: 'file-adhoc',
          masterUsed: { source: 'file-adhoc', fromMs, toMs, rowsCount: parsed.rows.length },
          rangeFrom: new Date(fromMs).toISOString(),
          rangeTo: new Date(toMs).toISOString(),
          cutoffNote: '📁 Cargas leídas del archivo subido (' + parsed.rows.length +
                      ' filas válidas, ' + parsed.skipped + ' skip, ' + countedRows +
                      ' depósitos cruzaron) · desde ' +
                      new Date(fromMs).toLocaleString('es-AR') + ' hasta ' +
                      new Date(toMs).toLocaleString('es-AR')
        }
      });
    } catch (err) {
      logger.error(`/api/admin/raffles/:id/analyze-csv: ${err.message}`);
      res.status(500).json({ error: err.message });
    }
  }
);

// GET /api/admin/raffles/:id/user-detail?username=X&from=ISO&to=ISO
// Vista de detalle (lupa) para un usuario en un sorteo. Devuelve:
//   - participation: tickets, cupos, pagado
//   - daily: cargas y monto desde DailyPlayerStats (por dia) en el periodo
//   - live: cargas y deposits crudos desde JUGAYGANA en el periodo
//   - mismatch: bool si daily.count != live.count
app.get('/api/admin/raffles/:id/user-detail', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const raffle = await Raffle.findOne({ id: req.params.id }).lean();
    if (!raffle) return res.status(404).json({ error: 'Sorteo no encontrado.' });
    // Hardening: req.query.username puede ser array u objeto si el cliente
    // arma ?username[]=a&username[]=b o ?username[$ne]=null. Rechazamos
    // explicitamente cualquier cosa que no sea string. Cap a 64 chars para
    // evitar DoS regex con inputs gigantes.
    if (typeof req.query.username !== 'string') {
      return res.status(400).json({ error: 'username debe ser string.' });
    }
    const usernameRaw = req.query.username.trim().slice(0, 64);
    if (!usernameRaw) return res.status(400).json({ error: 'username requerido.' });
    const username = usernameRaw.toLowerCase();

    const fromQ = req.query.from ? new Date(req.query.from) : null;
    const toQ = req.query.to ? new Date(req.query.to) : null;
    const fromMs = fromQ && !isNaN(fromQ.getTime())
      ? fromQ.getTime()
      : (raffle.createdAt ? new Date(raffle.createdAt).getTime() : 0);
    const toMs = toQ && !isNaN(toQ.getTime())
      ? toQ.getTime()
      : (raffle.drawnAt ? new Date(raffle.drawnAt).getTime() : Date.now());

    // Participation.
    const part = await RaffleParticipation.findOne({
      raffleId: raffle.id,
      $or: [
        { username: usernameRaw },
        { username: usernameRaw.toLowerCase() },
        { username: { $regex: '^' + usernameRaw.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '$', $options: 'i' } }
      ]
    }).lean();

    // Daily breakdown.
    const dayStart = new Date(fromMs); dayStart.setUTCHours(0, 0, 0, 0);
    const dayEnd = new Date(toMs); dayEnd.setUTCHours(23, 59, 59, 999);
    const dailyRows = await DailyPlayerStats.find({
      username,
      dateUtc: { $gte: dayStart, $lte: dayEnd }
    }).sort({ dateUtc: 1 }).lean();
    const daily = {
      count: dailyRows.reduce((s, r) => s + (r.depositCount || 0), 0),
      amount: dailyRows.reduce((s, r) => s + (r.depositSum || 0), 0),
      perDay: dailyRows.map(r => ({
        date: r.dateUtc,
        count: r.depositCount || 0,
        amount: r.depositSum || 0,
        withdrawCount: r.withdrawCount || 0,
        bonusCount: r.bonusCount || 0
      }))
    };

    // Live breakdown (best effort — si falla, devolvemos null).
    let live = null;
    try {
      const fmt = (d) => {
        const x = new Date(d);
        return x.getFullYear() + '-' + String(x.getMonth() + 1).padStart(2, '0') + '-' + String(x.getDate()).padStart(2, '0');
      };
      const r = await jugayganaMovements.getUserMovements(usernameRaw, {
        startDate: fmt(fromMs),
        endDate: fmt(toMs),
        pageSize: 500
      });
      if (r && r.success) {
        const deposits = [];
        let count = 0, amount = 0;
        for (const m of (r.movements || [])) {
          const candidates = [m.timestamp, m.Timestamp, m.date, m.Date, m.datetime, m.fecha, m.Fecha, m.createdAt];
          let ts = null;
          for (const c of candidates) {
            if (!c) continue;
            const t = new Date(c).getTime();
            if (isFinite(t) && t > 0) { ts = t; break; }
          }
          if (ts == null) continue;
          if (ts < fromMs || ts > toMs) continue;
          const type = String(m.type || m.operation || m.OperationType || m.Type || m.Operation || '').toLowerCase();
          let amt = 0;
          for (const k of ['amount', 'Amount', 'value', 'Value', 'monto', 'Monto']) {
            if (m[k] !== undefined) { amt = parseFloat(m[k]); break; }
          }
          const isDep = type.includes('deposit') || type.includes('credit') || type.includes('carga') || type.includes('recarga');
          if (!isDep) continue;
          deposits.push({ ts, amount: amt, type });
          count++;
          amount += amt;
        }
        deposits.sort((a, b) => b.ts - a.ts);
        live = { count, amount, deposits };
      } else {
        live = { count: 0, amount: 0, deposits: [], error: (r && r.error) || 'sin respuesta' };
      }
    } catch (e) {
      live = { count: 0, amount: 0, deposits: [], error: e.message };
    }

    res.json({
      raffle: { id: raffle.id, name: raffle.name },
      username: usernameRaw,
      period: { from: new Date(fromMs).toISOString(), to: new Date(toMs).toISOString() },
      participation: part ? {
        ticketNumbers: (part.ticketNumbers || []).slice().sort((a, b) => a - b),
        cuposCount: part.cuposCount,
        entryCostPaid: part.entryCostPaid,
        joinedAt: part.joinedAt,
        lastBoughtAt: part.lastBoughtAt,
        isWinner: part.isWinner
      } : null,
      daily,
      live,
      mismatch: live && !live.error ? (daily.count !== live.count) : null
    });
  } catch (err) {
    logger.error(`/api/admin/raffles/:id/user-detail: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// GET /api/admin/raffles/:id/verify-cargas?from=ISO&to=ISO
// Corre el cruce contra DailyPlayerStats y contra LIVE en paralelo, devuelve
// la lista de mismatches para que el admin pueda revisar uno por uno.
// LIMITADO a sorteos relampago (sino no aplica).
app.get('/api/admin/raffles/:id/verify-cargas', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const raffle = await Raffle.findOne({ id: req.params.id }).lean();
    if (!raffle) return res.status(404).json({ error: 'Sorteo no encontrado.' });
    if (raffle.raffleType !== 'relampago') {
      return res.status(400).json({ error: 'Solo aplica a relámpagos.' });
    }

    const fromQ = req.query.from ? new Date(req.query.from) : null;
    const toQ = req.query.to ? new Date(req.query.to) : null;
    const fromMs = fromQ && !isNaN(fromQ.getTime())
      ? fromQ.getTime()
      : (raffle.createdAt ? new Date(raffle.createdAt).getTime() : 0);
    const toMs = toQ && !isNaN(toQ.getTime())
      ? toQ.getTime()
      : (raffle.drawnAt ? new Date(raffle.drawnAt).getTime() : Date.now());

    const parts = await RaffleParticipation.find({ raffleId: raffle.id }).lean();
    const usernamesLc = parts.map(p => String(p.username || '').toLowerCase().trim()).filter(Boolean);

    // Daily counts.
    const dayStart = new Date(fromMs); dayStart.setUTCHours(0, 0, 0, 0);
    const dayEnd = new Date(toMs); dayEnd.setUTCHours(23, 59, 59, 999);
    const dailyAgg = await DailyPlayerStats.aggregate([
      { $match: { username: { $in: usernamesLc }, dateUtc: { $gte: dayStart, $lte: dayEnd } } },
      { $group: { _id: '$username', count: { $sum: '$depositCount' }, amount: { $sum: '$depositSum' } } }
    ]);
    const dailyByUser = {};
    for (const row of dailyAgg) dailyByUser[row._id] = { count: row.count || 0, amount: row.amount || 0 };

    // Live counts (concurrency 5).
    const liveByUser = {};
    const concurrency = 5;
    for (let i = 0; i < parts.length; i += concurrency) {
      const slice = parts.slice(i, i + concurrency);
      const results = await Promise.all(slice.map(p => _getLightningCargasCount(p.username, toMs)));
      for (let j = 0; j < slice.length; j++) {
        const lc = String(slice[j].username).toLowerCase();
        liveByUser[lc] = { count: results[j] || 0 };
      }
    }

    const rows = parts.map(p => {
      const lc = String(p.username || '').toLowerCase();
      const d = dailyByUser[lc] || { count: 0, amount: 0 };
      const l = liveByUser[lc] || { count: 0 };
      return {
        username: p.username,
        dailyCount: d.count,
        dailyAmount: d.amount,
        liveCount: l.count,
        diff: d.count - l.count,
        mismatch: d.count !== l.count
      };
    });

    const mismatches = rows.filter(r => r.mismatch);

    res.json({
      raffle: { id: raffle.id, name: raffle.name },
      period: { from: new Date(fromMs).toISOString(), to: new Date(toMs).toISOString() },
      total: rows.length,
      mismatchesCount: mismatches.length,
      rows
    });
  } catch (err) {
    logger.error(`/api/admin/raffles/:id/verify-cargas: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// =====================================================================
// MASTER ANALYSIS
// =====================================================================
// Analisis ad-hoc del Segment maestro (isMaster:true) para distintas
// secciones del admin. El admin aprieta "📊 Analizar con Maestro" en una
// seccion → corre el analisis correspondiente, persiste un snapshot en
// MasterAnalysisSnapshot y devuelve el snapshot + historial previo para
// poder ver evolucion entre uploads del archivo maestro.
//
// Secciones soportadas:
//   - top_jugadores: top N por monto cargado
//   - top_stats: totales globales (deposits/withdraws/bonuses/neto)
//   - recuperacion: usuarios por estado (activo/en_riesgo/perdido/inactivo)
//   - automatizaciones: cuantos users matchean cada regla activa hoy
//   - relampago: stats de cada relampago activo cruzados contra master
// =====================================================================

const _MASTER_ANALYSIS_SECTIONS = ['relampago', 'top_jugadores', 'top_stats', 'recuperacion', 'automatizaciones'];

// Calcula el analisis pedido leyendo del Segment maestro. Devuelve un
// objeto con la data + meta (rowsAnalyzed, lastUploadAt). Si no hay
// master configurado, tira error.
async function _runMasterAnalysis(section, opts = {}) {
  const master = await Segment.findOne({ isMaster: true }).lean();
  if (!master) {
    throw new Error('No hay segmento marcado como Maestro. Configurá uno en Segmentos.');
  }
  const rows = (master.rows || []);
  const fromMs = opts.fromMs || null;
  const toMs = opts.toMs || null;

  const filteredRows = rows.filter(r => {
    if (!r) return false;
    if (fromMs != null && r.t != null && r.t < fromMs) return false;
    if (toMs != null && r.t != null && r.t > toMs) return false;
    return true;
  });

  const lastUploadAt = (master.uploads && master.uploads.length > 0)
    ? master.uploads[master.uploads.length - 1].at
    : master.updatedAt;

  let data;
  if (section === 'top_jugadores') {
    // Agrupar por usuario, sumar deposits.
    const byUser = {};
    for (const r of filteredRows) {
      if (!r.u || r.kind !== 'deposit') continue;
      const u = String(r.u).toLowerCase();
      if (!byUser[u]) byUser[u] = { username: u, count: 0, sum: 0, lastAt: 0 };
      byUser[u].count++;
      byUser[u].sum += (r.amount || 0);
      if (r.t && r.t > byUser[u].lastAt) byUser[u].lastAt = r.t;
    }
    const top = Object.values(byUser).sort((a, b) => b.sum - a.sum).slice(0, 50);
    data = {
      totalUsers: Object.keys(byUser).length,
      totalDepositsSum: top.reduce((s, x) => s + x.sum, 0),
      top
    };
  } else if (section === 'top_stats') {
    let depCount = 0, depSum = 0, witCount = 0, witSum = 0, bonCount = 0, bonSum = 0;
    const usersDep = new Set(), usersWit = new Set();
    for (const r of filteredRows) {
      if (!r.u) continue;
      if (r.kind === 'deposit') { depCount++; depSum += (r.amount || 0); usersDep.add(r.u); }
      else if (r.kind === 'withdraw') { witCount++; witSum += (r.amount || 0); usersWit.add(r.u); }
      else if (r.kind === 'bonus') { bonCount++; bonSum += (r.amount || 0); }
    }
    data = {
      deposits: { count: depCount, sum: depSum, uniqueUsers: usersDep.size },
      withdraws: { count: witCount, sum: witSum, uniqueUsers: usersWit.size },
      bonuses: { count: bonCount, sum: bonSum },
      netToHouse: depSum - witSum - bonSum
    };
  } else if (section === 'recuperacion') {
    // Estado por user segun dias desde ultima carga real (deposit) en el
    // master. Activo <7d, en_riesgo 7-14d, perdido 14-30d, inactivo >30d.
    const now = Date.now();
    const lastByUser = {};
    for (const r of filteredRows) {
      if (!r.u || r.kind !== 'deposit') continue;
      const u = String(r.u).toLowerCase();
      if (!lastByUser[u] || (r.t && r.t > lastByUser[u])) lastByUser[u] = r.t || 0;
    }
    const buckets = { activo: 0, en_riesgo: 0, perdido: 0, inactivo: 0 };
    const usersByBucket = { activo: [], en_riesgo: [], perdido: [], inactivo: [] };
    for (const u of Object.keys(lastByUser)) {
      const days = (now - (lastByUser[u] || 0)) / (24 * 3600 * 1000);
      let b;
      if (days < 7) b = 'activo';
      else if (days < 14) b = 'en_riesgo';
      else if (days < 30) b = 'perdido';
      else b = 'inactivo';
      buckets[b]++;
      if (usersByBucket[b].length < 200) usersByBucket[b].push({ username: u, daysSince: Math.round(days) });
    }
    data = { totalUsers: Object.keys(lastByUser).length, buckets, samples: usersByBucket };
  } else if (section === 'automatizaciones') {
    // Para cada regla activa, contar cuantos users matchearian su criterio
    // basico (cargas en ventana). Es una aproximacion — el sistema real
    // de NotificationRule tiene mas filtros (audience, equipo, etc.).
    const rules = await NotificationRule.find({ isActive: true }).lean().catch(() => []);
    const now = Date.now();
    // Pre-armar por usuario: cantidad de cargas en 7d, 14d, 30d.
    const stats = {};
    for (const r of filteredRows) {
      if (!r.u || r.kind !== 'deposit') continue;
      const u = String(r.u).toLowerCase();
      if (!stats[u]) stats[u] = { d7: 0, d14: 0, d30: 0, lastAt: 0 };
      const ageDays = (now - (r.t || 0)) / (24 * 3600 * 1000);
      if (ageDays <= 7) stats[u].d7++;
      if (ageDays <= 14) stats[u].d14++;
      if (ageDays <= 30) stats[u].d30++;
      if (r.t && r.t > stats[u].lastAt) stats[u].lastAt = r.t;
    }
    const ruleResults = rules.map(rule => {
      const minCharges = Number(rule.minChargesLastDays || 0);
      const windowDays = Number(rule.minChargesLastDaysWindow || 30);
      const bucket = windowDays <= 7 ? 'd7' : (windowDays <= 14 ? 'd14' : 'd30');
      let matches = 0;
      for (const u of Object.keys(stats)) if (stats[u][bucket] >= minCharges) matches++;
      return {
        id: rule.id || String(rule._id),
        name: rule.name || rule.title || '(sin nombre)',
        minCharges, windowDays, matches
      };
    });
    data = { totalRules: rules.length, totalUsersInMaster: Object.keys(stats).length, rules: ruleResults };
  } else if (section === 'relampago') {
    // Stats de relampagos activos cruzando contra el master.
    const raffles = await Raffle.find({ raffleType: 'relampago', status: { $in: ['active', 'closed'] } }).lean();
    const cargasByUser = {};
    for (const r of filteredRows) {
      if (!r.u || r.kind !== 'deposit') continue;
      const u = String(r.u).toLowerCase();
      cargasByUser[u] = (cargasByUser[u] || 0) + 1;
    }
    const out = [];
    for (const raffle of raffles) {
      const parts = await RaffleParticipation.find({ raffleId: raffle.id }).lean();
      let qualifying = 0, total = parts.length;
      for (const p of parts) {
        const c = cargasByUser[String(p.username || '').toLowerCase()] || 0;
        if (c >= 5) qualifying++;
      }
      out.push({ id: raffle.id, name: raffle.name, status: raffle.status, total, qualifying });
    }
    data = { rafflesCount: out.length, raffles: out };
  } else {
    throw new Error('Seccion no soportada: ' + section);
  }

  return {
    section,
    masterSlug: master.slug,
    masterUploadAt: lastUploadAt,
    rangeFrom: fromMs ? new Date(fromMs) : null,
    rangeTo: toMs ? new Date(toMs) : null,
    rowsAnalyzed: filteredRows.length,
    data
  };
}

// POST /api/admin/master-analysis/:section
// Corre el analisis fresco, persiste snapshot, devuelve { snapshot, history }.
app.post('/api/admin/master-analysis/:section', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const section = String(req.params.section || '').toLowerCase();
    if (!_MASTER_ANALYSIS_SECTIONS.includes(section)) {
      return res.status(400).json({ error: 'Seccion invalida. Validas: ' + _MASTER_ANALYSIS_SECTIONS.join(', ') });
    }
    const fromQ = req.query.from ? new Date(req.query.from) : null;
    const toQ = req.query.to ? new Date(req.query.to) : null;
    const fromMs = fromQ && !isNaN(fromQ.getTime()) ? fromQ.getTime() : null;
    const toMs = toQ && !isNaN(toQ.getTime()) ? toQ.getTime() : null;

    const result = await _runMasterAnalysis(section, { fromMs, toMs });

    const snapshot = await MasterAnalysisSnapshot.create({
      section,
      ranAt: new Date(),
      ranBy: (req.user && req.user.username) || 'admin',
      masterSlug: result.masterSlug,
      masterUploadAt: result.masterUploadAt,
      rangeFrom: result.rangeFrom,
      rangeTo: result.rangeTo,
      rowsAnalyzed: result.rowsAnalyzed,
      data: result.data
    });

    // Historial: ultimos 10 snapshots de la seccion (excluyendo el recien creado).
    const history = await MasterAnalysisSnapshot.find({
      section,
      _id: { $ne: snapshot._id }
    }).sort({ ranAt: -1 }).limit(10).lean();

    res.json({ snapshot: snapshot.toObject(), history });
  } catch (err) {
    logger.error(`/api/admin/master-analysis/${req.params.section}: ${err.message}\n${err.stack}`);
    res.status(500).json({ error: err.message || 'Error del servidor' });
  }
});

// GET /api/admin/master-analysis/:section
// Devuelve el snapshot mas reciente + historial (para que el modal cargue
// la ultima foto sin tener que re-analizar).
app.get('/api/admin/master-analysis/:section', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const section = String(req.params.section || '').toLowerCase();
    if (!_MASTER_ANALYSIS_SECTIONS.includes(section)) {
      return res.status(400).json({ error: 'Seccion invalida.' });
    }
    const all = await MasterAnalysisSnapshot.find({ section }).sort({ ranAt: -1 }).limit(11).lean();
    if (all.length === 0) {
      return res.json({ snapshot: null, history: [] });
    }
    res.json({ snapshot: all[0], history: all.slice(1) });
  } catch (err) {
    logger.error(`GET /api/admin/master-analysis/${req.params.section}: ${err.message}`);
    res.status(500).json({ error: err.message || 'Error del servidor' });
  }
});

// POST /api/admin/raffles/:id/draw
// El admin carga (a) lotteryNumber: numero crudo de la Loteria Nacional
// Nocturna (1er premio); el sistema mapea por modulo si el cupo esta
// incompleto y busca al ganador por su ticketNumbers. Opcional:
// (b) winnerUsername para forzar/confirmar el ganador.
app.post('/api/admin/raffles/:id/draw', authMiddleware, superAdminMiddleware, async (req, res) => {
  try {
    const raffle = await Raffle.findOne({ id: req.params.id });
    if (!raffle) return res.status(404).json({ error: 'Sorteo no encontrado.' });
    if (raffle.status === 'drawn' || raffle.status === 'archived' || raffle.status === 'cancelled') {
      return res.status(400).json({ error: `Este sorteo está en estado "${raffle.status}" — no se puede sortear.` });
    }

    const lotteryNumber = parseInt(req.body && req.body.lotteryNumber, 10);
    const explicitWinner = String((req.body && req.body.winnerUsername) || '').trim();
    const lotteryDrawSource = String((req.body && req.body.lotteryDrawSource) || '').slice(0, 200).trim();
    const lotteryDrawDateRaw = req.body && req.body.lotteryDrawDate;
    if (!Number.isFinite(lotteryNumber) || lotteryNumber < 1) {
      return res.status(400).json({ error: 'Falta lotteryNumber (entero ≥ 1).' });
    }

    const parts = await RaffleParticipation.find({ raffleId: raffle.id }).sort({ joinedAt: 1 }).lean();
    let totalCuposSold = 0;
    for (const p of parts) totalCuposSold += (p.cuposCount || 1);
    if (totalCuposSold === 0) return res.status(400).json({ error: 'No hay cupos vendidos.' });

    // Mapeo loteria -> ticket vendido. Los users eligen su numero del 1..100,
    // asi que los vendidos pueden ser dispersos (ej. [3, 7, 12, 33, 41]).
    // Construimos la lista real de tickets vendidos y mapeamos por modulo
    // al INDICE en esa lista, no al numero crudo. Asi cumplimos la regla
    // "si la loteria sale fuera del rango vendido, cicla al rango vendido".
    const soldNumbers = [];
    for (const p of parts) {
      if (Array.isArray(p.ticketNumbers)) {
        for (const n of p.ticketNumbers) soldNumbers.push(Number(n));
      }
    }
    soldNumbers.sort((a, b) => a - b);
    if (soldNumbers.length === 0) {
      return res.status(400).json({ error: 'No hay numeros asignados a participantes (data inconsistente).' });
    }
    let mappedNumber;
    let wasMapped;
    if (soldNumbers.includes(lotteryNumber)) {
      // El numero crudo salio y es uno vendido — ganador directo.
      mappedNumber = lotteryNumber;
      wasMapped = false;
    } else {
      // Cicla a un ticket vendido por modulo sobre la cantidad de vendidos.
      const idx = ((lotteryNumber - 1) % soldNumbers.length + soldNumbers.length) % soldNumbers.length;
      mappedNumber = soldNumbers[idx];
      wasMapped = true;
    }
    let winner = parts.find(p => Array.isArray(p.ticketNumbers) && p.ticketNumbers.includes(mappedNumber));
    if (explicitWinner) {
      const found = parts.find(p => p.username.toLowerCase() === explicitWinner.toLowerCase());
      if (!found) return res.status(400).json({ error: `El usuario "${explicitWinner}" no participa en este sorteo.` });
      winner = found;
      // Si forzamos ganador, fijamos mappedNumber a uno de SUS tickets para
      // que el push y el detalle muestren un numero coherente.
      if (Array.isArray(found.ticketNumbers) && found.ticketNumbers.length > 0) {
        mappedNumber = Number(found.ticketNumbers[0]);
        wasMapped = (mappedNumber !== lotteryNumber);
      }
    }
    if (!winner) {
      return res.status(500).json({ error: `No se encontró ganador para el número ${mappedNumber}.` });
    }

    let lotteryDrawDate = null;
    if (lotteryDrawDateRaw) {
      const d = new Date(lotteryDrawDateRaw);
      if (!isNaN(d.getTime())) lotteryDrawDate = d;
    }

    // Lock atomico: solo el primer caller que vea status active/closed Y
    // winnerUsername=null pasa a 'drawn'. Si otro admin ya inicio el draw,
    // este recibe null y aborta antes de creditar premio (evita doble
    // acreditacion del premio si dos admins clickean simultaneamente).
    const setFields = {
      status: 'drawn',
      winnerUsername: winner.username,
      winningTicketNumber: mappedNumber,
      lotteryDrawNumber: lotteryNumber,
      drawnAt: new Date(),
      drawnBy: req.user.username || 'admin',
      prizeClaimable: false
    };
    if (lotteryDrawSource) setFields.lotteryDrawSource = lotteryDrawSource;
    if (lotteryDrawDate) setFields.lotteryDrawDate = lotteryDrawDate;
    const drawLock = await Raffle.findOneAndUpdate(
      { id: raffle.id, status: { $in: ['active', 'closed'] }, winnerUsername: null },
      { $set: setFields },
      { new: true }
    );
    if (!drawLock) {
      return res.status(409).json({ error: 'Este sorteo ya fue sorteado por otra sesión. Recargá el panel.' });
    }
    await RaffleParticipation.updateOne({ id: winner.id }, { $set: { isWinner: true } });

    // === Regla del relampago: ganador necesita >= 5 cargas REALES con
    // timestamp ANTERIOR al drawnAt. Cargas posteriores al sorteo NO cuentan.
    // Si no califica, premio se "forfeit": no se acredita ni queda reclamable.
    // Aplica solo a raffleType='relampago' (los pagos no tienen este gate).
    const LIGHTNING_MIN_CARGAS = 5;
    let lightningForfeited = false;
    let lightningCargasCount = 0;
    if (raffle.raffleType === 'relampago') {
      const drawnAtTs = drawLock.drawnAt || new Date();
      lightningCargasCount = await _getLightningCargasCount(
        winner.username,
        new Date(drawnAtTs).getTime()
      );
      if (lightningCargasCount < LIGHTNING_MIN_CARGAS) {
        lightningForfeited = true;
        await Raffle.updateOne(
          { id: raffle.id },
          { $set: {
            prizeForfeitedAt: new Date(),
            prizeForfeitedReason: `winner cargas=${lightningCargasCount} < ${LIGHTNING_MIN_CARGAS}`,
            prizeClaimable: false
          }}
        ).catch(() => {});
        logger.info(`[raffles] LIGHTNING FORFEIT ${winner.username} cargas=${lightningCargasCount}/${LIGHTNING_MIN_CARGAS} ${raffle.name}`);
      } else {
        logger.info(`[raffles] LIGHTNING winner OK ${winner.username} cargas=${lightningCargasCount}/${LIGHTNING_MIN_CARGAS}`);
      }
    }

    // === AUTO-CREDIT del premio al ganador ===
    let prizeAutoCredited = false;
    let autoCreditError = null;
    const prize = Number(raffle.prizeValueARS) || 0;
    if (prize > 0 && !lightningForfeited) {
      try {
        const credit = await jugaygana.creditUserBalance(winner.username, prize);
        if (credit && credit.success) {
          await Raffle.updateOne(
            { id: raffle.id },
            { $set: {
              prizeClaimedAt: new Date(),
              prizeClaimable: false,
              prizeClaimTxId: (credit.transactionId || credit.transferId) || null
            }}
          );
          prizeAutoCredited = true;
          logger.info(`[raffles] AUTO-CREDIT OK ${winner.username} +$${prize} (${raffle.name})`);
        } else {
          // Credit fallo: marcar reclamable para que el user pueda intentar manualmente
          autoCreditError = (credit && credit.error) || 'Error desconocido al acreditar';
          await Raffle.updateOne(
            { id: raffle.id },
            { $set: { prizeClaimable: true } }
          );
          logger.error(`[raffles] AUTO-CREDIT FAIL ${winner.username} ${raffle.name}: ${autoCreditError} — marcado prizeClaimable para retry manual`);
        }
      } catch (e) {
        autoCreditError = e.message;
        await Raffle.updateOne(
          { id: raffle.id },
          { $set: { prizeClaimable: true } }
        ).catch(() => {});
        logger.error(`[raffles] AUTO-CREDIT EXC ${winner.username} ${raffle.name}: ${e.message}`);
      }
    }

    let winnerPushed = 0, losersPushed = 0;
    try {
      const winTitle = lightningForfeited
        ? '🎲 Salió tu número pero…'
        : '🏆 ¡GANASTE EL SORTEO! ' + (raffle.emoji || '🎁');
      const winBody = lightningForfeited
        ? `Tu número #${mappedNumber} fue el ganador, PERO necesitabas mínimo ${LIGHTNING_MIN_CARGAS} cargas ANTES del sorteo. Tenés ${lightningCargasCount}. Por eso no podemos acreditarte $${prize.toLocaleString('es-AR')}. La próxima cargá antes para asegurarlo.`
        : (prizeAutoCredited
          ? `¡Salió tu número #${mappedNumber}! Ganaste $${prize.toLocaleString('es-AR')} y ya te lo acreditamos. Entrá a la app a ver tu felicitación 🎉 (queda 24hs)`
          : `¡Salió tu número #${mappedNumber}! Ganaste $${prize.toLocaleString('es-AR')}. Entrá a la app y tocá "Reclamar premio" para acreditarlo a tu saldo.`);
      const winRes = await sendNotificationToAllUsers(
        User,
        winTitle,
        winBody,
        {
          source: lightningForfeited ? 'raffle-win-forfeit' : 'raffle-win',
          raffleId: raffle.id,
          isWinner: 'true',
          autoCredited: prizeAutoCredited ? 'true' : 'false',
          forfeited: lightningForfeited ? 'true' : 'false',
          winningTicketNumber: String(mappedNumber)
        },
        { username: { $regex: '^' + String(winner.username).replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '$', $options: 'i' } }
      );
      winnerPushed = (winRes && winRes.successCount) || 0;
    } catch (e) { logger.warn(`[raffles] notif ganador: ${e.message}`); }

    try {
      // Todos los participantes que no son el ganador. Dedup por username
      // (por si una participation tiene el username con casing distinto).
      const seen = new Set();
      const loserUsernames = [];
      for (const p of parts) {
        const uname = String(p.username || '').trim();
        if (!uname) continue;
        const key = uname.toLowerCase();
        if (key === String(winner.username).toLowerCase()) continue;
        if (seen.has(key)) continue;
        seen.add(key);
        loserUsernames.push(uname);
      }
      if (loserUsernames.length > 0) {
        const mapNote = wasMapped ? ` (mapeado a #${mappedNumber} dentro del cupo vendido)` : '';
        const loseBody = lightningForfeited
          ? `🎰 Número ganador: #${mappedNumber}${mapNote}. Salió @${winner.username} pero NO podía reclamar (no tenía ${LIGHTNING_MIN_CARGAS} cargas antes del sorteo). El premio quedó sin acreditar. Cargá ANTES del próximo para tener derecho.`
          : `🎰 Número ganador: #${mappedNumber}${mapNote}. Ganó @${winner.username} y se llevó $${prize.toLocaleString('es-AR')}. ¡Ya hay cupos nuevos! Entrá y elegí tu próximo número.`;
        const loseRes = await sendNotificationToAllUsers(
          User,
          (raffle.emoji || '🎁') + ' Salió el ' + raffle.prizeName,
          loseBody,
          {
            source: lightningForfeited ? 'raffle-lose-forfeit' : 'raffle-lose',
            raffleId: raffle.id,
            isWinner: 'false',
            forfeited: lightningForfeited ? 'true' : 'false',
            winningTicketNumber: String(mappedNumber),
            lotteryDrawNumber: String(lotteryNumber)
          },
          { username: { $in: loserUsernames } }
        );
        losersPushed = (loseRes && loseRes.successCount) || 0;
      }
    } catch (e) { logger.warn(`[raffles] notif perdedores: ${e.message}`); }

    // Asegurar que el tipo siga teniendo una instancia activa.
    try { await _ensureActiveRafflesSeeded(); } catch (_) {}

    res.json({
      success: true,
      winnerUsername: winner.username,
      winningTicketNumber: mappedNumber,
      lotteryDrawNumber: lotteryNumber,
      lotteryWasMapped: wasMapped,
      totalCuposSold,
      prizeValueARS: raffle.prizeValueARS,
      prizeAutoCredited,
      autoCreditError,
      lightningForfeited,
      lightningCargasCount: raffle.raffleType === 'relampago' ? lightningCargasCount : null,
      lightningMinCargas: raffle.raffleType === 'relampago' ? LIGHTNING_MIN_CARGAS : null,
      pushNotifications: { winnerPushed, losersPushed }
    });
  } catch (err) {
    logger.error(`/api/admin/raffles/draw: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// POST /api/admin/raffles/:id/cancel — cancela un sorteo y reembolsa a
// participantes. Idempotente: si ya se cancelo antes, no reembolsa de nuevo
// (cada participation tiene refundedAt como guard).
app.post('/api/admin/raffles/:id/cancel', authMiddleware, superAdminMiddleware, async (req, res) => {
  try {
    const raffle = await Raffle.findOne({ id: req.params.id });
    if (!raffle) return res.status(404).json({ error: 'Sorteo no encontrado.' });
    if (raffle.status === 'drawn' || raffle.status === 'archived' || raffle.status === 'cancelled') {
      return res.status(400).json({ error: `Este sorteo está en estado "${raffle.status}" — no se puede cancelar.` });
    }
    raffle.status = 'cancelled';
    await raffle.save();

    const parts = await RaffleParticipation.find({ raffleId: raffle.id, refundedAt: null }).lean();
    let refundedCount = 0, refundedAmount = 0, errors = 0;
    for (const p of parts) {
      if (!p.entryCostPaid || p.entryCostPaid <= 0) continue;
      // Reservar el reembolso atomicamente — solo el primer caller pasa.
      const reserved = await RaffleParticipation.findOneAndUpdate(
        { id: p.id, refundedAt: null },
        { $set: { refundedAt: new Date(), refundedAmount: p.entryCostPaid } }
      );
      if (!reserved) continue; // ya lo reembolsamos en otra ejecucion
      try {
        const r = await jugaygana.creditUserBalance(p.username, p.entryCostPaid);
        if (r && r.success) {
          refundedCount++;
          refundedAmount += p.entryCostPaid;
          await RaffleParticipation.updateOne(
            { id: p.id },
            { $set: { refundedTxId: (r.transactionId || r.transferId) || null } }
          ).catch(() => {});
        } else {
          // Rollback del marker para que un retry pueda volver a intentarlo.
          await RaffleParticipation.updateOne(
            { id: p.id },
            { $set: { refundedAt: null, refundedAmount: 0 } }
          ).catch(() => {});
          errors++;
          logger.warn(`[raffles] cancel refund fail ${p.username} ${raffle.name}: ${r && r.error}`);
        }
      } catch (e) {
        await RaffleParticipation.updateOne(
          { id: p.id },
          { $set: { refundedAt: null, refundedAmount: 0 } }
        ).catch(() => {});
        errors++;
        logger.error(`[raffles] cancel refund exc ${p.username} ${raffle.name}: ${e.message}`);
      }
    }
    try { await _ensureActiveRafflesSeeded(); } catch (_) {}

    res.json({ success: true, refundedCount, refundedAmount, errors });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// DELETE /api/admin/raffles/:id — borra DEFINITIVAMENTE un sorteo.
//
// Modo normal: solo si esta drawn/cancelled/archived Y no tiene participantes.
// Modo force=1: permite borrar AUNQUE haya participantes (admin asume el
//   data loss). Util para limpiar sorteos de prueba donde lalodj jugo. Igual
//   chequeamos status: nunca se borra un active/closed — primero sortear/cancelar.
app.delete('/api/admin/raffles/:id', authMiddleware, superAdminMiddleware, async (req, res) => {
  try {
    const force = String(req.query.force || '').toLowerCase() === '1' ||
                  String(req.query.force || '').toLowerCase() === 'true';
    const raffle = await Raffle.findOne({ id: req.params.id }).lean();
    if (!raffle) return res.status(404).json({ error: 'Sorteo no encontrado.' });
    if (raffle.status === 'active' || raffle.status === 'closed') {
      return res.status(400).json({ error: 'No se puede borrar un sorteo activo/cerrado. Sorteálo o cancelálo primero.' });
    }
    const partsCount = await RaffleParticipation.countDocuments({ raffleId: raffle.id });
    if (partsCount > 0 && !force) {
      return res.status(400).json({
        error: `Este sorteo tiene ${partsCount} ${partsCount === 1 ? 'participante' : 'participantes'} — usá force=1 para borrar igual (perdés el historial).`,
        participants: partsCount
      });
    }
    // En modo force tambien borramos las participaciones del sorteo (sino
    // quedan huerfanas referenciando un raffleId que no existe).
    if (partsCount > 0 && force) {
      await RaffleParticipation.deleteMany({ raffleId: raffle.id }).catch(() => {});
      logger.warn(`[raffles] FORCE-DELETE ${raffle.name} con ${partsCount} participantes borrados por ${req.user.username || 'admin'}`);
    }
    // Limpiar tambien spends huerfanos (defensa en profundidad — no deberian
    // existir si partsCount=0 pero por si acaso). RaffleSpend NO bloquea la
    // baja del sorteo, son logs.
    await RaffleSpend.deleteMany({ raffleId: raffle.id }).catch(() => {});
    await Raffle.deleteOne({ id: raffle.id });
    logger.info(`[raffles] DELETE ${raffle.name} (${raffle.id}) status=${raffle.status} force=${force} por ${req.user.username || 'admin'}`);
    res.json({ success: true, deletedId: raffle.id, deletedName: raffle.name, deletedParticipants: force ? partsCount : 0 });
  } catch (err) {
    logger.error(`/api/admin/raffles/:id DELETE: ${err.message}`);
    res.status(500).json({ error: 'Error eliminando sorteo' });
  }
});

// POST /api/admin/raffles/cleanup — archiva 'drawn' y 'cancelled' y reseed.
// Idempotente. Por defecto respeta la ventana de 24h del banner de
// "Felicitaciones" del ganador. Si admin pasa ?force=1, archiva todo.
app.post('/api/admin/raffles/cleanup', authMiddleware, superAdminMiddleware, async (req, res) => {
  try {
    const force = String(req.query.force || req.body?.force || '').toLowerCase() === '1' ||
                  String(req.query.force || req.body?.force || '').toLowerCase() === 'true';
    const FELICITACIONES_TTL_MS = 24 * 3600 * 1000;
    const drawnQuery = force ? { status: 'drawn' } : {
      status: 'drawn',
      $or: [
        { drawnAt: { $lt: new Date(Date.now() - FELICITACIONES_TTL_MS) } },
        { drawnAt: null },
        { drawnAt: { $exists: false } }
      ]
    };
    const drawnUpd = await Raffle.updateMany(drawnQuery, { $set: { status: 'archived' } });
    const cancelledUpd = await Raffle.updateMany({ status: 'cancelled' }, { $set: { status: 'archived' } });
    await _ensureActiveRafflesSeeded();
    res.json({
      success: true,
      archived: (drawnUpd.modifiedCount || 0) + (cancelledUpd.modifiedCount || 0),
      drawnArchived: drawnUpd.modifiedCount || 0,
      cancelledArchived: cancelledUpd.modifiedCount || 0,
      respected24hWindow: !force
    });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// GET /api/admin/raffles/legacy — lista sorteos del modelo viejo (loss-credit:
// iphone/caribe/auto/other) que todavia esten 'active' o 'closed'. Para que
// el admin pueda ver qué hay y decidir purgar.
app.get('/api/admin/raffles/legacy', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const legacyTypes = ['iphone', 'caribe', 'auto', 'other'];
    const raffles = await Raffle.find(
      { raffleType: { $in: legacyTypes }, status: { $in: ['active', 'closed'] } }
    ).sort({ createdAt: -1 }).lean();
    const ids = raffles.map(r => r.id);
    const partsAgg = await RaffleParticipation.aggregate([
      { $match: { raffleId: { $in: ids } } },
      { $group: { _id: '$raffleId', cuposSold: { $sum: '$cuposCount' }, participants: { $sum: 1 }, revenue: { $sum: '$entryCostPaid' } } }
    ]);
    const byId = {};
    for (const p of partsAgg) byId[p._id] = p;
    res.json({
      raffles: raffles.map(r => ({
        id: r.id,
        name: r.name,
        emoji: r.emoji,
        raffleType: r.raffleType,
        status: r.status,
        entryCost: r.entryCost,
        prizeValueARS: r.prizeValueARS,
        totalTickets: r.totalTickets,
        cuposSold: (byId[r.id] && byId[r.id].cuposSold) || 0,
        participants: (byId[r.id] && byId[r.id].participants) || 0,
        revenue: (byId[r.id] && byId[r.id].revenue) || 0,
        createdAt: r.createdAt,
        monthKey: r.monthKey,
        entryMode: r.entryMode
      }))
    });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// POST /api/admin/raffles/purge-legacy — cancela TODOS los sorteos legacy
// activos/closed y reembolsa a sus participantes (los que pagaron). El
// modelo viejo era de cargas/loss-credit asi que en muchos casos el
// entryCostPaid es 0 (gratis). Solo se reembolsa si entryCostPaid > 0.
app.post('/api/admin/raffles/purge-legacy', authMiddleware, superAdminMiddleware, async (req, res) => {
  try {
    const legacyTypes = ['iphone', 'caribe', 'auto', 'other'];
    const targets = await Raffle.find(
      { raffleType: { $in: legacyTypes }, status: { $in: ['active', 'closed'] } }
    ).lean();
    let cancelled = 0, refundedCount = 0, refundedAmount = 0, errors = 0;
    for (const r of targets) {
      try {
        await Raffle.updateOne({ id: r.id }, { $set: { status: 'cancelled' } });
        cancelled++;
        // Solo participantes que NO fueron reembolsados antes (idempotente).
        const parts = await RaffleParticipation.find({ raffleId: r.id, refundedAt: null }).lean();
        for (const p of parts) {
          if (!p.entryCostPaid || p.entryCostPaid <= 0) continue;
          const reserved = await RaffleParticipation.findOneAndUpdate(
            { id: p.id, refundedAt: null },
            { $set: { refundedAt: new Date(), refundedAmount: p.entryCostPaid } }
          );
          if (!reserved) continue;
          try {
            const cr = await jugaygana.creditUserBalance(p.username, p.entryCostPaid);
            if (cr && cr.success) {
              refundedCount++;
              refundedAmount += p.entryCostPaid;
              await RaffleParticipation.updateOne(
                { id: p.id },
                { $set: { refundedTxId: (cr.transactionId || cr.transferId) || null } }
              ).catch(() => {});
            } else {
              await RaffleParticipation.updateOne(
                { id: p.id },
                { $set: { refundedAt: null, refundedAmount: 0 } }
              ).catch(() => {});
              errors++;
              logger.warn(`[raffles purge-legacy] refund fail ${p.username} ${r.name}: ${cr && cr.error}`);
            }
          } catch (e) {
            await RaffleParticipation.updateOne(
              { id: p.id },
              { $set: { refundedAt: null, refundedAmount: 0 } }
            ).catch(() => {});
            errors++;
            logger.error(`[raffles purge-legacy] refund exc ${p.username} ${r.name}: ${e.message}`);
          }
        }
      } catch (e) {
        errors++;
        logger.error(`[raffles purge-legacy] ${r.name}: ${e.message}`);
      }
    }
    // Asegurar que los nuevos esten activos.
    try { await _ensureActiveRafflesSeeded(); } catch (_) {}
    logger.info(`[raffles purge-legacy] cancelled=${cancelled} refundedCount=${refundedCount} refundedAmount=${refundedAmount} errors=${errors}`);
    res.json({ success: true, cancelled, refundedCount, refundedAmount, errors });
  } catch (err) {
    logger.error(`/api/admin/raffles/purge-legacy: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// POST /api/admin/raffles/seed — fuerza el seed de los 4 sorteos. Util si el
// boot todavia no corrio o algo se rompio. Idempotente.
app.post('/api/admin/raffles/seed', authMiddleware, superAdminMiddleware, async (req, res) => {
  try {
    _invalidateSeedCache();
    const before = await Raffle.countDocuments({ status: 'active' });
    await _ensureActiveRafflesSeeded();
    const after = await Raffle.countDocuments({ status: 'active' });
    res.json({ success: true, before, after, created: Math.max(0, after - before) });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// POST /api/admin/raffles/:id/announce — push masivo anunciando un sorteo.
// El admin compone titulo/body, elige equipos (vacio = todos) y si solo
// gente con app o todos. Reusamos sendNotificationToAllUsers con filtro.
//
// Body: { title, body, teams: [], hasAppOnly: true }
//
// Limitamos a sorteos que estan vivos (active/closed) para no spamear con
// avisos de sorteos ya sorteados o archivados.
app.post('/api/admin/raffles/:id/announce', authMiddleware, superAdminMiddleware, bulkLaunchLimiter, async (req, res) => {
  try {
    const raffle = await Raffle.findOne({ id: req.params.id }).lean();
    if (!raffle) return res.status(404).json({ error: 'Sorteo no encontrado.' });
    if (raffle.status !== 'active' && raffle.status !== 'closed') {
      return res.status(400).json({ error: `No se puede anunciar un sorteo en estado "${raffle.status}".` });
    }
    const b = req.body || {};
    const title = String(b.title || '').slice(0, 100).trim();
    const body = String(b.body || '').slice(0, 500).trim();
    if (!title || !body) return res.status(400).json({ error: 'Faltan title y/o body.' });
    const teams = Array.isArray(b.teams) ? b.teams.map(String).slice(0, 100) : [];
    const usernames = Array.isArray(b.usernames)
      ? b.usernames.map(u => String(u || '').toLowerCase().trim()).filter(Boolean).slice(0, 50)
      : [];
    const hasAppOnly = b.hasAppOnly !== false;

    // Filter de audiencia. Hay 3 modos posibles:
    //   1) usernames[] (test) -> match exacto por username, ignora teams y
    //      hasAppOnly. Pensado para testear el sorteo con un user puntual y
    //      garantizar que le llegue el push aunque tenga la app sin standalone.
    //   2) teams[]            -> match por prefijo de username (equipo).
    //   3) sin nada           -> todos.
    const userFilter = {};
    if (usernames.length > 0) {
      const safeUsers = usernames.map(u => u.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'));
      userFilter.username = { $regex: '^(' + safeUsers.join('|') + ')$', $options: 'i' };
    } else {
      if (teams.length > 0) {
        // El prefijo del username matchea el equipo (case-insensitive).
        const escapedTeams = teams.map(t => String(t).replace(/[.*+?^${}()|[\]\\]/g, '\\$&'));
        userFilter.username = { $regex: '^(' + escapedTeams.join('|') + ')', $options: 'i' };
      }
      // hasAppOnly: filtra a users con la PWA instalada. El field correcto
      // es fcmTokenContext='standalone' (token registrado desde la app
      // standalone) o algun fcmTokens[*].context==='standalone'.
      if (hasAppOnly) {
        userFilter.$or = [
          { fcmTokenContext: 'standalone' },
          { 'fcmTokens.context': 'standalone' }
        ];
      }
    }

    const result = await sendNotificationToAllUsers(
      User,
      title,
      body,
      {
        source: 'raffle-announce',
        raffleId: raffle.id,
        raffleName: raffle.name,
        raffleType: raffle.raffleType,
        prizeValueARS: String(raffle.prizeValueARS || 0)
      },
      userFilter
    );
    logger.info(`[raffles] ANNOUNCE ${raffle.name} por ${req.user.username || 'admin'} usernames=[${usernames.join(',') || '-'}] teams=[${teams.join(',') || 'all'}] hasAppOnly=${hasAppOnly} sent=${(result && result.successCount) || 0}`);
    res.json({
      success: true,
      sent: (result && result.successCount) || 0,
      failed: (result && result.failureCount) || 0,
      eligible: (result && result.totalSent) || 0,
      teams: teams.length > 0 ? teams : ['all'],
      usernames
    });
  } catch (err) {
    logger.error(`/api/admin/raffles/announce: ${err.message}`);
    res.status(500).json({ error: 'Error enviando anuncio del sorteo' });
  }
});

// POST /api/admin/raffles/seed-lightning — crea el sorteo RELAMPAGO si no hay
// otro activo. Es free, hero del modal (arriba de todo), inscripcion automatica
// cuando el user abre la app, 100 cupos. Una sola vez: si se llena o se sortea,
// NO respawnea. Para correr otro, el admin vuelve a llamar este endpoint.
//
// Body opcional: { prizeValueARS, totalTickets } para customizar el premio o cupo.
// Defaults: $200.000 premio, 100 cupos, gratis.
// GET /api/admin/raffles/lightning-roi — metricas de impacto de la estrategia
// del relampago. Para cada sorteo relampago (drawn / closed / active), trae:
//   - participantes,
//   - cargas+monto totales DESDE drawnAt (o createdAt si aun no se sorteo),
//   - premio entregado (si se sorteo y se acredito),
//   - net = cargas_post - premio (positivo = relampago "se pago" via cargas).
// Asi el admin ve si el gancho funciona como conversion a cargas reales.
app.get('/api/admin/raffles/lightning-roi', authMiddleware, superAdminMiddleware, async (req, res) => {
  try {
    const limit = Math.max(1, Math.min(50, parseInt(req.query.limit, 10) || 20));
    const raffles = await Raffle.find(
      { raffleType: 'relampago' },
      { id: 1, name: 1, prizeValueARS: 1, totalTickets: 1, _ticketCounter: 1, status: 1, drawnAt: 1, prizeClaimedAt: 1, prizeForfeitedAt: 1, createdAt: 1, instanceNumber: 1, winnerUsername: 1, isFree: 1, entryCost: 1 }
    ).sort({ createdAt: -1 }).limit(limit).lean();

    const items = [];
    for (const r of raffles) {
      const parts = await RaffleParticipation.find({ raffleId: r.id }, { username: 1, entryCostPaid: 1 }).lean();
      const totalEntries = parts.length;
      const totalEntryRevenue = parts.reduce((s, p) => s + (p.entryCostPaid || 0), 0);
      const cutoff = r.drawnAt || r.createdAt;
      // Cargas POST (timestamp >= cutoff) de los participantes, agregadas
      // por suma de monto + count.
      const usernames = parts.map(p => p.username);
      let cargasPostCount = 0;
      let cargasPostAmount = 0;
      let cargasPostUsers = 0;
      if (usernames.length > 0 && cutoff) {
        const safeUsernames = usernames.map(u => '^' + String(u).replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '$');
        const agg = await Transaction.aggregate([
          { $match: {
            type: 'deposit',
            timestamp: { $gte: new Date(cutoff) },
            $or: safeUsernames.map(re => ({ username: { $regex: re, $options: 'i' } }))
          }},
          { $group: {
            _id: { $toLower: '$username' },
            count: { $sum: 1 },
            amount: { $sum: { $ifNull: ['$amount', 0] } }
          }}
        ]);
        cargasPostUsers = agg.length;
        for (const a of agg) {
          cargasPostCount += a.count || 0;
          cargasPostAmount += a.amount || 0;
        }
      }
      const prizeAwarded = (r.status === 'drawn' && r.prizeClaimedAt && !r.prizeForfeitedAt)
        ? Number(r.prizeValueARS) || 0
        : 0;
      items.push({
        id: r.id,
        name: r.name,
        instanceNumber: r.instanceNumber,
        status: r.status,
        isFree: !!r.isFree,
        entryCost: r.entryCost || 0,
        prizeValueARS: r.prizeValueARS || 0,
        cuposSold: r._ticketCounter || 0,
        totalTickets: r.totalTickets || 0,
        createdAt: r.createdAt,
        drawnAt: r.drawnAt || null,
        winnerUsername: r.winnerUsername || null,
        forfeited: !!r.prizeForfeitedAt,
        totalEntries,
        totalEntryRevenue,
        cargasPostCount,
        cargasPostAmount,
        cargasPostUsers,
        prizeAwarded,
        net: totalEntryRevenue + cargasPostAmount - prizeAwarded
      });
    }

    // Totales agregados de todos los relampagos.
    const totals = items.reduce((acc, it) => {
      acc.totalRaffles += 1;
      acc.totalEntries += it.totalEntries;
      acc.totalEntryRevenue += it.totalEntryRevenue;
      acc.totalCargasPostCount += it.cargasPostCount;
      acc.totalCargasPostAmount += it.cargasPostAmount;
      acc.totalPrizeAwarded += it.prizeAwarded;
      acc.totalNet += it.net;
      return acc;
    }, {
      totalRaffles: 0, totalEntries: 0, totalEntryRevenue: 0,
      totalCargasPostCount: 0, totalCargasPostAmount: 0,
      totalPrizeAwarded: 0, totalNet: 0
    });

    res.json({ raffles: items, totals });
  } catch (err) {
    logger.error(`/api/admin/raffles/lightning-roi: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// =====================================================================
// SEGMENTOS (listas de usuarios para analizar conversion)
// =====================================================================
// El admin sube CSV / pega URL Sheets con una lista de usuarios (top
// jugadores, recuperacion, sin WP, con app, bonus 5k/10k/2k, etc.) y el
// sistema cruza contra Transaction.deposit (real, JUGAYGANA) para mostrar
// quien volvio a cargar despues de la subida + monto + conversion %.
//
// Endpoints:
//   GET    /api/admin/segments             — list all segments (resumen)
//   POST   /api/admin/segments             — crear segmento (slug, name, kind)
//   GET    /api/admin/segments/:slug       — detalle con conversion analysis
//   POST   /api/admin/segments/:slug/upload  — subir CSV (texto) o URL Sheets
//   POST   /api/admin/segments/:slug/import-lightning — importar de un raffle
//   DELETE /api/admin/segments/:slug       — borrar
// =====================================================================

// Parser CSV minimalista que maneja: comas, comillas dobles, comillas dobles
// escapadas (""). NO maneja saltos de linea dentro de celdas (raro y
// suficientemente atipico que prefiero rechazar la fila a meter una libreria).
// Devuelve array de arrays de strings.
function _parseCsv(text) {
  if (!text) return [];
  const rows = [];
  const lines = text.split(/\r?\n/);
  for (const raw of lines) {
    const line = raw.trim();
    if (!line) continue;
    const cells = [];
    let cur = '';
    let inQ = false;
    for (let i = 0; i < line.length; i++) {
      const c = line[i];
      if (inQ) {
        if (c === '"') {
          if (line[i + 1] === '"') { cur += '"'; i++; }
          else { inQ = false; }
        } else { cur += c; }
      } else {
        if (c === ',') { cells.push(cur); cur = ''; }
        else if (c === '"' && cur === '') { inQ = true; }
        else { cur += c; }
      }
    }
    cells.push(cur);
    rows.push(cells.map(s => s.trim()));
  }
  return rows;
}

// Convierte rows crudos en una lista de objetos. Si hay header, lo usa para
// las keys (lowercase). Si no, asume que la primera columna es username.
// Detecta header viendo si la primera fila contiene "username" o "user".
function _csvRowsToObjects(rows) {
  if (rows.length === 0) return { items: [], headers: [] };
  const first = rows[0].map(s => String(s).toLowerCase().trim());
  const looksLikeHeader = first.some(c => /^(username|user|usuario|nombre|nick|telefono|phone|email)$/.test(c));
  let headers, dataRows;
  if (looksLikeHeader) {
    headers = first;
    dataRows = rows.slice(1);
  } else {
    headers = ['username'];
    dataRows = rows;
  }
  const items = [];
  for (const r of dataRows) {
    const obj = {};
    for (let i = 0; i < headers.length; i++) {
      const k = headers[i] || ('col' + i);
      obj[k] = r[i] != null ? String(r[i]) : '';
    }
    items.push(obj);
  }
  return { items, headers };
}

// Saca el username de un row procesado. Busca columnas comunes en orden.
function _pickUsername(row) {
  const candidates = ['username', 'user', 'usuario', 'nick', 'nombre'];
  for (const k of candidates) {
    if (row[k] != null && String(row[k]).trim()) {
      return String(row[k]).replace(/^@/, '').toLowerCase().trim();
    }
  }
  // Fallback: primera columna no vacia.
  for (const k of Object.keys(row)) {
    if (row[k] != null && String(row[k]).trim()) {
      return String(row[k]).replace(/^@/, '').toLowerCase().trim();
    }
  }
  return null;
}

// Categoriza un type del CSV en deposit/withdraw/bonus/null. Reusa los mismos
// patrones tanto al normalizar transacciones crudas como al agregar.
function _txKind(type) {
  const t = String(type || '').toLowerCase().trim();
  if (/(individual_bonus|bonus|bonif|premio|gift|regalo)/.test(t)) return 'bonus';
  if (/(deposit|carga|recarga)/.test(t)) return 'deposit';
  if (/(withdraw|descarga|pago|extraccion|retiro)/.test(t)) return 'withdraw';
  return null;
}

// Detecta si los items parecen un log de transacciones (col type + amount/account).
// Si lo son, normaliza a {username, kind, amount, timeMs, team} sin agregar —
// la agregacion se hace en runtime al pedir el detalle (asi se puede filtrar
// por fecha o por lente). Cap 50000 para no explotar el doc de Mongo.
function _normalizeTxLog(items) {
  if (items.length === 0) return null;
  const first = items[0];
  const hasType = 'type' in first || 'tipo' in first || 'operacion' in first;
  const hasAmount = 'account' in first || 'amount' in first || 'monto' in first || 'value' in first || 'cantidad' in first;
  if (!hasType || !hasAmount) return null;
  const out = [];
  for (const it of items) {
    const u = _pickUsername(it);
    if (!u) continue;
    const kind = _txKind(it.type || it.tipo || it.operacion);
    const amtRaw = it.account != null ? it.account : (it.amount != null ? it.amount : (it.monto != null ? it.monto : (it.value != null ? it.value : it.cantidad)));
    const amount = Math.abs(parseFloat(String(amtRaw || '').replace(/[^0-9.\-,]/g, '').replace(/,/g, '.'))) || 0;
    const timeRaw = it.time || it.fecha || it.date || it.timestamp || null;
    let timeMs = null;
    if (timeRaw) {
      const t = new Date(timeRaw);
      if (!isNaN(t.getTime())) timeMs = t.getTime();
    }
    out.push({
      u, kind, amount, t: timeMs,
      team: String(it.equipo || it.team || '').trim() || undefined
    });
    if (out.length >= 50000) break;
  }
  return out;
}

// Aggrega una lista de transacciones normalizadas (output de _normalizeTxLog)
// por usuario. Aplica filtro de fecha si se pasa fromMs/toMs. Devuelve array
// de aggregates con totals por kind + first/last time.
function _aggregateNormalizedTx(txs, fromMs, toMs) {
  const byUser = new Map();
  for (const r of txs) {
    if (fromMs != null && r.t != null && r.t < fromMs) continue;
    if (toMs != null && r.t != null && r.t > toMs) continue;
    if (!byUser.has(r.u)) {
      byUser.set(r.u, {
        username: r.u,
        team: r.team || '',
        depositCount: 0, depositSum: 0,
        withdrawCount: 0, withdrawSum: 0,
        bonusCount: 0, bonusSum: 0,
        firstTime: null, lastTime: null
      });
    }
    const agg = byUser.get(r.u);
    if (r.kind === 'deposit') { agg.depositCount++; agg.depositSum += r.amount; }
    else if (r.kind === 'withdraw') { agg.withdrawCount++; agg.withdrawSum += r.amount; }
    else if (r.kind === 'bonus') { agg.bonusCount++; agg.bonusSum += r.amount; }
    if (r.t != null) {
      if (agg.firstTime == null || r.t < agg.firstTime) agg.firstTime = r.t;
      if (agg.lastTime == null || r.t > agg.lastTime) agg.lastTime = r.t;
    }
    if (!agg.team && r.team) agg.team = r.team;
  }
  return Array.from(byUser.values()).map(a => ({
    username: a.username,
    team: a.team || undefined,
    depositCount: a.depositCount,
    depositSum: a.depositSum,
    withdrawCount: a.withdrawCount,
    withdrawSum: a.withdrawSum,
    bonusCount: a.bonusCount,
    bonusSum: a.bonusSum,
    firstTime: a.firstTime ? new Date(a.firstTime).toISOString() : null,
    lastTime: a.lastTime ? new Date(a.lastTime).toISOString() : null
  }));
}

// Fetcha CSV desde una URL. Auto-convierte URLs de Google Sheets edit/view
// al endpoint export?format=csv para que el admin pueda pegar la URL del
// sheet directamente sin tener que "publicar a web". Funciona si el sheet
// esta compartido como "cualquiera con el link puede ver".
//
// Tambien soporta:
//   - URLs publicadas a web (.../pub?output=csv)
//   - URLs export ya armadas (.../export?format=csv)
//   - Cualquier URL externa que devuelva CSV directo
//
// Defensa: si la respuesta es HTML (sheet no compartido o URL del editor),
// tiramos error claro en lugar de parsearlo como filas basura.
async function _fetchCsvFromUrl(url) {
  if (!/^https?:\/\//i.test(url)) throw new Error('URL inválida (necesita http/https)');

  let resolvedUrl = url;
  const sheetMatch = url.match(/docs\.google\.com\/spreadsheets\/d\/([a-zA-Z0-9_-]+)/);
  if (sheetMatch && !/[?&]format=csv/.test(url) && !/output=csv/.test(url)) {
    const sheetId = sheetMatch[1];
    const gidMatch = url.match(/[#?&]gid=(\d+)/);
    const gid = gidMatch ? gidMatch[1] : '0';
    resolvedUrl = `https://docs.google.com/spreadsheets/d/${sheetId}/export?format=csv&gid=${gid}`;
  }

  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), 15000);
  try {
    const r = await fetch(resolvedUrl, { signal: controller.signal, redirect: 'follow' });
    clearTimeout(timeoutId);
    if (!r.ok) {
      throw new Error('HTTP ' + r.status + ' al fetchear (¿la planilla no es pública? Compartila como "Cualquiera con el link puede ver")');
    }
    const ct = String(r.headers.get('content-type') || '').toLowerCase();
    const text = await r.text();
    if (text.length > 20 * 1024 * 1024) throw new Error('CSV muy grande (max 20MB)');
    // Si vino HTML, la URL no es CSV. Probable: sheet sin compartir publico
    // o link del editor en otro dominio. Damos instrucciones claras.
    if (ct.includes('text/html') || /^\s*<!doctype\s+html|^\s*<html/i.test(text)) {
      throw new Error('La URL devolvió HTML, no CSV. Asegurate de que la planilla esté compartida como "Cualquiera con el link puede ver" — o publicala a web (Archivo → Compartir → Publicar a la web → "como CSV").');
    }
    return text;
  } catch (e) {
    clearTimeout(timeoutId);
    throw e;
  }
}

// Helper: ya tenemos _getLightningCargasCount que cuenta cargas pre-cutoff.
// Para segmentos queremos contar cargas POST-cutoff (despues de la subida)
// y devolver count + amount. Reutiliza jugayganaMovements igual.
async function _getCargasPostForUser(username, sinceMs) {
  if (!username) return { count: 0, amount: 0, hasAny: false };
  const days = 365;
  const startMs = Number(sinceMs) || (Date.now() - days * 24 * 3600 * 1000);
  const endMs = Date.now();
  const fmt = (d) => {
    const x = new Date(d);
    const y = x.getFullYear();
    const m = String(x.getMonth() + 1).padStart(2, '0');
    const dd = String(x.getDate()).padStart(2, '0');
    return `${y}-${m}-${dd}`;
  };
  try {
    const r = await jugayganaMovements.getUserMovements(username, {
      startDate: fmt(startMs),
      endDate: fmt(endMs),
      pageSize: 500
    });
    if (!r || !r.success) return { count: 0, amount: 0, hasAny: false };
    let count = 0, amount = 0;
    for (const m of (r.movements || [])) {
      const candidates = [m.timestamp, m.Timestamp, m.date, m.Date, m.datetime, m.fecha, m.Fecha, m.createdAt];
      let ts = null;
      for (const c of candidates) {
        if (!c) continue;
        const t = new Date(c).getTime();
        if (isFinite(t) && t > 0) { ts = t; break; }
      }
      // Solo contamos cargas DESPUES del cutoff (sinceMs).
      if (ts && ts < Number(sinceMs)) continue;
      const type = String(m.type || m.operation || m.OperationType || m.Type || m.Operation || '').toLowerCase();
      let amt = 0;
      if (m.amount !== undefined) amt = parseFloat(m.amount);
      else if (m.Amount !== undefined) amt = parseFloat(m.Amount);
      else if (m.value !== undefined) amt = parseFloat(m.value);
      else if (m.Value !== undefined) amt = parseFloat(m.Value);
      else if (m.monto !== undefined) amt = parseFloat(m.monto);
      else if (m.Monto !== undefined) amt = parseFloat(m.Monto);
      const isDep = type.includes('deposit') || type.includes('credit') ||
                    type.includes('carga') || type.includes('recarga') || amt > 0;
      if (isDep) {
        count++;
        amount += Math.abs(amt) || 0;
      }
    }
    return { count, amount, hasAny: count > 0 };
  } catch (e) {
    logger.warn(`[segments] _getCargasPostForUser ${username}: ${e.message}`);
    return { count: 0, amount: 0, hasAny: false };
  }
}

// GET /api/admin/segments — lista resumida.
app.get('/api/admin/segments', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const segs = await Segment.find({}, { rows: 0 }).sort({ updatedAt: -1 }).lean();
    res.json({
      segments: segs.map(s => ({
        slug: s.slug,
        name: s.name,
        description: s.description || '',
        kind: s.kind || 'custom',
        isMaster: !!s.isMaster,
        userCount: (s.usernames || []).length,
        uploadsCount: (s.uploads || []).length,
        lastUploadAt: s.uploads && s.uploads.length > 0 ? s.uploads[s.uploads.length - 1].at : null,
        lastUploadSource: s.uploads && s.uploads.length > 0 ? s.uploads[s.uploads.length - 1].source : null,
        createdAt: s.createdAt,
        updatedAt: s.updatedAt
      }))
    });
  } catch (err) {
    logger.error(`/api/admin/segments: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// POST /api/admin/segments — crear nuevo segmento (vacio).
app.post('/api/admin/segments', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const b = req.body || {};
    const name = String(b.name || '').trim().slice(0, 120);
    if (!name) return res.status(400).json({ error: 'Falta name' });
    const slug = String(b.slug || name).toLowerCase().trim()
      .replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 64);
    if (!slug) return res.status(400).json({ error: 'Slug inválido' });
    const exists = await Segment.findOne({ slug }).lean();
    if (exists) return res.status(400).json({ error: `Ya existe un segmento con slug "${slug}".` });
    const description = String(b.description || '').slice(0, 500);
    const kind = String(b.kind || 'custom').slice(0, 32);
    const seg = await Segment.create({ slug, name, description, kind, usernames: [], rows: [], uploads: [] });
    res.json({ success: true, segment: { slug: seg.slug, name: seg.name, kind: seg.kind } });
  } catch (err) {
    logger.error(`/api/admin/segments POST: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// DELETE /api/admin/segments/:slug — borrar.
app.delete('/api/admin/segments/:slug', authMiddleware, superAdminMiddleware, async (req, res) => {
  try {
    const r = await Segment.deleteOne({ slug: String(req.params.slug || '').toLowerCase() });
    if (r.deletedCount === 0) return res.status(404).json({ error: 'Segmento no encontrado' });
    res.json({ success: true });
  } catch (err) {
    logger.error(`/api/admin/segments DELETE: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// POST /api/admin/segments/:slug/master — marca este segmento como Master.
// Solo UNO puede ser master a la vez — desmarca los demas.
// Body: { isMaster: true|false }. Default true.
app.post('/api/admin/segments/:slug/master', authMiddleware, superAdminMiddleware, async (req, res) => {
  try {
    const slug = String(req.params.slug || '').toLowerCase();
    const seg = await Segment.findOne({ slug });
    if (!seg) return res.status(404).json({ error: 'Segmento no encontrado' });
    const setMaster = (req.body && typeof req.body.isMaster === 'boolean') ? req.body.isMaster : true;
    if (setMaster) {
      // Desmarca cualquier otro master.
      await Segment.updateMany({ slug: { $ne: slug }, isMaster: true }, { $set: { isMaster: false } });
      seg.isMaster = true;
    } else {
      seg.isMaster = false;
    }
    await seg.save();
    res.json({ success: true, isMaster: seg.isMaster });
  } catch (err) {
    logger.error(`/api/admin/segments/:slug/master: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// Cuenta cargas (deposits) de un user en el segmento Maestro, en un rango de
// fechas opcional. Reusa _normalizeTxLog format guardado en seg.rows. Mucho
// mas rapido que ir a JUGAYGANA por cada user (es un find local + filter en
// memoria).
async function _getMasterCargasForUser(masterSeg, username, fromMs, toMs) {
  if (!masterSeg || !masterSeg.rows || masterSeg.rows.length === 0) {
    return { count: 0, amount: 0, hasAny: false };
  }
  const userLower = String(username || '').toLowerCase().trim();
  if (!userLower) return { count: 0, amount: 0, hasAny: false };
  let count = 0, amount = 0;
  for (const r of masterSeg.rows) {
    if (!r.u || r.kind !== 'deposit') continue;
    if (r.u !== userLower) continue;
    if (fromMs != null && r.t != null && r.t < fromMs) continue;
    if (toMs != null && r.t != null && r.t > toMs) continue;
    count++;
    amount += r.amount || 0;
  }
  return { count, amount, hasAny: count > 0 };
}

// POST /api/admin/segments/:slug/upload — sube CSV (texto) o URL Sheets.
// Body: { csv: "...", url: "https://..." }  — uno de los dos.
// Reemplaza la lista actual y agrega entry al historial.
app.post('/api/admin/segments/:slug/upload', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const slug = String(req.params.slug || '').toLowerCase();
    const seg = await Segment.findOne({ slug });
    if (!seg) return res.status(404).json({ error: 'Segmento no encontrado' });
    const b = req.body || {};
    let csvText = String(b.csv || '');
    let source = 'file';
    let sourceDetail = String(b.filename || '').slice(0, 500);
    if (!csvText && b.url) {
      try {
        csvText = await _fetchCsvFromUrl(String(b.url));
        source = 'sheets-url';
        sourceDetail = String(b.url).slice(0, 500);
      } catch (e) {
        return res.status(400).json({ error: 'No se pudo leer la URL: ' + e.message });
      }
    }
    if (!csvText) return res.status(400).json({ error: 'Pasá `csv` (texto) o `url`.' });
    const rows = _parseCsv(csvText);
    if (rows.length === 0) return res.status(400).json({ error: 'CSV vacío o no parseable.' });
    const { items, headers } = _csvRowsToObjects(rows);

    // Si el CSV es un log de transacciones (cols type + account/amount),
    // guardamos las transacciones CRUDAS normalizadas (no agregadas). Asi en
    // el detalle podemos filtrar por rango de fechas + lentes y re-agregar
    // al toque sin re-uploadear. Si no es tx-log, flow plano (lista de
    // usernames sin dedupes).
    const normTxs = _normalizeTxLog(items);
    let cleanRows = [];
    let usernamesSet = new Set();
    if (normTxs && normTxs.length > 0) {
      cleanRows = normTxs;
      usernamesSet = new Set(normTxs.map(r => r.u));
    } else {
      for (const it of items) {
        const u = _pickUsername(it);
        if (!u) continue;
        if (usernamesSet.has(u)) continue;
        usernamesSet.add(u);
        cleanRows.push({ ...it, username: u });
        if (cleanRows.length >= 5000) break;
      }
    }
    seg.usernames = Array.from(usernamesSet);
    seg.rows = cleanRows;
    seg.uploads.push({
      at: new Date(),
      by: (req.user && req.user.username) || 'admin',
      source,
      sourceDetail,
      rowsCount: cleanRows.length
    });
    // Cap historial a las ultimas 50 entradas.
    if (seg.uploads.length > 50) seg.uploads = seg.uploads.slice(-50);
    await seg.save();
    logger.info(`[segments] upload ${slug} source=${source} rows=${cleanRows.length} headers=[${headers.join(',')}]`);
    res.json({
      success: true,
      slug,
      rowsCount: cleanRows.length,
      headers
    });
  } catch (err) {
    logger.error(`/api/admin/segments/upload: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// POST /api/admin/segments/:slug/import-lightning — importa participantes
// de un relampago como segmento. Body: { raffleId }.
app.post('/api/admin/segments/:slug/import-lightning', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const slug = String(req.params.slug || '').toLowerCase();
    const seg = await Segment.findOne({ slug });
    if (!seg) return res.status(404).json({ error: 'Segmento no encontrado' });
    const raffleId = String((req.body && req.body.raffleId) || '');
    if (!raffleId) return res.status(400).json({ error: 'Falta raffleId' });
    const raffle = await Raffle.findOne({ id: raffleId, raffleType: 'relampago' }).lean();
    if (!raffle) return res.status(404).json({ error: 'Relámpago no encontrado' });
    const parts = await RaffleParticipation.find({ raffleId }, { username: 1, ticketNumbers: 1 }).lean();
    const usernamesSet = new Set();
    const cleanRows = [];
    for (const p of parts) {
      const u = String(p.username || '').toLowerCase().trim();
      if (!u || usernamesSet.has(u)) continue;
      usernamesSet.add(u);
      cleanRows.push({
        username: u,
        ticketNumber: (p.ticketNumbers && p.ticketNumbers[0]) || null,
        raffleName: raffle.name
      });
    }
    seg.usernames = Array.from(usernamesSet);
    seg.rows = cleanRows;
    seg.uploads.push({
      at: new Date(),
      by: (req.user && req.user.username) || 'admin',
      source: 'lightning',
      sourceDetail: `${raffle.name} (${raffleId})`,
      rowsCount: cleanRows.length
    });
    if (seg.uploads.length > 50) seg.uploads = seg.uploads.slice(-50);
    await seg.save();
    res.json({ success: true, slug, rowsCount: cleanRows.length });
  } catch (err) {
    logger.error(`/api/admin/segments/import-lightning: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// GET /api/admin/segments/:slug — detalle con conversion analysis.
// Query:
//   ?from=ISO        — filtro: solo transacciones desde esta fecha
//   ?to=ISO          — filtro: solo transacciones hasta esta fecha
//   ?lens=top|bonus|deposit|withdraw|sin-app|con-app|relampago|all
//                    — filtro adicional: top jugadores, solo bonus, etc.
//   ?topN=50         — para lens=top, cuantos mostrar (default 50)
//   ?since=ISO       — para el "Volvió a cargar": cutoff de cargas POST
//                      (default: max(to, lastUploadAt))
//   ?analyze=1       — hace cross-reference contra JUGAYGANA
app.get('/api/admin/segments/:slug', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const slug = String(req.params.slug || '').toLowerCase();
    const seg = await Segment.findOne({ slug }).lean();
    if (!seg) return res.status(404).json({ error: 'Segmento no encontrado' });
    const lastUploadAt = seg.uploads && seg.uploads.length > 0
      ? seg.uploads[seg.uploads.length - 1].at
      : null;

    // Date range filter (sobre las transacciones del archivo).
    const fromMs = req.query.from ? new Date(req.query.from).getTime() : null;
    const toMs = req.query.to ? new Date(req.query.to).getTime() : null;
    const fromValid = fromMs && !isNaN(fromMs);
    const toValid = toMs && !isNaN(toMs);

    // Detectamos formato del segmento: si rows[0] tiene .u + .kind es tx-log
    // normalizado (formato nuevo). Si tiene username es flow viejo (lista
    // plana o agregados).
    const rows = seg.rows || [];
    const isTxLog = rows.length > 0 && rows[0] && rows[0].u != null && rows[0].kind != null;

    // Aggregar segun el formato
    let aggregates = [];
    if (isTxLog) {
      aggregates = _aggregateNormalizedTx(rows, fromValid ? fromMs : null, toValid ? toMs : null);
    } else {
      // Flow viejo: rows ya son aggregates (o solo usernames). Devolvemos
      // como vienen.
      aggregates = rows.map(r => ({
        username: r.username || _pickUsername(r) || '',
        team: r.team,
        depositCount: r.depositCount, depositSum: r.depositSum,
        withdrawCount: r.withdrawCount, withdrawSum: r.withdrawSum,
        bonusCount: r.bonusCount, bonusSum: r.bonusSum,
        firstTime: r.firstTime, lastTime: r.lastTime
      })).filter(x => x.username);
    }

    // Aplicar lens (filtro adicional sobre los aggregates).
    const lens = String(req.query.lens || 'all').toLowerCase();
    const topN = Math.max(1, Math.min(500, parseInt(req.query.topN, 10) || 50));
    let lensApplied = lens;
    if (lens === 'top') {
      aggregates.sort((a, b) => (b.depositSum || 0) - (a.depositSum || 0));
      aggregates = aggregates.slice(0, topN);
    } else if (lens === 'bonus') {
      aggregates = aggregates.filter(a => (a.bonusCount || 0) > 0);
    } else if (lens === 'deposit') {
      aggregates = aggregates.filter(a => (a.depositCount || 0) > 0);
    } else if (lens === 'withdraw') {
      aggregates = aggregates.filter(a => (a.withdrawCount || 0) > 0);
    } else if (lens === 'sin-app' || lens === 'con-app') {
      // Cruzar contra User: fcmTokenContext='standalone' o fcmTokens.context='standalone'
      const usernames = aggregates.map(a => a.username);
      if (usernames.length > 0) {
        const safeUsernames = usernames.map(u => '^' + String(u).replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '$');
        const usersWithApp = await User.find({
          username: { $in: usernames.map(u => new RegExp('^' + String(u).replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '$', 'i')) },
          $or: [
            { fcmTokenContext: 'standalone' },
            { 'fcmTokens.context': 'standalone' }
          ]
        }, { username: 1 }).lean();
        const appSet = new Set(usersWithApp.map(u => String(u.username).toLowerCase()));
        if (lens === 'con-app') aggregates = aggregates.filter(a => appSet.has(a.username.toLowerCase()));
        else aggregates = aggregates.filter(a => !appSet.has(a.username.toLowerCase()));
      }
    } else if (lens === 'relampago') {
      // Cruzar con RaffleParticipation (raffleType='relampago')
      const usernames = aggregates.map(a => a.username);
      if (usernames.length > 0) {
        const lightningRaffles = await Raffle.find({ raffleType: 'relampago' }, { id: 1 }).lean();
        const lightningIds = lightningRaffles.map(r => r.id);
        const parts = await RaffleParticipation.find({
          raffleId: { $in: lightningIds },
          username: { $in: usernames.map(u => new RegExp('^' + String(u).replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '$', 'i')) }
        }, { username: 1 }).lean();
        const partSet = new Set(parts.map(p => String(p.username).toLowerCase()));
        aggregates = aggregates.filter(a => partSet.has(a.username.toLowerCase()));
      } else {
        aggregates = [];
      }
    }
    // lens='all' (default) o cualquier otro -> no filtra.

    // "Volvió a cargar" cutoff. Default: max(to, lastUploadAt).
    const sinceCandidate = req.query.since ? new Date(req.query.since) : null;
    let cutoffMs = sinceCandidate && !isNaN(sinceCandidate.getTime()) ? sinceCandidate.getTime() : null;
    if (!cutoffMs) {
      cutoffMs = toValid ? toMs : (lastUploadAt ? new Date(lastUploadAt).getTime() : null);
    }
    const analyze = String(req.query.analyze || '') === '1';

    let usersAnalyzed = [];
    let totals = { converted: 0, totalCargasPost: 0, totalAmountPost: 0 };

    if (analyze && cutoffMs) {
      const concurrency = 5;
      for (let i = 0; i < aggregates.length; i += concurrency) {
        const slice = aggregates.slice(i, i + concurrency);
        const results = await Promise.all(slice.map(x => _getCargasPostForUser(x.username, cutoffMs)));
        for (let j = 0; j < slice.length; j++) {
          const r = results[j];
          usersAnalyzed.push({
            username: slice[j].username,
            meta: slice[j],
            cargasPostCount: r.count,
            cargasPostAmount: r.amount,
            converted: r.hasAny
          });
          if (r.hasAny) totals.converted++;
          totals.totalCargasPost += r.count;
          totals.totalAmountPost += r.amount;
        }
      }
    } else {
      usersAnalyzed = aggregates.map(a => ({
        username: a.username,
        meta: a,
        cargasPostCount: null,
        cargasPostAmount: null,
        converted: null
      }));
    }

    res.json({
      segment: {
        slug: seg.slug,
        name: seg.name,
        description: seg.description || '',
        kind: seg.kind || 'custom',
        userCount: (seg.usernames || []).length,
        lastUploadAt,
        isTxLog,
        rowsCount: rows.length,
        cutoffUsed: cutoffMs ? new Date(cutoffMs).toISOString() : null,
        dateFrom: fromValid ? new Date(fromMs).toISOString() : null,
        dateTo: toValid ? new Date(toMs).toISOString() : null,
        lensApplied
      },
      analyzed: analyze && !!cutoffMs,
      users: usersAnalyzed,
      totals,
      uploads: (seg.uploads || []).slice().reverse()
    });
  } catch (err) {
    logger.error(`/api/admin/segments/:slug: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

app.post('/api/admin/raffles/seed-lightning', authMiddleware, superAdminMiddleware, async (req, res) => {
  try {
    // Tope: hasta 3 relampagos active+closed simultaneos. El admin arma el N°1
    // manual y el auto-respawn (cuando uno se llena) abre los siguientes hasta
    // llegar a 3. Si admin intenta crear cuando ya hay 3, rechazamos.
    const openCount = await Raffle.countDocuments({ raffleType: 'relampago', status: { $in: ['active', 'closed'] } });
    if (openCount >= 3) {
      const existing = await Raffle.findOne({ raffleType: 'relampago', status: { $in: ['active', 'closed'] } }).sort({ createdAt: -1 }).lean();
      return res.status(400).json({
        error: 'Ya hay 3 sorteos RELÁMPAGO simultáneos (tope máximo). Sorteá o cancelá uno antes de crear otro.',
        raffle: existing ? { id: existing.id, name: existing.name, status: existing.status, cuposSold: existing._ticketCounter || 0, totalTickets: existing.totalTickets } : null
      });
    }
    const b = req.body || {};
    const prizeValueARS = Math.max(1, parseInt(b.prizeValueARS, 10) || LIGHTNING_RAFFLE_CONFIG.prize);
    const totalTickets = Math.max(2, Math.min(1000, parseInt(b.totalTickets, 10) || LIGHTNING_RAFFLE_CONFIG.totalTickets));
    // Default: gratis (legacy). Admin puede pasar isFree=false + entryCost>0
    // para crear un RELAMPAGO pago. Mismo flujo que los pagos semanales — el
    // /buy descuenta saldo y si no alcanza, el front muestra QUIERO CARGAR.
    const isFreeIn = (typeof b.isFree === 'boolean') ? b.isFree : true;
    const entryCostIn = isFreeIn ? 0 : Math.max(1, parseInt(b.entryCost, 10) || 0);
    if (!isFreeIn && entryCostIn < 1) {
      return res.status(400).json({ error: 'Para un RELÁMPAGO PAGO, entryCost debe ser ≥ 1.' });
    }

    const prevCount = await Raffle.countDocuments({ raffleType: 'relampago' });
    // Regla del owner: el PRIMER relampago es para todos (hook). A partir
    // del segundo, requiere haber participado en algun pago (gancho de
    // upsell). Admin puede override pasando requiresPaidTicket en el body.
    const requiresPaidTicket = (typeof b.requiresPaidTicket === 'boolean')
      ? b.requiresPaidTicket
      : prevCount > 0;
    // Threshold de cargas reales en la ultima semana (0 = sin requerimiento).
    // Cap razonable (1..50) para evitar valores absurdos. Las cargas se
    // cuentan via Transaction type='deposit' (los bonus no cuentan).
    const requiresMinChargesLastWeek = Math.max(0, Math.min(50, parseInt(b.requiresMinChargesLastWeek, 10) || 0));

    // Audiencia: 4 modos (all, except, only, user). Sanitizamos los equipos
    // (lowercase, trim, dedup) y los usernames (lowercase, trim, dedup) para
    // que el filter sea consistente con _userInRaffleAudience. El modo 'user'
    // es solo para testing: el admin elige 1 (o pocos) usernames y nadie mas
    // ve el sorteo.
    const audienceMode = ['all', 'except', 'only', 'user'].includes(b.audienceMode) ? b.audienceMode : 'all';
    const audienceTeamsRaw = Array.isArray(b.audienceTeams) ? b.audienceTeams : [];
    const audienceTeams = Array.from(new Set(
      audienceTeamsRaw.map(t => String(t || '').trim()).filter(Boolean)
    )).slice(0, 50);
    const audienceUsernamesRaw = Array.isArray(b.audienceUsernames) ? b.audienceUsernames : [];
    const audienceUsernames = Array.from(new Set(
      audienceUsernamesRaw.map(u => String(u || '').toLowerCase().trim()).filter(Boolean)
    )).slice(0, 20);
    if (audienceMode === 'user' && audienceUsernames.length === 0) {
      return res.status(400).json({ error: 'En modo "Solo a 1 usuario (test)" tenés que ingresar al menos 1 username.' });
    }
    const drawArg = _nextMondayDraw();
    const weekKey = _isoWeekKey(drawArg);
    const id = uuidv4();
    const description = requiresPaidTicket
      ? 'Sorteo RELÁMPAGO. Solo para clientes con al menos 1 número en sorteos pagos. ¡Entrá y mirá!'
      : (isFreeIn
        ? 'Sorteo RELÁMPAGO. Inscripción gratuita por única vez. ¡Entrá y mirá si hay cupo!'
        : `Sorteo RELÁMPAGO PAGO. Entrada $${entryCostIn.toLocaleString('es-AR')} por número. ¡Entrá rápido antes que se llene!`);
    const created = await Raffle.create({
      id,
      raffleType: 'relampago',
      instanceNumber: prevCount + 1,
      name: prizeValueARS === LIGHTNING_RAFFLE_CONFIG.prize && isFreeIn
        ? LIGHTNING_RAFFLE_CONFIG.name
        : `⚡ RELÁMPAGO${isFreeIn ? '' : ' PAGO'} · $${prizeValueARS.toLocaleString('es-AR')}`,
      prizeName: `$${prizeValueARS.toLocaleString('es-AR')} en saldo`,
      description,
      emoji: '⚡',
      entryCost: entryCostIn,
      totalTickets,
      prizeValueARS,
      _ticketCounter: 0,
      claimedNumbers: [],
      drawDate: drawArg,
      weekKey,
      status: 'active',
      isFree: isFreeIn,
      minCargasARS: 0,
      requiresPaidTicket,
      audienceMode,
      audienceTeams,
      audienceUsernames,
      requiresMinChargesLastWeek,
      lotteryRule: 'Sorteo RELÁMPAGO. Mismo mecanismo que los demás: 1° premio de la Lotería Nacional Nocturna del lunes próximo.',
      createdAt: new Date()
    });
    logger.info(`[raffles] LIGHTNING raffle creado #${prevCount + 1} prize=$${prizeValueARS} cupos=${totalTickets} id=${id}`);
    res.json({
      success: true,
      raffle: {
        id: created.id,
        name: created.name,
        totalTickets: created.totalTickets,
        prizeValueARS: created.prizeValueARS
      }
    });
  } catch (err) {
    logger.error(`/api/admin/raffles/seed-lightning: ${err.message}`);
    res.status(500).json({ error: 'Error creando sorteo relámpago' });
  }
});

// POST /api/admin/raffles/seed-test — crea un sorteo de prueba si no hay otro
// activo. Pensado para validar el flujo punta a punta (buy -> draw -> auto-
// credit) con poca plata real. NO auto-respawnea. Cuando se sortea, podes
// llamar otra vez al endpoint para crear uno nuevo.
//
// Body opcional: { entryCost, prizeValueARS, totalTickets } para customizar.
// Defaults: entryCost=$100, prize=$500, cupos=5.
app.post('/api/admin/raffles/seed-test', authMiddleware, superAdminMiddleware, async (req, res) => {
  try {
    const existing = await Raffle.findOne({ raffleType: 'test', status: 'active' }).lean();
    if (existing) {
      return res.status(400).json({
        error: 'Ya hay un sorteo de prueba activo. Sorteálo o cancelalo antes de crear otro.',
        raffle: { id: existing.id, name: existing.name, cuposSold: existing._ticketCounter || 0, totalTickets: existing.totalTickets }
      });
    }
    const b = req.body || {};
    const entryCost = Math.max(1, parseInt(b.entryCost, 10) || 100);
    const prizeValueARS = Math.max(1, parseInt(b.prizeValueARS, 10) || 500);
    const totalTickets = Math.max(2, Math.min(100, parseInt(b.totalTickets, 10) || 5));

    // instanceNumber: contar cuantos test hubo (active + drawn + archived) y
    // sumar 1, para que el #N sea consistente con el flujo de paid.
    const prevCount = await Raffle.countDocuments({ raffleType: 'test' });

    const drawArg = _nextMondayDraw();
    const weekKey = _isoWeekKey(drawArg);
    const id = uuidv4();
    const created = await Raffle.create({
      id,
      raffleType: 'test',
      instanceNumber: prevCount + 1,
      name: `🧪 Sorteo PRUEBA $${prizeValueARS.toLocaleString('es-AR')}`,
      prizeName: `$${prizeValueARS.toLocaleString('es-AR')} en saldo`,
      description: 'Sorteo de prueba para validar el flujo. Entrada baja, premio chico — sortealo cuando quieras desde admin.',
      emoji: '🧪',
      entryCost,
      totalTickets,
      prizeValueARS,
      _ticketCounter: 0,
      claimedNumbers: [],
      drawDate: drawArg,
      weekKey,
      status: 'active',
      isFree: false,
      lotteryRule: 'Sorteo de PRUEBA. El admin lo sortea manualmente cuando quiera (no espera a la lotería).',
      createdAt: new Date()
    });
    logger.info(`[raffles] TEST raffle creado #${prevCount + 1} entry=$${entryCost} prize=$${prizeValueARS} cupos=${totalTickets} id=${id}`);
    res.json({
      success: true,
      raffle: {
        id: created.id,
        name: created.name,
        entryCost: created.entryCost,
        totalTickets: created.totalTickets,
        prizeValueARS: created.prizeValueARS
      }
    });
  } catch (err) {
    logger.error(`/api/admin/raffles/seed-test: ${err.message}`);
    res.status(500).json({ error: 'Error creando sorteo de prueba' });
  }
});

// GET /api/admin/raffles/spend-daily — cierre diario de gasto en sorteos pagos.
// Devuelve por dia (TZ ARG): total ARS, cantidad de compras, cupos vendidos,
// usuarios unicos, y desglose por tipo. La fuente es RaffleSpend (un row por
// compra individual). El default trae los ultimos 30 dias.
//
// Query params:
//   ?days=30     -> rango (default 30)
//   ?from=YYYY-MM-DD&to=YYYY-MM-DD -> rango explicito (override)
//   ?kind=paid   -> solo paid (default). free no genera spend.
app.get('/api/admin/raffles/spend-daily', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const daysParam = Math.max(1, Math.min(365, parseInt(req.query.days, 10) || 30));
    const from = (req.query.from && /^\d{4}-\d{2}-\d{2}$/.test(req.query.from)) ? req.query.from : null;
    const to = (req.query.to && /^\d{4}-\d{2}-\d{2}$/.test(req.query.to)) ? req.query.to : null;

    let dayKeyMatch;
    if (from && to) {
      dayKeyMatch = { $gte: from, $lte: to };
    } else {
      // Tomar las ultimas N fechas (TZ ARG) -> calculamos lista de claves.
      const argNow = _argZonedNow();
      const keys = [];
      for (let i = 0; i < daysParam; i++) {
        const d = new Date(argNow);
        d.setUTCDate(argNow.getUTCDate() - i);
        const y = d.getUTCFullYear();
        const m = String(d.getUTCMonth() + 1).padStart(2, '0');
        const day = String(d.getUTCDate()).padStart(2, '0');
        keys.push(`${y}-${m}-${day}`);
      }
      dayKeyMatch = { $in: keys };
    }

    const paidTypes = RAFFLE_TYPES.map(t => t.type);
    const match = { dayKeyArg: dayKeyMatch, raffleType: { $in: paidTypes } };

    // Agregado por dia.
    const byDay = await RaffleSpend.aggregate([
      { $match: match },
      { $group: {
          _id: '$dayKeyArg',
          totalARS: { $sum: '$amountARS' },
          buys: { $sum: 1 },
          cupos: { $sum: '$cuposCount' },
          users: { $addToSet: '$username' }
      } },
      { $project: {
          _id: 0,
          dayKey: '$_id',
          totalARS: 1,
          buys: 1,
          cupos: 1,
          uniqueUsers: { $size: '$users' }
      } },
      { $sort: { dayKey: -1 } }
    ]);

    // Desglose por tipo de sorteo (sumado en el rango).
    const byType = await RaffleSpend.aggregate([
      { $match: match },
      { $group: {
          _id: '$raffleType',
          totalARS: { $sum: '$amountARS' },
          buys: { $sum: 1 },
          cupos: { $sum: '$cuposCount' }
      } },
      { $project: { _id: 0, raffleType: '$_id', totalARS: 1, buys: 1, cupos: 1 } },
      { $sort: { totalARS: -1 } }
    ]);

    // Totales del rango completo.
    const totals = byDay.reduce((acc, r) => {
      acc.totalARS += r.totalARS || 0;
      acc.buys += r.buys || 0;
      acc.cupos += r.cupos || 0;
      return acc;
    }, { totalARS: 0, buys: 0, cupos: 0 });

    // Usuarios unicos del rango entero (no se puede sumar uniqueUsers por dia).
    const uniqRangeAgg = await RaffleSpend.aggregate([
      { $match: match },
      { $group: { _id: '$username' } },
      { $count: 'n' }
    ]);
    totals.uniqueUsers = (uniqRangeAgg[0] && uniqRangeAgg[0].n) || 0;

    // Fill-in: si un dia no tiene compras, lo devolvemos con ceros para que
    // la UI muestre todos los dias del rango (mejor UX que un grafico
    // saltando dias).
    const byDayMap = Object.fromEntries(byDay.map(r => [r.dayKey, r]));
    const requestedKeys = (dayKeyMatch.$in)
      ? dayKeyMatch.$in
      : (() => {
          const keys = [];
          const start = new Date(from + 'T00:00:00Z');
          const end = new Date(to + 'T00:00:00Z');
          for (let d = new Date(start); d <= end; d.setUTCDate(d.getUTCDate() + 1)) {
            const y = d.getUTCFullYear();
            const m = String(d.getUTCMonth() + 1).padStart(2, '0');
            const day = String(d.getUTCDate()).padStart(2, '0');
            keys.push(`${y}-${m}-${day}`);
          }
          return keys.reverse();
        })();
    const filled = requestedKeys.map(k => byDayMap[k] || ({
      dayKey: k, totalARS: 0, buys: 0, cupos: 0, uniqueUsers: 0
    }));

    res.json({
      success: true,
      range: { days: daysParam, from: from || filled[filled.length - 1]?.dayKey, to: to || filled[0]?.dayKey },
      totals,
      byDay: filled,
      byType,
      typesIncluded: paidTypes
    });
  } catch (err) {
    logger.error(`/api/admin/raffles/spend-daily: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// GET /api/admin/raffles/spend-daily/:dayKey — detalle del dia (cada compra).
// Util para abrir un dia y ver quien compro que.
app.get('/api/admin/raffles/spend-daily/:dayKey', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const dayKey = String(req.params.dayKey || '');
    if (!/^\d{4}-\d{2}-\d{2}$/.test(dayKey)) {
      return res.status(400).json({ error: 'dayKey invalido (formato YYYY-MM-DD)' });
    }
    const paidTypes = RAFFLE_TYPES.map(t => t.type);
    const rows = await RaffleSpend.find(
      { dayKeyArg: dayKey, raffleType: { $in: paidTypes } },
      { _id: 0, id: 1, username: 1, raffleType: 1, raffleName: 1, cuposCount: 1, ticketNumbers: 1, amountARS: 1, jugayganaTxId: 1, createdAt: 1 }
    ).sort({ createdAt: -1 }).limit(2000).lean();

    const totals = rows.reduce((acc, r) => {
      acc.totalARS += r.amountARS || 0;
      acc.buys += 1;
      acc.cupos += r.cuposCount || 0;
      return acc;
    }, { totalARS: 0, buys: 0, cupos: 0 });

    res.json({ success: true, dayKey, totals, rows });
  } catch (err) {
    logger.error(`/api/admin/raffles/spend-daily/:dayKey: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// GET /api/admin/raffles/dashboard — KPIs de la semana del proximo draw.
// Resumen rápido para el panel: 4 sorteos activos + agregados por tipo +
// top compradores + recaudación de la semana.
//
// El "weekKey del dashboard" no es el de la semana calendario actual, sino
// el de la semana del PROXIMO Lunes (= weekKey con el que se crearon los
// sorteos activos). Esto es lo que el admin espera ver: "que pasa con los
// GET /api/admin/raffles/audience-config?kind=paid|free
// Lee la audiencia configurada que se va a aplicar a las proximas
// instancias de sorteos pagos o gratis. Default { mode:'all', teams:[] }.
app.get('/api/admin/raffles/audience-config', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const kind = (req.query.kind === 'free') ? 'free' : 'paid';
    const cfg = await _readRaffleAudienceConfig(kind);
    res.json({ kind, ...cfg });
  } catch (err) {
    logger.error(`/api/admin/raffles/audience-config GET: ${err.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// PUT /api/admin/raffles/audience-config?kind=paid|free
// Body: { mode, teams }
// Guarda la audiencia y la aplica a TODAS las instancias 'active' del
// kind correspondiente — asi el cambio impacta inmediatamente, no solo
// en el proximo respawn. Las instancias 'closed' o 'drawn' no se tocan.
app.put('/api/admin/raffles/audience-config', authMiddleware, superAdminMiddleware, async (req, res) => {
  try {
    const kind = (req.query.kind === 'free') ? 'free' : 'paid';
    const b = req.body || {};
    const mode = ['all', 'except', 'only'].includes(b.mode) ? b.mode : 'all';
    const teams = Array.isArray(b.teams)
      ? Array.from(new Set(b.teams.map(t => String(t || '').trim()).filter(Boolean))).slice(0, 50)
      : [];
    if (mode !== 'all' && teams.length === 0) {
      return res.status(400).json({ error: 'Si el modo no es "todos", elegí al menos 1 equipo.' });
    }
    const finalCfg = { mode, teams: mode === 'all' ? [] : teams };
    const key = kind === 'free' ? 'raffle_audience_free' : 'raffle_audience_paid';
    await setConfig(key, finalCfg, req.user?.username || null);

    // Aplicar a las instancias active del kind. Si es paid afectamos los
    // raffleType de RAFFLE_TYPES; si es free afectamos los de FREE_RAFFLE_TYPES.
    const types = kind === 'free' ? FREE_RAFFLE_TYPES.map(t => t.type) : RAFFLE_TYPES.map(t => t.type);
    const upd = await Raffle.updateMany(
      { raffleType: { $in: types }, status: 'active' },
      { $set: { audienceMode: finalCfg.mode, audienceTeams: finalCfg.teams } }
    );

    logger.info(`[raffles] audience-config ${kind} mode=${finalCfg.mode} teams=${JSON.stringify(finalCfg.teams)} affected=${upd.modifiedCount}`);
    res.json({ success: true, kind, mode: finalCfg.mode, teams: finalCfg.teams, activeUpdated: upd.modifiedCount });
  } catch (err) {
    logger.error(`/api/admin/raffles/audience-config PUT: ${err.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// sorteos que se van a sortear el lunes que viene". Antes mostraba la
// semana calendario actual (ej: martes 5/5 -> W19) pero los sorteos
// activos tenian weekKey = W20 (semana del lunes 11/5 que es el draw),
// asi el dashboard quedaba vacio.
app.get('/api/admin/raffles/dashboard', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    await _ensureActiveRafflesSeededCached();
    const kind = (req.query.kind === 'free') ? 'free'
                : (req.query.kind === 'relampago') ? 'relampago'
                : 'paid';
    let typeList;
    if (kind === 'relampago') typeList = ['relampago'];
    else if (kind === 'free') typeList = FREE_RAFFLE_TYPES.map(t => t.type);
    else typeList = RAFFLE_TYPES.map(t => t.type);
    const nextDraw = _nextMondayDraw();
    const drawArg = new Date(nextDraw.getTime() - 3 * 3600 * 1000);
    const dashboardWeek = _isoWeekKey(drawArg);
    const calendarWeek = _isoWeekKey(_argZonedNow());
    // Sorteos del weekKey del proximo draw (incluye drawn por si ya se
    // sorteo en la semana del draw). Tambien aceptamos sorteos sin weekKey
    // (legacy) que esten active/closed para no perderlos del panel.
    // RELAMPAGO se trata distinto: como es one-shot y el weekKey lo seteamos
    // al crear pero podria desfasar si se creo dias antes, lo traemos por
    // raffleType independiente del weekKey.
    let weekFilter;
    if (kind === 'relampago') {
      weekFilter = {
        status: { $in: ['active', 'closed', 'drawn'] },
        raffleType: 'relampago'
      };
    } else {
      weekFilter = {
        $or: [
          { weekKey: dashboardWeek },
          { weekKey: { $in: ['', null] }, status: { $in: ['active', 'closed'] } }
        ],
        status: { $in: ['active', 'closed', 'drawn'] },
        raffleType: { $in: typeList }
      };
    }
    const weekRaffles = await Raffle.find(weekFilter)
      .sort({ prizeValueARS: -1, instanceNumber: 1 })
      .lean();

    const ids = weekRaffles.map(r => r.id);
    const partsAgg = await RaffleParticipation.aggregate([
      { $match: { raffleId: { $in: ids } } },
      { $group: {
        _id: '$raffleId',
        cuposSold: { $sum: '$cuposCount' },
        participants: { $sum: 1 },
        revenue: { $sum: '$entryCostPaid' }
      }}
    ]);
    const aggById = {};
    for (const a of partsAgg) aggById[a._id] = a;

    // Stats por tipo (esta semana). Itera el typeList correcto.
    let cfgList;
    if (kind === 'relampago') {
      // Para relampago derivamos config "on the fly" desde los raffles
      // existentes (no hay array fijo porque cada uno se crea on-demand
      // con valores potencialmente distintos).
      cfgList = weekRaffles
        .filter(r => r.raffleType === 'relampago')
        .map(r => ({
          type: 'relampago',
          emoji: r.emoji || '⚡',
          name: r.name,
          prize: r.prizeValueARS || 0,
          entryCost: 0,
          minCargasARS: 0,
          totalTickets: r.totalTickets || 0
        }))
        .filter((c, i, a) => a.findIndex(x => x.name === c.name) === i);
      // Si no hay ningun relampago todavia, mostramos placeholder.
      if (cfgList.length === 0) {
        cfgList = [{
          type: 'relampago',
          emoji: '⚡',
          name: '⚡ RELÁMPAGO · $200.000',
          prize: 200000,
          entryCost: 0,
          minCargasARS: 0,
          totalTickets: 100
        }];
      }
    } else {
      cfgList = (kind === 'free') ? FREE_RAFFLE_TYPES : RAFFLE_TYPES;
    }
    const byType = {};
    for (const cfg of cfgList) {
      byType[cfg.type] = {
        type: cfg.type,
        emoji: cfg.emoji,
        label: cfg.name,
        prize: cfg.prize,
        entryCost: cfg.entryCost || 0,
        minCargasARS: cfg.minCargasARS || 0,
        totalTickets: cfg.totalTickets,
        instances: 0,
        cuposSold: 0,
        revenue: 0,
        filled: 0,
        drawn: 0,
        active: 0
      };
    }
    let totalRevenue = 0, totalCuposSold = 0, totalFilled = 0;
    for (const r of weekRaffles) {
      const t = byType[r.raffleType];
      if (!t) continue;
      const a = aggById[r.id] || { cuposSold: 0, participants: 0, revenue: 0 };
      t.instances += 1;
      t.cuposSold += a.cuposSold;
      t.revenue += a.revenue;
      if (r.status === 'drawn') t.drawn += 1;
      if (r.status === 'closed') t.filled += 1;
      if (r.status === 'active') t.active += 1;
      totalRevenue += a.revenue;
      totalCuposSold += a.cuposSold;
      if (r.status === 'closed' || r.status === 'drawn') totalFilled += 1;
    }

    // Top 10 compradores de la semana (suma de cuposCount + entryCostPaid)
    const topAgg = await RaffleParticipation.aggregate([
      { $match: { raffleId: { $in: ids } } },
      { $group: {
        _id: { $toLower: '$username' },
        username: { $first: '$username' },
        cuposCount: { $sum: '$cuposCount' },
        entryCostPaid: { $sum: '$entryCostPaid' }
      }},
      { $sort: { entryCostPaid: -1 } },
      { $limit: 10 }
    ]);
    const topBuyers = topAgg.map(t => ({
      username: t.username,
      cuposCount: t.cuposCount,
      totalPaid: t.entryCostPaid
    }));

    // Personas únicas que compraron esta semana
    const uniqueAgg = await RaffleParticipation.aggregate([
      { $match: { raffleId: { $in: ids } } },
      { $group: { _id: { $toLower: '$username' } } },
      { $count: 'count' }
    ]);
    const uniqueBuyers = (uniqueAgg[0] && uniqueAgg[0].count) || 0;

    // Premios pagados (drawn + prizeClaimedAt)
    let prizesPaid = 0, prizesPending = 0;
    for (const r of weekRaffles) {
      if (r.status === 'drawn') {
        if (r.prizeClaimedAt) prizesPaid += (r.prizeValueARS || 0);
        else prizesPending += (r.prizeValueARS || 0);
      }
    }

    res.json({
      weekKey: dashboardWeek,
      calendarWeek,
      drawDate: nextDraw,
      kpis: {
        totalRevenue,
        totalCuposSold,
        totalCupos: weekRaffles.reduce((s, r) => s + (r.totalTickets || 0), 0),
        uniqueBuyers,
        rafflesCount: weekRaffles.length,
        rafflesFilled: totalFilled,
        prizesPaid,
        prizesPending,
        netProfit: totalRevenue - prizesPaid - prizesPending
      },
      byType: Object.values(byType).sort((a, b) => (b.prize || 0) - (a.prize || 0)),
      topBuyers,
      raffles: weekRaffles.map(r => ({
        id: r.id,
        name: r.name,
        emoji: r.emoji,
        raffleType: r.raffleType,
        instanceNumber: r.instanceNumber,
        entryCost: r.entryCost,
        totalTickets: r.totalTickets,
        prizeValueARS: r.prizeValueARS,
        cuposSold: (aggById[r.id] && aggById[r.id].cuposSold) || 0,
        participants: (aggById[r.id] && aggById[r.id].participants) || 0,
        revenue: (aggById[r.id] && aggById[r.id].revenue) || 0,
        drawDate: r.drawDate,
        status: r.status,
        winnerUsername: r.winnerUsername,
        winningTicketNumber: r.winningTicketNumber,
        lotteryDrawNumber: r.lotteryDrawNumber,
        prizeClaimable: r.prizeClaimable || false,
        prizeClaimedAt: r.prizeClaimedAt,
        prizeForfeitedAt: r.prizeForfeitedAt || null,
        prizeForfeitedReason: r.prizeForfeitedReason || null,
        drawnAt: r.drawnAt,
        audienceMode: r.audienceMode || 'all',
        audienceTeams: r.audienceTeams || [],
        audienceUsernames: r.audienceUsernames || [],
        requiresPaidTicket: !!r.requiresPaidTicket
      }))
    });
  } catch (err) {
    logger.error(`/api/admin/raffles/dashboard: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// GET /api/admin/raffles/history — agregado por semana de TODOS los sorteos.
// Devuelve hasta `limit` semanas (default 12), ordenadas más recientes primero.
app.get('/api/admin/raffles/history', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const limit = Math.max(1, Math.min(52, parseInt(req.query.limit, 10) || 12));
    const kind = (req.query.kind === 'free') ? 'free'
                : (req.query.kind === 'relampago') ? 'relampago'
                : 'paid';
    let typeList;
    if (kind === 'relampago') typeList = ['relampago'];
    else if (kind === 'free') typeList = FREE_RAFFLE_TYPES.map(t => t.type);
    else typeList = RAFFLE_TYPES.map(t => t.type);
    // Pipeline: agrupar Raffles por weekKey, joinear participaciones para revenue y cupos.
    const raffles = await Raffle.find(
      {
        status: { $in: ['active', 'closed', 'drawn', 'archived'] },
        weekKey: { $ne: '' },
        raffleType: { $in: typeList }
      },
      { id: 1, weekKey: 1, raffleType: 1, instanceNumber: 1, status: 1,
        prizeValueARS: 1, totalTickets: 1, prizeClaimedAt: 1, drawnAt: 1, drawDate: 1, _id: 0 }
    ).lean();

    if (raffles.length === 0) return res.json({ weeks: [] });

    const ids = raffles.map(r => r.id);
    const partsAgg = await RaffleParticipation.aggregate([
      { $match: { raffleId: { $in: ids } } },
      { $group: {
        _id: '$raffleId',
        cuposSold: { $sum: '$cuposCount' },
        participants: { $sum: 1 },
        revenue: { $sum: '$entryCostPaid' }
      }}
    ]);
    const aggById = {};
    for (const a of partsAgg) aggById[a._id] = a;

    // Personas únicas por semana (otra aggregation con join)
    const weekToRaffleIds = {};
    for (const r of raffles) {
      (weekToRaffleIds[r.weekKey] = weekToRaffleIds[r.weekKey] || []).push(r.id);
    }
    const uniquePerWeek = {};
    for (const wk of Object.keys(weekToRaffleIds)) {
      const ua = await RaffleParticipation.aggregate([
        { $match: { raffleId: { $in: weekToRaffleIds[wk] } } },
        { $group: { _id: { $toLower: '$username' } } },
        { $count: 'count' }
      ]);
      uniquePerWeek[wk] = (ua[0] && ua[0].count) || 0;
    }

    // Agrupar por weekKey
    const weekMap = {};
    for (const r of raffles) {
      const wk = r.weekKey;
      if (!weekMap[wk]) {
        weekMap[wk] = {
          weekKey: wk,
          drawDate: r.drawDate,
          totalRaffles: 0,
          totalCuposSold: 0,
          totalCupos: 0,
          totalRevenue: 0,
          totalPrizesPaid: 0,
          totalPrizesPending: 0,
          drawnRaffles: 0,
          archivedRaffles: 0,
          activeRaffles: 0,
          closedRaffles: 0,
          uniqueBuyers: uniquePerWeek[wk] || 0,
          byType: {}
        };
      }
      const w = weekMap[wk];
      const a = aggById[r.id] || { cuposSold: 0, participants: 0, revenue: 0 };
      w.totalRaffles += 1;
      w.totalCuposSold += a.cuposSold;
      w.totalCupos += (r.totalTickets || 0);
      w.totalRevenue += a.revenue;
      if (r.status === 'drawn' || r.status === 'archived') {
        if (r.prizeClaimedAt) w.totalPrizesPaid += (r.prizeValueARS || 0);
        else if (r.status === 'drawn') w.totalPrizesPending += (r.prizeValueARS || 0);
        else w.totalPrizesPaid += (r.prizeValueARS || 0); // archived asume pagado
      }
      if (r.status === 'drawn') w.drawnRaffles += 1;
      if (r.status === 'archived') w.archivedRaffles += 1;
      if (r.status === 'active') w.activeRaffles += 1;
      if (r.status === 'closed') w.closedRaffles += 1;
      // Por tipo
      const t = r.raffleType;
      if (!w.byType[t]) w.byType[t] = { type: t, count: 0, cuposSold: 0, revenue: 0 };
      w.byType[t].count += 1;
      w.byType[t].cuposSold += a.cuposSold;
      w.byType[t].revenue += a.revenue;
    }

    const weeks = Object.values(weekMap)
      .map(w => ({ ...w, byType: Object.values(w.byType), netProfit: w.totalRevenue - w.totalPrizesPaid - w.totalPrizesPending }))
      .sort((a, b) => b.weekKey.localeCompare(a.weekKey))
      .slice(0, limit);

    res.json({ weeks });
  } catch (err) {
    logger.error(`/api/admin/raffles/history: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// GET /api/admin/raffles/history/:weekKey — detalle de una semana
app.get('/api/admin/raffles/history/:weekKey', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const wk = req.params.weekKey;
    const raffles = await Raffle.find(
      { weekKey: wk, status: { $in: ['active', 'closed', 'drawn', 'archived'] } }
    ).sort({ raffleType: 1, instanceNumber: 1 }).lean();
    const ids = raffles.map(r => r.id);
    const partsAgg = await RaffleParticipation.aggregate([
      { $match: { raffleId: { $in: ids } } },
      { $group: {
        _id: '$raffleId',
        cuposSold: { $sum: '$cuposCount' },
        participants: { $sum: 1 },
        revenue: { $sum: '$entryCostPaid' }
      }}
    ]);
    const aggById = {};
    for (const a of partsAgg) aggById[a._id] = a;

    res.json({
      weekKey: wk,
      raffles: raffles.map(r => ({
        id: r.id,
        name: r.name,
        emoji: r.emoji,
        raffleType: r.raffleType,
        instanceNumber: r.instanceNumber,
        entryCost: r.entryCost,
        totalTickets: r.totalTickets,
        prizeValueARS: r.prizeValueARS,
        cuposSold: (aggById[r.id] && aggById[r.id].cuposSold) || 0,
        participants: (aggById[r.id] && aggById[r.id].participants) || 0,
        revenue: (aggById[r.id] && aggById[r.id].revenue) || 0,
        drawDate: r.drawDate,
        status: r.status,
        winnerUsername: r.winnerUsername,
        winningTicketNumber: r.winningTicketNumber,
        lotteryDrawNumber: r.lotteryDrawNumber,
        prizeClaimable: r.prizeClaimable || false,
        prizeClaimedAt: r.prizeClaimedAt,
        drawnAt: r.drawnAt
      }))
    });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// Migracion one-shot: cancela todos los sorteos legacy (loss-credit:
// iphone/caribe/auto) que esten activos sin participantes. Idempotente.
async function _migrateLegacyRafflesAtBoot() {
  const legacyTypes = ['iphone', 'caribe', 'auto', 'other'];
  try {
    const legacyActive = await Raffle.find(
      { raffleType: { $in: legacyTypes }, status: { $in: ['active', 'closed'] } },
      { id: 1, name: 1, _id: 0 }
    ).lean();
    for (const r of legacyActive) {
      const parts = await RaffleParticipation.countDocuments({ raffleId: r.id });
      if (parts === 0) {
        await Raffle.updateOne({ id: r.id }, { $set: { status: 'cancelled' } });
        logger.info(`[raffles] migrate-legacy: cancel ${r.name} (sin participantes)`);
      } else {
        // Si tiene participantes, lo dejamos para que admin lo resuelva manualmente.
        logger.warn(`[raffles] migrate-legacy: ${r.name} tiene ${parts} participantes — admin debe sortear o cancelar manualmente`);
      }
    }
  } catch (e) {
    logger.warn(`[raffles] migrate-legacy: ${e.message}`);
  }
}
setTimeout(() => { _migrateLegacyRafflesAtBoot().catch(() => {}); }, 7000);

// ============================================================
// CLIENTES ACTIVOS SIN APP — análisis para campaña externa
// ============================================================
// Lista de jugadores ACTIVOS en la plataforma (depositaron en JUGAYGANA
// en los últimos N días) que NO tienen app+notifs. Es el target de la
// campaña externa de WhatsApp para fidelizarlos: mandarles un mensaje
// "bajate la app y reclamá tus $5.000 de bienvenida".
//
// Definición de ACTIVO (default): depositó >= 1 vez en últimos 30 días
// según DailyPlayerStats (que se llena con los imports CSV de JUGAYGANA).
// El admin puede ajustar la ventana y los umbrales por query string.
//
// Performance: una sola aggregation pipeline en Mongo, sin llamadas
// externas. Apto para refresh manual a demanda.

// Helper: dateKey YYYY-MM-DD en TZ Argentina, mismo formato que el resto del sistema.
function _activePlayersTodayKey() {
  const { year, month, day } = _getArgentinaParts();
  return `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
}

// Construye los agregados por equipo a partir de la lista de players.
function _activePlayersBuildTeams(players) {
  const byTeam = new Map();
  for (const p of players) {
    const tn = p.lineTeamName || '— Sin equipo asignado —';
    if (!byTeam.has(tn)) {
      byTeam.set(tn, {
        teamName: tn,
        count: 0, countWithApp: 0, countWithoutApp: 0,
        totalDepositsARS: 0, totalDepositCount: 0
      });
    }
    const t = byTeam.get(tn);
    t.count++;
    if (p.hasChannel) t.countWithApp++; else t.countWithoutApp++;
    t.totalDepositsARS += p.totalDepositsARS || 0;
    t.totalDepositCount += p.depositCount || 0;
  }
  return Array.from(byTeam.values()).sort((a, b) => b.totalDepositsARS - a.totalDepositsARS);
}

// Clasifica un user en segmento por recency (días desde último depósito):
//   hot   : 0-30 días (calientes — actividad reciente)
//   warm  : 30-90 días (tibios — empezaron a despegarse)
//   cool  : 90-180 días (fríos — semi-perdidos)
//   cold  : 180+ días (congelados — perdidos hace tiempo)
//   never : nunca depositaron en la ventana de lookup
function _classifySegment(daysSince) {
  if (daysSince === null || daysSince === undefined) return 'never';
  if (daysSince < 30) return 'hot';
  if (daysSince < 90) return 'warm';
  if (daysSince < 180) return 'cool';
  return 'cold';
}

// Helper: agrega actividad por user desde DailyPlayerStats y clasifica por
// segmento de recency. `windowDays` define hasta cuán atrás miramos para
// armar la base de "alguna vez activos". `segment` filtra el resultado por
// recency bucket; pasá 'all' (o nada) para todo, 'never' incluye usuarios
// que NO depositaron en la ventana (tomados de User collection).
async function _computeActivePlayers({ windowDays, minDepositCount, minDepositARS, excludeWithApp, team, segment, includeNeverDeposited, recoveredLookbackDays }) {
  const since = new Date(Date.now() - windowDays * 24 * 3600 * 1000);
  const now = Date.now();
  const wantNever = segment === 'never' || segment === 'all' || !!includeNeverDeposited;
  // Ventana para "recuperados": users que instalaron app+notifs en los
  // ultimos N dias (default 7). Se computa sobre appFirstInstalledAt.
  const recoveredWindowMs = (Math.max(1, recoveredLookbackDays || 7)) * 24 * 3600 * 1000;
  const recoveredSince = now - recoveredWindowMs;

  // 1) Aggregate de DailyPlayerStats: depósitos por username en la ventana.
  const stats = await DailyPlayerStats.aggregate([
    { $match: { dateUtc: { $gte: since } } },
    {
      $group: {
        _id: '$username',
        totalDepositsARS: { $sum: '$depositSum' },
        depositCount: { $sum: '$depositCount' },
        totalWithdrawsARS: { $sum: '$withdrawSum' },
        withdrawCount: { $sum: '$withdrawCount' },
        lastActivityDate: { $max: '$dateUtc' }
      }
    },
    {
      $match: {
        $and: [
          { depositCount: { $gte: minDepositCount } },
          { totalDepositsARS: { $gte: minDepositARS } }
        ]
      }
    },
    { $sort: { totalDepositsARS: -1 } }
  ]);

  // Set de usernames YA presentes en stats (lowercased) para excluir al
  // armar la lista de "never depositaron" (no doble-contar).
  const statsSet = new Set();
  for (const s of stats) statsSet.add(String(s._id).toLowerCase());

  // 2) Lookup a User. Si querés 'never', traemos a TODOS los users con
  // role='user' y filtramos los que ya están en stats. Si no, sólo los que
  // estén en stats (más eficiente).
  const userQuery = wantNever
    ? { role: 'user' }
    : { role: 'user', username: { $in: stats.map(s => s._id) } };

  const users = await User.find(
    userQuery,
    {
      username: 1, lineTeamName: 1, linePhone: 1,
      lastLogin: 1, fcmTokens: 1, fcmTokenContext: 1, notifPermission: 1,
      role: 1, createdAt: 1, appFirstInstalledAt: 1,
      _id: 0
    }
  ).lean();
  const byUsername = new Map();
  for (const u of users) byUsername.set(String(u.username).toLowerCase(), u);

  // 2.5) Welcome bonus REAL: vive en RefundClaim type='welcome_install',
  //      no en User. Hago un Set de usernames que ya reclamaron para
  //      mostrar la flag correcta. Sin esto, todos aparecían como "no
  //      reclamado" siempre (el campo welcomeBonusClaimed no existe en
  //      el schema de User).
  const welcomeClaimedDocs = await RefundClaim.find(
    { type: 'welcome_install' },
    { username: 1, _id: 0 }
  ).lean();
  const welcomeClaimedSet = new Set(welcomeClaimedDocs.map(r => String(r.username).toLowerCase()));

  // Helper para chequear app+notifs en el MISMO token (evita el bug de
  // OR-cross-token donde un context-standalone-sin-permiso + otro
  // browser-con-permiso disparaban hasChannel=true incorrectamente).
  const _channelOf = (u) => {
    const tokens = Array.isArray(u.fcmTokens) ? u.fcmTokens : [];
    const hasApp = u.fcmTokenContext === 'standalone' ||
                   tokens.some(t => t && t.context === 'standalone');
    const hasNotifs = u.notifPermission === 'granted' ||
                      tokens.some(t => t && t.notifPermission === 'granted');
    // hasChannel ESTRICTO: legacy single-token con AMBOS, o algún
    // elemento del array con AMBOS en el mismo token (igual que
    // APP_NOTIFS_FILTER del weeklyStrategyService que usa $elemMatch).
    const legacyMatch = u.fcmTokenContext === 'standalone' && u.notifPermission === 'granted';
    const arrayMatch = tokens.some(t => t && t.context === 'standalone' && t.notifPermission === 'granted');
    const hasChannel = legacyMatch || arrayMatch;
    return { hasApp, hasNotifs, hasChannel };
  };

  // 3) Enriquecer stats + clasificar por segment. Tambien computamos lista
  // de RECUPERADOS: users que tienen hasChannel=true Y appFirstInstalledAt
  // dentro de la ventana (default 7d). Se backfillea heuristicamente con la
  // primera fcmTokens.updatedAt valida si el user no tiene el campo seteado.
  const all = []; // todos los users (stats + never), cada uno con .segment
  const recovered = []; // users que recuperamos (instalaron app+notifs reciente)
  let totalWithApp = 0;
  let totalWithoutApp = 0;
  const enrichRow = (u, statRow) => {
    const { hasApp, hasNotifs, hasChannel } = _channelOf(u);
    if (hasChannel) totalWithApp++;
    else totalWithoutApp++;
    // Determinar appFirstInstalledAt: campo del schema o fallback heuristico
    // (la primera fcmTokens.updatedAt con context=standalone+granted).
    let installedAt = u.appFirstInstalledAt ? new Date(u.appFirstInstalledAt).getTime() : null;
    if (hasChannel && !installedAt) {
      const tokens = Array.isArray(u.fcmTokens) ? u.fcmTokens : [];
      const validTokens = tokens.filter(t => t && t.context === 'standalone' && t.notifPermission === 'granted' && t.updatedAt);
      if (validTokens.length > 0) {
        installedAt = Math.min(...validTokens.map(t => new Date(t.updatedAt).getTime()));
      }
    }
    const isRecovered = hasChannel && installedAt && installedAt >= recoveredSince;
    const lastTs = statRow && statRow.lastActivityDate ? new Date(statRow.lastActivityDate).getTime() : null;
    const daysSince = lastTs ? Math.floor((now - lastTs) / (24 * 3600 * 1000)) : null;
    return {
      username: u.username,
      lineTeamName: u.lineTeamName || null,
      linePhone: u.linePhone || null,
      lastLogin: u.lastLogin || null,
      totalDepositsARS: statRow ? (Number(statRow.totalDepositsARS) || 0) : 0,
      depositCount: statRow ? (Number(statRow.depositCount) || 0) : 0,
      totalWithdrawsARS: statRow ? (Number(statRow.totalWithdrawsARS) || 0) : 0,
      withdrawCount: statRow ? (Number(statRow.withdrawCount) || 0) : 0,
      lastActivityDate: statRow ? statRow.lastActivityDate : null,
      daysSinceLastActivity: daysSince,
      segment: _classifySegment(daysSince),
      hasApp, hasNotifs, hasChannel,
      appFirstInstalledAt: installedAt ? new Date(installedAt) : null,
      isRecovered,
      welcomeBonusClaimed: welcomeClaimedSet.has(String(u.username).toLowerCase())
    };
  };
  for (const s of stats) {
    const u = byUsername.get(String(s._id).toLowerCase());
    if (!u) continue; // existe en DailyPlayerStats pero no en User (raro)
    if (u.role && u.role !== 'user') continue;
    const row = enrichRow(u, s);
    all.push(row);
    if (row.isRecovered) recovered.push(row);
  }

  // 4) Si querés 'never', agregá los users que NO están en stats.
  if (wantNever) {
    for (const u of users) {
      const lc = String(u.username).toLowerCase();
      if (statsSet.has(lc)) continue;
      if (u.role && u.role !== 'user') continue;
      const row = enrichRow(u, null);
      all.push(row);
      if (row.isRecovered) recovered.push(row);
    }
  }

  // 5) Distribución por segmento (sobre toda la base, antes de filtros).
  const segmentCounts = { hot: 0, warm: 0, cool: 0, cold: 0, never: 0 };
  const segmentCountsWithoutApp = { hot: 0, warm: 0, cool: 0, cold: 0, never: 0 };
  for (const p of all) {
    segmentCounts[p.segment]++;
    if (!p.hasChannel) segmentCountsWithoutApp[p.segment]++;
  }

  // 6) Aplicar filtros finales.
  const seg = segment && segment !== 'all' ? segment : null;
  const out = [];
  for (const p of all) {
    if (seg && p.segment !== seg) continue;
    if (excludeWithApp && p.hasChannel) continue;
    if (team && (p.lineTeamName || '').trim() !== team) continue;
    out.push(p);
  }

  // Re-sort: never al final, por depósitos descendente.
  out.sort((a, b) => {
    if (a.segment === 'never' && b.segment !== 'never') return 1;
    if (b.segment === 'never' && a.segment !== 'never') return -1;
    return (b.totalDepositsARS || 0) - (a.totalDepositsARS || 0);
  });

  // Recuperados: ordenar por fecha de instalacion descendente y devolver
  // siempre (no afectado por filtros de team/segment, es informacion global).
  recovered.sort((a, b) => {
    const ta = a.appFirstInstalledAt ? a.appFirstInstalledAt.getTime() : 0;
    const tb = b.appFirstInstalledAt ? b.appFirstInstalledAt.getTime() : 0;
    return tb - ta;
  });

  return {
    players: out,
    windowDays,
    totalActiveAll: all.length,
    totalWithApp,
    totalWithoutApp,
    matchedUsers: out.length,
    segmentCounts,
    segmentCountsWithoutApp,
    segment: seg || 'all',
    recoveredRecently: recovered,
    recoveredCount: recovered.length,
    recoveredLookbackDays: Math.max(1, recoveredLookbackDays || 7)
  };
}

// GET /api/admin/active-players
// Query: windowDays (default 30, max 730), minDepositCount (1), minDepositARS (0),
//        excludeWithApp (true), team (optional), limit (200), offset (0),
//        groupByTeam (false), segment (all|hot|warm|cool|cold|never)
app.get('/api/admin/active-players', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const windowDays = Math.min(Math.max(parseInt(req.query.windowDays) || 30, 1), 730);
    const minDepositCount = Math.max(parseInt(req.query.minDepositCount) || 1, 0);
    const minDepositARS = Math.max(parseInt(req.query.minDepositARS) || 0, 0);
    const excludeWithApp = req.query.excludeWithApp !== 'false';
    const team = req.query.team ? String(req.query.team).trim() : null;
    const limit = Math.min(parseInt(req.query.limit) || 500, 5000);
    const offset = Math.max(parseInt(req.query.offset) || 0, 0);
    const groupByTeam = req.query.groupByTeam === 'true';
    const segmentRaw = req.query.segment ? String(req.query.segment).trim().toLowerCase() : 'all';
    const segment = ['all','hot','warm','cool','cold','never'].includes(segmentRaw) ? segmentRaw : 'all';
    const recoveredLookbackDays = Math.min(Math.max(parseInt(req.query.recoveredLookbackDays) || 7, 1), 90);

    const t0 = Date.now();
    const r = await _computeActivePlayers({
      windowDays, minDepositCount, minDepositARS, excludeWithApp, team, segment, recoveredLookbackDays
    });

    if (!groupByTeam) {
      const slice = r.players.slice(offset, offset + limit);
      return res.json({
        success: true,
        ...r,
        players: slice,
        total: r.players.length,
        offset, limit,
        computedInMs: Date.now() - t0
      });
    }

    // Agrupar por equipo.
    const byTeam = new Map();
    for (const p of r.players) {
      const tn = p.lineTeamName || '— Sin equipo asignado —';
      if (!byTeam.has(tn)) {
        byTeam.set(tn, {
          teamName: tn,
          count: 0,
          totalDepositsARS: 0,
          totalWithdrawsARS: 0,
          totalDepositCount: 0,
          users: []
        });
      }
      const t = byTeam.get(tn);
      t.count++;
      t.totalDepositsARS += p.totalDepositsARS;
      t.totalWithdrawsARS += p.totalWithdrawsARS;
      t.totalDepositCount += p.depositCount;
      t.users.push(p);
    }
    const teams = Array.from(byTeam.values()).sort((a, b) => b.totalDepositsARS - a.totalDepositsARS);
    res.json({
      success: true,
      windowDays: r.windowDays,
      totalActiveAll: r.totalActiveAll,
      totalWithApp: r.totalWithApp,
      totalWithoutApp: r.totalWithoutApp,
      matchedUsers: r.matchedUsers,
      segmentCounts: r.segmentCounts,
      segmentCountsWithoutApp: r.segmentCountsWithoutApp,
      segment: r.segment,
      teams,
      recoveredRecently: r.recoveredRecently,
      recoveredCount: r.recoveredCount,
      recoveredLookbackDays: r.recoveredLookbackDays,
      computedInMs: Date.now() - t0
    });
  } catch (err) {
    logger.error(`GET active-players: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// GET /api/admin/active-players/export — descarga CSV de la lista actual.
app.get('/api/admin/active-players/export', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const windowDays = Math.min(Math.max(parseInt(req.query.windowDays) || 30, 1), 730);
    const minDepositCount = Math.max(parseInt(req.query.minDepositCount) || 1, 0);
    const minDepositARS = Math.max(parseInt(req.query.minDepositARS) || 0, 0);
    const excludeWithApp = req.query.excludeWithApp !== 'false';
    const team = req.query.team ? String(req.query.team).trim() : null;
    const segmentRaw = req.query.segment ? String(req.query.segment).trim().toLowerCase() : 'all';
    const segment = ['all','hot','warm','cool','cold','never'].includes(segmentRaw) ? segmentRaw : 'all';

    const r = await _computeActivePlayers({
      windowDays, minDepositCount, minDepositARS, excludeWithApp, team, segment
    });

    const escapeCsv = (s) => {
      const v = String(s == null ? '' : s);
      if (v.includes(',') || v.includes('"') || v.includes('\n')) {
        return '"' + v.replace(/"/g, '""') + '"';
      }
      return v;
    };
    const lines = [];
    lines.push(['username','equipo','linea_telefono','ultimo_login','depositos_arsacum','cantidad_depositos','retiros_ars','cantidad_retiros','ultima_actividad','dias_sin_actividad','segmento','tiene_app','tiene_notifs','reclamo_welcome'].join(','));
    for (const p of r.players) {
      lines.push([
        escapeCsv(p.username),
        escapeCsv(p.lineTeamName || ''),
        escapeCsv(p.linePhone || ''),
        escapeCsv(p.lastLogin ? new Date(p.lastLogin).toISOString() : ''),
        Math.round(p.totalDepositsARS),
        p.depositCount,
        Math.round(p.totalWithdrawsARS),
        p.withdrawCount,
        escapeCsv(p.lastActivityDate ? new Date(p.lastActivityDate).toISOString() : ''),
        p.daysSinceLastActivity == null ? '' : p.daysSinceLastActivity,
        escapeCsv(p.segment || ''),
        p.hasApp ? 'si' : 'no',
        p.hasNotifs ? 'si' : 'no',
        p.welcomeBonusClaimed ? 'si' : 'no'
      ].join(','));
    }
    const csv = lines.join('\n');
    const fname = `clientes-activos-${segment}-${windowDays}d-${(team || 'todos').replace(/\W/g,'_')}-${new Date().toISOString().slice(0,10)}.csv`;
    res.setHeader('Content-Type', 'text/csv; charset=utf-8');
    res.setHeader('Content-Disposition', `attachment; filename="${fname}"`);
    res.send('﻿' + csv); // BOM para que Excel abra UTF-8 bien
  } catch (err) {
    logger.error(`GET active-players/export: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// ============================================================
// SNAPSHOTS DE CLIENTES ACTIVOS — diario auto + manual on-demand
// ============================================================
// Cron 03:00 ART: snapshot agregado (counts/sums por equipo, sin
// usernames). Sirve para ver evolución día a día — qué tan rápido
// crece o decrece el universo de "activos sin app".
//
// Manual: el admin aprieta "Generar reporte ahora" → se crea un
// snapshot kind='manual' con la lista completa de usernames para
// poder descargar CSV. El status pasa de queued → running → ready.
// El cómputo es rápido (~1 seg) pero lo hacemos async para que el
// admin no quede bloqueado y pueda navegar mientras.

async function _runActivePlayersDailySnapshot() {
  const todayKey = _activePlayersTodayKey();
  // Idempotente: si ya existe el de hoy, skip.
  const existing = await ActivePlayersSnapshot.findOne({ dateKey: todayKey, kind: 'auto-daily' }).lean();
  if (existing) {
    logger.info(`[active-players] snapshot diario ${todayKey} ya existe, skip`);
    return;
  }
  const t0 = Date.now();
  try {
    // Defaults del cron: ventana 30d, mín 1 carga, sin filtrar app (queremos
    // saber el total y el split). El UI puede pedir snapshots manuales
    // con filtros distintos.
    const r = await _computeActivePlayers({
      windowDays: 30, minDepositCount: 1, minDepositARS: 0,
      excludeWithApp: false, team: null
    });
    const teams = _activePlayersBuildTeams(r.players);
    await ActivePlayersSnapshot.create({
      id: uuidv4(),
      dateKey: todayKey,
      kind: 'auto-daily',
      status: 'ready',
      params: { windowDays: 30, minDepositCount: 1, minDepositARS: 0, excludeWithApp: false },
      totalActiveAll: r.totalActiveAll,
      totalWithApp: r.totalWithApp,
      totalWithoutApp: r.totalWithoutApp,
      matchedUsers: r.matchedUsers,
      teams,
      users: [], // auto-daily NO guarda usernames
      generatedAt: new Date(),
      generatedBy: 'cron',
      computedInMs: Date.now() - t0
    });
    logger.info(`[active-players] snapshot diario ${todayKey} OK: ${r.totalActiveAll} activos (${r.totalWithoutApp} sin app)`);
  } catch (err) {
    logger.error(`[active-players] snapshot diario ${todayKey} error: ${err.message}`);
  }
}

// Bootstrap: 5 min después del boot tomamos uno (por si el server
// arrancó después del horario del cron). Después corre 3am todos
// los días según hora ART.
setTimeout(() => { _runActivePlayersDailySnapshot(); }, 5 * 60 * 1000);
// Checker cada 10 min: si son las 03:0X ART y no hay snapshot de hoy, lo toma.
setInterval(async () => {
  try {
    const now = _getArgentinaParts();
    const fmt = new Intl.DateTimeFormat('en-US', {
      timeZone: 'America/Argentina/Buenos_Aires', hour: '2-digit', hour12: false
    });
    const hour = parseInt(fmt.format(new Date()), 10);
    if (hour === 3) {
      await _runActivePlayersDailySnapshot();
    }
  } catch (_) {}
}, 10 * 60 * 1000);

// Cleanup: cada 24h borrar snapshots manuales > 30 días.
setInterval(async () => {
  try {
    const cutoff = new Date(Date.now() - 30 * 24 * 3600 * 1000);
    const r = await ActivePlayersSnapshot.deleteMany({
      kind: 'manual',
      generatedAt: { $lt: cutoff }
    });
    if (r.deletedCount > 0) logger.info(`[active-players] cleanup: ${r.deletedCount} snapshots manuales viejos eliminados`);
  } catch (err) {
    logger.warn(`[active-players] cleanup error: ${err.message}`);
  }
}, 24 * 60 * 60 * 1000);

// POST /api/admin/active-players/snapshot — pedir un reporte manual.
// Devuelve { id, status: 'queued' } inmediatamente. El cómputo se hace
// async (en background con setImmediate). El admin polea GET /:id
// hasta que status='ready' y entonces baja el CSV.
app.post('/api/admin/active-players/snapshot', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const body = req.body || {};
    const segmentRaw = body.segment ? String(body.segment).trim().toLowerCase() : 'all';
    const params = {
      windowDays: Math.min(Math.max(parseInt(body.windowDays) || 30, 1), 730),
      minDepositCount: Math.max(parseInt(body.minDepositCount) || 1, 0),
      minDepositARS: Math.max(parseInt(body.minDepositARS) || 0, 0),
      excludeWithApp: body.excludeWithApp !== false,
      segment: ['all','hot','warm','cool','cold','never'].includes(segmentRaw) ? segmentRaw : 'all'
    };

    // Crear el row con status 'queued' antes de devolver.
    const id = uuidv4();
    const todayKey = _activePlayersTodayKey();
    await ActivePlayersSnapshot.create({
      id,
      dateKey: todayKey,
      kind: 'manual',
      status: 'queued',
      params,
      generatedAt: new Date(),
      generatedBy: req.user.username || 'admin'
    });

    // Disparar el cómputo async. No await — el cliente recibe la
    // respuesta inmediatamente con jobId.
    setImmediate(async () => {
      const t0 = Date.now();
      try {
        await ActivePlayersSnapshot.updateOne({ id }, { $set: { status: 'running' } });
        const r = await _computeActivePlayers(params);
        const teams = _activePlayersBuildTeams(r.players);
        await ActivePlayersSnapshot.updateOne({ id }, {
          $set: {
            status: 'ready',
            totalActiveAll: r.totalActiveAll,
            totalWithApp: r.totalWithApp,
            totalWithoutApp: r.totalWithoutApp,
            matchedUsers: r.matchedUsers,
            teams,
            users: r.players,
            computedInMs: Date.now() - t0
          }
        });
        logger.info(`[active-players] snapshot manual ${id} OK en ${Date.now() - t0}ms (${r.matchedUsers} users)`);
      } catch (err) {
        await ActivePlayersSnapshot.updateOne({ id }, {
          $set: { status: 'error', errorMessage: err.message, computedInMs: Date.now() - t0 }
        });
        logger.error(`[active-players] snapshot manual ${id} error: ${err.message}`);
      }
    });

    res.json({ success: true, id, status: 'queued' });
  } catch (err) {
    logger.error(`POST active-players/snapshot: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// GET /api/admin/active-players/snapshot/:id — estado y datos de un snapshot.
app.get('/api/admin/active-players/snapshot/:id', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const includeUsers = req.query.includeUsers === 'true';
    const select = includeUsers ? '-_id' : '-_id -users';
    const snap = await ActivePlayersSnapshot.findOne({ id: req.params.id }).select(select).lean();
    if (!snap) return res.status(404).json({ error: 'No encontrado' });
    res.json({ success: true, snapshot: snap });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// GET /api/admin/active-players/snapshots — lista paginada.
// Query: kind (auto-daily | manual), limit, offset
app.get('/api/admin/active-players/snapshots', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const filter = {};
    if (req.query.kind) filter.kind = req.query.kind;
    const limit = Math.min(parseInt(req.query.limit) || 60, 365);
    const offset = Math.max(parseInt(req.query.offset) || 0, 0);
    const items = await ActivePlayersSnapshot.find(filter)
      .sort({ generatedAt: -1 })
      .skip(offset)
      .limit(limit)
      .select('-_id -users') // sin lista de usuarios para que sea liviano
      .lean();
    res.json({ success: true, items });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// GET /api/admin/active-players/snapshot/:id/csv — descargar CSV.
app.get('/api/admin/active-players/snapshot/:id/csv', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const snap = await ActivePlayersSnapshot.findOne({ id: req.params.id }).lean();
    if (!snap) return res.status(404).json({ error: 'No encontrado' });
    if (snap.status !== 'ready') return res.status(409).json({ error: 'Snapshot todavía no está listo (status=' + snap.status + ')' });
    if (!snap.users || snap.users.length === 0) {
      return res.status(400).json({ error: 'Este snapshot no incluye lista de usuarios (es agregado solamente)' });
    }
    const teamFilter = req.query.team ? String(req.query.team).trim() : null;
    const players = teamFilter
      ? snap.users.filter(u => (u.lineTeamName || '— Sin equipo asignado —') === teamFilter)
      : snap.users;

    const escapeCsv = (s) => {
      const v = String(s == null ? '' : s);
      if (v.includes(',') || v.includes('"') || v.includes('\n')) return '"' + v.replace(/"/g, '""') + '"';
      return v;
    };
    const lines = [];
    lines.push(['username','equipo','linea_telefono','ultimo_login','depositos_arsacum','cantidad_depositos','retiros_ars','cantidad_retiros','ultima_actividad','tiene_app','tiene_notifs','reclamo_welcome'].join(','));
    for (const p of players) {
      lines.push([
        escapeCsv(p.username),
        escapeCsv(p.lineTeamName || ''),
        escapeCsv(p.linePhone || ''),
        escapeCsv(p.lastLogin ? new Date(p.lastLogin).toISOString() : ''),
        Math.round(p.totalDepositsARS || 0),
        p.depositCount || 0,
        Math.round(p.totalWithdrawsARS || 0),
        p.withdrawCount || 0,
        escapeCsv(p.lastActivityDate ? new Date(p.lastActivityDate).toISOString() : ''),
        p.hasApp ? 'si' : 'no',
        p.hasNotifs ? 'si' : 'no',
        p.welcomeBonusClaimed ? 'si' : 'no'
      ].join(','));
    }
    const fname = `clientes-activos-snapshot-${snap.dateKey}-${(teamFilter || 'todos').replace(/\W/g,'_')}.csv`;
    res.setHeader('Content-Type', 'text/csv; charset=utf-8');
    res.setHeader('Content-Disposition', `attachment; filename="${fname}"`);
    res.send('﻿' + lines.join('\n'));
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// POST /api/admin/active-players/refresh-today — forzar recompute
// del punto de HOY en el chart de evolución. Útil si querés ver cómo
// cambió la métrica desde la mañana (cuando corrió el cron a las 3am)
// hasta la tarde sin esperar al cron de mañana.
app.post('/api/admin/active-players/refresh-today', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const todayKey = _activePlayersTodayKey();
    // Borrar el de hoy (si existe) para que el helper lo recompute.
    await ActivePlayersSnapshot.deleteOne({ dateKey: todayKey, kind: 'auto-daily' });
    await _runActivePlayersDailySnapshot();
    const fresh = await ActivePlayersSnapshot.findOne({ dateKey: todayKey, kind: 'auto-daily' })
      .select('-_id -users').lean();
    res.json({ success: true, refreshed: !!fresh, snapshot: fresh });
  } catch (err) {
    logger.error(`POST refresh-today: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// GET /api/admin/active-players/evolution — datos para el chart de
// evolución diaria. Devuelve los últimos N días (default 30) de
// snapshots auto-daily.
app.get('/api/admin/active-players/evolution', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const days = Math.min(Math.max(parseInt(req.query.days) || 30, 7), 180);
    const items = await ActivePlayersSnapshot.find({ kind: 'auto-daily' })
      .sort({ dateKey: -1 })
      .limit(days)
      .select('dateKey totalActiveAll totalWithApp totalWithoutApp generatedAt -_id')
      .lean();
    items.reverse(); // cronológico
    res.json({ success: true, items, days });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ============================================================
// ENDPOINTS ADMIN — Recuperación de inactivos
// ----------------------------------------------------------------
// Sección dedicada en el panel para estudiar la población que tiene
// la app instalada y armar estrategias escalonadas de re-engagement
// (48h, 72h, 7d, etc) sin tocar la sección de Automatizaciones.
// El motor de fondo es el mismo (NotificationRule + Suggestions),
// pero acá lo presentamos con panorama de actividad, audiencia en vivo
// y edición inline antes de aprobar.
// ============================================================

// Panorama: distribución de usuarios con app instalada por última vez
// que entraron. Se usa para entender la audiencia ANTES de lanzar.
app.get('/api/admin/recovery/panorama', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    // Filtro base: users reales (no admin), activos, no bloqueados, con app
    // instalada (al menos un fcmToken con context='standalone' O el flag
    // legacy fcmTokenContext='standalone').
    const baseFilter = {
      role: 'user',
      isActive: { $ne: false },
      isBlocked: { $ne: true },
      $or: [
        { fcmTokenContext: 'standalone' },
        { 'fcmTokens.context': 'standalone' }
      ]
    };

    const now = Date.now();
    const H = 3600 * 1000;
    const buckets = [
      { key: 'active24h',     label: 'Activos hoy (< 24h)',         minH: 0,    maxH: 24,    color: '#25d366' },
      { key: 'inactive24_48', label: '24-48h sin entrar',           minH: 24,   maxH: 48,    color: '#ffd700' },
      { key: 'inactive48_72', label: '48-72h sin entrar',           minH: 48,   maxH: 72,    color: '#ff9f3f' },
      { key: 'inactive72_168', label: '72h-7 días sin entrar',      minH: 72,   maxH: 168,   color: '#ff5050' },
      { key: 'inactive7d_30d', label: '7-30 días sin entrar',       minH: 168,  maxH: 720,   color: '#a855f7' },
      { key: 'inactive30dPlus', label: '+30 días (perdidos)',       minH: 720,  maxH: null,  color: '#555' }
    ];

    // Total con app instalada (denominador).
    const totalInstalled = await User.countDocuments(baseFilter);

    // Para cada bucket, contar.
    const out = [];
    for (const b of buckets) {
      const range = {};
      if (b.maxH != null) range.$gte = new Date(now - b.maxH * H);
      range.$lte = new Date(now - b.minH * H);
      const filter = Object.assign({}, baseFilter, { lastLogin: range });
      const count = await User.countDocuments(filter);
      out.push({ key: b.key, label: b.label, color: b.color, minH: b.minH, maxH: b.maxH, count });
    }

    // Sin lastLogin (instalaron y nunca abrieron). Edge case.
    const neverLoggedIn = await User.countDocuments(Object.assign({}, baseFilter, { $or: [
      ...baseFilter.$or
    ], lastLogin: { $in: [null] } }));

    // Top 10 más recientes que dejaron de entrar (entre 24-168h sin login).
    const recentlyDropped = await User.find(
      Object.assign({}, baseFilter, { lastLogin: { $gte: new Date(now - 168 * H), $lte: new Date(now - 24 * H) } }),
      { username: 1, lastLogin: 1, _id: 0 }
    ).sort({ lastLogin: -1 }).limit(10).lean();

    res.json({
      success: true,
      generatedAt: new Date().toISOString(),
      totalInstalled,
      buckets: out,
      neverLoggedIn,
      recentlyDropped
    });
  } catch (err) {
    logger.error(`recovery/panorama: ${err.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// Listar estrategias de recuperación (NotificationRule con category='recovery')
// + audiencia en vivo que matchearía AHORA si dispararan.
app.get('/api/admin/recovery/strategies', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const rules = await NotificationRule.find({ category: 'recovery' }).sort({ code: 1 }).lean();

    // Para cada regla, resolver audiencia ahora (sin enviar nada).
    const enriched = [];
    for (const rule of rules) {
      let audienceCount = 0;
      let audienceSample = [];
      try {
        const aud = await notificationRulesService._resolveAudience(rule, _notifRulesModels);
        audienceCount = aud.length;
        audienceSample = aud.slice(0, 10);
      } catch (e) {
        // Si la regla tiene audienceType no resoluble, devolvemos 0 sin romper.
        audienceCount = 0;
        audienceSample = [];
      }
      enriched.push({
        id: rule.id,
        code: rule.code,
        name: rule.name,
        description: rule.description || null,
        enabled: rule.enabled,
        triggerType: rule.triggerType,
        cronSchedule: rule.cronSchedule || null,
        audienceType: rule.audienceType,
        audienceConfig: rule.audienceConfig || {},
        title: rule.title,
        body: rule.body,
        requiresAdminApproval: !!rule.requiresAdminApproval,
        cooldownMinutes: rule.cooldownMinutes,
        lastFiredAt: rule.lastFiredAt || null,
        totalFiresLifetime: rule.totalFiresLifetime || 0,
        audienceCount,
        audienceSample
      });
    }

    res.json({ success: true, strategies: enriched });
  } catch (err) {
    logger.error(`recovery/strategies: ${err.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// Crear una nueva estrategia de recuperación. Front pasa minHoursAgo,
// maxHoursAgo, hour ART, title, body. Backend completa el resto con
// defaults seguros (requiresAdminApproval=true, audienceType=installed-but-inactive).
app.post('/api/admin/recovery/strategies', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    if (req.user.role !== 'admin') {
      return res.status(403).json({ error: 'Solo el admin principal puede crear estrategias.' });
    }
    const { name, minHoursAgo, maxHoursAgo, hour, title, body, cooldownMinutes } = req.body || {};

    const minH = Number(minHoursAgo);
    const maxH = Number(maxHoursAgo);
    const cronH = Number(hour);
    if (!Number.isFinite(minH) || !Number.isFinite(maxH) || minH < 0 || maxH <= minH) {
      return res.status(400).json({ error: 'minHoursAgo y maxHoursAgo inválidos (maxHoursAgo > minHoursAgo > 0)' });
    }
    if (!Number.isFinite(cronH) || cronH < 0 || cronH > 23) {
      return res.status(400).json({ error: 'hour inválido (0-23)' });
    }
    if (typeof title !== 'string' || !title.trim() || title.length > 200) {
      return res.status(400).json({ error: 'title requerido (max 200)' });
    }
    if (typeof body !== 'string' || !body.trim() || body.length > 1000) {
      return res.status(400).json({ error: 'body requerido (max 1000)' });
    }

    // Code único: D-INST-<minH>H. Si ya existe, anteponer timestamp.
    let code = 'D-INST-' + minH + 'H';
    const existing = await NotificationRule.findOne({ code }).lean();
    if (existing) code = code + '-' + Date.now();

    const rule = await NotificationRule.create({
      id: require('uuid').v4(),
      code,
      name: (name && String(name).trim()) || ('Inactivos ' + minH + 'h'),
      description: 'Estrategia de re-engagement para usuarios con app instalada y sin login en ' + minH + '-' + maxH + 'h.',
      category: 'recovery',
      enabled: true,
      triggerType: 'cron',
      cronSchedule: { hour: cronH, minute: 0 },
      audienceType: 'installed-but-inactive',
      audienceConfig: { minHoursAgo: minH, maxHoursAgo: maxH },
      title: title.trim(),
      body: body.trim(),
      bonus: { type: 'none' },
      requiresAdminApproval: true,
      cooldownMinutes: Number.isFinite(Number(cooldownMinutes)) ? Math.max(60, Number(cooldownMinutes)) : Math.max(minH * 60, 24 * 60),
      createdBy: req.user.username || null
    });

    res.json({ success: true, rule: rule.toObject() });
  } catch (err) {
    logger.error(`recovery/strategies POST: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// ============================================================
// ENDPOINTS ADMIN para Automatizaciones
// ============================================================

// Listar reglas con filtros.
app.get('/api/admin/notification-rules', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const { category, enabled } = req.query;
    const filter = {};
    if (category) filter.category = category;
    if (enabled === 'true') filter.enabled = true;
    if (enabled === 'false') filter.enabled = false;
    const rules = await NotificationRule.find(filter)
      .sort({ category: 1, code: 1 })
      .lean();
    res.json({ success: true, rules });
  } catch (err) {
    logger.error(`/api/admin/notification-rules: ${err.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// Toggle enabled / editar copy.
app.patch('/api/admin/notification-rules/:id', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const { id } = req.params;
    const allowed = ['enabled', 'title', 'body', 'cooldownMinutes', 'requiresAdminApproval', 'cronSchedule', 'bonus'];
    const update = {};
    for (const k of allowed) {
      if (req.body[k] !== undefined) update[k] = req.body[k];
    }
    update.updatedBy = req.user.username || null;
    const rule = await NotificationRule.findOneAndUpdate(
      { id },
      { $set: update },
      { new: true }
    );
    if (!rule) return res.status(404).json({ error: 'Regla no encontrada' });
    res.json({ success: true, rule });
  } catch (err) {
    logger.error(`PATCH notification-rules: ${err.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// Test manual: dispara una regla AHORA (resuelve audiencia + manda push o
// crea suggestion según corresponda).
app.post('/api/admin/notification-rules/:id/test-fire', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    if (req.user.role !== 'admin') {
      return res.status(403).json({ error: 'Solo el admin principal puede testear reglas.' });
    }
    const { id } = req.params;
    const rule = await NotificationRule.findOne({ id }).lean();
    if (!rule) return res.status(404).json({ error: 'Regla no encontrada' });
    const audience = await notificationRulesService._resolveAudience(rule, _notifRulesModels);
    res.json({
      success: true,
      ruleCode: rule.code,
      audienceCount: audience.length,
      audienceSample: audience.slice(0, 20),
      note: 'Dry run: solo se resolvió la audiencia. No se envió nada.'
    });
  } catch (err) {
    logger.error(`test-fire: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// Listar suggestions pendientes de aprobación (para el badge + tab).
app.get('/api/admin/notification-rules/suggestions', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const { status = 'pending' } = req.query;
    const filter = status === 'all' ? {} : { status };
    const suggestions = await NotificationRuleSuggestion.find(filter)
      .sort({ suggestedAt: -1 })
      .limit(200)
      .lean();
    const pendingCount = await NotificationRuleSuggestion.countDocuments({ status: 'pending' });
    res.json({ success: true, suggestions, pendingCount });
  } catch (err) {
    logger.error(`GET suggestions: ${err.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// Editar título/cuerpo de una suggestion PENDING antes de aprobarla.
// Solo se puede editar si status='pending'. La audiencia (audienceUsernames)
// no se toca: ya quedó fijada al momento de crear la suggestion.
app.put('/api/admin/notification-rules/suggestions/:id', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    if (req.user.role !== 'admin') {
      return res.status(403).json({ error: 'Solo el admin principal puede editar sugerencias.' });
    }
    const { id } = req.params;
    const { title, body } = req.body || {};

    if (typeof title !== 'string' || typeof body !== 'string') {
      return res.status(400).json({ error: 'title y body son requeridos (string)' });
    }
    const trimmedTitle = title.trim();
    const trimmedBody = body.trim();
    if (!trimmedTitle || !trimmedBody) {
      return res.status(400).json({ error: 'title y body no pueden estar vacíos' });
    }
    if (trimmedTitle.length > 200 || trimmedBody.length > 1000) {
      return res.status(400).json({ error: 'title (max 200) o body (max 1000) muy largos' });
    }

    const sug = await NotificationRuleSuggestion.findOne({ id }).lean();
    if (!sug) return res.status(404).json({ error: 'Sugerencia no encontrada' });
    if (sug.status !== 'pending') {
      return res.status(400).json({ error: `Sugerencia en estado ${sug.status}, no se puede editar` });
    }

    await NotificationRuleSuggestion.updateOne(
      { id },
      { $set: { title: trimmedTitle, body: trimmedBody } }
    );

    res.json({ success: true, title: trimmedTitle, body: trimmedBody });
  } catch (err) {
    logger.error(`PUT suggestion: ${err.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// Aprobar una suggestion: dispara el push real + crea giveaway si tiene bonus.
app.post('/api/admin/notification-rules/suggestions/:id/approve', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    if (req.user.role !== 'admin') {
      return res.status(403).json({ error: 'Solo el admin principal puede aprobar sugerencias.' });
    }
    const { id } = req.params;
    const sug = await NotificationRuleSuggestion.findOne({ id }).lean();
    if (!sug) return res.status(404).json({ error: 'Sugerencia no encontrada' });
    if (sug.status !== 'pending') return res.status(400).json({ error: `Sugerencia en estado ${sug.status}, no se puede aprobar` });

    // 1) Si tiene giveaway, crearlo primero (cancela cualquier giveaway activo).
    // CRÍTICO: el regalo se crea con audienceWhitelist = sug.audienceUsernames
    // para que SOLO esos usuarios puedan reclamarlo. Sin whitelist, el regalo
    // sería visible a TODOS los users que pollen /api/money-giveaway/active y
    // los primeros en llegar cobrarían (incluso si NO eran del segmento target).
    let giveawayId = null;
    if (sug.bonus && sug.bonus.type === 'giveaway' && sug.bonus.amount > 0) {
      // Cancelar solo giveaways auto-rule previos (no tocar manuales del
      // admin ni los de auto-strategy del lunes — pueden coexistir).
      await MoneyGiveaway.updateMany(
        { status: 'active', strategySource: 'auto-rule' },
        { $set: { status: 'cancelled' } }
      );
      const ga = await MoneyGiveaway.create({
        id: uuidv4(),
        amount: sug.bonus.amount,
        totalBudget: sug.bonus.amount * sug.audienceCount,
        maxClaims: sug.audienceCount,
        durationMinutes: sug.bonus.durationMinutes || 60,
        expiresAt: new Date(Date.now() + (sug.bonus.durationMinutes || 60) * 60 * 1000),
        prefix: null,
        audienceWhitelist: (sug.audienceUsernames || []).map(u => String(u).toLowerCase()),
        requireZeroBalance: !!sug.bonus.requireZeroBalance,
        notificationHistoryId: null,
        status: 'active',
        strategySource: 'auto-rule',
        createdBy: req.user.username || null
      });
      giveawayId = ga.id;
    }

    // 2) Mandar push.
    const filter = { username: { $in: sug.audienceUsernames } };
    const data = {
      source: 'rule-suggestion',
      ruleCode: sug.ruleCode,
      tag: 'auto-rule-' + sug.ruleCode
    };
    if (giveawayId) {
      data.giveawayAmount = String(sug.bonus.amount);
      data.giveawayDurationMinutes = String(sug.bonus.durationMinutes);
    }
    let sendResult = { successCount: 0, failureCount: 0, error: null };
    try {
      sendResult = await _notifRulesSendFn(User, sug.title, sug.body, data, filter);
    } catch (sendErr) {
      sendResult.error = sendErr.message;
    }

    // 2.5) Si el push falló COMPLETAMENTE y se había creado un giveaway,
    // cancelarlo: nadie se va a enterar y el budget queda asignado en limbo.
    // Si el push fue parcialmente exitoso (>= 1 entregado), lo dejamos vivo.
    if (giveawayId && sendResult.error && (sendResult.successCount || 0) === 0) {
      await MoneyGiveaway.updateOne(
        { id: giveawayId },
        { $set: { status: 'cancelled' } }
      ).catch(() => {});
      logger.error(`[suggestion/approve] giveaway ${giveawayId} CANCELADO porque el push falló totalmente: ${sendResult.error}`);
      giveawayId = null;
    }

    // 3) NotificationHistory.
    const historyId = uuidv4();
    try {
      await NotificationHistory.create({
        id: historyId,
        sentAt: new Date(),
        audienceType: 'list',
        audienceCount: sug.audienceCount,
        title: sug.title,
        body: sug.body,
        type: giveawayId ? 'money_giveaway' : 'plain',
        successCount: sendResult.successCount || 0,
        failureCount: sendResult.failureCount || 0,
        sentBy: req.user.username || null,
        meta: {
          ruleId: sug.ruleId,
          ruleCode: sug.ruleCode,
          source: 'rule-suggestion',
          suggestionId: sug.id
        }
      });
    } catch (_) {}

    // 4) Marcar suggestion como aprobada.
    await NotificationRuleSuggestion.updateOne(
      { id: sug.id },
      {
        $set: {
          status: 'approved',
          resolvedAt: new Date(),
          resolvedBy: req.user.username || null,
          notificationHistoryId: historyId,
          giveawayId,
          pushDelivered: sendResult.successCount || 0,
          pushFailed: sendResult.failureCount || 0
        }
      }
    );

    res.json({
      success: true,
      pushDelivered: sendResult.successCount || 0,
      pushFailed: sendResult.failureCount || 0,
      giveawayId,
      sendError: sendResult.error || null
    });
  } catch (err) {
    logger.error(`approve suggestion: ${err.message}`);
    res.status(500).json({ error: err.message });
  }
});

// Descartar una suggestion.
app.post('/api/admin/notification-rules/suggestions/:id/reject', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    if (req.user.role !== 'admin') {
      return res.status(403).json({ error: 'Solo el admin principal puede rechazar sugerencias.' });
    }
    const { id } = req.params;
    const reason = req.body?.reason ? String(req.body.reason).slice(0, 200) : null;
    const r = await NotificationRuleSuggestion.findOneAndUpdate(
      { id, status: 'pending' },
      {
        $set: {
          status: 'rejected',
          resolvedAt: new Date(),
          resolvedBy: req.user.username || null,
          rejectionReason: reason
        }
      },
      { new: true }
    );
    if (!r) return res.status(404).json({ error: 'Sugerencia no encontrada o ya resuelta' });
    res.json({ success: true });
  } catch (err) {
    logger.error(`reject suggestion: ${err.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// ============================================
// ESTADISTICAS ESTRATEGICAS — segmentacion + recuperacion + ROI
// ============================================
//
// Modelo de datos: PlayerStats (cache por user) + RecoveryPush (audit log).
//
// Flujo:
//   1. Admin toca "Refrescar" -> POST /api/admin/stats/refresh
//      Recorre todos los users locales, pega JUGAYGANA por uno (con
//      throttle), suma RefundClaim + MoneyGiveawayClaim del mes,
//      calcula tier + activityStatus + isOpportunist, persiste a Mongo.
//   2. Admin lee la tabla -> GET /api/admin/stats/players?segment=...
//   3. Admin toca "Recuperar todos los X" -> POST /api/admin/stats/recovery-push
//      Crea filas en RecoveryPush (con cooldown 7d por user) y dispara
//      la notif (reusa sendBulkNotification logic).
//
// Reglas de tier (sobre cargas REALES de JUGAYGANA en ult. 30d, descontando
// los credits nuestros):
//   VIP    : >= 10 cargas reales Y >= $200.000
//   ORO    : >= 5 cargas reales Y  >= $100.000
//   PLATA  : >= 5 cargas reales O  >= $30.000  (lo primero que se cumpla)
//   BRONCE : >= 2 cargas reales (fiel pero chico)
//   NUEVO  : creado hace < 14 dias, sin patron aun
//   SIN_DATOS: no se pudo resolver JUGAYGANA o no tiene historial
//
// Reglas de activityStatus (dias desde ULTIMA carga REAL):
//   ACTIVO    : 0-7 dias
//   EN_RIESGO : 8-15 dias
//   PERDIDO   : 16-30 dias
//   INACTIVO  : 31+ dias
//   NUEVO     : creado hace < 14d sin cargas todavia
//
// Oportunista: reclamo bonos N veces en ult 30d sin hacer carga real
// despues. Default N=3 — flag visible en panel para que admin lo dropee
// del listado de bonos masivos.
// ============================================
const STATS_TIER_RULES = {
  vipMinCharges: 10,
  vipMinAmount: 200000,
  oroMinCharges: 5,
  oroMinAmount: 100000,
  plataMinCharges: 5,
  plataMinAmount: 30000,
  bronceMinCharges: 2
};
const STATS_ACTIVITY_DAYS = {
  activo: 7,
  enRiesgo: 15,
  perdido: 30
};
const RECOVERY_COOLDOWN_MS = 7 * 24 * 60 * 60 * 1000; // 7 dias entre pushes al mismo user
const OPPORTUNIST_THRESHOLD = 3;

function _computeTier(realChargesCount, realDepositsAmount, accountAgeDays) {
  if (accountAgeDays != null && accountAgeDays < 14) return 'NUEVO';
  if (realChargesCount >= STATS_TIER_RULES.vipMinCharges &&
      realDepositsAmount >= STATS_TIER_RULES.vipMinAmount) return 'VIP';
  if (realChargesCount >= STATS_TIER_RULES.oroMinCharges &&
      realDepositsAmount >= STATS_TIER_RULES.oroMinAmount) return 'ORO';
  if (realChargesCount >= STATS_TIER_RULES.plataMinCharges ||
      realDepositsAmount >= STATS_TIER_RULES.plataMinAmount) return 'PLATA';
  if (realChargesCount >= STATS_TIER_RULES.bronceMinCharges) return 'BRONCE';
  return 'SIN_DATOS';
}

function _computeActivityStatus(daysSinceLastCharge, accountAgeDays, hasAnyCharge) {
  // NUEVO: cuenta jovencita sin cargas (todavia onboarding).
  if (!hasAnyCharge && accountAgeDays != null && accountAgeDays < 14) return 'NUEVO';
  if (daysSinceLastCharge == null) return 'INACTIVO'; // nunca cargo y no es nuevo
  if (daysSinceLastCharge <= STATS_ACTIVITY_DAYS.activo) return 'ACTIVO';
  if (daysSinceLastCharge <= STATS_ACTIVITY_DAYS.enRiesgo) return 'EN_RIESGO';
  if (daysSinceLastCharge <= STATS_ACTIVITY_DAYS.perdido) return 'PERDIDO';
  return 'INACTIVO';
}

// Para JUGAYGANA: dado una respuesta de getUserNetLastMonth + lista de
// transferencias, contamos cuantas son "deposits del user" (sus cargas reales)
// vs creditos admin (los bonos nuestros). Por ahora aproximamos: pedimos
// total_deposits y restamos lo que sabemos que dimos en RefundClaim+MoneyGiveawayClaim
// del mismo periodo. La fecha de "ultima carga real" la dejamos como
// lastDepositDate de JUGAYGANA si hay deposits>0; si no podemos saberlo
// granular aca, usamos (refreshedAt - 30d) como floor conservador.
async function _refreshPlayerStatsFor(username, opts = {}) {
  const u = String(username || '').toLowerCase().trim();
  if (!u) return { ok: false, error: 'no_username' };

  // Datos desde JUGAYGANA (depositos + retiros del ult. mes).
  const periodMs = 30 * 24 * 60 * 60 * 1000;
  const fromDate = new Date(Date.now() - periodMs);

  let jPayload = null;
  try {
    jPayload = await jugaygana.getUserNetLastMonth(u);
  } catch (e) {
    logger.warn(`[stats] getUserNetLastMonth fallo para ${u}: ${e.message}`);
  }

  // Sumas de bonos NUESTROS dados en los ult. 30d (RefundClaim + MoneyGiveawayClaim).
  const [refundAgg, giveawayAgg, userDoc] = await Promise.all([
    RefundClaim.aggregate([
      { $match: {
          username: u,
          status: { $in: ['completed', null] },
          claimedAt: { $gte: fromDate }
      }},
      { $group: { _id: null, total: { $sum: '$amount' }, count: { $sum: 1 } } }
    ]).catch(() => []),
    MoneyGiveawayClaim.aggregate([
      { $match: {
          username: u,
          status: 'completed',
          claimedAt: { $gte: fromDate }
      }},
      { $group: { _id: null, total: { $sum: '$amount' }, count: { $sum: 1 } } }
    ]).catch(() => []),
    User.findOne({ username: u }).select('id createdAt').lean().catch(() => null)
  ]);

  const refundsTotal = (refundAgg[0] && refundAgg[0].total) || 0;
  const refundsCount = (refundAgg[0] && refundAgg[0].count) || 0;
  const giveawaysTotal = (giveawayAgg[0] && giveawayAgg[0].total) || 0;
  const giveawaysCount = (giveawayAgg[0] && giveawayAgg[0].count) || 0;
  const bonusTotal = refundsTotal + giveawaysTotal;
  const bonusCount = refundsCount + giveawaysCount;

  // Cargas reales = deposits totales JUGAYGANA − bonos nuestros (los bonos
  // los acreditamos via creditUserBalance que JUGAYGANA puede contar como
  // deposit). Floor en 0 por si la cuenta queda negativa por timing/edge cases.
  const jDeposits = (jPayload && jPayload.success ? Number(jPayload.totalDeposits || 0) : 0);
  const jWithdraws = (jPayload && jPayload.success ? Number(jPayload.totalWithdraws || 0) : 0);
  const realDeposits = Math.max(0, jDeposits - bonusTotal);

  // Aproximacion de cargas-reales-count: por ahora, si el monto real > 0
  // contamos al menos 1, sino 0. Para el conteo exacto necesitariamos
  // listar transactions de JUGAYGANA — TODO en fase 2.
  const realChargesCount = realDeposits > 0 ? Math.max(1, Math.round(realDeposits / 5000)) : 0;

  const accountAgeDays = userDoc && userDoc.createdAt
    ? Math.floor((Date.now() - new Date(userDoc.createdAt).getTime()) / (24*3600*1000))
    : null;

  // Cargar el doc actual para preservar lastSeenApp (que se actualiza fuera
  // del refresh) y lastRecoveryPushAt.
  const existing = await PlayerStats.findOne({ username: u }).lean();
  const lastRealDepositDate = realDeposits > 0
    ? (existing && existing.lastRealDepositDate
       ? new Date(Math.max(new Date(existing.lastRealDepositDate).getTime(), Date.now() - periodMs/2))
       : new Date(Date.now() - periodMs/2)) // mid-period como aproximacion conservadora
    : (existing ? existing.lastRealDepositDate : null);

  // dias desde ultima carga real
  const daysSinceLastCharge = lastRealDepositDate
    ? Math.floor((Date.now() - new Date(lastRealDepositDate).getTime()) / (24*3600*1000))
    : null;

  const tier = _computeTier(realChargesCount, realDeposits, accountAgeDays);
  const activityStatus = _computeActivityStatus(daysSinceLastCharge, accountAgeDays, realChargesCount > 0);

  // Oportunista: bonos sin carga real subsiguiente.
  // Si bonusCount > 0 y realChargesCount == 0 -> claros oportunistas.
  // Si bonusCount >> realChargesCount -> sospechoso.
  let bonusesWithoutDeposit = 0;
  if (bonusCount > 0 && realChargesCount === 0) bonusesWithoutDeposit = bonusCount;
  else if (bonusCount > realChargesCount * 2) bonusesWithoutDeposit = bonusCount - realChargesCount;
  const isOpportunist = bonusesWithoutDeposit >= OPPORTUNIST_THRESHOLD;

  const netToHouse = realDeposits - jWithdraws - bonusTotal;

  await PlayerStats.updateOne(
    { username: u },
    {
      $set: {
        userId: userDoc ? userDoc.id : null,
        lastRealDepositDate,
        realDeposits30d: realDeposits,
        realChargesCount30d: realChargesCount,
        withdraws30d: jWithdraws,
        bonusGiven30d: bonusTotal,
        bonusCount30d: bonusCount,
        netToHouse30d: netToHouse,
        tier,
        activityStatus,
        bonusesClaimedWithoutDeposit30d: bonusesWithoutDeposit,
        isOpportunist,
        refreshedAt: new Date()
      },
      $setOnInsert: { username: u }
    },
    { upsert: true }
  );

  return { ok: true, username: u, tier, activityStatus };
}

// Estado del refresh (para que el admin vea progreso desde el panel).
let _statsRefreshState = { running: false, total: 0, done: 0, errors: 0, startedAt: null, finishedAt: null };

app.post('/api/admin/stats/refresh', authMiddleware, adminMiddleware, async (req, res) => {
  if (_statsRefreshState.running) {
    return res.json({
      success: false,
      message: 'Ya hay un refresh corriendo',
      state: _statsRefreshState
    });
  }

  // Empezamos asincronicamente — devolvemos 200 al admin enseguida.
  // El admin polea GET /api/admin/stats/refresh para ver progreso.
  _statsRefreshState = {
    running: true, total: 0, done: 0, errors: 0,
    startedAt: new Date().toISOString(), finishedAt: null
  };
  res.json({ success: true, state: _statsRefreshState });

  // Background work
  (async () => {
    try {
      // Listamos solo users que abrieron la app alguna vez O que tienen
      // claims, para no martillar JUGAYGANA con cuentas dormidas.
      const usernames = await User.find({
        role: { $nin: ['admin', 'depositor', 'withdrawer'] },
        isActive: true
      }).select('username').lean();
      _statsRefreshState.total = usernames.length;

      for (const u of usernames) {
        if (!u.username) continue;
        try {
          await _refreshPlayerStatsFor(u.username);
        } catch (e) {
          _statsRefreshState.errors++;
          logger.warn(`[stats refresh] ${u.username}: ${e.message}`);
        }
        _statsRefreshState.done++;
        // Throttle: 200ms entre users (~5/seg) para no romper JUGAYGANA.
        await new Promise(r => setTimeout(r, 200));
      }

      // Resolver outcomes pendientes de RecoveryPush (en el mismo pase).
      await _resolvePendingRecoveryOutcomes();
    } catch (e) {
      logger.error(`[stats refresh] fatal: ${e.message}`);
    } finally {
      _statsRefreshState.running = false;
      _statsRefreshState.finishedAt = new Date().toISOString();
    }
  })();
});

app.get('/api/admin/stats/refresh', authMiddleware, adminMiddleware, async (req, res) => {
  res.json({ state: _statsRefreshState });
});

// Para cada RecoveryPush con outcome=pending, mira si el user (a) reclamo
// el bono y/o (b) hizo carga real despues del sentAt. Si carga real ->
// 'recovered'. Si solo bono -> 'opportunist'. Si pasaron 14d sin nada ->
// 'no_response'.
async function _resolvePendingRecoveryOutcomes() {
  const pending = await RecoveryPush.find({ outcome: 'pending' }).lean();
  const NOW = Date.now();
  const FOURTEEN_DAYS = 14 * 24 * 3600 * 1000;
  for (const p of pending) {
    const sentMs = new Date(p.sentAt).getTime();
    const stats = await PlayerStats.findOne({ username: p.username }).lean();
    let outcome = 'pending';
    let realDepositMade = p.realDepositMade;
    let realDepositAt = p.realDepositAt;
    let realDepositAmount = p.realDepositAmount;
    let bonusClaimed = p.bonusClaimed;
    let bonusClaimedAt = p.bonusClaimedAt;

    if (stats && stats.lastRealDepositDate &&
        new Date(stats.lastRealDepositDate).getTime() >= sentMs) {
      outcome = 'recovered';
      realDepositMade = true;
      realDepositAt = realDepositAt || stats.lastRealDepositDate;
      realDepositAmount = realDepositAmount || stats.realDeposits30d;
    } else {
      // Mira si reclamo el bono que mandamos.
      const claimAfter = await Promise.all([
        MoneyGiveawayClaim.findOne({
          username: p.username,
          claimedAt: { $gte: new Date(sentMs) }
        }).lean(),
        RefundClaim.findOne({
          username: p.username,
          claimedAt: { $gte: new Date(sentMs) }
        }).lean()
      ]);
      if (claimAfter[0] || claimAfter[1]) {
        bonusClaimed = true;
        bonusClaimedAt = bonusClaimedAt || (claimAfter[0]?.claimedAt || claimAfter[1]?.claimedAt);
        // Si pasaron 14d desde el send y solo reclamo bono, es oportunista.
        if (NOW - sentMs >= FOURTEEN_DAYS) outcome = 'opportunist';
      } else if (NOW - sentMs >= FOURTEEN_DAYS) {
        outcome = 'no_response';
      }
    }

    if (outcome !== p.outcome || bonusClaimed !== p.bonusClaimed || realDepositMade !== p.realDepositMade) {
      await RecoveryPush.updateOne(
        { _id: p._id },
        {
          $set: {
            outcome,
            bonusClaimed,
            bonusClaimedAt,
            realDepositMade,
            realDepositAt,
            realDepositAmount,
            outcomeResolvedAt: outcome === 'pending' ? null : new Date()
          }
        }
      );
    }
  }
}

// GET /api/admin/stats/players — listado segmentado
// Query: ?tier=VIP&activityStatus=EN_RIESGO&sortBy=netToHouse30d&order=desc&limit=100
app.get('/api/admin/stats/players', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const q = {};
    if (req.query.tier) q.tier = String(req.query.tier);
    if (req.query.activityStatus) q.activityStatus = String(req.query.activityStatus);
    if (req.query.opportunist === 'true') q.isOpportunist = true;
    if (req.query.opportunist === 'false') q.isOpportunist = false;

    const sortBy = String(req.query.sortBy || 'netToHouse30d');
    const order = req.query.order === 'asc' ? 1 : -1;
    const limit = Math.min(parseInt(req.query.limit, 10) || 100, 500);

    const players = await PlayerStats.find(q)
      .sort({ [sortBy]: order })
      .limit(limit)
      .lean();

    // Hidratamos cada player con su histórico de claims de giveaways:
    // count, total $, último claim. Una sola agregación con $in para
    // todos los usernames del listado actual — fast path.
    if (players.length > 0) {
      const usernames = players.map(p => p.username).filter(Boolean);
      const claimAgg = await MoneyGiveawayClaim.aggregate([
        { $match: { username: { $in: usernames }, status: 'completed' } },
        {
          $group: {
            _id: '$username',
            count: { $sum: 1 },
            total: { $sum: '$amount' },
            lastClaimAt: { $max: '$claimedAt' }
          }
        }
      ]);
      const byUser = new Map();
      for (const c of claimAgg) byUser.set(c._id, c);
      for (const p of players) {
        const c = byUser.get(p.username);
        p.giveawayClaimsCount = c ? c.count : 0;
        p.giveawayTotalClaimed = c ? c.total : 0;
        p.giveawayLastClaimAt = c ? c.lastClaimAt : null;
      }
    }

    res.json({ players, total: players.length });
  } catch (error) {
    logger.error(`/api/admin/stats/players: ${error.message}`);
    res.status(500).json({ error: 'Error del servidor' });
  }
});

// ============================================
// SEGMENTACION DE JUGADORES — PANEL "TOP JUGADORES"
// ============================================
// Endpoint que cruza PlayerStats + DailyPlayerStats + UserLineLookup + User
// para devolver listados por segmento con todo lo que hace falta para
// decidir accion (push, WA por linea del equipo, bono).
//
// Segmentos custom (umbrales pedidos por owner):
//   CALIENTE   : 10+ cargas en los ultimos 7 dias
//   EN_RIESGO  : sin carga hace 5-9 dias
//   PERDIDO    : sin carga hace 10-19 dias
//   INACTIVO   : sin carga hace 20+ dias O nunca cargo
//
// Periodo:
//   w1/w2/w3/w4 = semanas calendario del mes actual (1-7, 8-14, 15-21, 22-fin)
//   month       = mes actual completo
//
// Filtros: team (lineTeamName), hasApp (yes/no/all), tier (VIP..BRONCE), limit.
// ============================================
const _SEGMENT_THRESHOLDS = {
  caliente: { last7dDepositCountMin: 10 },
  en_riesgo: { daysSinceMin: 5, daysSinceMax: 9 },
  perdido: { daysSinceMin: 10, daysSinceMax: 19 },
  inactivo: { daysSinceMin: 20 } // o null lastRealDepositDate
};

function _computeCustomSegment(daysSince, depositCountLast7d) {
  // CALIENTE prima sobre el resto: aunque esten ACTIVOS, los super
  // frecuentes los flaggeamos para que el admin los vea aparte.
  if ((depositCountLast7d || 0) >= _SEGMENT_THRESHOLDS.caliente.last7dDepositCountMin) {
    return 'CALIENTE';
  }
  if (daysSince == null) return 'INACTIVO';
  if (daysSince >= _SEGMENT_THRESHOLDS.inactivo.daysSinceMin) return 'INACTIVO';
  if (daysSince >= _SEGMENT_THRESHOLDS.perdido.daysSinceMin) return 'PERDIDO';
  if (daysSince >= _SEGMENT_THRESHOLDS.en_riesgo.daysSinceMin) return 'EN_RIESGO';
  return 'ACTIVO';
}

// Calcula los limites del rango (inicio, fin) en UTC para un periodo dado
// del mes calendario actual ARG. Devuelve { from: Date, to: Date, label }.
function _computePeriodRange(period) {
  const argNow = _argZonedNow();
  const y = argNow.getUTCFullYear();
  const m = argNow.getUTCMonth();
  // monthStart en ARG (00:00 ARG = 03:00 UTC)
  const monthStartArg = new Date(Date.UTC(y, m, 1));
  // monthEnd: dia 1 del mes siguiente, 00:00 ARG
  const monthEndArg = new Date(Date.UTC(y, m + 1, 1));

  let fromArg, toArg, label;
  if (period === 'w1') {
    fromArg = new Date(Date.UTC(y, m, 1));
    toArg = new Date(Date.UTC(y, m, 8));
    label = 'Semana 1 (1-7)';
  } else if (period === 'w2') {
    fromArg = new Date(Date.UTC(y, m, 8));
    toArg = new Date(Date.UTC(y, m, 15));
    label = 'Semana 2 (8-14)';
  } else if (period === 'w3') {
    fromArg = new Date(Date.UTC(y, m, 15));
    toArg = new Date(Date.UTC(y, m, 22));
    label = 'Semana 3 (15-21)';
  } else if (period === 'w4') {
    fromArg = new Date(Date.UTC(y, m, 22));
    toArg = monthEndArg;
    label = 'Semana 4 (22-fin)';
  } else {
    fromArg = monthStartArg;
    toArg = monthEndArg;
    label = 'Mes completo';
  }
  // Pasar de "midnight ARG" a UTC real (sumar 3h).
  const from = new Date(fromArg.getTime() + 3 * 3600 * 1000);
  const to = new Date(toArg.getTime() + 3 * 3600 * 1000);
  return { from, to, label, period };
}

// GET /api/admin/players/segments — listado de jugadores por segmento custom.
//
// Query:
//   period   : w1 | w2 | w3 | w4 | month   (default month)
//   segment  : caliente | en_riesgo | perdido | inactivo | all (default all)
//   team     : team name (lineTeamName) — exact match
//   hasApp   : yes | no | all (default all) — yes = tiene fcmToken (app instalada y push activos)
//   tier     : VIP | ORO | PLATA | BRONCE | NUEVO | SIN_DATOS
//   limit    : max rows (default 500, max 2000)
//
// Devuelve: { range, counts: {caliente, en_riesgo, perdido, inactivo}, players[] }
app.get('/api/admin/players/segments', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const period = ['w1', 'w2', 'w3', 'w4', 'month'].includes(req.query.period) ? req.query.period : 'month';
    const requestedSegment = String(req.query.segment || 'all').toLowerCase();
    const teamFilter = req.query.team ? String(req.query.team).trim() : null;
    const hasApp = ['yes', 'no'].includes(req.query.hasApp) ? req.query.hasApp : 'all';
    const tierFilter = ['VIP', 'ORO', 'PLATA', 'BRONCE', 'NUEVO', 'SIN_DATOS'].includes(req.query.tier) ? req.query.tier : null;
    const limit = Math.min(parseInt(req.query.limit, 10) || 500, 2000);

    const range = _computePeriodRange(period);
    const last7dStart = new Date(Date.now() - 7 * 24 * 3600 * 1000);

    // 1) Base: PlayerStats con filtro de tier.
    const psQuery = {};
    if (tierFilter) psQuery.tier = tierFilter;
    const allStats = await PlayerStats.find(psQuery)
      .sort({ realDeposits30d: -1 })
      .limit(2000)
      .lean();

    if (allStats.length === 0) {
      return res.json({
        range,
        counts: { CALIENTE: 0, EN_RIESGO: 0, PERDIDO: 0, INACTIVO: 0, ACTIVO: 0, total: 0 },
        players: []
      });
    }

    const usernames = allStats.map(p => p.username).filter(Boolean);

    // 2) Cargas en periodo seleccionado (DailyPlayerStats agg)
    const periodAgg = await DailyPlayerStats.aggregate([
      { $match: { username: { $in: usernames }, dateUtc: { $gte: range.from, $lt: range.to } } },
      { $group: {
        _id: '$username',
        chargesInPeriod: { $sum: '$depositCount' },
        depositsInPeriod: { $sum: '$depositSum' }
      } }
    ]);
    const periodMap = {};
    for (const a of periodAgg) periodMap[a._id] = a;

    // 3) Cargas en los ultimos 7 dias (para detectar CALIENTE)
    const last7Agg = await DailyPlayerStats.aggregate([
      { $match: { username: { $in: usernames }, dateUtc: { $gte: last7dStart } } },
      { $group: {
        _id: '$username',
        chargesLast7d: { $sum: '$depositCount' },
        depositsLast7d: { $sum: '$depositSum' }
      } }
    ]);
    const last7Map = {};
    for (const a of last7Agg) last7Map[a._id] = a;

    // 4) Equipos (UserLineLookup)
    const norms = usernames.map(u => String(u).toLowerCase().replace(/[^a-z0-9]/g, ''));
    const lineupRows = await UserLineLookup.find({ usernameNorm: { $in: norms } })
      .select('usernameNorm linePhone lineTeamName')
      .lean();
    const teamByNorm = {};
    for (const r of lineupRows) teamByNorm[r.usernameNorm] = r;

    // 5) App + telefono + nombre real (User) + preferencia de encuesta
    const userRows = await User.find(
      { username: { $in: usernames } },
      { username: 1, fcmToken: 1, fcmTokens: 1, phone: 1, whatsapp: 1, name: 1, createdAt: 1, notifPreference: 1, notifPreferenceAt: 1, _id: 0 }
    ).lean();
    const userByName = {};
    for (const u of userRows) {
      userByName[String(u.username).toLowerCase()] = u;
    }

    // 6) Bonus claims agregados (welcome/giveaway) en el periodo seleccionado
    // — para el ROI por bono.
    const giveawayAgg = await MoneyGiveawayClaim.aggregate([
      { $match: { username: { $in: usernames }, status: 'completed' } },
      { $group: {
        _id: '$username',
        count: { $sum: 1 },
        totalARS: { $sum: '$amount' },
        lastClaimAt: { $max: '$claimedAt' }
      } }
    ]);
    const givByName = {};
    for (const g of giveawayAgg) givByName[g._id] = g;

    // 7) Computar segmento + componer
    const counts = { CALIENTE: 0, EN_RIESGO: 0, PERDIDO: 0, INACTIVO: 0, ACTIVO: 0 };
    const out = [];
    for (const ps of allStats) {
      const uname = ps.username;
      const ulow = String(uname).toLowerCase();
      const norm = ulow.replace(/[^a-z0-9]/g, '');
      const usr = userByName[ulow] || null;
      const team = teamByNorm[norm] || null;
      const last7 = last7Map[uname] || { chargesLast7d: 0, depositsLast7d: 0 };
      const inP = periodMap[uname] || { chargesInPeriod: 0, depositsInPeriod: 0 };
      const giv = givByName[uname] || null;

      const daysSince = ps.lastRealDepositDate
        ? Math.floor((Date.now() - new Date(ps.lastRealDepositDate).getTime()) / (24 * 3600 * 1000))
        : null;

      const segment = _computeCustomSegment(daysSince, last7.chargesLast7d);
      counts[segment] = (counts[segment] || 0) + 1;

      // Filtros segmento + team + app
      if (requestedSegment !== 'all' && requestedSegment.toUpperCase() !== segment) continue;
      if (teamFilter && (!team || team.lineTeamName !== teamFilter)) continue;

      const hasFcm = !!(usr && (usr.fcmToken || (Array.isArray(usr.fcmTokens) && usr.fcmTokens.length > 0)));
      if (hasApp === 'yes' && !hasFcm) continue;
      if (hasApp === 'no' && hasFcm) continue;

      out.push({
        username: uname,
        userId: ps.userId,
        name: usr ? usr.name : null,
        phone: usr ? (usr.phone || usr.whatsapp || null) : null,
        accountCreatedAt: usr ? usr.createdAt : null,

        tier: ps.tier,
        activityStatus: ps.activityStatus,
        segment,

        hasApp: hasFcm,
        lastSeenApp: ps.lastSeenApp,

        team: team ? team.lineTeamName : null,
        linePhone: team ? team.linePhone : null,

        lastRealDepositDate: ps.lastRealDepositDate,
        daysSinceLastDeposit: daysSince,

        // Periodo seleccionado
        chargesInPeriod: inP.chargesInPeriod || 0,
        depositsInPeriod: inP.depositsInPeriod || 0,

        // Ult 7 dias (para CALIENTE)
        chargesLast7d: last7.chargesLast7d || 0,
        depositsLast7d: last7.depositsLast7d || 0,

        // 30 dias rolling (cache PlayerStats)
        realDeposits30d: ps.realDeposits30d || 0,
        realChargesCount30d: ps.realChargesCount30d || 0,
        bonusGiven30d: ps.bonusGiven30d || 0,
        netToHouse30d: ps.netToHouse30d || 0,
        isOpportunist: !!ps.isOpportunist,

        // ROI por bono
        bonusClaimsCount: giv ? giv.count : 0,
        bonusClaimsTotal: giv ? giv.totalARS : 0,
        lastBonusClaimAt: giv ? giv.lastClaimAt : null,
        roiPerBonus: (giv && giv.totalARS > 0) ? (ps.realDeposits30d || 0) / giv.totalARS : null,

        recoveryAttemptsLifetime: ps.recoveryAttemptsLifetime || 0,
        lastRecoveryPushAt: ps.lastRecoveryPushAt,

        // Encuesta de notifs (Fase 1)
        notifPreference: (userByName[ulow] && userByName[ulow].notifPreference) || null,
        notifPreferenceAt: (userByName[ulow] && userByName[ulow].notifPreferenceAt) || null
      });
    }

    out.sort((a, b) => (b.realDeposits30d || 0) - (a.realDeposits30d || 0));
    const sliced = out.slice(0, limit);

    // Listas auxiliares para el cliente
    const teamSet = new Set();
    for (const r of lineupRows) if (r.lineTeamName) teamSet.add(r.lineTeamName);
    const teamsAvailable = [...teamSet].sort();

    res.json({
      range,
      counts: {
        ...counts,
        total: allStats.length,
        shown: sliced.length
      },
      filters: { period, segment: requestedSegment, team: teamFilter, hasApp, tier: tierFilter, limit },
      teamsAvailable,
      players: sliced
    });
  } catch (err) {
    logger.error(`/api/admin/players/segments: ${err.message}`);
    res.status(500).json({ error: 'Error obteniendo segmentos' });
  }
});

// POST /api/admin/players/segments/notify — manda push masivo a todos los
// players de un segmento (filtrado por team/hasApp). Solo afecta a los con
// app instalada (fcmToken). Si hasApp=no, se ignora (sin destino para push).
app.post('/api/admin/players/segments/notify', authMiddleware, superAdminMiddleware, bulkLaunchLimiter, async (req, res) => {
  try {
    const body = req.body || {};
    const segment = String(body.segment || '').toUpperCase();
    const team = body.team ? String(body.team).trim() : null;
    const tier = body.tier ? String(body.tier) : null;
    const title = String(body.title || '').slice(0, 80).trim();
    const text = String(body.body || '').slice(0, 240).trim();
    if (!title || !text) return res.status(400).json({ error: 'Falta title o body' });
    if (!['CALIENTE', 'EN_RIESGO', 'PERDIDO', 'INACTIVO', 'ACTIVO'].includes(segment)) {
      return res.status(400).json({ error: 'segment invalido' });
    }

    // Reutilizamos /segments para filtrar (con hasApp=yes obligatorio).
    const psQuery = {};
    if (tier && ['VIP', 'ORO', 'PLATA', 'BRONCE', 'NUEVO', 'SIN_DATOS'].includes(tier)) psQuery.tier = tier;
    // Sort por realDeposits30d desc para que si el limit corta, queden los
    // VIPs (no sea aleatorio por orden de insercion).
    const allStats = await PlayerStats.find(psQuery).sort({ realDeposits30d: -1 }).limit(2000).lean();
    const usernames = allStats.map(p => p.username);

    const last7dStart = new Date(Date.now() - 7 * 24 * 3600 * 1000);
    const last7Agg = await DailyPlayerStats.aggregate([
      { $match: { username: { $in: usernames }, dateUtc: { $gte: last7dStart } } },
      { $group: { _id: '$username', chargesLast7d: { $sum: '$depositCount' } } }
    ]);
    const last7Map = {};
    for (const a of last7Agg) last7Map[a._id] = a.chargesLast7d;

    const norms = usernames.map(u => String(u).toLowerCase().replace(/[^a-z0-9]/g, ''));
    const lineupRows = await UserLineLookup.find({ usernameNorm: { $in: norms } })
      .select('usernameNorm lineTeamName').lean();
    const teamByNorm = {};
    for (const r of lineupRows) teamByNorm[r.usernameNorm] = r.lineTeamName;

    const targets = [];
    for (const ps of allStats) {
      const daysSince = ps.lastRealDepositDate
        ? Math.floor((Date.now() - new Date(ps.lastRealDepositDate).getTime()) / (24 * 3600 * 1000))
        : null;
      const seg = _computeCustomSegment(daysSince, last7Map[ps.username] || 0);
      if (seg !== segment) continue;
      if (team) {
        const norm = String(ps.username).toLowerCase().replace(/[^a-z0-9]/g, '');
        if (teamByNorm[norm] !== team) continue;
      }
      targets.push(ps.username);
    }

    if (targets.length === 0) {
      return res.json({ success: true, eligible: 0, sent: 0, message: 'No hay destinatarios con app en ese segmento.' });
    }

    const result = await sendNotificationToAllUsers(
      User,
      title,
      text,
      { source: 'segments-bulk', segment, team: team || '' },
      { username: { $in: targets } }
    );

    res.json({
      success: true,
      eligible: targets.length,
      sent: (result && result.successCount) || 0,
      failed: (result && result.failureCount) || 0,
      segment,
      team: team || null
    });
  } catch (err) {
    logger.error(`/api/admin/players/segments/notify: ${err.message}`);
    res.status(500).json({ error: 'Error enviando notificación segmentada' });
  }
});

// ============================================
// CALENDARIO SEMANAL — planificacion + lanzamiento + ROI
// ============================================
//
// Endpoints:
//   GET  /api/admin/calendar/week?weekKey=YYYY-Www  -> plan completo (auto-crea con refund pinned)
//   POST /api/admin/calendar/week/:weekKey/strategy -> agregar strategy al plan
//   PUT  /api/admin/calendar/strategy/:weekKey/:id  -> editar strategy
//   DELETE /api/admin/calendar/strategy/:weekKey/:id-> borrar (no permitido si lanzada)
//   POST /api/admin/calendar/strategy/:weekKey/:id/launch -> disparar el push
//   POST /api/admin/calendar/strategy/:weekKey/:id/refresh-performance -> recalcular ROI
//   GET  /api/admin/calendar/history -> lista de semanas pasadas
//   POST /api/admin/calendar/strategy-suggestions -> sugiere nombres unicos basado en historial
// ============================================

const _DAY_LABELS = ['Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado', 'Domingo'];

function _weekKeyFromDate(d) {
  // Pasar a ARG para alinear con resto del codigo.
  const drawArg = new Date(d.getTime() - 3 * 3600 * 1000);
  return _isoWeekKey(drawArg);
}

function _weekStartFromKey(weekKey) {
  // weekKey "YYYY-Www" -> Lunes 00:00 ARG (= 03:00 UTC).
  const m = /^(\d{4})-W(\d{2})$/.exec(weekKey);
  if (!m) return null;
  const year = parseInt(m[1], 10);
  const week = parseInt(m[2], 10);
  // ISO week: lunes de la primera semana del año (la que contiene el 4 de enero).
  const jan4 = new Date(Date.UTC(year, 0, 4));
  const jan4Dow = jan4.getUTCDay() || 7;
  const week1Mon = new Date(Date.UTC(year, 0, 4 + 1 - jan4Dow));
  const monday = new Date(week1Mon.getTime() + (week - 1) * 7 * 24 * 3600 * 1000);
  // Pasar a UTC real (sumar 3h porque queremos 00:00 ARG = 03:00 UTC)
  return new Date(monday.getTime() + 3 * 3600 * 1000);
}

// Auto-fija una strategy "refund" en CADA dia de la semana si todavia no
// existe una. Satisface "fijo siempre el msj del reembolso" del owner:
// la audiencia es la UNION de quienes tienen reembolso pendiente
// (daily/weekly/monthly) HOY — el cron de refundReminderService ya sabe
// quienes son. Copy pre-configurado pero editable.
async function _ensureRefundPinnedDaily(plan) {
  let added = 0;
  const weekKey = plan.weekKey;
  // El "lunes" es el primer dia de la semana (dayIndex=0). El sabado=5,
  // domingo=6. Pre-llenamos copy especifico segun el dia de la semana.
  // Si dos GETs concurrentes invocan esto, el `findOneAndUpdate` con
  // `$ne: true` en el array embebido garantiza que solo UNO logre el push
  // del pinned por dia (el otro recibe null y lo skipea).
  for (let i = 0; i < 7; i++) {
    let day = plan.days.find(d => d.dayIndex === i);
    if (!day) {
      day = { dayIndex: i, label: _DAY_LABELS[i], strategies: [] };
      plan.days.push(day);
    }
    const hasRefund = (day.strategies || []).some(s => s.type === 'refund' && s.isPinned);
    if (!hasRefund) {
      // Copy pre-terminado pensado para HOY:
      //   - Lunes: hablamos de reembolso semanal (cierre del sabado/domingo)
      //   - Dia 1: hablamos de reembolso mensual
      //   - Resto: reembolso diario (perdida del dia anterior)
      // El admin puede editar despues.
      let title, body;
      if (i === 0) {
        // Lunes
        title = '💰 Tu reembolso semanal te espera';
        body = 'Cerramos la semana — si jugaste y no ganaste, tu reembolso ya está disponible. Entrá a la app y reclamalo antes de que se pierda.';
      } else {
        // Resto de la semana: reembolso diario + cualquier semanal/mensual pendiente
        title = '💰 Tenés reembolso disponible HOY';
        body = 'No te lo lleves a perder. Pasá por la app, tocá Reclamar y te devolvemos lo que te corresponde.';
      }
      day.strategies.push({
        id: uuidv4(),
        dayIndex: i,
        order: 0,
        type: 'refund',
        title,
        body,
        bonusPercent: 0,
        targetSegment: 'all',
        targetTier: null,
        targetTeams: [],
        hasAppOnly: true,
        refundTypes: ['daily', 'weekly', 'monthly'],
        status: 'pendiente',
        isPinned: true,
        notes: 'Difusion pre-configurada y FIJA. Audiencia automatica: usuarios con reembolso pendiente (diario/semanal/mensual) HOY, con app instalada y notifs activas, sin clamar todavia el periodo actual. Tocá "Ver destinatarios" para previsualizar exactamente a quien le llega antes de lanzar. El copy es editable, los filtros tambien.'
      });
      added++;
    }
  }
  // Sort days
  plan.days.sort((a, b) => a.dayIndex - b.dayIndex);
  return added;
}

// Recalcula el summary agregado del plan.
function _recalcPlanSummary(plan) {
  let total = 0, launched = 0, pending = 0;
  let totalSent = 0, totalResp = 0, newDeposits = 0, bonusGiven = 0;
  let positives = 0, negatives = 0, neutrals = 0;
  for (const day of plan.days) {
    for (const s of (day.strategies || [])) {
      total++;
      if (s.status === 'lanzado' || s.status === 'completado') {
        launched++;
        totalSent += s.sentCount || 0;
        if (s.performance) {
          totalResp += s.performance.respondersCount || 0;
          newDeposits += s.performance.newDepositsAmountARS || 0;
          bonusGiven += s.performance.bonusGivenARS || 0;
          if (s.performance.sentiment === 'positivo') positives++;
          else if (s.performance.sentiment === 'negativo') negatives++;
          else if (s.performance.sentiment === 'neutro') neutrals++;
        }
      } else if (s.status === 'pendiente') {
        pending++;
      }
    }
  }
  plan.summary = {
    totalStrategies: total,
    launchedCount: launched,
    pendingCount: pending,
    totalSent,
    totalResponders: totalResp,
    totalNewDeposits: newDeposits,
    totalBonusGiven: bonusGiven,
    aggregateRoi: bonusGiven > 0 ? (newDeposits / bonusGiven) : 0,
    sentiment: positives > negatives + neutrals ? 'positivo' : (negatives > positives ? 'negativo' : (positives + neutrals + negatives > 0 ? 'neutro' : 'sin_datos'))
  };
}

// Resuelve audiencia para una strategy. Si type='refund', delegamos al
// refundReminderService que ya sabe quien tiene reembolso disponible
// para reclamar HOY (cruzando DailyPlayerStats con netLoss > 0 y
// RefundClaim ausente para el periodKey actual). Soporta union de los
// 3 tipos (daily+weekly+monthly) para que un push diario alcance a
// cualquiera con algo pendiente.
//
// Para tipos push/bonus, segmentamos por segmento custom + tier + equipo.
//
// Devuelve { usernames: [...], breakdown: {...debugInfo} } para que el
// preview muestre desgloses utiles al admin.
async function _resolveStrategyAudience(strategy) {
  // ====== refund: delega al service ======
  if (strategy.type === 'refund') {
    const types = (strategy.refundTypes && strategy.refundTypes.length > 0)
      ? strategy.refundTypes
      : ['daily', 'weekly', 'monthly'];
    const teamFilter = (strategy.targetTeams && strategy.targetTeams.length === 1)
      ? strategy.targetTeams[0]
      : null; // si hay multiples, filtramos despues
    const teamsAllowed = (strategy.targetTeams && strategy.targetTeams.length > 0)
      ? new Set(strategy.targetTeams)
      : null;

    const breakdown = { byType: {}, totalUnique: 0 };
    const allUsers = new Map(); // lower(username) -> { username, types: [], lineTeamName, potentialAmount }

    for (const t of types) {
      try {
        const r = await refundReminderService.computeRefundReminderAudience({
          type: t,
          teamFilter, // si hay UN solo team, podemos filtrar a nivel service
          models: _strategyModels,
          weeklyService: weeklyStrategyService,
          logger
        });
        breakdown.byType[t] = {
          eligible: r.totals.eligible,
          alreadyClaimed: r.totals.alreadyClaimed,
          withoutChannel: r.totals.withoutChannel,
          finalAudience: r.totals.finalAudience,
          periodKey: r.periodKey,
          windowFrom: r.window && r.window.start,
          windowTo: r.window && r.window.end
        };
        for (const u of (r.perUser || [])) {
          // Multi-team filter (si hay >= 2 teams, lo aplicamos aca).
          if (teamsAllowed && teamsAllowed.size > 0 && !teamsAllowed.has(u.lineTeamName)) continue;
          const k = String(u.username).toLowerCase();
          if (!allUsers.has(k)) {
            allUsers.set(k, {
              username: u.username,
              types: [t],
              lineTeamName: u.lineTeamName,
              potentialAmount: u.potentialAmount || 0
            });
          } else {
            const e = allUsers.get(k);
            if (!e.types.includes(t)) e.types.push(t);
            // Sumar el potential de todos los tipos.
            e.potentialAmount = (e.potentialAmount || 0) + (u.potentialAmount || 0);
          }
        }
      } catch (e) {
        logger.warn(`[calendar refund-audience] type=${t} fail: ${e.message}`);
        breakdown.byType[t] = { error: e.message };
      }
    }

    const list = [...allUsers.values()];
    breakdown.totalUnique = list.length;

    return {
      usernames: list.map(u => u.username),
      breakdown,
      details: list.sort((a, b) => (b.potentialAmount || 0) - (a.potentialAmount || 0))
    };
  }

  // ====== push/bonus: segmento custom + tier + equipo ======
  const psQuery = {};
  if (strategy.targetTier) psQuery.tier = strategy.targetTier;
  const allStats = await PlayerStats.find(psQuery).sort({ realDeposits30d: -1 }).limit(5000).lean();
  if (allStats.length === 0) return { usernames: [], breakdown: { totalUnique: 0 }, details: [] };

  const usernames = allStats.map(p => p.username);

  const last7dStart = new Date(Date.now() - 7 * 24 * 3600 * 1000);
  const last7Agg = await DailyPlayerStats.aggregate([
    { $match: { username: { $in: usernames }, dateUtc: { $gte: last7dStart } } },
    { $group: { _id: '$username', chargesLast7d: { $sum: '$depositCount' } } }
  ]);
  const last7Map = {};
  for (const a of last7Agg) last7Map[a._id] = a.chargesLast7d;

  const norms = usernames.map(u => String(u).toLowerCase().replace(/[^a-z0-9]/g, ''));
  const lineupRows = await UserLineLookup.find({ usernameNorm: { $in: norms } })
    .select('usernameNorm lineTeamName').lean();
  const teamByNorm = {};
  for (const r of lineupRows) teamByNorm[r.usernameNorm] = r.lineTeamName;

  let usersWithApp = new Set();
  if (strategy.hasAppOnly) {
    const userRows = await User.find(
      { username: { $in: usernames }, $or: [{ fcmToken: { $ne: null } }, { 'fcmTokens.0': { $exists: true } }] },
      { username: 1, _id: 0 }
    ).lean();
    usersWithApp = new Set(userRows.map(u => String(u.username).toLowerCase()));
  }

  const segReq = String(strategy.targetSegment || 'all').toUpperCase();
  const teamSet = new Set(strategy.targetTeams || []);
  const useTeamFilter = teamSet.size > 0;

  const targets = [];
  const details = [];
  for (const ps of allStats) {
    const ulow = String(ps.username).toLowerCase();
    const norm = ulow.replace(/[^a-z0-9]/g, '');
    if (strategy.hasAppOnly && !usersWithApp.has(ulow)) continue;

    const daysSince = ps.lastRealDepositDate
      ? Math.floor((Date.now() - new Date(ps.lastRealDepositDate).getTime()) / (24 * 3600 * 1000))
      : null;
    const seg = _computeCustomSegment(daysSince, last7Map[ps.username] || 0);
    if (segReq !== 'ALL' && seg !== segReq) continue;

    const tname = teamByNorm[norm] || null;
    if (useTeamFilter) {
      if (!tname || !teamSet.has(tname)) continue;
    }

    targets.push(ps.username);
    details.push({
      username: ps.username,
      segment: seg,
      tier: ps.tier,
      lineTeamName: tname,
      daysSinceLastDeposit: daysSince
    });
  }
  return { usernames: targets, breakdown: { totalUnique: targets.length }, details };
}

app.get('/api/admin/calendar/week', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const weekKey = req.query.weekKey || _isoWeekKey(_argZonedNow());
    const weekStart = _weekStartFromKey(weekKey);
    if (!weekStart) return res.status(400).json({ error: 'weekKey invalido (formato YYYY-Www)' });

    // Upsert atomico para evitar race entre dos GETs concurrentes que
    // ambos creaban el plan + 7 pinned. setOnInsert solo se aplica si
    // el doc no existia.
    await WeeklyCalendarPlan.findOneAndUpdate(
      { weekKey },
      {
        $setOnInsert: {
          weekKey,
          weekStartDate: weekStart,
          status: 'draft',
          days: _DAY_LABELS.map((l, i) => ({ dayIndex: i, label: l, strategies: [] })),
          summary: {},
          createdBy: req.user.username || 'admin'
        }
      },
      { upsert: true, new: true }
    );
    let plan = await WeeklyCalendarPlan.findOne({ weekKey });
    await _ensureRefundPinnedDaily(plan);
    _recalcPlanSummary(plan);
    await plan.save();

    res.json({ plan: plan.toObject() });
  } catch (err) {
    logger.error(`/api/admin/calendar/week: ${err.message}`);
    res.status(500).json({ error: 'Error cargando plan semanal' });
  }
});

app.post('/api/admin/calendar/week/:weekKey/strategy', authMiddleware, superAdminMiddleware, async (req, res) => {
  try {
    const weekKey = req.params.weekKey;
    const weekStart = _weekStartFromKey(weekKey);
    if (!weekStart) return res.status(400).json({ error: 'weekKey invalido' });

    const body = req.body || {};
    const dayIndex = parseInt(body.dayIndex, 10);
    if (!Number.isFinite(dayIndex) || dayIndex < 0 || dayIndex > 6) {
      return res.status(400).json({ error: 'dayIndex invalido (0..6)' });
    }
    const bonusPercent = Math.max(0, Math.min(100, parseInt(body.bonusPercent, 10) || 0));
    if (body.bonusPercent != null && body.bonusPercent !== '' && (bonusPercent < 50 && bonusPercent > 0)) {
      return res.status(400).json({ error: 'El bono mínimo es 50%' });
    }

    let plan = await WeeklyCalendarPlan.findOne({ weekKey });
    if (!plan) {
      plan = new WeeklyCalendarPlan({
        weekKey,
        weekStartDate: weekStart,
        days: _DAY_LABELS.map((l, i) => ({ dayIndex: i, label: l, strategies: [] })),
        createdBy: req.user.username || 'admin'
      });
      await _ensureRefundPinnedDaily(plan);
    }

    let day = plan.days.find(d => d.dayIndex === dayIndex);
    if (!day) {
      day = { dayIndex, label: _DAY_LABELS[dayIndex], strategies: [] };
      plan.days.push(day);
    }

    const validRefundTypes = ['daily', 'weekly', 'monthly'];
    const refundTypes = Array.isArray(body.refundTypes)
      ? body.refundTypes.filter(t => validRefundTypes.includes(t))
      : validRefundTypes.slice();
    const newStrat = {
      id: uuidv4(),
      dayIndex,
      order: (day.strategies || []).length,
      type: ['push', 'refund', 'bonus'].includes(body.type) ? body.type : 'push',
      title: String(body.title || '').slice(0, 100),
      body: String(body.body || '').slice(0, 500),
      bonusPercent,
      bonusFlatARS: Math.max(0, parseInt(body.bonusFlatARS, 10) || 0),
      targetSegment: String(body.targetSegment || 'all').toLowerCase(),
      targetTier: ['VIP', 'ORO', 'PLATA', 'BRONCE', 'NUEVO'].includes(body.targetTier) ? body.targetTier : null,
      targetTeams: Array.isArray(body.targetTeams) ? body.targetTeams.map(String).slice(0, 50) : [],
      hasAppOnly: body.hasAppOnly !== false,
      refundTypes: refundTypes.length > 0 ? refundTypes : validRefundTypes,
      status: 'pendiente',
      isPinned: false,
      notes: String(body.notes || '').slice(0, 500)
    };
    if (!newStrat.title || !newStrat.body) {
      return res.status(400).json({ error: 'Faltan title y body' });
    }

    // Cap defensivo: como la lista de strategies vive embebida en el doc
    // del plan (ver schema), dejarla crecer sin limite haria que el doc
    // se acerque al limite de 16MB de Mongo (sobre todo con
    // targetUsernames de 5000 cada uno tras el lanzamiento). Limites
    // generosos pero firmes — el flujo real espera pocas strategies/dia.
    const STRATS_PER_DAY_MAX = 12;
    const STRATS_PER_PLAN_MAX = 60;
    if ((day.strategies || []).length >= STRATS_PER_DAY_MAX) {
      return res.status(400).json({ error: `Máximo ${STRATS_PER_DAY_MAX} difusiones por día. Eliminá alguna pendiente para agregar otra.` });
    }
    const totalStrats = plan.days.reduce((acc, d) => acc + (d.strategies || []).length, 0);
    if (totalStrats >= STRATS_PER_PLAN_MAX) {
      return res.status(400).json({ error: `Máximo ${STRATS_PER_PLAN_MAX} difusiones por semana.` });
    }

    day.strategies.push(newStrat);
    plan.markModified('days');
    _recalcPlanSummary(plan);
    await plan.save();

    res.json({ success: true, strategy: newStrat, plan: plan.toObject() });
  } catch (err) {
    logger.error(`/api/admin/calendar/strategy add: ${err.message}`);
    res.status(500).json({ error: 'Error guardando difusión' });
  }
});

app.put('/api/admin/calendar/strategy/:weekKey/:id', authMiddleware, superAdminMiddleware, async (req, res) => {
  try {
    const { weekKey, id } = req.params;
    const plan = await WeeklyCalendarPlan.findOne({ weekKey });
    if (!plan) return res.status(404).json({ error: 'Plan no encontrado' });
    let found = null;
    for (const d of plan.days) {
      for (const s of d.strategies) if (s.id === id) found = s;
    }
    if (!found) return res.status(404).json({ error: 'Strategy no encontrada' });
    if (found.status === 'lanzando' || found.status === 'lanzado' || found.status === 'completado') {
      return res.status(400).json({ error: 'No se puede editar una strategy ya lanzada' });
    }
    const b = req.body || {};
    if (b.title != null) found.title = String(b.title).slice(0, 100);
    if (b.body != null) found.body = String(b.body).slice(0, 500);
    if (b.bonusPercent != null) {
      const bp = Math.max(0, Math.min(100, parseInt(b.bonusPercent, 10) || 0));
      if (bp > 0 && bp < 50) return res.status(400).json({ error: 'Bono mínimo 50%' });
      found.bonusPercent = bp;
    }
    if (b.bonusFlatARS != null) found.bonusFlatARS = Math.max(0, parseInt(b.bonusFlatARS, 10) || 0);
    if (b.targetSegment != null) found.targetSegment = String(b.targetSegment).toLowerCase();
    if (b.targetTier !== undefined) found.targetTier = ['VIP', 'ORO', 'PLATA', 'BRONCE', 'NUEVO'].includes(b.targetTier) ? b.targetTier : null;
    if (Array.isArray(b.targetTeams)) found.targetTeams = b.targetTeams.map(String).slice(0, 50);
    if (b.hasAppOnly != null) found.hasAppOnly = !!b.hasAppOnly;
    if (Array.isArray(b.refundTypes)) {
      const valid = ['daily', 'weekly', 'monthly'];
      const ts = b.refundTypes.filter(t => valid.includes(t));
      if (found.type === 'refund' && ts.length === 0) {
        return res.status(400).json({ error: 'Para una difusión de reembolso necesitás al menos un tipo (daily/weekly/monthly).' });
      }
      found.refundTypes = ts;
    }
    if (b.notes != null) found.notes = String(b.notes).slice(0, 500);
    plan.markModified('days');
    _recalcPlanSummary(plan);
    await plan.save();
    res.json({ success: true, strategy: found });
  } catch (err) {
    logger.error(`/api/admin/calendar/strategy edit: ${err.message}`);
    res.status(500).json({ error: 'Error editando difusión' });
  }
});

// POST /api/admin/calendar/quick-launch — lanza una difusion ad-hoc
// (sin necesidad de guardarla en el plan). Resuelve audiencia con la
// misma logica que el calendar y envia push masivo. Util para presets
// como "50% bono a perdedores chicos" desde la pestaña Lanzar ahora.
//
// Body: title, body, type, bonusPercent, targetSegment, tiers[],
//       targetTeams[], hasAppOnly, refundTypes[]
//
// Si tiers tiene mas de 1 entrada, hacemos 1 llamada por tier y unimos
// los resultados (PlayerStats query es por tier exacto). Asi
// "perdedores chicos" puede pegarle a BRONCE+PLATA en una sola accion.
app.post('/api/admin/calendar/quick-launch', authMiddleware, superAdminMiddleware, bulkLaunchLimiter, async (req, res) => {
  try {
    const b = req.body || {};
    const title = String(b.title || '').slice(0, 100).trim();
    const body = String(b.body || '').slice(0, 500).trim();
    if (!title || !body) return res.status(400).json({ error: 'Falta title o body' });
    const bonusPercent = Math.max(0, Math.min(100, parseInt(b.bonusPercent, 10) || 0));
    if (bonusPercent > 0 && bonusPercent < 50) return res.status(400).json({ error: 'Bono mínimo 50%' });
    const type = ['push', 'refund', 'bonus'].includes(b.type) ? b.type : 'push';
    const tiers = Array.isArray(b.tiers) ? b.tiers.filter(t => ['VIP', 'ORO', 'PLATA', 'BRONCE', 'NUEVO'].includes(t)) : [];

    // Construimos una "pseudo-strategy" para reutilizar _resolveStrategyAudience.
    const baseStrategy = {
      type,
      title,
      body,
      bonusPercent,
      bonusFlatARS: 0,
      targetSegment: String(b.targetSegment || 'all').toLowerCase(),
      targetTier: null,
      targetTeams: Array.isArray(b.targetTeams) ? b.targetTeams.map(String) : [],
      hasAppOnly: b.hasAppOnly !== false,
      refundTypes: Array.isArray(b.refundTypes) && b.refundTypes.length > 0
        ? b.refundTypes.filter(t => ['daily','weekly','monthly'].includes(t))
        : ['daily','weekly','monthly']
    };

    // Si hay tiers multiples, iteramos y unimos.
    let allTargets = new Set();
    let unionDetails = [];
    if (tiers.length === 0) {
      const aud = await _resolveStrategyAudience(baseStrategy);
      for (const u of (aud.usernames || [])) allTargets.add(u);
      unionDetails = aud.details || [];
    } else {
      for (const t of tiers) {
        const aud = await _resolveStrategyAudience({ ...baseStrategy, targetTier: t });
        for (const u of (aud.usernames || [])) allTargets.add(u);
        unionDetails = unionDetails.concat(aud.details || []);
      }
    }
    // Cap a 5000 destinatarios por difusion. Truncamos ANTES de enviar
    // para que sentCount/respondersCount/targetUsernames coincidan exactamente
    // y los reportes de ROI sean correctos.
    const MAX_TARGETS = 5000;
    let targets = [...allTargets];
    const totalEligible = targets.length;
    if (totalEligible > MAX_TARGETS) {
      logger.warn(`[quick-launch] capping audience from ${totalEligible} to ${MAX_TARGETS}`);
      targets = targets.slice(0, MAX_TARGETS);
    }
    if (targets.length === 0) {
      return res.status(400).json({ error: 'No hay destinatarios con esos filtros.', sample: [] });
    }

    const bonusBadge = bonusPercent > 0 ? ` 🎁 BONO ${bonusPercent}%` : '';
    const sendResult = await sendNotificationToAllUsers(
      User,
      title + bonusBadge,
      body,
      {
        source: 'quick-launch',
        type,
        bonusPercent: String(bonusPercent),
        targetSegment: baseStrategy.targetSegment,
        tiers: tiers.join(',') || 'all'
      },
      { username: { $in: targets } }
    );

    // Tambien lo guardamos en el plan de la semana actual como una strategy
    // ya lanzada — asi queda en el historial y la performance se puede
    // medir despues.
    const weekKey = _isoWeekKey(_argZonedNow());
    const weekStart = _weekStartFromKey(weekKey);
    let plan = await WeeklyCalendarPlan.findOne({ weekKey });
    if (!plan) {
      plan = new WeeklyCalendarPlan({
        weekKey, weekStartDate: weekStart,
        days: _DAY_LABELS.map((l, i) => ({ dayIndex: i, label: l, strategies: [] })),
        createdBy: req.user.username || 'admin'
      });
      await _ensureRefundPinnedDaily(plan);
    }
    const argNow = _argZonedNow();
    const dayIdx = (argNow.getUTCDay() || 7) - 1; // 0=lunes
    let day = plan.days.find(d => d.dayIndex === dayIdx);
    if (!day) {
      day = { dayIndex: dayIdx, label: _DAY_LABELS[dayIdx], strategies: [] };
      plan.days.push(day);
    }
    day.strategies.push({
      id: uuidv4(),
      dayIndex: dayIdx,
      order: day.strategies.length,
      type, title, body,
      bonusPercent,
      bonusFlatARS: 0,
      targetSegment: baseStrategy.targetSegment,
      targetTier: tiers.length === 1 ? tiers[0] : null,
      targetTeams: baseStrategy.targetTeams,
      hasAppOnly: baseStrategy.hasAppOnly,
      refundTypes: baseStrategy.refundTypes,
      status: 'lanzado',
      isPinned: false,
      launchedAt: new Date(),
      launchedBy: req.user.username || 'admin',
      targetUsernames: targets,
      sentCount: (sendResult && sendResult.successCount) || 0,
      deliveredCount: (sendResult && sendResult.successCount) || 0,
      failedCount: (sendResult && sendResult.failureCount) || 0,
      performance: { sentiment: 'sin_datos' },
      notes: tiers.length > 1 ? `Quick-launch a tiers: ${tiers.join('+')}` : 'Quick-launch'
    });
    plan.markModified('days');
    if (plan.status === 'draft') plan.status = 'active';
    _recalcPlanSummary(plan);
    await plan.save();

    res.json({
      success: true,
      eligible: targets.length,
      sent: (sendResult && sendResult.successCount) || 0,
      failed: (sendResult && sendResult.failureCount) || 0,
      tiers: tiers.length > 0 ? tiers : ['all'],
      sample: unionDetails.slice(0, 30)
    });
  } catch (err) {
    logger.error(`/api/admin/calendar/quick-launch: ${err.message}`);
    res.status(500).json({ error: 'Error en quick-launch' });
  }
});

// GET /api/admin/calendar/strategy/:weekKey/:id/preview — devuelve la
// audiencia que recibiria el push si se lanzara AHORA. Para refund-type
// trae el desglose por tipo (daily/weekly/monthly) y la lista de users
// con cuanto le tocaria de reembolso. Para push/bonus, trae los users
// del segmento + tier + equipo + app filter.
app.get('/api/admin/calendar/strategy/:weekKey/:id/preview', authMiddleware, adminMiddleware, async (req, res) => {
  try {
    const { weekKey, id } = req.params;
    const plan = await WeeklyCalendarPlan.findOne({ weekKey }).lean();
    if (!plan) return res.status(404).json({ error: 'Plan no encontrado' });
    let found = null;
    for (const d of (plan.days || [])) for (const s of (d.strategies || [])) if (s.id === id) found = s;
    if (!found) return res.status(404).json({ error: 'Strategy no encontrada' });

    const aud = await _resolveStrategyAudience(found);
    const limit = Math.max(1, Math.min(parseInt(req.query.limit, 10) || 200, 1000));
    res.json({
      success: true,
      strategyId: id,
      type: found.type,
      total: (aud.usernames || []).length,
      breakdown: aud.breakdown || {},
      sample: (aud.details || []).slice(0, limit),
      truncated: (aud.details || []).length > limit
    });
  } catch (err) {
    logger.error(`/api/admin/calendar/strategy preview: ${err.message}`);
    res.status(500).json({ error: 'Error calculando audiencia' });
  }
});

app.delete('/api/admin/calendar/strategy/:weekKey/:id', authMiddleware, superAdminMiddleware, async (req, res) => {
  try {
    const { weekKey, id } = req.params;
    const plan = await WeeklyCalendarPlan.findOne({ weekKey });
    if (!plan) return res.status(404).json({ error: 'Plan no encontrado' });
    let found = null, parentDay = null;
    for (const d of plan.days) {
      for (const s of d.strategies) if (s.id === id) { found = s; parentDay = d; }
    }
    if (!found) return res.status(404).json({ error: 'Strategy no encontrada' });
    if (found.isPinned) return res.status(400).json({ error: 'No se puede borrar una strategy fija (refund). Editala o cancelala.' });
    if (found.status === 'lanzando' || found.status === 'lanzado' || found.status === 'completado') {
      return res.status(400).json({ error: 'No se puede borrar una strategy ya lanzada (queda en historial).' });
    }
    parentDay.strategies = parentDay.strategies.filter(s => s.id !== id);
    plan.markModified('days');
    _recalcPlanSummary(plan);
    await plan.save();
    res.json({ success: true });
  } catch (err) {
    logger.error(`/api/admin/calendar/strategy delete: ${err.message}`);
    res.status(500).json({ error: 'Error eliminando difusión' });
  }
});

// DELETE /api/admin/calendar/week/:weekKey/strategies/non-pinned
// Limpia TODAS las strategies no-pinned (las difusiones manuales viejas)
// y deja el plan con solo las pinned (refund recordatorios fijos). Ignora
// las que ya estan 'lanzado' o 'completado' (esas son historial). Las
// 'lanzando' se mantienen para no cortar un push en curso. Solo borra
// 'pendiente' o 'cancelado'. Util para limpiar la pantalla de planes
// viejos cuando el owner cambia de estrategia.
app.delete('/api/admin/calendar/week/:weekKey/strategies/non-pinned', authMiddleware, superAdminMiddleware, async (req, res) => {
  try {
    const { weekKey } = req.params;
    const plan = await WeeklyCalendarPlan.findOne({ weekKey });
    if (!plan) return res.status(404).json({ error: 'Plan no encontrado' });
    let removed = 0;
    for (const d of plan.days) {
      const before = d.strategies.length;
      d.strategies = d.strategies.filter(s => {
        if (s.isPinned) return true; // pinned siempre se queda
        if (s.status === 'lanzado' || s.status === 'completado') return true; // historial
        if (s.status === 'lanzando') return true; // en curso, no tocar
        return false; // pendiente / cancelado / draft -> borrar
      });
      removed += (before - d.strategies.length);
    }
    plan.markModified('days');
    _recalcPlanSummary(plan);
    await plan.save();
    logger.info(`[calendar] cleanup non-pinned weekKey=${weekKey} removed=${removed} by=${req.user?.username || 'admin'}`);
    res.json({ success: true, removed });
  } catch (err) {
    logger.error(`/api/admin/calendar/week/strategies/non-pinned: ${err.message}`);
    res.status(500).json({ error: 'Error limpiando difusiones' });
  }
});

// POST /api/admin/calendar/bonus-reminder
// Quick-action: manda push masivo a TODOS los users que NO reclamaron
// su bono diario / semanal / mensual del periodo actual. Usa la misma
// pipeline que /quick-launch (con type='refund' y refundTypes=[<type>])
// para que el plan de la semana lo registre y aparezca el ROI despues.
//
// Body: { type: 'daily'|'weekly'|'monthly' }
//
// Title/body se setean automaticos con copy preestablecido — el owner
// solo decide CUAL bono y nosotros nos ocupamos del resto. Asi las
// difusiones quedan uniformes y rapidas de lanzar.
app.post('/api/admin/calendar/bonus-reminder', authMiddleware, superAdminMiddleware, bulkLaunchLimiter, async (req, res) => {
  try {
    const b = req.body || {};
    const refundType = String(b.type || '').toLowerCase();
    if (!['daily', 'weekly', 'monthly'].includes(refundType)) {
      return res.status(400).json({ error: 'Type invalido. Tiene que ser daily, weekly o monthly.' });
    }
    const presets = {
      daily:   { title: '💰 ¡No te olvides de tu bono diario!',   body: 'No reclamaste tu bono de hoy todavía. Entrá a la app y pedilo, es automático.' },
      weekly:  { title: '📆 ¡No reclamaste tu bono semanal!',     body: 'Esta semana todavía no pediste tu bono. Reclamalo antes que termine la semana.' },
      monthly: { title: '🗓 ¡Te falta el bono mensual del mes!',  body: 'No reclamaste el bono del mes. Entrá ahora y pedilo, no se acumula al siguiente.' }
    };
    const preset = presets[refundType];

    // Reusamos la logica de quick-launch construyendo una pseudo-strategy.
    const baseStrategy = {
      type: 'refund',
      title: preset.title,
      body: preset.body,
      bonusPercent: 0,
      bonusFlatARS: 0,
      targetSegment: 'all',
      targetTier: null,
      targetTeams: [],
      hasAppOnly: true,
      refundTypes: [refundType]
    };

    const aud = await _resolveStrategyAudience(baseStrategy);
    const targets = (aud.usernames || []);
    if (targets.length === 0) {
      return res.json({ success: true, eligible: 0, sent: 0, failed: 0, message: 'No hay usuarios elegibles ahora — todos ya reclamaron o no tienen app instalada.' });
    }

    const MAX_TARGETS = 5000;
    const finalTargets = targets.length > MAX_TARGETS ? targets.slice(0, MAX_TARGETS) : targets;

    const sendResult = await sendNotificationToAllUsers(
      User,
      preset.title,
      preset.body,
      {
        source: 'bonus-reminder',
        refundType,
        targetSegment: 'all'
      },
      { username: { $in: finalTargets } }
    );

    // Registrar en el plan de la semana actual (mismo patron que quick-launch).
    const weekKey = _isoWeekKey(_argZonedNow());
    const weekStart = _weekStartFromKey(weekKey);
    let plan = await WeeklyCalendarPlan.findOne({ weekKey });
    if (!plan) {
      plan = new WeeklyCalendarPlan({
        weekKey, weekStartDate: weekStart,
        days: _DAY_LABELS.map((l, i) => ({ dayIndex: i, label: l, strategies: [] })),
        createdBy: req.user.username || 'admin'
      });
      await _ensureRefundPinnedDaily(plan);
    }
    const argNow = _argZonedNow();
    const dayIdx = (argNow.getUTCDay() || 7) - 1;
    let day = plan.days.find(d => d.dayIndex === dayIdx);
    if (!day) {
      day = { dayIndex: dayIdx, label: _DAY_LABELS[dayIdx], strategies: [] };
      plan.days.push(day);
    }
    day.strategies.push({
      id: uuidv4(),
      dayIndex: dayIdx,
      order: day.strategies.length,
      type: 'refund',
      title: preset.title,
      body: preset.body,
      bonusPercent: 0,
      bonusFlatARS: 0,
      targetSegment: 'all',
      targetTier: null,
      targetTeams: [],
      hasAppOnly: true,
      refundTypes: [refundType],
      status: 'lanzado',
      isPinned: false,
      launchedAt: new Date(),
      launchedBy: req.user.username || 'admin',
      targetUsernames: finalTargets,
      sentCount: (sendResult && sendResult.successCount) || 0,
      deliveredCount: (sendResult && sendResult.successCount) || 0,
      failedCount: (sendResult && sendResult.failureCount) || 0,
      performance: { sentiment: 'sin_datos' },
      notes: `Recordatorio bono ${refundType} (quick-action)`
    });
    plan.markModified('days');
    if (plan.status === 'draft') plan.status = 'active';
    _recalcPlanSummary(plan);
    await plan.save();

    res.json({
      success: true,
      eligible: targets.length,
      sent: (sendResult && sendResult.successCount) || 0,
      failed: (sendResult && sendResult.failureCount) || 0,
      refundType
    });
  } catch (err) {
    logger.error(`/api/admin/calendar/bonus-reminder: ${err.message}`);
    res.status(500).json({ error: 'Error mandando recordatorio' });
  }
});

app.post('/api/admin/calendar/strategy/:weekKey/:id/launch', authMiddleware, superAdminMiddleware, bulkLaunchLimiter, async (req, res) => {
  try {
    const { weekKey, id } = req.params;

    // Lock atomico: pasar de 'pendiente' a 'lanzando' en una sola operacion
    // condicional. Si dos requests llegan simultaneas, solo una matchea
    // (la otra recibe null) — la perdedora devuelve 409 sin disparar push.
    const lockedPlan = await WeeklyCalendarPlan.findOneAndUpdate(
      { weekKey, days: { $elemMatch: { strategies: { $elemMatch: { id, status: 'pendiente' } } } } },
      { $set: { 'days.$[d].strategies.$[s].status': 'lanzando' } },
      {
        arrayFilters: [{ 'd.strategies.id': id }, { 's.id': id, 's.status': 'pendiente' }],
        new: true
      }
    );
    if (!lockedPlan) {
      // Diagnostico: ya esta en otro estado, o no existe
      const probe = await WeeklyCalendarPlan.findOne({ weekKey, 'days.strategies.id': id }, { 'days.strategies.$': 1 }).lean();
      if (!probe) return res.status(404).json({ error: 'Plan o strategy no encontrada' });
      return res.status(409).json({ error: 'La strategy ya está siendo lanzada o ya se lanzó. Recargá la página para ver el estado actual.' });
    }
    const plan = lockedPlan;
    let found = null;
    for (const d of plan.days) for (const s of d.strategies) if (s.id === id) { found = s; break; }
    if (!found) return res.status(500).json({ error: 'Strategy no encontrada tras lock' });
    if (!found.title || !found.body) {
      // Restaurar estado y devolver error
      await WeeklyCalendarPlan.updateOne(
        { weekKey, 'days.strategies.id': id },
        { $set: { 'days.$[d].strategies.$[s].status': 'pendiente' } },
        { arrayFilters: [{ 'd.strategies.id': id }, { 's.id': id }] }
      ).catch(() => {});
      return res.status(400).json({ error: 'Falta title o body en la strategy' });
    }

    let targets = [];
    let sendResult = null;
    let totalEligibleAud = 0;
    try {
      const aud = await _resolveStrategyAudience(found);
      targets = aud.usernames || [];
      totalEligibleAud = targets.length;
      // Cap a 5000 antes de enviar para que sentCount/responseRate sean
      // calculables sobre la misma lista (storage = send target).
      const MAX_TARGETS = 5000;
      if (targets.length > MAX_TARGETS) {
        logger.warn(`[calendar launch] capping audience from ${targets.length} to ${MAX_TARGETS} (strategy ${found.id})`);
        targets = targets.slice(0, MAX_TARGETS);
      }
      if (targets.length === 0) {
        // Restaurar a 'pendiente' atomicamente
        await WeeklyCalendarPlan.updateOne(
          { weekKey, 'days.strategies.id': id },
          { $set: { 'days.$[d].strategies.$[s].status': 'pendiente' } },
          { arrayFilters: [{ 'd.strategies.id': id }, { 's.id': id }] }
        ).catch(() => {});
        return res.status(400).json({
          error: found.type === 'refund'
            ? 'No hay usuarios con reembolso pendiente para reclamar HOY (cruzando los tipos seleccionados, equipo y app).'
            : 'No hay destinatarios que cumplan los filtros (segmento + tier + equipo + app).',
          breakdown: aud.breakdown
        });
      }

      const bonusBadge = found.bonusPercent > 0
        ? ` 🎁 BONO ${found.bonusPercent}%`
        : (found.bonusFlatARS > 0 ? ` 🎁 BONO $${found.bonusFlatARS.toLocaleString('es-AR')}` : '');
      sendResult = await sendNotificationToAllUsers(
        User,
        (found.title || '') + bonusBadge,
        found.body || '',
        {
          source: 'weekly-calendar',
          weekKey,
          strategyId: found.id,
          strategyType: found.type,
          bonusPercent: String(found.bonusPercent || 0),
          targetSegment: found.targetSegment || 'all'
        },
        { username: { $in: targets } }
      );
    } catch (sendErr) {
      logger.error(`[calendar] launch ${id} error: ${sendErr.message}`);
      // Restaurar a pendiente atomicamente (no usar plan.save() porque
      // el doc en memoria puede estar stale despues del lock).
      await WeeklyCalendarPlan.updateOne(
        { weekKey, 'days.strategies.id': id },
        { $set: { 'days.$[d].strategies.$[s].status': 'pendiente' } },
        { arrayFilters: [{ 'd.strategies.id': id }, { 's.id': id }] }
      ).catch(() => {});
      return res.status(500).json({ error: 'Error al enviar la notificacion. Intentalo de nuevo en unos segundos.' });
    }

    found.status = 'lanzado';
    found.launchedAt = new Date();
    found.launchedBy = req.user.username || 'admin';
    found.targetUsernames = targets; // ya capeada arriba a MAX_TARGETS
    found.sentCount = (sendResult && sendResult.successCount) || 0;
    found.deliveredCount = found.sentCount;
    found.failedCount = (sendResult && sendResult.failureCount) || 0;
    found.performance = {
      measuredAt: null,
      daysObserved: 0,
      respondersCount: 0,
      responseRate: 0,
      newDepositsCount: 0,
      newDepositsAmountARS: 0,
      bonusGivenARS: 0,
      bonusClaimedCount: 0,
      roi: 0,
      sentiment: 'sin_datos'
    };

    plan.markModified('days');
    if (plan.status === 'draft') plan.status = 'active';
    _recalcPlanSummary(plan);
    await plan.save();

    res.json({
      success: true,
      strategy: found,
      sent: found.sentCount,
      failed: found.failedCount,
      eligible: targets.length
    });
  } catch (err) {
    logger.error(`/api/admin/calendar/strategy launch: ${err.message}`);
    res.status(500).json({ error: 'Error lanzando difusión' });
  }
});

app.post('/api/admin/calendar/strategy/:weekKey/:id/refresh-performance', authMiddleware, superAdminMiddleware, async (req, res) => {
  try {
    const { weekKey, id } = req.params;
    const plan = await WeeklyCalendarPlan.findOne({ weekKey });
    if (!plan) return res.status(404).json({ error: 'Plan no encontrado' });
    let found = null;
    for (const d of plan.days) for (const s of d.strategies) if (s.id === id) found = s;
    if (!found) return res.status(404).json({ error: 'Strategy no encontrada' });
    if (!found.launchedAt) return res.status(400).json({ error: 'Strategy no lanzada todavia' });

    const since = new Date(found.launchedAt);
    const daysObs = Math.max(0, Math.floor((Date.now() - since.getTime()) / (24 * 3600 * 1000)));
    const targets = found.targetUsernames || [];
    if (targets.length === 0) {
      found.performance = { ...found.performance, measuredAt: new Date(), daysObserved: daysObs, sentiment: 'sin_datos' };
      plan.markModified('days');
      _recalcPlanSummary(plan);
      await plan.save();
      return res.json({ success: true, performance: found.performance });
    }

    // DailyPlayerStats indexa por dateUtc = inicio de dia UTC. Si comparamos
    // contra launchedAt directo, perdemos el dia del lanzamiento (porque el
    // documento de ese dia tiene dateUtc < launchedAt). Solucion: bajar
    // sinceUtc al inicio del dia ARG que contiene el lanzamiento — asi
    // contamos todas las cargas de ese dia y los siguientes. Convertimos
    // launchedAt a hora ARG, tomamos su 00:00 ARG, y volvemos a UTC.
    const argShift = 3 * 3600 * 1000;
    const argLaunch = new Date(since.getTime() - argShift);
    const argDayStart = new Date(Date.UTC(argLaunch.getUTCFullYear(), argLaunch.getUTCMonth(), argLaunch.getUTCDate()));
    const sinceUtc = new Date(argDayStart.getTime() + argShift); // 00:00 ARG = 03:00 UTC
    const depAgg = await DailyPlayerStats.aggregate([
      { $match: { username: { $in: targets }, dateUtc: { $gte: sinceUtc } } },
      { $group: {
          _id: '$username',
          deps: { $sum: '$depositCount' },
          depAmt: { $sum: '$depositSum' }
      } }
    ]);
    let respondersCount = 0;
    let newDepositsCount = 0;
    let newDepositsAmount = 0;
    for (const a of depAgg) {
      if ((a.deps || 0) > 0) {
        respondersCount++;
        newDepositsCount += a.deps;
        newDepositsAmount += a.depAmt;
      }
    }

    // Bonos efectivamente entregados a los targets desde el lanzamiento.
    const bonusAgg = await MoneyGiveawayClaim.aggregate([
      { $match: { username: { $in: targets }, status: 'completed', claimedAt: { $gte: sinceUtc } } },
      { $group: { _id: null, count: { $sum: 1 }, total: { $sum: '$amount' } } }
    ]);
    const bonusGiven = (bonusAgg[0] && bonusAgg[0].total) || 0;
    const bonusCount = (bonusAgg[0] && bonusAgg[0].count) || 0;

    const responseRate = targets.length > 0 ? (respondersCount / targets.length) : 0;
    const roi = bonusGiven > 0 ? (newDepositsAmount / bonusGiven) : (newDepositsAmount > 0 ? Infinity : 0);

    // Sentiment: ROI > 1.5 = positivo, < 0.5 = negativo, ente medio = neutro.
    // Si daysObs < 2, mantener "sin_datos" (todavia muy temprano).
    let sentiment = 'sin_datos';
    if (daysObs >= 2) {
      if (roi >= 1.5 || responseRate >= 0.20) sentiment = 'positivo';
      else if (roi < 0.5 && responseRate < 0.05) sentiment = 'negativo';
      else sentiment = 'neutro';
    }

    found.performance = {
      measuredAt: new Date(),
      daysObserved: daysObs,
      respondersCount,
      responseRate,
      newDepositsCount,
      newDepositsAmountARS: newDepositsAmount,
      bonusGivenARS: bonusGiven,
      bonusClaimedCount: bonusCount,
      roi: Number.isFinite(roi) ? roi : 999,
      sentiment
    };

    // Si pasaron mas de 7 dias, marcar completado.
    if (daysObs >= 7) found.status = 'completado';

    plan.markModified('days');
    _recalcPlanSummary(plan);
    await plan.save();

    res.json({ success: true, performance: found.performance, status: found.status });
  } catch (err) {
    logger.error(`/api/admin/calendar/strategy perf: ${err.message}`);
    res.status(500).json({ error: 'Error refrescando rendimiento' });
  }
});

